def _normalize_card_date(raw):
    """Normalize card date to 'DD Month YYYY' format.
    Handles: dd.mm.yyyy, mm/dd/yyyy, dd/mm/yyyy, 'D Month YYYY', 'Month D YYYY', MM/YYYY, raw text."""
    if not raw or not isinstance(raw, str):
        return raw or ''
    raw = raw.strip()
    import re as _re
    from datetime import datetime as _dt
    # dd.mm.yyyy (Rolex warranty card standard)
    m = _re.match(r'^(\d{1,2})\.(\d{1,2})\.(\d{4})$', raw)
    if m:
        day, month, year = int(m.group(1)), int(m.group(2)), int(m.group(3))
        try:
            d = _dt(year, month, day)
            return d.strftime('%-d %B %Y')
        except ValueError:
            pass
    # Already in "D Month YYYY" or "DD Month YYYY" — validate and return
    m = _re.match(r'^(\d{1,2})\s+(January|February|March|April|May|June|July|August|September|October|November|December)\s+(\d{4})$', raw, _re.IGNORECASE)
    if m:
        return raw
    # "Month D, YYYY"
    m = _re.match(r'^(January|February|March|April|May|June|July|August|September|October|November|December)\s+(\d{1,2}),?\s+(\d{4})$', raw, _re.IGNORECASE)
    if m:
        try:
            d = _dt(int(m.group(3)), list(['', 'January','February','March','April','May','June','July','August','September','October','November','December']).index(m.group(1).title()), int(m.group(2)))
            return d.strftime('%-d %B %Y')
        except (ValueError, IndexError):
            pass
    # MM/YYYY — keep as is (no day info)
    m = _re.match(r'^(\d{1,2})/(\d{4})$', raw)
    if m:
        return raw
    return raw

