# ── Security Headers (every response) ──
@app.after_request
def set_security_headers(response):
    # Skip restrictive headers for public photo endpoints (Google Sheets needs to embed these)
    if request.path.startswith('/api/public/posting-photo/'):
        return response
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['Referrer-Policy'] = 'strict-origin-when-cross-origin'
    response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Content-Security-Policy'] = (
        "default-src 'self'; "
        "script-src 'self' 'unsafe-inline'; "
        "style-src 'self' 'unsafe-inline' https://fonts.googleapis.com; "
        "font-src 'self' https://fonts.gstatic.com; "
        "img-src 'self' data:; "
        "connect-src 'self'; "
        "frame-ancestors 'none';"
    )
    return response

# ── Rate Limiting (login brute-force protection) ──
_login_attempts = {}  # ip -> [timestamps]
_LOGIN_MAX = 5        # max attempts per window
_LOGIN_WINDOW = 300   # 5-minute window

def _check_rate_limit(ip):
    """Returns True if rate-limited."""
    now = time.time()
    attempts = _login_attempts.get(ip, [])
    attempts = [t for t in attempts if now - t < _LOGIN_WINDOW]
    _login_attempts[ip] = attempts
    return len(attempts) >= _LOGIN_MAX

def _record_attempt(ip):
    now = time.time()
    if ip not in _login_attempts:
        _login_attempts[ip] = []
    _login_attempts[ip].append(now)

def _audit_log(event, ip, detail=''):
    """Append login/auth events to audit log."""
    from datetime import datetime
    log_path = BASE_DIR / '.audit.log'
    try:
        with open(log_path, 'a') as f:
            ts = datetime.now(ET).strftime('%Y-%m-%d %H:%M:%S')
            f.write(f'{ts} | {event:12s} | {ip:15s} | {detail}\n')
    except Exception:
        pass

