_security_config = _load_security_config()

def _verify_api_key(req):
    """Check for valid API key in Authorization header or query param."""
    api_key = _security_config.get('api_key', '')
    if not api_key:
        return False
    auth = req.headers.get('Authorization', '')
    if auth.startswith('Bearer ') and auth[7:] == api_key:
        return True
    if req.args.get('api_key') == api_key:
        return True
    return False

def login_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        # API key auth (for programmatic access)
        if _verify_api_key(request):
            return f(*args, **kwargs)
        # Localhost bypass for local programmatic access (CLI, automation)
        client_ip = request.headers.get('CF-Connecting-IP', request.remote_addr)
        if client_ip in ('127.0.0.1', '::1', 'localhost') and not request.headers.get('CF-Connecting-IP'):
            return f(*args, **kwargs)
        # Log unauthorized API attempts
        if not session.get('authenticated') and (request.is_json or request.path.startswith('/api/')):
            _audit_log('UNAUTH_API', client_ip, request.path)
        if not session.get('authenticated'):
            if request.is_json or request.path.startswith('/api/'):
                return jsonify({"error": "unauthorized"}), 401
            return redirect('/login')
        return f(*args, **kwargs)
    return decorated

# Role-based access: restrict endpoints to specific roles
# Roles: admin (Jeffin), full (trusted employee), logistics (Masuk/Keluar only), media (postings/photos/inventory/operations)
ROLE_PAGES = {
    'admin': None,  # None = all pages
    'full': None,   # Full access too
    'logistics': {'jam'},  # Only Jam page (Masuk + Keluar tabs)
    'media': {'postings', 'photos', 'inventory', 'jam'},  # Media role: postings, photos, inventory, operations
    'consignment': {'payments'},  # Consignment partners: only Sin cashflow under payments
}
