VALID_ROLES = ('full', 'logistics', 'media', 'consignment')

def _get_user_role():
    """Get the current user's role from session."""
    # Session role takes priority (employee logins set this)
    if session.get('user_role'):
        return session['user_role']
    # API key without session = external/admin API call
    if _verify_api_key(request):
        return 'admin'
    return 'admin'  # Default admin for backward compat

# Map API route prefixes to page categories for role enforcement
# If an API prefix is not listed here, it's allowed for all authenticated users
_API_PAGE_MAP = {
    '/api/internal-invoices': 'invoices',
    '/api/zoho/invoices': 'invoices',
    '/api/ifs/labels': 'shipping',
    '/api/shipping': 'shipping',
    '/api/deals': 'deals',
    '/api/seller': 'deals',
    '/api/payments': 'payments',
    '/api/inventory/batch-sold': 'invoices',
    '/api/inventory/mark-seller-paid': 'payments',
    '/api/telegram/post-shipped': 'shipping',
    '/api/telegram/post-sold': 'invoices',
    '/api/telegram/post-to-my-postings': 'postings',
    '/api/my-postings/repost': 'postings',
    '/api/my-postings/repost-all': 'postings',
    '/api/my-postings/post-direct': 'postings',
    '/api/valley-bank': 'payments',
    '/api/briefing': 'briefing',
    '/api/mission-control': 'mission-control',
    '/api/users': 'admin',
    '/api/sheet': 'admin',
}

# Pages each role is DENIED (inverse of allowed for efficiency)
# admin/full = no restrictions
def _check_role_access(role, page_category):
    """Return True if role can access this page category."""
    if role in ('admin', 'full'):
        return True
    allowed = ROLE_PAGES.get(role)
    if allowed is None:
        return True  # No restrictions
    # Special: 'admin' category = admin only
    if page_category == 'admin':
        return role == 'admin'
    return page_category in allowed

@app.before_request
def _log_request():
    """Log every request: IP, method, path, timestamp."""
    import logging
    _req_logger = logging.getLogger('dashboard.access')
    if not _req_logger.handlers:
        _h = logging.FileHandler(os.path.join(os.path.dirname(__file__), 'access.log'))
        _h.setFormatter(logging.Formatter('%(message)s'))
        _req_logger.addHandler(_h)
        _req_logger.setLevel(logging.INFO)
    _req_logger.info(f"{datetime.utcnow().isoformat()}Z {request.remote_addr} {request.method} {request.path}")

@app.before_request
def _enforce_role_access():
    """Server-side enforcement: block API access to pages outside user's role."""
    path = request.path
    if not path.startswith('/api/'):
        return  # HTML pages handled by CSS + frontend
    # Skip auth-related endpoints
    if path in ('/api/login', '/api/user-role'):
        return
    # API key = admin, skip
    if _verify_api_key(request):
        return
    if not session.get('authenticated'):
        return  # login_required will handle this
    role = session.get('user_role', 'admin')
    if role in ('admin', 'full'):
        return  # Full access
    # Check each prefix (longest match first)
    for prefix, page_cat in sorted(_API_PAGE_MAP.items(), key=lambda x: -len(x[0])):
        if path.startswith(prefix):
            if not _check_role_access(role, page_cat):
                _audit_log('ROLE_DENIED', f'role={role}', f'{request.method} {path} (needs {page_cat})')
                return jsonify({'error': 'access denied'}), 403
            return
    # For inventory write endpoints, media can only read
    if role == 'media':
        # Media can read inventory but not modify sales/shipping/payments
        write_blocked = ['/api/inventory/ship', '/api/inventory/mark-seller-paid']
        if path in write_blocked and request.method == 'POST':
            _audit_log('ROLE_DENIED', f'role={role}', f'{request.method} {path}')
            return jsonify({'error': 'access denied'}), 403
        # Block sold endpoints
        if '/sold' in path and request.method == 'POST':
            _audit_log('ROLE_DENIED', f'role={role}', f'{request.method} {path}')
            return jsonify({'error': 'access denied'}), 403

