def avg_bottom_25(prices):
    """Average of bottom 25% of prices. Min 2 items. If <2 eligible, use lowest."""
    if not prices:
        return None
    sorted_p = sorted(prices)
    n = max(2, len(sorted_p) // 4)  # 25% but at least 2
    n = min(n, len(sorted_p))  # can't take more than we have
    return round(sum(sorted_p[:n]) / n)

def avg2_cheapest(prices):
    """Average of 2 cheapest listings."""
    if not prices:
        return None
    sorted_p = sorted(prices)
    n = min(2, len(sorted_p))
    return round(sum(sorted_p[:n]) / n)


def get_latest_sync():
    """Get the latest chat sync folder date."""
