def load_data():
    """Load all data files and refresh cache."""
    global data_cache
    
    try:
        # Load listings with outlier filtering
        listings_file = BASE_DIR / 'rolex_listings.json'
        if listings_file.exists():
            with open(listings_file, 'r', encoding='utf-8') as f:
                raw_listings = json.load(f)
            
            # ── Pre-clean: fix ref parsing bugs ──
            import re as _re
            precleaned = []
            _ref_fixes = 0
            _ref_drops = 0
            for l in raw_listings:
                ref = l.get('ref', '') or ''
                
                # Fix 1: Strip currency suffix from ref (e.g. "12500HKD" → "12500")
                if _re.search(r'(HKD|USD|EUR|GBP|AED|SGD|USDT)$', ref, _re.IGNORECASE):
                    ref = _re.sub(r'(HKD|USD|EUR|GBP|AED|SGD|USDT)$', '', ref, flags=_re.IGNORECASE).strip()
                    l['ref'] = ref
                    _ref_fixes += 1
                
                # Fix 2: Truncated Rolex refs (5 digits starting with 12/13/22/27/28/33)
                # e.g. "12503" should be "126503", "12100" should be "126100"
                if _re.match(r'^(12|13|22|27|28|33)\d{3}$', ref):
                    # Try to expand: 12503 → 126503 (insert '6' after first 2 digits for 12xxxx)
                    # Common patterns: 12X → 126X, 13X → 13XX, 22X → 22XX, 27X → 278X, 28X → 228X
                    expanded = None
                    if ref.startswith('12'):
                        expanded = '126' + ref[2:]  # 12503 → 126503
                    elif ref.startswith('13'):
                        expanded = '134' + ref[2:]  # 13430 → 134300 — but only 5 digits, so 13430 → 134300? no
                        # Actually: 13430 is 5 digits. Rolex refs are 6. Could be 134300 or 136300
                        expanded = None  # ambiguous, drop
                    elif ref.startswith('27'):
                        expanded = '278' + ref[2:]  # 27827 → 278274? tricky
                        expanded = None  # ambiguous
                    
                    if expanded:
                        l['ref'] = expanded
                        _ref_fixes += 1
                    else:
                        _ref_drops += 1
                        continue  # drop ambiguous truncated refs
                
                # Fix 3: Drop refs that are clearly not watch refs (< 5 digits or garbage)
                if not _re.match(r'^\d{5,7}', ref) and not _re.match(r'^\d+[A-Z]', ref, _re.IGNORECASE):
                    if len(ref) < 5:
                        _ref_drops += 1
                        continue
                
                # Fix 4: Drop "Style" model (it's a parsing artifact, not a real model)
                if l.get('model') == 'Style':
                    l['model'] = ''
                
                precleaned.append(l)
            
            raw_listings = precleaned
            if _ref_fixes or _ref_drops:
                print(f"🔧 Ref cleanup: {_ref_fixes} fixed, {_ref_drops} dropped")
            
            # Canonicalize refs (G/NG/VI/RBR suffix merging)
            if PARSE_V4_AVAILABLE:
                _canon_count = 0
                for l in raw_listings:
                    ref = l.get('ref', '')
                    if ref:
                        canon = canonicalize(ref)
                        if canon and canon != ref:
                            l['ref'] = canon
                            _canon_count += 1
                if _canon_count:
                    print(f"🔗 Ref canonicalization: merged {_canon_count} suffix variants")
            
            # Clean outliers: remove misparsed prices using per-ref-per-dial IQR
            # Group by (ref, dial) because same ref can have wildly different prices
            # for different dials/materials (e.g. 128238 Green=$48K vs Puzzles=$215K)
            from collections import defaultdict
            by_ref = defaultdict(list)
            by_ref_dial = defaultdict(list)
            for l in raw_listings:
                if l.get('ref') and l.get('price_usd', 0) > 0:
                    by_ref[l['ref']].append(l)
                    dial = l.get('dial') or 'Unknown'
                    by_ref_dial[(l['ref'], dial)].append(l)
            
            cleaned = []
            outliers_removed = 0
            
            # First pass: per-ref-per-dial IQR (most precise)
            processed = set()
            for (ref, dial), items in by_ref_dial.items():
                prices = sorted([i['price_usd'] for i in items])
                if len(prices) >= 4:
                    q1 = prices[len(prices)//4]
                    q3 = prices[(3*len(prices))//4]
                    iqr = q3 - q1
                    lower = q1 - 2.0 * iqr
                    upper = q3 + 2.0 * iqr
                    
                    med = prices[len(prices)//2]
                    if iqr > 2.0 * med and med > 0:
                        lower = med * 0.25
                        upper = med * 3.0
                    
                    for i in items:
                        processed.add(id(i))
                        if lower <= i['price_usd'] <= upper:
                            cleaned.append(i)
                        else:
                            outliers_removed += 1
            
            # Second pass: remaining items use per-ref IQR
            for ref, items in by_ref.items():
                remaining = [i for i in items if id(i) not in processed]
                if not remaining:
                    continue
                # Use ALL items for this ref to compute IQR (more data)
                all_prices = sorted([i['price_usd'] for i in items])
                if len(all_prices) >= 4:
                    q1 = all_prices[len(all_prices)//4]
                    q3 = all_prices[(3*len(all_prices))//4]
                    iqr = q3 - q1
                    lower = q1 - 2.0 * iqr
                    upper = q3 + 2.0 * iqr
                    
                    med = all_prices[len(all_prices)//2]
                    if iqr > 2.0 * med and med > 0:
                        lower = med * 0.25
                        upper = med * 3.0
                    
                    for i in remaining:
                        if lower <= i['price_usd'] <= upper:
                            cleaned.append(i)
                        else:
                            outliers_removed += 1
                else:
                    cleaned.extend(remaining)
            
            # Remove anything under $3000 USD (no modern Rolex sells this low — clearly misparsed)
            before = len(cleaned)
            cleaned = [l for l in cleaned if l.get('price_usd', 0) >= 3000]
            outliers_removed += before - len(cleaned)
            
            # ── Per-ref median outlier filter ──
            # Remove listings where price is <40% or >400% of the ref's median.
            # Catches: unconverted HKD, misparsed deposits/accessories, double-conversion errors.
            from statistics import median as _stat_median
            _ref_price_lists = defaultdict(list)
            for l in cleaned:
                _r = l.get('ref', '')
                _p = l.get('price_usd', 0)
                if _r and _p > 0:
                    _ref_price_lists[_r].append(_p)
            _ref_meds = {r: _stat_median(ps) for r, ps in _ref_price_lists.items() if len(ps) >= 5}
            
            before = len(cleaned)
            cleaned = [l for l in cleaned if not (
                l.get('ref') in _ref_meds and l.get('price_usd', 0) > 0 and (
                    l['price_usd'] < _ref_meds[l['ref']] * 0.40 or
                    l['price_usd'] > _ref_meds[l['ref']] * 4.0
                )
            )]
            _median_removed = before - len(cleaned)
            if _median_removed:
                print(f"🎯 Per-ref median filter removed {_median_removed} extreme outliers")
            outliers_removed += _median_removed
            
            # ── Same-seller-same-ref-same-timestamp conflict filter ──
            # When same seller posts same ref at 2+ wildly different prices at same timestamp,
            # it's a multi-ref parse error. Keep only the one closest to the ref's median.
            from collections import defaultdict as dd2
            conflict_key = dd2(list)
            for l in cleaned:
                key = (l.get('seller',''), l['ref'], l.get('ts',''))
                conflict_key[key].append(l)
            
            conflict_removed = 0
            new_cleaned = []
            for key, items in conflict_key.items():
                if len(items) <= 1:
                    new_cleaned.extend(items)
                    continue
                prices = [i['price_usd'] for i in items]
                lo, hi = min(prices), max(prices)
                if hi > lo * 1.5 and hi - lo > 2000:
                    # Conflict: keep the one closest to ref median
                    ref = key[1]
                    ref_prices = [i['price_usd'] for i in by_ref.get(ref, []) if i.get('price_usd', 0) > 0]
                    if ref_prices:
                        from statistics import median as smed
                        ref_med = smed(ref_prices)
                        best = min(items, key=lambda x: abs(x['price_usd'] - ref_med))
                        new_cleaned.append(best)
                        conflict_removed += len(items) - 1
                    else:
                        new_cleaned.extend(items)
                else:
                    new_cleaned.extend(items)
            cleaned = new_cleaned
            if conflict_removed:
                print(f"⚔️ Resolved {conflict_removed} same-seller price conflicts")
            
            # ── Price-list spam filter ──
            # Dealers post one message with 10+ refs at one price (e.g. HKD 388,000).
            # Parser assigns that price to EVERY ref → garbage data.
            # Detect: same (seller, timestamp, price) appearing on 4+ different refs = spam.
            from collections import Counter
            combo_refs = defaultdict(set)
            for l in cleaned:
                key = (l.get('seller',''), l.get('ts',''), l.get('price',0))
                combo_refs[key].add(l.get('ref',''))
            spam_keys = {k for k, refs in combo_refs.items() if len(refs) >= 4}
            if spam_keys:
                before_spam = len(cleaned)
                cleaned = [l for l in cleaned if (l.get('seller',''), l.get('ts',''), l.get('price',0)) not in spam_keys]
                spam_removed = before_spam - len(cleaned)
                print(f"🗑️ Removed {spam_removed} price-list spam listings ({len(spam_keys)} bulk messages)")
            
            # ── Fix region by currency ──
            # Some HK-group sellers price in USD. Region should follow currency, not group.
            region_fixes = 0
            for l in cleaned:
                curr = l.get('currency', 'USD')
                old_region = l.get('region', '')
                if curr == 'HKD' and old_region != 'HK':
                    l['region'] = 'HK'
                    region_fixes += 1
                elif curr in ('USD', 'USDT') and old_region == 'HK':
                    # Keep as HK if source text also has HKD price (dual-price listing from HK seller)
                    src = (l.get('source_text', '') or '').upper()
                    if 'HK$' in src or 'HKD' in src:
                        pass  # HK seller with USD equivalent — keep as HK
                    else:
                        l['region'] = 'US'
                        region_fixes += 1
                elif curr in ('EUR', 'GBP') and old_region not in ('EU',):
                    l['region'] = 'EU'
                    region_fixes += 1
            # Also fix USD listings from HK sellers (dual-price: HKD + USD equivalent)
            for l in cleaned:
                if l.get('region') == 'US' and l.get('currency') in ('USD', 'USDT'):
                    src = (l.get('source_text', '') or '').upper()
                    if 'HK$' in src or 'HKD' in src:
                        l['region'] = 'HK'
                        region_fixes += 1
            if region_fixes:
                print(f"🌍 Fixed region on {region_fixes} listings (currency→region)")
            
            # ── Currency misdetection fix ──
            # Some HK-region USD prices are actually HKD (e.g. $1,370,000 USD should be HKD)
            # Detect: if a USD price from HK region is >5x the median for same ref, it's likely HKD
            from statistics import median as stat_median
            currency_fixes = 0
            ref_medians = {}
            for ref, items in by_ref.items():
                usd_prices = [i['price_usd'] for i in items if i.get('price_usd', 0) > 0]
                if len(usd_prices) >= 3:
                    ref_medians[ref] = stat_median(usd_prices)
            
            FX_HKD = 0.128  # approximate HKD to USD rate
            new_cleaned = []
            for l in cleaned:
                ref = l.get('ref', '')
                med = ref_medians.get(ref)
                if (med and l.get('currency') == 'USD' and l.get('region') == 'US' 
                    and l['price_usd'] > med * 4.0 and l['price_usd'] * FX_HKD > med * 0.5 
                    and l['price_usd'] * FX_HKD < med * 2.0):
                    # This USD price makes more sense as HKD
                    l['price_usd'] = round(l['price'] * FX_HKD, 2)
                    l['raw_usd'] = l['price_usd']
                    l['currency'] = 'HKD'
                    l['region'] = 'HK'
                    currency_fixes += 1
                new_cleaned.append(l)
            cleaned = new_cleaned
            if currency_fixes:
                print(f"💱 Fixed {currency_fixes} likely-HKD prices misdetected as USD")
            
            # ── Completeness inference for Unknown ──
            # For Pre-owned Unknown: if price is within 20% of the Full Set median for same ref+condition,
            # infer it's likely Full Set. This recovers ~40% of data that's excluded from analysis.
            from statistics import median as stat_median2
            ref_cond_medians = defaultdict(lambda: defaultdict(list))
            for l in cleaned:
                if l.get('completeness') in ('Full Set', 'W+C', 'Watch Only'):
                    ref_cond_medians[(l['ref'], l.get('condition',''))][l['completeness']].append(l['price_usd'])
            
            comp_inferred = 0
            for l in cleaned:
                if l.get('completeness') != 'Unknown':
                    continue
                key = (l['ref'], l.get('condition', ''))
                tiers = ref_cond_medians.get(key, {})
                fs_prices = tiers.get('Full Set', [])
                wo_prices = tiers.get('Watch Only', [])
                
                if not fs_prices:
                    continue
                
                fs_med = stat_median2(fs_prices)
                price = l['price_usd']
                
                # If price is within ±25% of Full Set median → infer Full Set
                if fs_med * 0.75 <= price <= fs_med * 1.25:
                    l['completeness'] = 'Full Set'
                    l['completeness_inferred'] = True
                    comp_inferred += 1
                # If Watch Only data exists and price is closer to WO median → infer Watch Only
                elif wo_prices:
                    wo_med = stat_median2(wo_prices)
                    if wo_med * 0.75 <= price <= wo_med * 1.25:
                        l['completeness'] = 'Watch Only'
                        l['completeness_inferred'] = True
                        comp_inferred += 1
            
            if comp_inferred:
                print(f"🔮 Inferred completeness for {comp_inferred} Unknown listings")
            
            # ── Year inference for BNIB ──
            # BNIB watches posted in 2025-2026 without a year → infer 2025/2026
            _year_inferred = 0
            for l in cleaned:
                if not l.get('year') and l.get('condition') == 'BNIB':
                    ts = l.get('ts', '')
                    if '26' in ts or '2026' in ts:
                        l['year'] = '2025/2026'
                        l['year_inferred'] = True
                        _year_inferred += 1
                    elif '25' in ts or '2025' in ts:
                        l['year'] = '2024/2025'
                        l['year_inferred'] = True
                        _year_inferred += 1
            if _year_inferred:
                print(f"📅 Inferred year for {_year_inferred} BNIB listings without card date")
            
            # ── Smart bracelet validation ──
            # Uses Rolex ref structure + model family rules (not hardcoded per-ref)
            from bracelet_rules import fix_all_bracelets
            bracelet_fixed = fix_all_bracelets(cleaned)
            if bracelet_fixed:
                print(f"🔧 Fixed bracelet on {bracelet_fixed} listings (smart ref→bracelet rules)")
            
            # ══════════════════════════════════════════════════════
            # ── COMPREHENSIVE DIAL & REF CONSOLIDATION ──
            # ══════════════════════════════════════════════════════
            _consolidation_count = 0

            # Datejust index-type consolidation:
            # Stick/Roman suffixes don't define a different dial — just index style.
            # Merge them back to base color.
            _DJ_DIAL_MERGE = {
                'Blue Roman': 'Azzurro Blue',  # Blue with Roman = Azzurro Blue
                'Blue Stick': 'Blue',           # Blue Stick = just Blue
                'Green Stick': 'Mint Green',    # No such thing as "Green Stick" — it's Mint Green
                'Mint Green Stick': 'Mint Green',
                'Mint Green Roman': 'Mint Green',
                'Rhodium': 'Grey',              # Rhodium IS grey
                'Rhodium Stick': 'Grey',
                'Slate': 'Grey',                # Slate IS grey
                'Grey Stick': 'Grey',
                'Silver Stick': 'Silver',
                'White Stick': 'White',
                'White Roman': 'White',
                'Black Stick': 'Black',
            }
            # DJ refs where this merge applies (fluted bezel DJ41, DJ36, etc.)
            _DJ_REFS = {'126334', '126234', '126284', '126283', '126233', '126331',
                        '126300', '126200', '126281', '116334', '116234', '116244'}

            for l in cleaned:
                ref = l.get('ref', '')
                ref_base = ref.rstrip('ABCDEFGHIJKLMNOPQRSTUVWXYZ') if ref else ''
                dial = l.get('dial', '')

                # G-suffix merge: 126334G → 126334, dial gets " Diamond" suffix
                if ref.endswith('G') and ref_base in _DJ_REFS:
                    l['ref'] = ref_base
                    if dial and 'Diamond' not in dial:
                        l['dial'] = f'{dial} Diamond'
                    elif not dial:
                        l['dial'] = 'Diamond'
                    _consolidation_count += 1
                    ref = ref_base  # use merged ref for further checks
                    dial = l['dial']

                # DJ dial merge
                if ref_base in _DJ_REFS or ref in _DJ_REFS:
                    new_dial = _DJ_DIAL_MERGE.get(dial)
                    if new_dial:
                        l['dial'] = new_dial
                        _consolidation_count += 1

                # 126300/126200 smooth bezel: "Blue" → "Azzurro Blue"
                if ref in ('126300', '126200') and l.get('dial') == 'Blue':
                    l['dial'] = 'Azzurro Blue'
                    _consolidation_count += 1

            # ── 228238 green variant reclassification ──
            for l in cleaned:
                ref = l.get('ref', '')
                dial = l.get('dial', '')
                price = l.get('price_usd', 0)
                _ref_base_dd = re.match(r'(\d+)', ref)
                _rb_dd = _ref_base_dd.group(1) if _ref_base_dd else ''
                # 228238 Casino/Money Green (solid bright green) — distinct from Green Ombré (gradient)
                if _rb_dd == '228238' and dial in ('Bright Green', 'Green Roman', 'Casino Green'):
                    l['dial'] = 'Money Green'
                    _consolidation_count += 1
                # Other Day-Date ambiguous "Green" → drop (could be many variants)
                elif _rb_dd in ('228238','228235','228236','228239','128238','128235') and dial == 'Green':
                    l['_drop'] = True
                    _consolidation_count += 1
                # Rename any "Green Roman" → "Bright Green" for non-228238
                elif dial == 'Green Roman' and _rb_dd != '228238':
                    l['dial'] = 'Bright Green'
                    _consolidation_count += 1
                # 228235 standalone "Ombré" → "Ombré Slate" (only ombré variant on 228235)
                if _rb_dd == '228235' and dial == 'Ombré':
                    l['dial'] = 'Ombré Slate'
                    _consolidation_count += 1
            # ── Diamond-default ref normalization ──
            # For 278383(RBR), 278273, 278274, 278384(RBR) etc:
            # Plain "Green" → "Green Diamond" (diamond markers are default)
            # "vi Green" / "Green Roman" → "Green Roman VI" (separate dial)
            _DIAMOND_DEFAULT_BASES = {'278383','278273','278274','278384','278381','278288','279381','279383','279384'}
            for l in cleaned:
                ref = l.get('ref', '')
                dial = l.get('dial', '')
                _ref_base_dm = re.match(r'(\d+)', ref)
                _rb_dm = _ref_base_dm.group(1) if _ref_base_dm else ''
                if _rb_dm in _DIAMOND_DEFAULT_BASES:
                    if dial.startswith('vi '):
                        l['dial'] = dial[3:] + ' Roman VI'
                        _consolidation_count += 1
                    elif dial.endswith(' Roman') and 'Roman VI' not in dial:
                        # DON'T auto-add "VI" — "Pink Roman" ≠ "Pink Roman VI"
                        # Only add "VI" if the raw text explicitly mentions VI
                        _raw = l.get('raw_text', l.get('text', '')).lower()
                        if ' vi ' in _raw or ' vi/' in _raw or _raw.endswith(' vi'):
                            l['dial'] = dial + ' VI'
                            _consolidation_count += 1
                        # Otherwise keep as-is (e.g. "Pink Roman" stays "Pink Roman")
                    elif dial and 'Diamond' not in dial and 'MOP' not in dial and 'Pavé' not in dial and 'Baguette' not in dial and 'Roman VI' not in dial and 'Roman' not in dial:
                        l['dial'] = dial + ' Diamond'
                        _consolidation_count += 1

            # ── Universal dial synonym normalization ──
            _syn_path = BASE_DIR / 'dial_synonyms.json'
            if _syn_path.exists():
                with open(_syn_path) as _sf:
                    _syn_raw = json.load(_sf)
                # Build reverse map: synonym -> canonical (global)
                _syn_reverse = {}
                for canonical, synonyms in _syn_raw.items():
                    if canonical.startswith('_'):
                        continue
                    if isinstance(synonyms, list):
                        for s in synonyms:
                            _syn_reverse[s] = canonical
                # Build ref-specific map: {ref: {old_dial: new_dial}}
                _ref_syn = {}
                for ref_key, mapping in _syn_raw.get('_ref_specific', {}).items():
                    if ref_key.startswith('_'):
                        continue
                    if isinstance(mapping, dict):
                        _ref_syn[ref_key] = mapping
                _syn_count = 0
                _changes = set()
                for l in cleaned:
                    d = l.get('dial', '')
                    r = re.match(r'(\d+[A-Za-z]*)', l.get('ref', ''))
                    r = r.group(1) if r else ''
                    # Ref-specific first (higher priority)
                    if r in _ref_syn and d in _ref_syn[r]:
                        old = d
                        l['dial'] = _ref_syn[r][d]
                        _syn_count += 1
                        _changes.add(f'{r}:{old}→{l["dial"]}')
                    # Global synonyms
                    elif d in _syn_reverse:
                        old = d
                        l['dial'] = _syn_reverse[d]
                        _syn_count += 1
                        _changes.add(f'{old}→{l["dial"]}')
                if _syn_count:
                    print(f"🔀 Dial synonyms: normalized {_syn_count} listings ({', '.join(sorted(_changes))})")

            # Remove listings marked for drop (ambiguous dials)
            cleaned = [l for l in cleaned if not l.get('_drop')]
            if _consolidation_count:
                print(f"🎨 Dial/ref consolidation: {_consolidation_count} changes (G-suffix merge, index-type merge, color standardization)")

            # ── Dial validation: remove misparsed dials using dial map ──
            _dial_map_path = BASE_DIR / 'rolex_dial_map.json'
            if _dial_map_path.exists():
                with open(_dial_map_path) as _dmf:
                    _dial_map = json.load(_dmf)
                
                # Also count per-ref dial occurrences for unmapped refs
                _ref_dial_counts = defaultdict(lambda: defaultdict(int))
                for l in cleaned:
                    _r = l.get('ref', '')
                    _d = l.get('dial', '')
                    if _r and _d and _d != 'Unknown':
                        _ref_dial_counts[_r][_d] += 1
                
                _dial_cleaned = 0
                for l in cleaned:
                    _ref = l.get('ref', '')
                    _dial = l.get('dial', '')
                    if not _ref or not _dial or _dial == 'Unknown':
                        continue
                    
                    known = _dial_map.get(_ref, {})
                    if known:
                        # Ref is in dial map — validate against it, but allow dials with 2+ occurrences
                        if _dial not in known and _ref_dial_counts[_ref][_dial] < 2:
                            l['dial'] = 'Unknown'
                            _dial_cleaned += 1
                    else:
                        # Ref not in dial map — trust parser, only reject single-occurrence gibberish dials
                        # Common real dials (Black, White, Blue, etc.) always pass
                        _TRUSTED_DIALS = {'Black','White','Blue','Green','Grey','Silver','Champagne','Ice Blue','Pink','Red','MOP','Pavé','Rainbow','Salmon','Yellow','Aubergine','Mint','Tiffany','Olive','Wimbledon','Chocolate','Rhodium','Slate','Azzurro','Beige'}
                        _dial_base = _dial.split()[0] if _dial else ''
                        if _dial_base not in _TRUSTED_DIALS and _ref_dial_counts[_ref][_dial] < 2:
                            l['dial'] = 'Unknown'
                            _dial_cleaned += 1
                
                if _dial_cleaned:
                    print(f"🎯 Dial validation: reclassified {_dial_cleaned} misparsed/low-confidence dials to Unknown")

            # v5 deduplication: remove same-seller duplicate postings
            if V5_AVAILABLE:
                before_dedup = len(cleaned)
                cleaned = v5_dedupe(cleaned)
                dedup_removed = before_dedup - len(cleaned)
                if dedup_removed:
                    print(f"🔄 v5 dedup removed {dedup_removed} duplicate listings ({before_dedup} → {len(cleaned)})")

            # ── Inject phone numbers from seller_phone_map.json ──
            phone_map_file = BASE_DIR / 'seller_phone_map.json'
            if phone_map_file.exists():
                with open(phone_map_file) as pmf:
                    seller_phone_map = json.load(pmf)
                phone_injected = 0
                for l in cleaned:
                    if not l.get('phone'):
                        seller = l.get('seller', '')
                        if seller in seller_phone_map:
                            l['phone'] = seller_phone_map[seller]
                            phone_injected += 1
                if phone_injected:
                    print(f"📱 Injected phone numbers for {phone_injected} listings from seller_phone_map.json")

            # ── Live FX re-conversion ──
            # Re-convert all HKD prices using the latest FX rate so prices
            # don't drift based on when each listing was originally parsed.
            _fx_cache_path = BASE_DIR / 'fx_cache.json'
            _current_hkd_rate = 0.128  # fallback
            if _fx_cache_path.exists():
                try:
                    _fx_data = json.loads(_fx_cache_path.read_text())
                    _current_hkd_rate = _fx_data.get('rates', {}).get('HKD', 0.128)
                except Exception:
                    pass
            
            _fx_reconverted = 0
            for l in cleaned:
                if l.get('currency') == 'HKD' and l.get('price', 0) > 0:
                    new_usd = round(l['price'] * _current_hkd_rate, 2)
                    if l.get('price_usd', 0) != new_usd:
                        l['price_usd'] = new_usd
                        l['raw_usd'] = new_usd
                        _fx_reconverted += 1
            if _fx_reconverted:
                print(f"💱 Re-converted {_fx_reconverted} HKD listings at rate {_current_hkd_rate:.6f}")
            
            # ── Price normalization: W+C → Full Set, HK → +shipping ──
            # W+C that's new (recent card, "new" indicators) = BNIB, price +$250 to normalize to full set
            # HK pieces: add $150 estimated shipping to normalize for US comparison
            _norm_wc = 0
            _norm_hk = 0
            _norm_condition = 0
            for l in cleaned:
                src = (l.get('source_text', '') or '').lower()
                comp = l.get('completeness', '')
                cond = l.get('condition', '')
                region = l.get('region', '')
                price = l.get('price_usd', 0)
                
                # ALL W+C → normalize to Full Set label
                # Price adjustment already done by parse_v4 (raw_usd ≠ price_usd means already adjusted)
                if comp == 'W+C':
                    l['completeness'] = 'Full Set'
                    raw = l.get('raw_usd', price)
                    if abs(price - raw) < 1:
                        # Not yet adjusted — add markup
                        l['price_usd'] = price + 250
                        l['_price_normalized'] = True
                        l['_norm_reason'] = 'W+C +$250 → Full Set'
                    else:
                        # Already adjusted by parser
                        l['_norm_reason'] = 'W+C → Full Set (price already adjusted)'
                    _norm_wc += 1
                    # Recent W+C = BNIB
                    card_year = None
                    yr = l.get('year', '')
                    if '/' in str(yr):
                        try: card_year = int(str(yr).split('/')[1])
                        except: pass
                    elif str(yr).isdigit():
                        card_year = int(yr)
                    is_new_wc = bool(_re.search(r'\bnew\b|\bbnib\b|\bunworn\b|\bnever\s*worn\b|\bn\d{1,2}\b', src))
                    if (is_new_wc or (card_year and card_year >= 2025)) and cond != 'BNIB':
                        l['condition'] = 'BNIB'
                        _norm_condition += 1
                
                # HK pieces: add shipping estimate for US-comparable pricing
                if region == 'HK' and price > 0:
                    l['price_usd'] = l['price_usd'] + 150
                    l['_price_normalized'] = True
                    l['_norm_reason'] = (l.get('_norm_reason', '') + ' | HK +$150 ship').strip(' |')
                    _norm_hk += 1
            
            if _norm_wc or _norm_hk or _norm_condition:
                parts = []
                if _norm_wc: parts.append(f"{_norm_wc} W+C→BNIB +$250")
                if _norm_hk: parts.append(f"{_norm_hk} HK +$150 shipping")
                if _norm_condition: parts.append(f"{_norm_condition} condition upgrades")
                print(f"💰 Price normalization: {', '.join(parts)}")
            
            # Strip Indonesian WhatsApp export junk from source_text
            _junk_re = re.compile(r'\+?\s*label\s+gambar tidak disertakan|gambar tidak disertakan|\(file terlampir\)', re.I)
            for l in cleaned:
                if l.get('source_text'):
                    l['source_text'] = _junk_re.sub('', l['source_text']).strip()
            data_cache['listings'] = cleaned
            data_cache['fx_hkd_rate'] = _current_hkd_rate
            print(f"📊 Loaded {len(cleaned)} Rolex listings ({outliers_removed} outliers removed from {len(raw_listings)} raw)")
        
        # Load other brand listings (Cartier, Tudor, IWC, etc.)
        _other_brands_count = 0
        for _brand_file in ['cartier_listings.json', 'tudor_listings.json', 'iwc_listings.json']:
            _bf = BASE_DIR / _brand_file
            if _bf.exists():
                try:
                    with open(_bf, 'r', encoding='utf-8') as f:
                        _brand_listings = json.load(f)
                    # Canonicalize refs
                    if PARSE_V4_AVAILABLE:
                        for l in _brand_listings:
                            ref = l.get('ref', '')
                            if ref:
                                canon = canonicalize(ref)
                                if canon: l['ref'] = canon
                    data_cache['listings'].extend(_brand_listings)
                    _other_brands_count += len(_brand_listings)
                    print(f"📊 Loaded {len(_brand_listings)} listings from {_brand_file}")
                except Exception as e:
                    print(f"⚠️ Error loading {_brand_file}: {e}")
        if _other_brands_count:
            print(f"📊 Total listings: {len(data_cache['listings'])} (incl. {_other_brands_count} non-Rolex)")
        
        # Load wholesale data
        wholesale_file = BASE_DIR / 'rolex_wholesale.json'
        if wholesale_file.exists():
            with open(wholesale_file, 'r', encoding='utf-8') as f:
                data_cache['wholesale'] = json.load(f)
            print(f"📈 Loaded wholesale data for {len(data_cache['wholesale'])} refs")
        
        # Load inventory from SQLite (source of truth)
        try:
            from database import get_db
            _inv_db = get_db()
            _inv_rows = _inv_db.execute(
                'SELECT * FROM watches WHERE deleted = 0 ORDER BY id'
            ).fetchall()
            _inv_db.close()
            
            # Map SQLite columns to the format calculate_inventory_pnl expects
            inventory_items = []
            for r in _inv_rows:
                inventory_items.append({
                    'id': r['id'],
                    'description': r['description'] or '',
                    'paid': 'Yes' if r['paid_supplier'] else '',
                    'bought_from': r['bought_from'] or '',
                    'sold_to': r['sold_to'] or '',
                    'cost_price': r['cost_price'] if r['cost_price'] else '',
                    'sale_price': r['sale_price'] if r['sale_price'] else '',
                    'sold_price': r['sold_price'] if r['sold_price'] else '',
                    'at_store': 'Yes' if r['at_store'] else 'No',
                    'posted': 'Yes' if r['posted'] else '',
                    'arrived': 'Yes' if r['arrived'] else '',
                    'sold': 'Yes' if r['sold'] else '',
                    'shipped': 'Yes' if r['shipped'] else '',
                    'paid_after_sold': 'Yes' if r['paid_buyer'] else '',
                    'sale_date': r['sale_date'] or '',
                    'date_on_card': r['card_date'] or '',
                    'serial': r['serial'] or '',
                    'wt': 'Yes' if r['wt'] else '',
                    'bought_date': r['buy_date'] or '',
                    'profit': r['profit'] if r['profit'] else '',
                })
            data_cache['inventory'] = inventory_items
            print(f"💼 Loaded {len(inventory_items)} inventory items from SQLite")
        except Exception as e:
            print(f"⚠️ Error loading inventory from SQLite: {e}")
            # Fallback to sheet_updater dump
            try:
                result = subprocess.run([
                    'python3', str(WORKSPACE / 'sheet_updater.py'), 'dump'
                ], capture_output=True, text=True, cwd=str(WORKSPACE))
                if result.returncode == 0:
                    data_cache['inventory'] = json.loads(result.stdout)
                    print(f"💼 Loaded {len(data_cache['inventory'])} inventory items (Bot Sheet fallback)")
                else:
                    data_cache['inventory'] = []
            except:
                data_cache['inventory'] = []
        
        # Build seller reputation index
        from collections import Counter
        seller_counts = Counter(l.get('seller', '') for l in data_cache.get('listings', []))
        seller_groups = defaultdict(set)
        for l in data_cache.get('listings', []):
            seller_groups[l.get('seller', '')].add(l.get('group', ''))
        data_cache['seller_scores'] = {}
        for seller, count in seller_counts.items():
            if not seller:
                continue
            score = min(100, 30 + count * 2 + len(seller_groups[seller]) * 5)
            # Named sellers (not phone numbers) get a small boost
            if not any(c in seller for c in ['+', '(', '‑']):
                score = min(100, score + 5)
            data_cache['seller_scores'][seller] = score
        
        # Load Jeffin's trade history from Bot Sheet for margin intelligence
        try:
            import subprocess as _sp
            result = _sp.run(['python3', 'sheet_updater.py', 'dump'], 
                           capture_output=True, text=True, cwd=str(WORKSPACE))
            if result.returncode == 0:
                bot_sheet = json.loads(result.stdout)
                trade_history = {}  # ref -> { sold_count, avg_cost, avg_sold, avg_margin, last_sold }
                for row in bot_sheet:
                    desc = row.get('description', '')
                    ref = desc.split()[0] if desc else ''
                    sold_to = row.get('sold_to', '')
                    cost_raw = str(row.get('cost_price', ''))
                    sp_raw = str(row.get('sold_price', ''))
                    sale_date = row.get('sale_date', '')
                    try:
                        cost = float(cost_raw.replace(',','').replace('$','').strip())
                        sp = float(sp_raw.replace(',','').replace('$','').strip())
                    except Exception:
                        cost, sp = 0, 0
                    
                    if sold_to and cost > 0 and sp > 0:
                        if ref not in trade_history:
                            trade_history[ref] = {'costs': [], 'solds': [], 'margins': [], 'count': 0, 'last_sold': ''}
                        margin = (sp - cost) / cost * 100
                        trade_history[ref]['costs'].append(cost)
                        trade_history[ref]['solds'].append(sp)
                        trade_history[ref]['margins'].append(margin)
                        trade_history[ref]['count'] += 1
                        if sale_date:
                            trade_history[ref]['last_sold'] = sale_date
                
                # Compute averages
                for ref, th in trade_history.items():
                    th['avg_cost'] = sum(th['costs']) / len(th['costs'])
                    th['avg_sold'] = sum(th['solds']) / len(th['solds'])
                    th['avg_margin'] = sum(th['margins']) / len(th['margins'])
                    del th['costs'], th['solds'], th['margins']  # clean up lists
                
                data_cache['trade_history'] = trade_history
                
                # Also compute overall avg margin for refs Jeffin hasn't traded
                all_margins = [th['avg_margin'] for th in trade_history.values()]
                data_cache['jeffin_avg_margin'] = sum(all_margins) / len(all_margins) if all_margins else 8.0
                
                print(f"📈 Loaded trade history: {len(trade_history)} refs, avg margin {data_cache['jeffin_avg_margin']:.1f}%")
        except Exception as e:
            print(f"⚠️ Could not load trade history: {e}")
            data_cache['trade_history'] = {}
            data_cache['jeffin_avg_margin'] = 8.0
        
        # Generate stats
        data_cache['stats'] = generate_stats()
        data_cache['last_refresh'] = datetime.now()
        
        print("✅ Data cache refreshed successfully")
        
    except Exception as e:
        print(f"✕ Error loading data: {e}")

def generate_stats():
    """Generate dashboard statistics."""
    listings = data_cache['listings']
    
    active_refs = len(set(l.get('ref', '') for l in listings if l.get('ref')))
    
    # Data freshness: find newest and oldest timestamps
    from collections import Counter
    brands = Counter(l.get('brand', 'Rolex') for l in listings)
    conditions = Counter(l.get('condition', '') for l in listings)
    completeness = Counter(l.get('completeness', '') for l in listings)
    
    # FX rate info
    fx_rate = None
    fx_age_hrs = None
    fx_cache_path = BASE_DIR / 'fx_cache.json'
    if fx_cache_path.exists():
        try:
            fx_data = json.loads(fx_cache_path.read_text())
            fx_rate = fx_data.get('rates', {}).get('HKD')
            fetched = fx_data.get('fetched_at', '')
            if fetched:
                from datetime import datetime as _dt
                fx_age_hrs = round((datetime.now() - _dt.fromisoformat(fetched)).total_seconds() / 3600, 1)
        except Exception:
            pass

    return {
        'total_listings': len(listings),
        'active_refs': active_refs,
        'unique_refs': active_refs,
        'regions': dict(Counter(l.get('region', '?') for l in listings if l.get('region'))),
        'dealers': len(set(l.get('seller', '') for l in listings if l.get('seller'))),
        'us_listings': sum(1 for l in listings if l.get('region') == 'US'),
        'hk_listings': sum(1 for l in listings if l.get('region') == 'HK'),
        'bnib_count': conditions.get('BNIB', 0),
        'preowned_count': conditions.get('Pre-owned', 0),
        'brands': dict(brands),
        'full_set_count': completeness.get('Full Set', 0),
        'unknown_comp_count': completeness.get('Unknown', 0),
        'fx_hkd_usd': fx_rate,
        'fx_age_hrs': fx_age_hrs,
    }

