def search_listings(query):
    """Search listings by reference, nickname, or text."""
    query = query.lower().strip()
    
    # Check if it's a nickname
    if query in NICKNAME_MAP:
        query = NICKNAME_MAP[query].lower()
    
    # Split query into tokens for multi-word matching
    query_tokens = query.split()
    
    results = []
    for listing in data_cache['listings']:
        if listing.get('brand', '').lower() != 'rolex':
            continue
        
        ref = str(listing.get('ref', '')).lower()
        model = str(listing.get('model', '')).lower()
        dial = str(listing.get('dial', '')).lower()
        seller = str(listing.get('seller', '')).lower()
        condition = str(listing.get('condition', '')).lower()
        
        searchable_text = f"{ref} {model} {dial} {seller} {condition}"
        
        # Strategy 1: Exact ref match (highest priority)
        if query == ref or query.replace(' ', '') == ref:
            results.append(listing)
            continue
        
        # Strategy 2: Query is a substring of ref or ref is substring of query
        if len(query) >= 5 and (query in ref or ref in query):
            results.append(listing)
            continue
        
        # Strategy 3: All tokens must match (prevents "rm 67-01" matching "01" in random text)
        if len(query_tokens) > 1:
            if all(tok in searchable_text for tok in query_tokens):
                results.append(listing)
                continue
        
        # Strategy 4: Single token — must match ref or be a substantial match in model/dial
        if len(query_tokens) == 1:
            tok = query_tokens[0]
            # For numeric-looking queries (refs), only match against ref field
            if any(c.isdigit() for c in tok) and len(tok) >= 4:
                if tok in ref:
                    results.append(listing)
            else:
                # Text queries (dial colors, models) — match in text
                if tok in searchable_text:
                    results.append(listing)
    
    return results

def get_filter_options():
    """Get available filter values from current listings."""
    dials = set()
    bracelets = set()
    years = set()
    conditions = set()
    refs = set()
    for l in data_cache['listings']:
        if l.get('brand', '').lower() != 'rolex':
            continue
        if l.get('dial'): dials.add(l['dial'])
        if l.get('bracelet'): bracelets.add(l['bracelet'])
        if l.get('year'): years.add(str(l['year']))
        if l.get('condition'): conditions.add(l['condition'])
        if l.get('ref'): refs.add(l['ref'])
    return {
        'dials': sorted(dials),
        'bracelets': sorted(bracelets),
        'years': sorted(years, reverse=True),
        'conditions': sorted(conditions),
        'refs': sorted(refs)
    }

DIAL_ALIAS_MAP = {
    'azzuro': 'blue', 'azzurro': 'blue', 'tiffany': 'turquoise blue',
    'pistachio': 'green', 'candy pink': 'pink', 'rhodium': 'slate',
    'mop': 'mother of pearl',
    'casino green': 'money green', 'bright green': 'money green',
    'green ombre': 'green ombré', 'ombre': 'ombré',
    'polar': 'white', 'polar white': 'white',
}
# Build reverse map too
DIAL_ALIAS_REVERSE = {}
for _a, _c in DIAL_ALIAS_MAP.items():
    DIAL_ALIAS_REVERSE.setdefault(_c, []).append(_a)

def _dial_matches(query_dial, listing_dial):
    """Check if dial query matches listing dial, expanding aliases.
    
    Key rule: "Champagne Stick" ≠ "Champagne Diamond" ≠ "Champagne"
    - G suffix refs (e.g. 126233G) = Diamond markers, separate from Stick
    - Exact match always wins
    - Single-word query matches as prefix ONLY (e.g. "Champagne" matches all champagne variants)
    - Multi-word query requires exact match (e.g. "Champagne Stick" only matches "Champagne Stick")
    """
    ql = query_dial.lower().strip()
    ld = (listing_dial or '').lower().strip()
    
    # Exact match
    if ql == ld:
        return True
    
    # Check aliases (exact)
    canon = DIAL_ALIAS_MAP.get(ql)
    if canon and canon == ld:
        return True
    for alias in DIAL_ALIAS_REVERSE.get(ql, []):
        if alias == ld:
            return True
    
    # Multi-word query = specific, require exact match only
    if ' ' in ql:
        # Also check alias expansions for exact
        if canon and canon == ld:
            return True
        return False
    
    # Single-word query = broad, match as prefix
    # "Champagne" matches "Champagne Stick", "Champagne Diamond", etc.
    if ql in ld:
        return True
    if canon and canon in ld:
        return True
    for alias in DIAL_ALIAS_REVERSE.get(ql, []):
        if alias in ld:
            return True
    
    return False

def filter_listings(ref=None, dial=None, bracelet=None, year=None, condition=None, region=None):
    """Filter listings by multiple criteria."""
    results = []
    ref_canonical = None
    if ref:
        ref_lower = ref.lower().strip()
        if ref_lower in NICKNAME_MAP:
            ref_canonical = NICKNAME_MAP[ref_lower].lower()
        elif PARSE_V4_AVAILABLE:
            ref_canonical = canonicalize(ref).lower()
        else:
            ref_canonical = ref_lower

    for l in data_cache['listings']:
        if ref_canonical and l.get('ref', '').lower() != ref_canonical:
            continue
        if dial and not _dial_matches(dial, l.get('dial', '')):
            continue
        if bracelet and bracelet.lower() not in (l.get('bracelet') or '').lower():
            continue
        if year and str(l.get('year', '')) != str(year):
            continue
        if condition and condition.lower() not in (l.get('condition') or '').lower():
            continue
        if region and (l.get('region') or '').upper() != region.upper():
            continue
        results.append(l)
    return results

def get_price_summary(ref, dial=None, bracelet=None, year=None, condition=None):
    """Get pricing summary for a reference with optional filters."""
    ref_canonical = ref
    if ref:
        ref_lower = ref.lower().strip()
        if ref_lower in NICKNAME_MAP:
            ref_canonical = NICKNAME_MAP[ref_lower]
        elif PARSE_V4_AVAILABLE:
            ref_canonical = canonicalize(ref)

    ref_listings = filter_listings(ref=ref, dial=dial, bracelet=bracelet, year=year, condition=condition)
    
    if not ref_listings:
        return None
    
    # Separate by region
    us_listings = [l for l in ref_listings if l.get('region') == 'US' and l.get('price_usd')]
    hk_listings = [l for l in ref_listings if l.get('region') == 'HK' and l.get('price_usd')]
    us_prices = [l['price_usd'] for l in us_listings]
    hk_prices = [l['price_usd'] for l in hk_listings]
    all_prices = [l['price_usd'] for l in ref_listings if l.get('price_usd')]

    # Multiple pricing metrics
    all_b25 = avg_bottom_25(all_prices)
    us_b25 = avg_bottom_25(us_prices)
    hk_b25 = avg_bottom_25(hk_prices)
    all_avg2 = avg2_cheapest(all_prices)
    us_avg2 = avg2_cheapest(us_prices)
    hk_avg2 = avg2_cheapest(hk_prices)
    all_low = min(all_prices) if all_prices else None
    all_high = max(all_prices) if all_prices else None

    # Backward compat: also set *_median fields to the same b25 values
    all_median = all_b25
    us_median = us_b25
    hk_median = hk_b25

    # Use v5 weighted stats for fair value if available
    if V5_AVAILABLE:
        fv = v5_fair_value(ref_listings)
        all_ws = v5_weighted_stats(ref_listings)
        n_eff = all_ws.get('n_eff', len(ref_listings))
    else:
        fv = None
        n_eff = len(ref_listings)
    
    # Get cheapest 20 listings
    cheapest = sorted(ref_listings, key=lambda x: x.get('price_usd', float('inf')))[:20]
    
    spread = None
    if us_median and hk_median:
        spread = abs(us_median - hk_median) / min(us_median, hk_median) * 100

    # Collect unique dials/bracelets/conditions/years in these results
    result_dials = sorted(set(l.get('dial') or 'Unknown' for l in ref_listings))
    result_bracelets = sorted(set(l.get('bracelet') or 'Unknown' for l in ref_listings))
    result_conditions = sorted(set(l.get('condition') or 'Unknown' for l in ref_listings))
    
    result = {
        'ref': ref_canonical,
        'total_listings': len(ref_listings),
        'us_count': len(us_prices),
        'hk_count': len(hk_prices),
        'us_b25': us_b25,
        'hk_b25': hk_b25,
        'all_b25': all_b25,
        'b25': all_b25,
        'avg2': all_avg2,
        'us_avg2': us_avg2,
        'hk_avg2': hk_avg2,
        'low': all_low,
        # Backward compat
        'us_median': us_median,
        'hk_median': hk_median,
        'all_median': all_median,
        'median': all_median,
        'all_low': all_low,
        'all_high': all_high,
        'spread_pct': spread,
        'cheapest_listings': cheapest,
        'available_dials': result_dials,
        'available_bracelets': result_bracelets,
        'available_conditions': result_conditions,
        'n_eff': round(n_eff, 1),
    }

    # Condition breakdown (BNIB vs Pre-owned)
    by_condition = {}
    for cond_name in ['BNIB', 'Pre-owned']:
        c_listings = [l for l in ref_listings if l.get('condition') == cond_name and l.get('price_usd')]
        if not c_listings:
            continue
        c_prices = sorted([l['price_usd'] for l in c_listings])
        c_us = [l['price_usd'] for l in c_listings if l.get('region') == 'US']
        c_hk = [l['price_usd'] for l in c_listings if l.get('region') == 'HK']
        by_condition[cond_name] = {
            'count': len(c_listings),
            'low': round(min(c_prices)),
            'avg2': avg2_cheapest(c_prices),
            'b25': avg_bottom_25(c_prices),
            'high': round(max(c_prices)),
            'us_count': len(c_us), 'us_low': round(min(c_us)) if c_us else None, 'us_b25': avg_bottom_25(c_us),
            'hk_count': len(c_hk), 'hk_low': round(min(c_hk)) if c_hk else None, 'hk_b25': avg_bottom_25(c_hk),
        }
    if by_condition:
        result['by_condition'] = by_condition

    # Year-matched pricing (same year as query or detected from listings)
    def _extract_year_num(y):
        if not y: return None
        s = str(y)
        m = __import__('re').search(r'(\d{4})', s)
        return int(m.group(1)) if m else None

    query_year = _extract_year_num(year)
    if not query_year:
        # Try to detect most common recent year from listings
        from collections import Counter
        year_counts = Counter()
        for l in ref_listings:
            yn = _extract_year_num(l.get('year'))
            if yn and yn >= 2024:
                year_counts[yn] += 1
        if year_counts:
            query_year = year_counts.most_common(1)[0][0]

    if query_year:
        year_listings = [l for l in ref_listings if _extract_year_num(l.get('year')) == query_year and l.get('price_usd')]
        if year_listings:
            y_us = [l['price_usd'] for l in year_listings if l.get('region') == 'US']
            y_hk = [l['price_usd'] for l in year_listings if l.get('region') == 'HK']
            y_all = [l['price_usd'] for l in year_listings]
            result['by_year'] = {
                'year': query_year,
                'count': len(year_listings),
                'low': round(min(y_all)),
                'b25': avg_bottom_25(y_all),
                'us_count': len(y_us), 'us_low': round(min(y_us)) if y_us else None, 'us_b25': avg_bottom_25(y_us),
                'hk_count': len(y_hk), 'hk_low': round(min(y_hk)) if y_hk else None, 'hk_b25': avg_bottom_25(y_hk),
            }

    # Add fair value data if available
    if fv:
        result['fair_value'] = fv['fair_value']
        result['fair_value_confidence'] = fv['confidence']
        result['fair_value_cv'] = fv['cv']

    # Auto-include per-dial breakdown for multi-variant refs (or any ref with 2+ dials)
    if not dial and len(result_dials) >= 2:
        by_dial = {}
        for d_name in result_dials:
            if d_name == 'Unknown':
                continue
            d_listings = [l for l in ref_listings if (l.get('dial') or 'Unknown') == d_name and l.get('price_usd')]
            if not d_listings:
                continue
            d_prices = sorted([l['price_usd'] for l in d_listings])
            d_b25 = avg_bottom_25(d_prices)
            d_avg2 = avg2_cheapest(d_prices)
            by_dial[d_name] = {
                'count': len(d_listings),
                'low': round(min(d_prices)),
                'avg2': d_avg2,
                'b25': d_b25,
                'median': d_b25,  # backward compat
                'high': round(max(d_prices)),
                'us_count': sum(1 for l in d_listings if l.get('region') == 'US'),
                'hk_count': sum(1 for l in d_listings if l.get('region') == 'HK'),
            }
        if by_dial:
            result['by_dial'] = by_dial
            result['is_multi_variant'] = True

    return result

def _get_multi_variant_refs():
    """Identify refs where dial creates >50% price difference — must group by dial."""
    from collections import defaultdict
    from statistics import median as smed
    listings = data_cache.get('listings', [])
    by_ref_dial = defaultdict(list)
    for l in listings:
        if l.get('price_usd', 0) > 0 and l.get('dial'):
            by_ref_dial[(l['ref'], l['dial'])].append(l['price_usd'])
    
    by_ref = defaultdict(dict)
    for (ref, dial), prices in by_ref_dial.items():
        if len(prices) >= 2:
            by_ref[ref][dial] = smed(prices)
    
    multi_variant = set()
    for ref, dials in by_ref.items():
        if len(dials) >= 2:
            lo, hi = min(dials.values()), max(dials.values())
            if hi > lo * 1.15:  # >15% spread between dials = must group by dial
                multi_variant.add(ref)
    return multi_variant

def get_deals():
    """Find best deals — listings priced well below the next cheapest for same ref+condition+completeness."""
    from collections import defaultdict, Counter
    
    listings = data_cache.get('listings', [])
    if not listings:
        return []
    
    multi_variant_refs = _get_multi_variant_refs()
    
    # Build seller activity index (how many total listings per seller)
    seller_activity = Counter(l.get('seller', '') for l in listings)
    
    # Normalize condition into buckets
    def norm_cond(c):
        c = (c or '').strip().upper()
        if c in ('BNIB', 'NEW', 'BRAND NEW', 'UNWORN'):
            return 'BNIB'
        if c in ('LIKE NEW', 'MINT', 'EXCELLENT'):
            return 'Like New'
        if c in ('PRE-OWNED', 'PREOWNED', 'USED'):
            return 'Pre-owned'
        return 'Unknown'
    
    # Normalize completeness into buckets (critical for fair comparison)
    def norm_comp(c):
        c = (c or '').strip().upper()
        if c in ('FULL SET', 'COMPLETE'):
            return 'Full Set'
        if c in ('W+C', 'WATCH + CARD', 'WATCH AND CARD'):
            return 'W+C'
        if c in ('WATCH ONLY', 'WATCH'):
            return 'Watch Only'
        return 'Unknown'
    
    # Normalize year into era buckets — critical for BNIB pricing
    # A 2021 BNIB is NOT comparable to a 2026 BNIB
    def year_era(y, cond):
        """Group years into pricing eras. Only split for BNIB where year matters most."""
        if cond != 'BNIB':
            return None  # Pre-owned pricing cares less about card date
        y = str(y or '').strip()
        if not y:
            return None
        # Extract year from formats: "2021", "01/2026", "02/2026"
        if '/' in y:
            parts = y.split('/')
            yr = int(parts[-1]) if len(parts[-1]) == 4 else int(parts[0]) if len(parts[0]) == 4 else 0
        else:
            try:
                yr = int(y[:4])
            except Exception:
                return None
        if yr <= 0:
            return None
        current_year = datetime.now().year
        if yr >= current_year - 1:
            return 'current'  # 2025-2026: current production
        elif yr >= current_year - 3:
            return 'recent'   # 2023-2024: recent but not current
        else:
            return 'older'    # 2022 and older: stale BNIB
    
    # Detect refs where bracelet significantly affects price (e.g., GMT Oyster vs Jubilee)
    multi_bracelet_refs = set()
    by_ref_bracelet = defaultdict(lambda: defaultdict(list))
    for l in listings:
        ref = l.get('ref', '')
        brace = (l.get('bracelet', '') or '').strip()
        price = l.get('price_usd', 0)
        if ref and brace and price > 0:
            by_ref_bracelet[ref][brace].append(price)
    for ref, bracelets in by_ref_bracelet.items():
        if len(bracelets) >= 2:
            medians = {}
            for b, prices in bracelets.items():
                if len(prices) >= 2:
                    medians[b] = sorted(prices)[len(prices) // 2]
            if len(medians) >= 2:
                lo, hi = min(medians.values()), max(medians.values())
                if hi > lo * 1.03:  # >3% spread between bracelets = must group by bracelet
                    multi_bracelet_refs.add(ref)
    
    # Group by (ref, condition_bucket, completeness_bucket, dial?, bracelet?, year_era?) — apples to apples
    # For multi-variant refs (where dial changes price by >15%), include dial in the key
    # For multi-bracelet refs (Oyster vs Jubilee etc.), include bracelet in the key
    # ── Stale listing detection ──
    # Listings >14 days old are less reliable — exclude from deal detection
    # (they may already be sold, price may have changed)
    from datetime import datetime as _dt2, timedelta as _td
    now = _dt2.now()
    stale_cutoff = now - _td(days=14)
    
    def is_fresh(l):
        ts = l.get('ts', '')
        if not ts:
            return True  # No timestamp = assume fresh (conservative)
        try:
            # Format: DD/MM/YY HH.MM.SS
            dt = _dt2.strptime(ts, '%d/%m/%y %H.%M.%S')
            return dt >= stale_cutoff
        except Exception:
            return True
    
    fresh_listings = [l for l in listings if is_fresh(l)]
    stale_count = len(listings) - len(fresh_listings)
    
    # For BNIB, also split by year era (stale BNIB ≠ fresh BNIB)
    by_group = defaultdict(list)
    for l in fresh_listings:
        ref = l.get('ref', '')
        price = l.get('price_usd', 0)
        if not ref or not price or price <= 0 or price < 3000:
            continue
        cond = norm_cond(l.get('condition', ''))
        comp = norm_comp(l.get('completeness', ''))
        era = year_era(l.get('year', ''), cond)
        # ALWAYS group by dial — different dials are different products, period.
        # A Black dial Daytona and a Blue dial Daytona have completely different market values.
        dial_key = (l.get('dial', '') or '').strip() or None
        brace_key = (l.get('bracelet', '') or '').strip() if ref in multi_bracelet_refs else None
        by_group[(ref, cond, comp, dial_key, brace_key, era)].append(l)
    
    deals = []
    for (ref, cond, comp, dial_key, brace_key, era), items in by_group.items():
        # Unknown completeness needs more data to be meaningful (noisier)
        min_count = 5 if comp == 'Unknown' else 3
        if len(items) < min_count:
            continue
        
        sorted_items = sorted(items, key=lambda x: x['price_usd'])
        prices = [x['price_usd'] for x in sorted_items]
        
        # Use wholesale ref median as sanity anchor if available
        ws = data_cache.get('wholesale', {}).get(ref, {})
        ws_median = ws.get('median', 0)
        
        # ── Robust outlier removal using MAD (Median Absolute Deviation) ──
        # MAD is far more robust than mean/stdev for skewed luxury watch data
        from statistics import median as _smed
        group_median = _smed(prices)
        deviations = [abs(p - group_median) for p in prices]
        mad = _smed(deviations) if deviations else 0
        
        if mad > 0:
            # Modified Z-score: 0.6745 normalizes MAD to match stdev for normal distributions
            # Threshold scales with market depth: thinner markets = more lenient
            mad_threshold = 3.5 if len(prices) >= 8 else 4.0 if len(prices) >= 5 else 5.0
            clean_items = [x for x in sorted_items 
                          if abs(0.6745 * (x['price_usd'] - group_median) / mad) <= mad_threshold]
        elif ws_median > 0:
            clean_items = [x for x in sorted_items if ws_median * 0.4 <= x['price_usd'] <= ws_median * 2.5]
        else:
            # MAD=0 means all prices identical or near-identical — keep all
            clean_items = sorted_items[:]
        
        if len(clean_items) < 3:
            continue
        
        clean_prices = [x['price_usd'] for x in clean_items]
        lowest = clean_items[0]
        second = clean_prices[1]

        # Use avg_bottom_25 as primary benchmark
        median = avg_bottom_25(clean_prices) or clean_prices[len(clean_prices) // 2]
        
        # CRITICAL: Compare against SAME-REGION b25, not cross-region
        # Otherwise every HK listing looks like a "deal" vs US prices
        lowest_region = lowest.get('region', '')
        same_region_items = [x for x in clean_items if x.get('region', '') == lowest_region]
        if len(same_region_items) >= 3:
            same_region_prices = [x['price_usd'] for x in same_region_items]
            effective_median = avg_bottom_25(same_region_prices) or sorted(same_region_prices)[len(same_region_prices) // 2]
        else:
            effective_median = median
        
        saving_vs_second = second - lowest['price_usd']
        saving_vs_median = effective_median - lowest['price_usd']
        pct_vs_second = saving_vs_second / second * 100 if second > 0 else 0
        pct_vs_median = saving_vs_median / effective_median * 100 if effective_median > 0 else 0
        
        # ── HARD FILTERS (skip if fundamentally unreliable) ──
        
        # Skip Watch Only / naked watches — different market, unreliable comps
        if comp == 'Watch Only':
            continue
        
        # Skip Unknown completeness — can't compare what we don't know
        if comp == 'Unknown':
            continue
        
        # Sanity: lowest shouldn't be <50% of median (likely misparsed)
        if lowest['price_usd'] < median * 0.5:
            continue
        
        # Don't flag inferred-completeness listings as deals
        if lowest.get('completeness_inferred'):
            continue
        
        # ── Natural spread detection ──
        # A "deal" must beat the ref's natural bid-ask spread to be meaningful.
        # If a ref naturally varies 10%, a 4% discount is just noise.
        if len(clean_prices) >= 4:
            from statistics import stdev as _stdev
            try:
                cv = _stdev(clean_prices) / effective_median if effective_median > 0 else 0
                # Natural spread ≈ 2x coefficient of variation (captures ~95% of normal range)
                natural_spread_pct = cv * 200  # e.g., CV=0.05 → 10% natural spread
            except Exception:
                natural_spread_pct = 0
        else:
            natural_spread_pct = 0
        
        # Minimum gap thresholds — condition-dependent, but never less than half the natural spread
        # BNIB is standardized: 3% gap is already meaningful, $300+ saving matters
        # Pre-owned has more variance: need bigger gap to be a real deal
        base_gap_bnib = 3.0
        base_gap_ln = 4.0
        base_gap_po = 5.0
        
        # If natural spread is wide, require at least half of it as the discount
        spread_floor = natural_spread_pct * 0.5
        
        if cond == 'BNIB':
            min_gap = max(base_gap_bnib, spread_floor)
            if pct_vs_median < min_gap or saving_vs_median < 300:
                continue
        elif cond == 'Like New':
            min_gap = max(base_gap_ln, spread_floor)
            if pct_vs_median < min_gap or saving_vs_median < 400:
                continue
        else:  # Pre-owned
            min_gap = max(base_gap_po, spread_floor)
            if pct_vs_median < min_gap or saving_vs_median < 500:
                continue
        
        # Max plausible discount — beyond this, it's almost certainly bad data
        # BNIB is a commodity: >8% below median is very suspicious
        # Like New: some variance but >15% is implausible
        # Pre-owned: real variance exists, but >25% is extreme
        max_plausible_gap = 8 if cond == 'BNIB' else 15 if cond == 'Like New' else 25
        if pct_vs_median > max_plausible_gap:
            continue
        
        # Seller dominance: if one seller provides >50% of the comparison group,
        # the median is just that seller's pricing, not a real market signal
        from collections import Counter as _C2
        seller_counts = _C2(x.get('seller', '') for x in clean_items)
        top_seller, top_count = seller_counts.most_common(1)[0]
        if top_count > len(clean_items) * 0.5 and len(clean_items) < 8:
            if lowest.get('seller', '') == top_seller:
                continue  # Can't be a deal against your own pricing
        
        # Seller activity
        seller_total = seller_activity.get(lowest.get('seller', ''), 0)
        
        # Very low-activity sellers: 1 listing = no track record, skip
        if seller_total <= 1:
            continue
        
        # Low-activity sellers with big discounts = likely bad data
        if seller_total <= 3 and pct_vs_median > 15:
            continue
        
        # HK import friction: wire ($40) + shipping ($150) = $190 fixed
        hk_friction = 190 if lowest.get('region') == 'HK' else 0
        
        # ── UNIQUE SELLER CHECK ──
        # Need at least 2 DIFFERENT sellers besides the deal seller to form a reliable median
        other_sellers = set(x.get('seller', '') for x in clean_items if x.get('seller', '') != lowest.get('seller', ''))
        if len(other_sellers) < 2:
            continue  # Median based on just 1 other seller is not a market price
        
        # ── SAME-SELLER DUPLICATE CHECK ──
        # If the deal seller has MULTIPLE listings for this same ref in this group,
        # it's their pricing strategy — not a one-off opportunity
        deal_seller = lowest.get('seller', '')
        deal_seller_count_in_group = sum(1 for x in clean_items if x.get('seller', '') == deal_seller)
        if deal_seller_count_in_group >= 3:
            continue  # Seller has 3+ of same ref/cond/comp — this is just their market position
        
        # ── COMPLETENESS SANITY CHECK ──
        # A W+C "deal" is not a deal if Full Set listings exist at equal or lower prices
        # for the same ref+condition. Why buy incomplete when complete is cheaper?
        if comp == 'W+C':
            # Scan all groups for this ref + same condition but Full Set
            fs_prices = []
            for gk, gitems in by_group.items():
                if gk[0] == ref and gk[1] == cond and gk[2] == 'Full Set':
                    fs_prices.extend(x['price_usd'] for x in gitems)
            if fs_prices and min(fs_prices) <= lowest['price_usd'] * 1.05:
                continue  # Full Set available at ≤5% more — W+C deal is pointless
        
        # ── PRICE CLUSTERING ──
        # A real deal stands out from a tight cluster. If prices are scattered, the "deal" 
        # might just be normal variance.
        from statistics import stdev as _sd
        price_tightness = 0  # 0 = scattered, higher = tighter cluster above the deal
        if len(clean_prices) >= 4:
            try:
                # Remove the deal price and check how tight the remaining cluster is
                remaining = clean_prices[1:]  # everything except the lowest
                sd = _sd(remaining)
                remaining_median = remaining[len(remaining) // 2]
                cv = sd / remaining_median if remaining_median > 0 else 1  # coefficient of variation
                price_tightness = max(0, 1 - cv * 10)  # tight cluster (cv<0.05) → high score
            except Exception:
                pass
        
        # ── CONFIDENCE SCORING ──
        # Designed so 90+ = exceptional, 75-89 = solid, 60-74 = moderate, <60 = filtered out
        confidence = 30  # base
        
        # Market depth (more listings = more reliable median) — max +12
        if len(clean_items) >= 15: confidence += 12
        elif len(clean_items) >= 10: confidence += 10
        elif len(clean_items) >= 7: confidence += 8
        elif len(clean_items) >= 5: confidence += 5
        elif len(clean_items) >= 4: confidence += 3
        # 3 listings = base only
        
        # Gap confirmation: is 2nd cheapest also notably below median? — max +6
        if pct_vs_second > 5:
            confidence += 6
        elif pct_vs_second > 3:
            confidence += 3
        
        # Region — max +5
        if lowest.get('region') == 'US':
            confidence += 5  # US = immediately actionable
        elif lowest.get('region') == 'HK':
            confidence += 2  # HK = needs import but still viable
        
        # Completeness — max +5
        if comp == 'Full Set':
            confidence += 5
        elif comp == 'W+C':
            confidence += 2
        
        # Condition — max +3
        if cond == 'BNIB':
            confidence += 3
        elif cond == 'Like New':
            confidence += 1
        
        # Seller credibility — max +8, min -8
        seller_score = data_cache.get('seller_scores', {}).get(lowest.get('seller', ''), 40)
        if seller_total >= 15:
            confidence += 5
        elif seller_total >= 8:
            confidence += 3
        elif seller_total <= 2:
            confidence -= 8
        
        if seller_score >= 70:
            confidence += 3
        elif seller_score < 30:
            confidence -= 5
        
        # Unique sellers: more diverse market = more reliable — max +5
        if len(other_sellers) >= 6:
            confidence += 5
        elif len(other_sellers) >= 4:
            confidence += 3
        
        # Price clustering: tight cluster above = strong signal — max +6
        if price_tightness > 0.8:
            confidence += 6
        elif price_tightness > 0.6:
            confidence += 4
        elif price_tightness > 0.3:
            confidence += 2
        
        # Wholesale anchor validation
        if ws_median > 0:
            discount_vs_wholesale = (ws_median - lowest['price_usd']) / ws_median * 100
            if 0 < discount_vs_wholesale < 15:
                confidence += 5  # below wholesale = genuine opportunity
            elif discount_vs_wholesale > 20:
                confidence -= 10  # way below wholesale = suspicious data
            elif lowest['price_usd'] > ws_median * 1.15:
                confidence -= 5  # well above wholesale — "deal" is relative
        
        # Seller dominance penalty (not a hard filter, but reduces confidence)
        if top_count > len(clean_items) * 0.4:
            confidence -= 8  # one seller has outsized influence on the median
        
        # Extreme discount penalty (exponential suspicion)
        if pct_vs_median > 20:
            confidence -= 15
        elif pct_vs_median > 15:
            confidence -= 8
        elif pct_vs_median > 12 and cond in ('BNIB', 'Like New'):
            confidence -= 5  # new watches shouldn't vary this much
        
        confidence = max(0, min(100, confidence))
        
        # ── TRADE HISTORY INTELLIGENCE ──
        trade_hist = data_cache.get('trade_history', {}).get(ref, None)
        jeffin_avg = data_cache.get('jeffin_avg_margin', 8.0)
        
        deal_price = lowest['price_usd'] + hk_friction  # true cost including HK friction
        
        if trade_hist:
            # Jeffin has traded this ref before — use his actual data
            est_sell_price = round(trade_hist['avg_sold'])
            est_margin_pct = round((est_sell_price - deal_price) / deal_price * 100, 1)
            est_profit = round(est_sell_price - deal_price)
            traded_before = True
            times_traded = trade_hist['count']
            hist_avg_margin = round(trade_hist['avg_margin'], 1)
        else:
            # Never traded — estimate using median market price and Jeffin's avg margin
            est_sell_price = round(effective_median * 0.98)  # conservative: sell at 98% of median
            est_margin_pct = round((est_sell_price - deal_price) / deal_price * 100, 1)
            est_profit = round(est_sell_price - deal_price)
            traded_before = False
            times_traded = 0
            hist_avg_margin = 0
        
        # Skip negative margin deals — no point showing something that loses money
        if est_margin_pct < 0:
            continue
        
        # Deal quality tier based on confidence + margin + history
        if confidence >= 85 and est_margin_pct >= 5 and traded_before:
            tier = 'A'  # High confidence, good margin, known ref
        elif confidence >= 75 and est_margin_pct >= 3:
            tier = 'B'  # Good deal, actionable
        elif confidence >= 55 and est_margin_pct >= 1:
            tier = 'C'  # Marginal — worth watching
        else:
            continue  # Not worth showing
        
        # Build comparable listings for detail view (cap at 25)
        comp_listings = [{
            'price': round(x['price_usd']),
            'seller': x.get('seller', ''),
            'phone': x.get('phone', ''),
            'year': x.get('year', ''),
            'condition': x.get('condition', ''),
            'dial': x.get('dial', ''),
            'bracelet': x.get('bracelet', ''),
            'completeness': x.get('completeness', ''),
            'ts': x.get('ts', ''),
            'region': x.get('region', ''),
            'source_text': x.get('source_text', ''),
        } for x in clean_items[:25]]

        deals.append({
            **lowest,
            'discount_pct': round(pct_vs_median, 1),
            'gap_pct': round(pct_vs_second, 1),
            'second_cheapest': round(second),
            'avg_price': round(effective_median),
            'total_listings': len(clean_items),
            'unique_sellers': len(other_sellers) + 1,
            'condition_bucket': cond,
            'completeness_bucket': comp,
            'confidence': confidence,
            'saving_usd': round(saving_vs_median),
            'seller_listings': seller_total,
            'seller_reputation': seller_score,
            'hk_friction': round(hk_friction) if hk_friction else 0,
            'price_tightness': round(price_tightness, 2),
            'natural_spread_pct': round(natural_spread_pct, 1),
            # Trade intelligence
            'est_sell_price': est_sell_price,
            'est_profit': est_profit,
            'est_margin_pct': est_margin_pct,
            'traded_before': traded_before,
            'times_traded': times_traded,
            'hist_avg_margin': hist_avg_margin,
            'tier': tier,
            'true_cost': round(deal_price),
            'comparable_listings': comp_listings,
        })
    
    # ── HISTORY-BASED DEALS: DISABLED ──
    # Previously compared single listings to Jeffin's avg cost/sold across ALL
    # conditions/dials/bracelets for a ref — fundamentally misleading.
    # A pre-owned Oyster Green at $15K is NOT comparable to a BNIB Jubilee White at $18K
    # just because they share the same ref number.
    # Trade history is still used as a SIGNAL in market-based deals above (est_sell_price),
    # but not as the sole benchmark.
    
    # ── POST-FILTERS ──
    
    # Minimum confidence floor — below this, the "deal" is too unreliable
    deals = [d for d in deals if d.get('confidence', 0) >= 55]
    
    # Cap per seller (max 2) AND per ref (max 3 — keep best dials)
    from collections import Counter as _Counter
    seller_deal_count = _Counter()
    ref_deal_count = _Counter()
    filtered_deals = []
    for d in sorted(deals, key=lambda x: (-x.get('confidence', 0), -x.get('est_profit', 0))):
        seller = d.get('seller', '')
        ref = d.get('ref', '')
        seller_deal_count[seller] += 1
        ref_deal_count[ref] += 1
        if seller_deal_count[seller] <= 2 and ref_deal_count[ref] <= 3:
            filtered_deals.append(d)
    
    return filtered_deals[:30]

def get_arbitrage():
    """Find HK→US arbitrage: lowest HK vs lowest US, condition-matched."""
    from collections import defaultdict
    from datetime import datetime as _dt3, timedelta as _td3
    
    arb_ops = []
    all_listings = data_cache.get('listings', [])
    seller_scores = data_cache.get('seller_scores', {})
    
    if not all_listings:
        return []
    
    # Filter stale listings (>14 days old)
    stale_cutoff = _dt3.now() - _td3(days=14)
    def is_fresh(l):
        ts = l.get('ts', '')
        if not ts:
            return True
        try:
            return _dt3.strptime(ts, '%d/%m/%y %H.%M.%S') >= stale_cutoff
        except Exception:
            return True
    listings = [l for l in all_listings if is_fresh(l)]
    
    def norm_cond(c):
        c = (c or '').strip().upper()
        if c in ('BNIB', 'NEW', 'BRAND NEW', 'UNWORN'):
            return 'BNIB'
        if c in ('PRE-OWNED', 'PREOWNED', 'USED', 'MINT', 'EXCELLENT'):
            return 'Pre-owned'
        return 'Unknown'
    
    # Normalize completeness
    def norm_comp(c):
        c = (c or '').strip().upper()
        if c in ('FULL SET', 'COMPLETE'):
            return 'Full Set'
        if c in ('W+C', 'WATCH + CARD', 'WATCH AND CARD'):
            return 'W+C'
        if c in ('WATCH ONLY', 'WATCH'):
            return 'Watch Only'
        return 'Unknown'
    
    # Detect multi-bracelet refs (same logic as deals)
    multi_bracelet_refs = set()
    by_ref_bracelet = defaultdict(lambda: defaultdict(list))
    for l in listings:
        ref = l.get('ref', '')
        brace = (l.get('bracelet', '') or '').strip()
        price = l.get('price_usd', 0)
        if ref and brace and price > 0:
            by_ref_bracelet[ref][brace].append(price)
    for ref, bracelets in by_ref_bracelet.items():
        if len(bracelets) >= 2:
            medians = {}
            for b, prices in bracelets.items():
                if len(prices) >= 2:
                    medians[b] = sorted(prices)[len(prices) // 2]
            if len(medians) >= 2:
                lo, hi = min(medians.values()), max(medians.values())
                if hi > lo * 1.03:
                    multi_bracelet_refs.add(ref)

    # Group by (ref, condition, completeness, dial, bracelet?) per region — apples to apples
    by_combo = defaultdict(lambda: {'HK': [], 'US': []})
    
    for l in listings:
        ref = l.get('ref', '')
        region = l.get('region', '')
        price = l.get('price_usd', 0)
        
        if not ref or not price or price <= 0:
            continue
        if region == 'EU':
            region = 'US'
        if region not in ('HK', 'US'):
            continue
        
        cond = norm_cond(l.get('condition', ''))
        comp = norm_comp(l.get('completeness', ''))
        # ALWAYS group by dial — different dials are different products
        dial_key = (l.get('dial', '') or '').strip() or None
        brace_key = (l.get('bracelet', '') or '').strip() if ref in multi_bracelet_refs else None
        key = (ref, cond, comp, dial_key, brace_key)
        by_combo[key][region].append({
            'price': price,
            'condition': l.get('condition', ''),
            'seller': l.get('seller', ''),
            'phone': l.get('phone', ''),
            'year': l.get('year', ''),
            'ts': l.get('ts', ''),
            'model': l.get('model', ''),
            'brand': l.get('brand', 'Rolex')
        })
    
    for (ref, cond, comp, dial_key, brace_key), regions in by_combo.items():
        hk_items = regions['HK']
        us_items = regions['US']
        
        if not hk_items or not us_items:
            continue
        
        # Skip Watch Only — different market, unreliable comps (same as deals)
        if comp == 'Watch Only':
            continue
        
        # Require minimum market depth on BOTH sides for reliable signals
        # 1 listing on either side = no real price discovery, skip
        if len(hk_items) < 2 or len(us_items) < 2:
            continue
        
        # Unknown completeness excluded — mixes Full Set + Watch Only, inflated spreads
        if comp == 'Unknown':
            continue
        
        # MAD-based outlier removal per region (consistent with deals algorithm)
        from statistics import median as _arb_med
        def mad_clean(items_list):
            prices = [x['price'] for x in items_list]
            if len(prices) < 3:
                return items_list
            med = _arb_med(prices)
            deviations = [abs(p - med) for p in prices]
            mad = _arb_med(deviations) if deviations else 0
            if mad <= 0:
                return items_list
            threshold = 4.0 if len(prices) < 5 else 3.5
            return [x for x in items_list 
                    if abs(0.6745 * (x['price'] - med) / mad) <= threshold]
        
        hk_clean = mad_clean(hk_items) if len(hk_items) >= 3 else hk_items
        us_clean = mad_clean(us_items) if len(us_items) >= 3 else us_items
        
        if not hk_clean or not us_clean:
            continue
        
        hk_sorted = sorted(hk_clean, key=lambda x: x['price'])
        us_sorted = sorted(us_clean, key=lambda x: x['price'])
        
        hk_low = hk_sorted[0]['price']
        us_low = us_sorted[0]['price']
        
        if hk_low < 1000:
            continue
        
        # Import cost model:
        # - Wire transfer: $40
        # - Shipping: $200 base for watches under $50K, +$50 per $10K above $50K
        # - Box/full set: $200 (HK watches often don't include proper box)
        wire_fee = 40
        if hk_low < 50000:
            shipping = 200
        else:
            shipping = 200 + 50 * int((hk_low - 50000) / 10000 + 1)
        box_fee = 200
        import_fee = wire_fee + shipping + box_fee
        
        profit = us_low - hk_low - import_fee
        profit_pct = profit / hk_low * 100 if hk_low > 0 else 0
        
        # Regional benchmark: avg bottom 25% per region (more stable than single lowest)
        hk_b25_prices = [x['price'] for x in hk_sorted]
        us_b25_prices = [x['price'] for x in us_sorted]
        hk_avg2 = avg_bottom_25(hk_b25_prices) or hk_low
        us_avg2 = avg_bottom_25(us_b25_prices) or us_low
        realistic_profit = us_avg2 - hk_avg2 - import_fee
        realistic_pct = realistic_profit / hk_avg2 * 100 if hk_avg2 > 0 else 0
        
        # Use avg-2-cheapest profit % for filtering — more robust than best-case
        filter_pct = realistic_pct
        # Sanity caps — beyond these, data is almost certainly unreliable
        # Watch Only excluded, Unknown needs extra depth, named completeness capped at 20%
        max_pct = 15 if comp == 'Unknown' else 20
        if profit > 500 and 2 <= filter_pct <= max_pct:
            arb_ops.append({
                'ref': ref,
                'direction': 'hk_to_us',
                'condition': cond,
                'completeness': comp,
                'hk_price': round(hk_low),
                'us_price': round(us_low),
                'hk_avg2': round(hk_avg2),
                'us_avg2': round(us_avg2),
                'buy_price': round(hk_low),
                'sell_price': round(us_low),
                'buy_avg2': round(hk_avg2),
                'sell_avg2': round(us_avg2),
                'profit': round(profit),
                'profit_pct': round(profit_pct, 1),
                'realistic_profit': round(realistic_profit),
                'realistic_pct': round(realistic_pct, 1),
                'import_fee': import_fee,
                'hk_count': len(hk_clean),
                'us_count': len(us_clean),
                'dial': dial_key or '',
                'bracelet': brace_key or '',
                'model': hk_sorted[0].get('model', '') or us_sorted[0].get('model', ''),
                'brand': hk_sorted[0].get('brand', '') or us_sorted[0].get('brand', 'Rolex'),
                'year': hk_sorted[0].get('year', '') or us_sorted[0].get('year', ''),
                'hk_seller': hk_sorted[0].get('seller', 'Unknown'),
                'us_seller': us_sorted[0].get('seller', 'Unknown'),
                # All individual listings for detail view
                'hk_listings': [{'price': x['price'], 'seller': x.get('seller',''), 'phone': x.get('phone',''), 'year': x.get('year',''), 'condition': x.get('condition',''), 'ts': x.get('ts','')} for x in hk_sorted],
                'us_listings': [{'price': x['price'], 'seller': x.get('seller',''), 'phone': x.get('phone',''), 'year': x.get('year',''), 'condition': x.get('condition',''), 'ts': x.get('ts','')} for x in us_sorted],
                # Market depth & confidence
                'depth': 'thick' if (len(hk_clean) >= 3 and len(us_clean) >= 3) else 'medium' if (len(hk_clean) >= 2 or len(us_clean) >= 2) else 'thin',
                'arb_confidence': min(100, max(0,
                    35  # base
                    + min(15, len(hk_clean) * 3)  # HK depth (max 15)
                    + min(15, len(us_clean) * 3)  # US depth (max 15)
                    + (8 if comp == 'Full Set' else 3)  # completeness reliability
                    + (6 if len(us_sorted) >= 3 else 0)  # median-based sell price
                    + (5 if seller_scores.get(hk_sorted[0].get('seller', ''), 40) >= 60 else 0)  # reputable HK seller
                    + (5 if dial_key else -5)  # dial-matched = higher confidence
                    - (10 if realistic_pct > 15 else 0)  # suspiciously high margin
                    - (5 if realistic_pct > 10 else 0)  # moderate suspicion
                    - (8 if len(set(x.get('seller','') for x in hk_clean)) < 2 else 0)  # single HK seller
                    - (8 if len(set(x.get('seller','') for x in us_clean)) < 2 else 0)  # single US seller
                )),
                'import_fee_breakdown': {
                    'shipping': shipping, 'wire': wire_fee, 'box': box_fee
                }
            })
    
    # ── US→HK direction: buy cheap in US, sell higher in HK ──
    for (ref, cond, comp, dial_key, brace_key), regions in by_combo.items():
        hk_items = regions['HK']
        us_items = regions['US']
        
        if not hk_items or not us_items:
            continue
        if comp == 'Watch Only' or comp == 'Unknown':
            continue
        if len(hk_items) < 2 or len(us_items) < 2:
            continue
        
        hk_clean = mad_clean(hk_items) if len(hk_items) >= 3 else hk_items
        us_clean = mad_clean(us_items) if len(us_items) >= 3 else us_items
        
        if not hk_clean or not us_clean:
            continue
        
        hk_sorted = sorted(hk_clean, key=lambda x: x['price'])
        us_sorted = sorted(us_clean, key=lambda x: x['price'])
        
        us_low = us_sorted[0]['price']
        hk_low = hk_sorted[0]['price']
        
        if us_low < 1000:
            continue
        
        # Export cost model (US→HK): wire $40 + shipping (same tiers) but NO box fee
        wire_fee = 40
        if us_low < 50000:
            shipping = 200
        else:
            shipping = 200 + 50 * int((us_low - 50000) / 10000 + 1)
        export_fee = wire_fee + shipping
        
        # US→HK: buy at US price, sell at HK price (avg bottom 25%)
        us_avg2 = avg_bottom_25([x['price'] for x in us_sorted]) or us_low
        hk_avg2 = avg_bottom_25([x['price'] for x in hk_sorted]) or hk_low
        
        profit = hk_low - us_low - export_fee
        profit_pct = profit / us_low * 100 if us_low > 0 else 0
        realistic_profit = hk_avg2 - us_avg2 - export_fee
        realistic_pct = realistic_profit / us_avg2 * 100 if us_avg2 > 0 else 0
        
        filter_pct = realistic_pct
        max_pct = 20
        if profit > 500 and 2 <= filter_pct <= max_pct:
            arb_ops.append({
                'ref': ref,
                'direction': 'us_to_hk',
                'condition': cond,
                'completeness': comp,
                'hk_price': round(hk_low),
                'us_price': round(us_low),
                'hk_avg2': round(hk_avg2),
                'us_avg2': round(us_avg2),
                'buy_price': round(us_low),
                'sell_price': round(hk_low),
                'buy_avg2': round(us_avg2),
                'sell_avg2': round(hk_avg2),
                'profit': round(profit),
                'profit_pct': round(profit_pct, 1),
                'realistic_profit': round(realistic_profit),
                'realistic_pct': round(realistic_pct, 1),
                'import_fee': export_fee,
                'hk_count': len(hk_clean),
                'us_count': len(us_clean),
                'dial': dial_key or '',
                'bracelet': brace_key or '',
                'model': us_sorted[0].get('model', '') or hk_sorted[0].get('model', ''),
                'brand': us_sorted[0].get('brand', '') or hk_sorted[0].get('brand', 'Rolex'),
                'year': us_sorted[0].get('year', '') or hk_sorted[0].get('year', ''),
                'hk_seller': hk_sorted[0].get('seller', 'Unknown'),
                'us_seller': us_sorted[0].get('seller', 'Unknown'),
                'hk_listings': [{'price': x['price'], 'seller': x.get('seller',''), 'phone': x.get('phone',''), 'year': x.get('year',''), 'condition': x.get('condition',''), 'ts': x.get('ts','')} for x in hk_sorted],
                'us_listings': [{'price': x['price'], 'seller': x.get('seller',''), 'phone': x.get('phone',''), 'year': x.get('year',''), 'condition': x.get('condition',''), 'ts': x.get('ts','')} for x in us_sorted],
                'depth': 'thick' if (len(hk_clean) >= 3 and len(us_clean) >= 3) else 'medium',
                'arb_confidence': min(100, max(0,
                    35
                    + min(15, len(us_clean) * 3)
                    + min(15, len(hk_clean) * 3)
                    + (8 if comp == 'Full Set' else 3)
                    + (6 if len(hk_sorted) >= 3 else 0)
                    + (5 if seller_scores.get(us_sorted[0].get('seller', ''), 40) >= 60 else 0)
                    + (5 if dial_key else -5)
                    - (10 if realistic_pct > 15 else 0)
                    - (5 if realistic_pct > 10 else 0)
                    - (8 if len(set(x.get('seller','') for x in us_clean)) < 2 else 0)
                    - (8 if len(set(x.get('seller','') for x in hk_clean)) < 2 else 0)
                )),
                'import_fee_breakdown': {
                    'shipping': shipping, 'wire': wire_fee, 'box': 0
                }
            })
    
    return sorted(arb_ops, key=lambda x: x.get('realistic_profit', x['profit']), reverse=True)[:200]

def parse_cost(val):
    """Parse cost string like '$21,500.00' to float."""
    if not val:
        return 0
    if isinstance(val, (int, float)):
        return float(val)
    s = str(val).replace('$', '').replace(',', '').strip()
    try:
        return float(s)
    except Exception:
        return 0

import re
REF_PATTERN = re.compile(r'\b(\d{5,6}[A-Za-z]{0,6})\b')
# Patek/AP: 5811/1G, 5711/1A, 26238ST etc.
BRAND_REF_PATTERN = re.compile(r'\b(\d{4,5}/\d{1,2}[A-Za-z]{0,3})\b')
# AP: 5-digit + 2-letter suffix
AP_REF_PAT = re.compile(r'\b(\d{5}[A-Za-z]{2})\b')

def extract_ref_from_description(desc):
    """Extract watch ref from Bot Sheet description. Handles Rolex, Patek, AP formats."""
    if not desc:
        return None
    # Try Patek format first (5811/1G, 5711/1A)
    m = BRAND_REF_PATTERN.search(desc)
    if m:
        return m.group(1).upper()
    # Then Rolex/AP format
    m = REF_PATTERN.search(desc)
    if m:
        return m.group(1).upper()  # uppercase to normalize 126710blnr → 126710BLNR
    return None

def extract_dial_from_description(desc):
    """Extract dial info from description, including diamond/baguette variants."""
    if not desc:
        return None
    desc_lower = desc.lower()
    
    # Compound dials first (more specific → less specific)
    # Diamond dials: "Blue Diamond", "Grey Diamond", "Black Diamond", etc.
    compound_patterns = [
        ('blue diamond', 'Blue Diamond'), ('grey diamond', 'Grey Diamond'), ('gray diamond', 'Grey Diamond'),
        ('black diamond', 'Black Diamond'), ('green diamond', 'Green Diamond'), ('silver diamond', 'Silver Diamond'),
        ('white diamond', 'White Diamond'), ('pink diamond', 'Pink Diamond'), ('champagne diamond', 'Champagne Diamond'),
        ('mop diamond', 'MOP Diamond'), ('chocolate diamond', 'Chocolate Diamond'),
        # Baguette variants
        ('black baguette', 'Black Baguette'), ('blue baguette', 'Blue Baguette'),
        ('diamond baguette', 'Diamond Baguette'),
        # Roman/stick marker variants  
        ('silver stick', 'Silver Stick'), ('silver roman', 'Silver Roman'),
        ('grey stick', 'Grey Stick'), ('grey roman', 'Grey Roman'),
        ('blue stick', 'Blue Stick'), ('blue roman', 'Blue Roman'),
        ('black stick', 'Black Stick'), ('black roman', 'Black Roman'),
        ('white stick', 'White Stick'), ('white roman', 'White Roman'),
        ('pink stick', 'Pink Stick'), ('pink roman', 'Pink Roman'),
        ('green roman vi ix diamond', 'Green Roman VI IX Diamond'),
        ('silver roman vi ix diamond', 'Silver Roman VI IX Diamond'),
        ('purple roman', 'Purple Roman'), ('green roman', 'Green Roman'),
        ('rhodium stick', 'Rhodium Stick'), ('rhodium roman', 'Rhodium Roman'),
        # Ombré
        ('smoke ombre', 'Ombré Slate'), ('green ombre', 'Green Ombré'), ('ombre slate', 'Ombré Slate'),
        # Special
        ('ice blue', 'Ice Blue'), ('mint green', 'Mint Green'), ('tiffany blue', 'Tiffany Blue'),
        ('azzurro blue', 'Azzurro Blue'), ('polar white', 'Polar White'),
        ('casino green', 'Money Green'), ('money green', 'Money Green'),
        ('money casino green', 'Money Green'),
        ('smoke ombr', 'Ombré Slate'),
    ]
    for pattern, dial_name in compound_patterns:
        if pattern in desc_lower:
            return dial_name
    
    # Simple dials
    # Fix common typos
    desc_lower = desc_lower.replace('wimbeldon', 'wimbledon')
    
    simple_dials = [
        'wimbledon', 'meteorite', 'champagne', 'pistachio', 'lavender', 'aubergine',
        'sundust', 'chocolate', 'rhodium', 'pavé', 'pave', 'tiffany', 'azzuro',
        'beige', 'slate', 'olive', 'mop', 'black', 'white', 'blue', 'green', 
        'silver', 'grey', 'gray', 'pink', 'red', 'brown', 'purple', 'coral', 'orange'
    ]
    dial_remap = {
        'Gray': 'Grey', 'Pave': 'Pavé', 'Tiffany': 'Tiffany Blue', 
        'Azzuro': 'Azzurro Blue', 'Slate': 'Grey',
    }
    for d in simple_dials:
        if d in desc_lower:
            result = d.title()
            for old, new in dial_remap.items():
                result = result.replace(old, new)
            return result
    return None

def extract_bracelet_from_description(desc):
    """Extract bracelet from description."""
    if not desc:
        return None
    desc_lower = desc.lower()
    for b in ['jubilee', 'oysterflex', 'oyster', 'president', 'leather']:
        if b in desc_lower:
            return b.title()
    return None

def calculate_inventory_pnl():
    """Calculate P&L for inventory items — shows ALL unsold watches."""
    inventory_pnl = []
    
    for item in data_cache['inventory']:
        # Only unsold watches
        if item.get('sold') == 'Yes':
            continue
            
        description = item.get('description', '')
        ref = extract_ref_from_description(description)
        
        cost_price = parse_cost(item.get('cost_price'))
        if not cost_price:
            continue
        
        dial = extract_dial_from_description(description)
        bracelet = extract_bracelet_from_description(description)
        
        # Get current market value — cascade from most specific to broadest
        # For BNIB inventory, use actual median (not b25) for fair portfolio valuation
        # b25 is a deal-finding metric; median better represents true market value
        market_value = None
        price_data = None
        benchmark = ''  # describes how market_value was derived
        comparable_count = 0
        
        def _portfolio_value(listings_data, prefer_us=True):
            """Compute fair market value for portfolio using actual median of filtered listings."""
            from statistics import median as smedian
            if not listings_data:
                return None, 0
            # Prefer US listings for US-based portfolio
            us = [l['price_usd'] for l in listings_data if l.get('region') == 'US' and l.get('price_usd')]
            all_p = [l['price_usd'] for l in listings_data if l.get('price_usd')]
            if prefer_us and len(us) >= 2:
                return round(smedian(us)), len(us)
            if all_p:
                return round(smedian(all_p)), len(all_p)
            return None, 0
        
        if ref:
            # 1. Exact: ref + dial + bracelet + BNIB
            if dial and bracelet:
                fl = filter_listings(ref=ref, dial=dial, bracelet=bracelet, condition='BNIB')
                if len(fl) >= 3:
                    market_value, comparable_count = _portfolio_value(fl)
                    if market_value:
                        benchmark = f'{dial} {bracelet} BNIB ({comparable_count})'
            # 2. ref + dial + BNIB
            if not market_value and dial:
                fl = filter_listings(ref=ref, dial=dial, condition='BNIB')
                if len(fl) >= 2:
                    market_value, comparable_count = _portfolio_value(fl)
                    if market_value:
                        benchmark = f'{dial} BNIB ({comparable_count})'
            # 3. Fuzzy dial match (any condition) — e.g. "MOP Diamond" matches "MOP" listings
            #    BEFORE bracelet-only fallback to avoid losing dial-specific pricing
            #    Strategy: prefer substring containment over word overlap to avoid
            #    "MOP Diamond" matching "Silver Diamond" via shared "Diamond" word
            #    Also includes ref variant matching (278274 matches 278274NG, 278274G, etc.)
            if not market_value and dial:
                all_ref = filter_listings(ref=ref)
                # Also include variant refs (e.g. 278274NG for 278274)
                import re
                base_ref = re.sub(r'[A-Z]+$', '', ref) if ref else ref
                if base_ref and base_ref != ref:
                    all_ref = all_ref + filter_listings(ref=base_ref)
                # Also find listings where their ref's base matches our ref
                if base_ref == ref:  # our ref has no suffix, look for suffixed variants
                    for l in data_cache.get('listings', []):
                        lr = l.get('ref', '')
                        lr_base = re.sub(r'[A-Z]+$', '', lr)
                        if lr_base == ref and lr != ref and l not in all_ref:
                            all_ref.append(l)
                dial_lower = dial.lower()
                dial_words = dial_lower.split()
                first_word = dial_words[0] if dial_words else ''
                # Priority 1: first word match (primary material/color identifier)
                # e.g. "MOP Diamond" → first word "MOP" matches "MOP" listings
                # This avoids "Diamond" matching "Silver Diamond" etc.
                if first_word and len(first_word) >= 2:
                    partial = [l for l in all_ref if l.get('dial') and l['dial'].lower().startswith(first_word)]
                else:
                    partial = []
                # Priority 2: exact substring containment (only if first word didn't work)
                if len(partial) < 2:
                    partial = [l for l in all_ref if l.get('dial') and (
                        l['dial'].lower() in dial_lower or
                        dial_lower in l['dial'].lower()
                    )]
                if len(partial) >= 2:
                    market_value, comparable_count = _portfolio_value(partial)
                    if market_value:
                        benchmark = f'{dial} ~match ({comparable_count})'
            # 3b. ref + dial exact (any condition)
            if not market_value and dial:
                fl = filter_listings(ref=ref, dial=dial)
                if fl:
                    market_value, comparable_count = _portfolio_value(fl)
                    if market_value:
                        benchmark = f'{dial} all ({comparable_count})'
            # 4. ref + bracelet + BNIB
            if not market_value and bracelet:
                fl = filter_listings(ref=ref, bracelet=bracelet, condition='BNIB')
                if len(fl) >= 2:
                    market_value, comparable_count = _portfolio_value(fl)
                    if market_value:
                        benchmark = f'{bracelet} BNIB ({comparable_count})'
            # 5. ref + dial exact (any condition) — kept as final dial attempt
            if not market_value and dial:
                fl = filter_listings(ref=ref, dial=dial)
                if fl:
                    market_value, comparable_count = _portfolio_value(fl)
                    if market_value:
                        benchmark = f'{dial} all ({comparable_count})'
            # 6. ref + BNIB (any dial/bracelet) — generic fallback
            if not market_value:
                fl = filter_listings(ref=ref, condition='BNIB')
                if len(fl) >= 2:
                    market_value, comparable_count = _portfolio_value(fl)
                    if market_value:
                        benchmark = f'BNIB ({comparable_count})'
            # 7. ref only (broadest)
            if not market_value:
                fl = filter_listings(ref=ref)
                if fl:
                    market_value, comparable_count = _portfolio_value(fl)
                    if market_value:
                        benchmark = f'all ({comparable_count})'
        
        profit_loss = (market_value - cost_price) if market_value else None
        profit_pct = (profit_loss / cost_price * 100) if (profit_loss is not None and cost_price) else None
        
        # Pricing confidence based on comparable count
        price_confidence = 'high' if comparable_count >= 5 else 'medium' if comparable_count >= 2 else 'low' if comparable_count >= 1 else 'none'
        
        # Calculate days held
        days_held = 0
        bought_date = item.get('bought_date', '')
        if bought_date:
            for fmt in ['%m/%d/%Y', '%d %B %Y', '%Y-%m-%d', '%d/%m/%Y']:
                try:
                    bought_dt = datetime.strptime(bought_date.strip(), fmt)
                    days_held = (datetime.now() - bought_dt).days
                    break
                except Exception:
                    continue
        
        # Status flags from Bot Sheet
        arrived = item.get('arrived') == 'Yes'
        shipped = item.get('shipped') == 'Yes'
        posted = item.get('posted') == 'Yes'
        at_store = item.get('at_store') == 'Yes'
        
        status = 'profit' if (profit_loss and profit_loss > 0) else 'loss' if (profit_loss and profit_loss < 0) else 'unknown'
        
        # --- HK/US Regional Wholesale Pricing (B25, cheapest 2, lowest) ---
        hk_wholesale = None  # B25
        us_wholesale = None  # B25
        hk_cheapest2 = None
        us_cheapest2 = None
        hk_lowest = None
        us_lowest = None
        hk_count = 0
        us_count = 0
        if ref:
            def _b25(prices):
                """Bottom 25th percentile (pure Python)."""
                if not prices:
                    return None
                n = len(prices)
                if n == 1:
                    return prices[0]
                idx = (n - 1) * 0.25
                lo = int(idx)
                hi = lo + 1
                if hi >= n:
                    return prices[lo]
                return prices[lo] + (prices[hi] - prices[lo]) * (idx - lo)
            
            # Get HK listings for this ref — ALWAYS dial-specific, never fall back to all dials
            hk_all = filter_listings(ref=ref, region='HK')
            if dial:
                hk_dial = [l for l in hk_all if _dial_matches(dial, l.get('dial', ''))]
                hk_use = hk_dial if hk_dial else []
            else:
                hk_use = hk_all
            hk_prices = sorted([l['price_usd'] for l in hk_use if l.get('price_usd')])
            if hk_prices:
                hk_wholesale = round(_b25(hk_prices))  # B25
                hk_cheapest2 = round(sum(hk_prices[:2]) / min(2, len(hk_prices)))  # avg of cheapest 2
                hk_lowest = round(hk_prices[0])
                hk_count = len(hk_prices)
            
            # Get US listings for this ref — ALWAYS dial-specific, never fall back to all dials
            us_all = filter_listings(ref=ref, region='US')
            if dial:
                us_dial = [l for l in us_all if _dial_matches(dial, l.get('dial', ''))]
                us_use = us_dial if us_dial else []
            else:
                us_use = us_all
            us_prices = sorted([l['price_usd'] for l in us_use if l.get('price_usd')])
            if us_prices:
                us_wholesale = round(_b25(us_prices))  # B25
                us_cheapest2 = round(sum(us_prices[:2]) / min(2, len(us_prices)))  # avg of cheapest 2
                us_lowest = round(us_prices[0])
                us_count = len(us_prices)
        
        inventory_pnl.append({
            'row': item.get('row'),
            'description': description,
            'ref': ref or '?',
            'dial': dial,
            'bracelet': bracelet,
            'cost_price': cost_price,
            'market_value': market_value,
            'profit_loss': profit_loss,
            'profit_pct': profit_pct,
            'days_held': days_held,
            'arrived': arrived,
            'shipped': shipped,
            'posted': posted,
            'at_store': at_store,
            'sold_to': item.get('sold_to', ''),
            'bought_from': item.get('bought_from', ''),
            'serial': item.get('serial', ''),
            'card_date': item.get('card_date', ''),
            'buy_date': item.get('buy_date', ''),
            'sale_price': item.get('sale_price', ''),
            'sold_price': item.get('sold_price', ''),
            'sale_date': item.get('sale_date', ''),
            'wt': item.get('wt', ''),
            'paid': item.get('paid_after_sold', ''),
            'status': status,
            'benchmark': benchmark,
            'price_confidence': price_confidence,
            'comparable_count': comparable_count,
            'hk_wholesale': hk_wholesale,
            'us_wholesale': us_wholesale,
            'hk_cheapest2': hk_cheapest2,
            'us_cheapest2': us_cheapest2,
            'hk_lowest': hk_lowest,
            'us_lowest': us_lowest,
            'hk_count': hk_count,
            'us_count': us_count,
        })
    
    return sorted(inventory_pnl, key=lambda x: (x['profit_pct'] is None, -(x['profit_pct'] or 0)))

