_market_ticker_cache = {'data': None, 'ts': 0}

@app.route('/api/market_ticker')
def api_market_ticker():
    """Real-time market data for ticker bar: S&P, NASDAQ, Gold, Oil, BTC, etc."""
    import time as _time
    now = _time.time()
    # Cache for 5 minutes (markets don't need second-level updates here)
    if _market_ticker_cache['data'] and now - _market_ticker_cache['ts'] < 300:
        return jsonify(_market_ticker_cache['data'])

    import urllib.request as _ureq

    TICKERS = [
        ('SPY', 'S&P 500', '$'),
        ('QQQ', 'NASDAQ', '$'),
        ('GC=F', 'Gold', '$'),
        ('SI=F', 'Silver', '$'),
        ('CL=F', 'Oil WTI', '$'),
        ('BTC-USD', 'Bitcoin', '$'),
        ('DX-Y.NYB', 'USD Index', ''),
        ('HKD=X', 'HKD/USD', ''),
        ('^VIX', 'VIX', ''),
        ('^TNX', '10Y Yield', ''),
    ]

    results = []
    for sym, label, prefix in TICKERS:
        try:
            url = f"https://query1.finance.yahoo.com/v8/finance/chart/{sym}?interval=1d&range=2d"
            req = _ureq.Request(url, headers={'User-Agent': 'Mozilla/5.0'})
            resp = _ureq.urlopen(req, timeout=4)
            data = json.loads(resp.read())
            meta = data['chart']['result'][0]['meta']
            price = meta.get('regularMarketPrice', 0)
            prev = meta.get('chartPreviousClose', price)
            chg = ((price - prev) / prev * 100) if prev else 0
            results.append({
                'symbol': sym, 'label': label, 'price': round(price, 2),
                'change_pct': round(chg, 2), 'prefix': prefix,
                'market_state': meta.get('marketState', 'REGULAR'),
            })
        except Exception:
            pass  # Skip failed tickers

    if results:
        _market_ticker_cache['data'] = results
        _market_ticker_cache['ts'] = now

    return jsonify(results)

