@app.route('/api/monthly_performance')
@login_required
def api_monthly_performance():
    """Monthly performance — reads from SQLite (single source of truth)."""
    try:
        from collections import defaultdict
        import re as _re

        _MONTHS_MAP = {'january':'01','february':'02','march':'03','april':'04','may':'05','june':'06',
                       'july':'07','august':'08','september':'09','october':'10','november':'11','december':'12'}

        def _parse_date(s):
            if not s: return None
            s = str(s).strip()
            m = _re.match(r'(\d{4})-(\d{2})-(\d{2})', s)
            if m: return (int(m.group(1)), int(m.group(2)), int(m.group(3)))
            m = _re.match(r'(\d{1,2})\s+(\w+)\s+(\d{4})', s)
            if m:
                mn = _MONTHS_MAP.get(m.group(2).lower())
                if mn: return (int(m.group(3)), int(mn), int(m.group(1)))
            m = _re.match(r'(\w+)\s+(\d{1,2}),?\s+(\d{4})', s)
            if m:
                mn = _MONTHS_MAP.get(m.group(1).lower())
                if mn: return (int(m.group(3)), int(mn), int(m.group(2)))
            m = _re.match(r'(\d{1,2})/(\d{1,2})/(\d{4})', s)
            if m: return (int(m.group(3)), int(m.group(1)), int(m.group(2)))
            return None

        def _date_to_month(d):
            if not d: return None
            return f"{d[0]}-{d[1]:02d}"

        db = get_db()
        sold_watches = db.execute('''
            SELECT id, description, cost_price, sold_price, sold_to, sale_date, 
                   shipped, paid_buyer, buy_date
            FROM watches WHERE sold = 1 AND deleted = 0
        ''').fetchall()

        monthly = defaultdict(lambda: {'pieces': 0, 'revenue': 0, 'cost': 0, 'profit': 0, 'deals': []})
        for w in sold_watches:
            sold_to = (w['sold_to'] or '').strip()
            if not sold_to:
                continue

            sale_d = _parse_date(w['sale_date'])
            buy_d = _parse_date(w['buy_date'])

            # Use sale_date as primary month indicator, fallback to buy_date
            dates = [d for d in (sale_d, buy_d) if d]
            if not dates:
                # Check audit log for sold timestamp
                audit = db.execute("SELECT timestamp FROM audit_log WHERE watch_id=? AND field='sold' AND new_value='1' ORDER BY timestamp DESC LIMIT 1", (w['id'],)).fetchone()
                if audit:
                    audit_d = _parse_date(audit['timestamp'][:10])
                    if audit_d:
                        dates = [audit_d]
            if not dates:
                continue

            mo = _date_to_month(sale_d) if sale_d else _date_to_month(max(dates))
            if not mo:
                continue
            if mo == '2026-01':
                mo = '2026-02'

            cost = float(w['cost_price'] or 0)
            sold = float(w['sold_price'] or 0)
            profit = sold - cost if (sold and cost) else 0

            # Extract ref from description
            ref_m = _re.match(r'(?:Pre-Owned )?(\d{5,6}[A-Za-z]*)', w['description'] or '')
            ref = ref_m.group(1) if ref_m else ''

            monthly[mo]['pieces'] += 1
            monthly[mo]['revenue'] += sold
            monthly[mo]['cost'] += cost
            monthly[mo]['profit'] += profit
            monthly[mo]['deals'].append({
                'id': w['id'],
                'ref': ref,
                'description': (w['description'] or '')[:40],
                'buyer': sold_to,
                'cost': cost,
                'sold': sold,
                'profit': profit,
                'shipped': bool(w['shipped']),
                'paid': bool(w['paid_buyer']),
            })

        result = []
        for mo in sorted(monthly.keys(), reverse=True):
            m = monthly[mo]
            margin = round(m['profit'] / m['revenue'] * 100, 1) if m['revenue'] else 0
            result.append({
                'month': mo,
                'pieces': m['pieces'],
                'revenue': round(m['revenue']),
                'cost': round(m['cost']),
                'profit': round(m['profit']),
                'margin': margin,
                'deals': sorted(m['deals'], key=lambda x: x['profit'], reverse=True),
            })

        total_pcs = sum(m['pieces'] for m in result)
        total_rev = sum(m['revenue'] for m in result)
        total_cost = sum(m['cost'] for m in result)
        total_profit = sum(m['profit'] for m in result)
        total_margin = round(total_profit / total_rev * 100, 1) if total_rev else 0

        # Analytics
        ref_stats = defaultdict(lambda: {'count': 0, 'total_profit': 0, 'total_cost': 0, 'total_revenue': 0})
        all_deals = []
        for mo_data in monthly.values():
            for d in mo_data['deals']:
                base_ref = _re.match(r'(\d{5,6})', d.get('ref', '') or d.get('description', ''))
                if base_ref:
                    r = base_ref.group(1)
                    ref_stats[r]['count'] += 1
                    ref_stats[r]['total_profit'] += d['profit']
                    ref_stats[r]['total_cost'] += d['cost']
                    ref_stats[r]['total_revenue'] += d['sold']
                all_deals.append(d)

        top_refs = []
        for r, s in sorted(ref_stats.items(), key=lambda x: x[1]['count'], reverse=True):
            margin = round(s['total_profit'] / s['total_revenue'] * 100, 1) if s['total_revenue'] else 0
            avg_profit = round(s['total_profit'] / s['count']) if s['count'] else 0
            top_refs.append({'ref': r, 'count': s['count'], 'total_profit': round(s['total_profit']),
                           'avg_profit': avg_profit, 'margin': margin})

        best_deals = sorted(all_deals, key=lambda x: x['profit'], reverse=True)[:5]
        worst_deals = sorted(all_deals, key=lambda x: x['profit'])[:5]

        # Capital analysis from SQLite
        unsold = db.execute('SELECT description, cost_price, sale_price FROM watches WHERE sold=0 AND deleted=0 AND cost_price > 1').fetchall()
        unsold_cost = sum(float(u['cost_price'] or 0) for u in unsold)
        unsold_count = len(unsold)
        potential_profit = sum(float(u['sale_price'] or 0) - float(u['cost_price'] or 0) for u in unsold if u['sale_price'] and float(u['sale_price'] or 0) > 0)

        avg_monthly_rev = total_rev / max(len(result), 1)
        capital_turnover = round(avg_monthly_rev / unsold_cost, 2) if unsold_cost else 0

        return jsonify({
            'months': result,
            'totals': {'pieces': total_pcs, 'revenue': total_rev, 'cost': total_cost, 'profit': total_profit, 'margin': total_margin},
            'analytics': {
                'top_refs': top_refs[:10],
                'best_deals': best_deals,
                'worst_deals': worst_deals,
                'capital': {
                    'tied_up': round(unsold_cost),
                    'unsold_count': unsold_count,
                    'potential_profit': round(potential_profit),
                    'turnover_ratio': capital_turnover,
                    'avg_monthly_revenue': round(avg_monthly_rev),
                },
            }
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500

