@app.route('/api/ref_info/<ref>')
@login_required
def api_ref_info(ref):
    """Get official reference info: dial variants, materials, retail price."""
    try:
        ref = ref.strip().upper()
        info = {'ref': ref, 'brand': None, 'model': None, 'dials': [], 'retail': None}
        
        # Check AP
        if PARSE_V4_AVAILABLE and ref in AP_REFS_DB:
            db = AP_REFS_DB[ref]
            info['brand'] = 'Audemars Piguet'
            info['model'] = db.get('model', '')
            info['family'] = db.get('family', '')
            info['retail'] = db.get('retail')
            info['case_mm'] = db.get('case_mm')
            info['dials'] = db.get('dials', [])
            if ref in AP_SUFFIX_DIALS:
                info['suffix_map'] = AP_SUFFIX_DIALS[ref]
        
        # Check Patek
        if PARSE_V4_AVAILABLE:
            for pk_ref, db in PATEK_REFS_DB.items():
                if ref.startswith(pk_ref.replace('/', '')):
                    info['brand'] = 'Patek Philippe'
                    info['model'] = db.get('model', '')
                    info['family'] = db.get('family', '')
                    info['retail'] = db.get('retail')
                    info['case_mm'] = db.get('case_mm')
                    info['dials'] = db.get('dials', [])
                    break
        
        # Check Patek catalog for more detailed variants
        catalog_path = Path(__file__).parent / 'patek_dial_catalog.json'
        if catalog_path.exists():
            patek_cat = json.loads(catalog_path.read_text())
            model_key = ref[:4] if len(ref) >= 4 else ref
            if model_key in patek_cat:
                info['variants'] = patek_cat[model_key]
        
        # Add listing stats from current data
        all_listings = data_cache.get('listings', [])
        if all_listings:
            ref_listings = [l for l in all_listings if l.get('ref', '').upper() == ref]
            if ref_listings:
                from collections import Counter
                info['listing_count'] = len(ref_listings)
                info['dial_distribution'] = dict(Counter(l.get('dial', 'Unknown') for l in ref_listings))
                prices = [l.get('price_usd', 0) or l.get('price', 0) for l in ref_listings if (l.get('price_usd', 0) or l.get('price', 0)) > 0]
                if prices:
                    info['price_range'] = {'low': min(prices), 'high': max(prices), 'avg': sum(prices) / len(prices)}
        
        return jsonify(info)
    except Exception as e:
        return jsonify({'error': str(e), 'ref': ref}), 500


