import threading

def _bg_sheet_sync(watch_ids=None):
    """Fire-and-forget background sheet sync after DB changes."""
    if not SHEET_SYNC_AVAILABLE:
        return
    def _do():
        try:
            if watch_ids:
                _sheet_quick_sync(watch_ids)
            else:
                _sheet_full_sync()
        except Exception as e:
            logger.warning(f"Background sheet sync failed: {e}")
        # Also sync public inventory sheet
        try:
            import subprocess
            subprocess.Popen(
                ['python3', os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))),
                 'public_inventory_sync.py'), 'sync'],
                stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL
            )
        except Exception:
            pass
    threading.Thread(target=_do, daemon=True).start()

