def _get_hero_photo(watch_id):
    """Get the arrival photo for a watch — the definitive photo taken when it arrives."""
    try:
        conn = get_db()
        photo = conn.execute(
            "SELECT file_path FROM watch_photos WHERE watch_id=? ORDER BY CASE photo_type WHEN 'hero' THEN 0 WHEN 'arrival' THEN 1 ELSE 2 END, created_at DESC LIMIT 1",
            (watch_id,)
        ).fetchone()
        conn.close()
        if photo and os.path.exists(photo[0]):
            return photo[0]
    except Exception as e:
        logger.warning(f"Hero photo lookup failed: {e}")
    return None


def _auto_create_invoice(watch_data, sold_to, sold_price, customer_info=None):
    """Auto-create an INTERNAL invoice when a watch is sold.
    
    Invoice format:
    - Item Name: [ref] [bracelet] [dial]
    - Item Description: [serial] [MM/YYYY]
    """
    import re
    from invoice_pdf import generate_invoice_pdf, get_next_invoice_number
    
    desc = watch_data.get('description', '')
    ref = watch_data.get('ref', '')
    bracelet = watch_data.get('bracelet', '')
    dial = watch_data.get('dial', '')
    serial = watch_data.get('serial', '')
    card_date = _normalize_card_date(watch_data.get('card_date', ''))
    watch_id = watch_data.get('id', None)
    
    # Build item name: [ref] [bracelet] [dial]
    name_parts = [ref, bracelet, dial]
    item_name = ' '.join(p for p in name_parts if p).strip()
    if not item_name:
        item_name = desc
    
    # Build item description: [serial] [full card date]
    desc_parts = []
    if serial:
        desc_parts.append(serial)
    if card_date:
        desc_parts.append(card_date)
    else:
        date_match = re.search(r'\b(\d{1,2}/\d{4})\b', desc)
        if date_match:
            desc_parts.append(date_match.group(1))
    item_desc = ' '.join(desc_parts).strip()
    
    try:
        price_val = float(str(sold_price).replace('$', '').replace(',', ''))
    except:
        price_val = 0
    
    if price_val <= 0:
        return None
    
    # HARD RULE: No invoice without serial and card date
    if not serial:
        logger.warning(f"Invoice blocked for {desc}: missing serial number")
        return None
    if not card_date and not any(desc_parts):
        logger.warning(f"Invoice blocked for {desc}: missing card date")
        return None
    
    items_json = [{
        'name': item_name,
        'description': item_desc,
        'serial': serial,
        'rate': price_val,
        'qty': 1,
        'amount': price_val,
    }]
    
    if customer_info is None:
        customer_info = {}
    cust_address = customer_info.get('address', '')
    cust_phone = customer_info.get('phone', '')
    cust_email = customer_info.get('email', '')
    
    try:
        conn = get_db()
        invoice_number = get_next_invoice_number(conn)
        now = now_et_iso()
        
        conn.execute("""
            INSERT INTO internal_invoices 
            (invoice_number, customer_name, customer_address, customer_phone, customer_email,
             items_json, subtotal, tax_rate, tax_amount, total, 
             status, notes, watch_id, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, 0, 0, ?, 'sent', '', ?, ?, ?)
        """, (invoice_number, sold_to, cust_address, cust_phone, cust_email,
              json.dumps(items_json), price_val, price_val,
              watch_id, now, now))
        inv_id = conn.execute("SELECT last_insert_rowid()").fetchone()[0]
        conn.commit()
        
        # Get the full record back for PDF generation
        inv_row = dict(conn.execute("SELECT * FROM internal_invoices WHERE id = ?", (inv_id,)).fetchone())
        
        # Generate PDF and store blob
        pdf_bytes = generate_invoice_pdf(inv_row)
        conn.execute('UPDATE internal_invoices SET pdf_blob=? WHERE id=?', (pdf_bytes, inv_id))
        conn.commit()
        
        logger.info(f"Auto-invoice created: {invoice_number} for {sold_to} — ${price_val:,.0f}")
        
        # Send PDF via Telegram
        try:
            BOT_TOKEN = os.environ.get('TELEGRAM_BOT_TOKEN', '8294337041:AAHWMY0vmn7ITkoCqabhglUU8uOmO2CQn1s')
            JEFFIN_ID = 1507693753
            import requests as _req
            pdf_filename = f'{invoice_number}_{item_name.replace(" ", "_")}.pdf'
            _req.post(
                f'https://api.telegram.org/bot{BOT_TOKEN}/sendDocument',
                data={
                    'chat_id': JEFFIN_ID,
                    'caption': f'{invoice_number} -- {item_name} to {sold_to} -- ${price_val:,.0f}'
                },
                files={'document': (pdf_filename, pdf_bytes, 'application/pdf')},
                timeout=15
            )
        except Exception as pdf_err:
            logger.warning(f"Auto-invoice PDF send failed: {pdf_err}")
        
        # Send watch photos alongside invoice
        try:
            watch_photos = conn.execute('SELECT file_path FROM watch_photos WHERE watch_id = ? ORDER BY created_at', (watch_id,)).fetchall() if watch_id else []
            for photo in watch_photos:
                ppath = Path(photo['file_path'])
                if ppath.exists():
                    _req.post(
                        f'https://api.telegram.org/bot{BOT_TOKEN}/sendPhoto',
                        data={'chat_id': JEFFIN_ID},
                        files={'photo': (ppath.name, (_pf := open(str(ppath), 'rb')), 'image/jpeg')},
                        timeout=15
                    )
                    _pf.close()
        except Exception as photo_err:
            logger.warning(f"Auto-invoice photo send failed: {photo_err}")
        
        conn.close()
        
        return {
            'invoice_id': inv_id,
            'invoice_number': invoice_number,
            'amount': price_val,
            'customer': sold_to,
        }
    except Exception as e:
        logger.error(f"Auto-invoice creation failed: {e}")
        return None


def _auto_update_invoice_serial(watch, serial='', card_date=''):
    """When serial/card_date is added to a sold watch, update the existing Zoho invoice line item."""
    import re
    sold_to = watch.get('sold_to', '')
    desc = watch.get('description', '')
    sold_price = watch.get('sold_price', '') or watch.get('sale_price', '')

    try:
        price_val = float(str(sold_price).replace('$', '').replace(',', ''))
    except:
        return

    # Find matching invoice by customer + amount
    try:
        result = zoho_list_invoices(status='All')
        invoices = result if isinstance(result, list) else result.get('invoices', [])
        target_inv = None
        sold_to_lower = sold_to.lower()
        for inv in invoices:
            inv_customer = inv.get('customer_name', '').lower()
            # Match by exact name OR if either contains the other (handles company vs person name)
            name_match = (inv_customer == sold_to_lower or
                         sold_to_lower in inv_customer or
                         inv_customer in sold_to_lower or
                         # Also check contact name in invoice
                         any(sold_to_lower in (cp.get('first_name','') + ' ' + cp.get('last_name','')).lower()
                             for cp in inv.get('contact_persons', [])))
            if name_match and abs(inv.get('total', 0) - price_val) < 1:
                target_inv = inv
                break

        if not target_inv:
            return

        inv_id = target_inv.get('invoice_id')
        # Fetch full invoice to get line items
        full_inv = zoho_get_invoice(inv_id)
        if not full_inv:
            return

        inv_data = full_inv if isinstance(full_inv, dict) and 'line_items' in full_inv else full_inv.get('invoice', full_inv)
        line_items = inv_data.get('line_items', [])
        if not line_items:
            return

        # Update first line item description with serial + card_date
        new_serial = serial or watch.get('serial', '')
        new_date = card_date or watch.get('date_on_card', '')
        desc_parts = [p for p in [new_serial, new_date] if p]
        new_desc = ' '.join(desc_parts).strip()

        if new_desc and new_desc != line_items[0].get('description', ''):
            line_items[0]['description'] = new_desc
            zoho_update_invoice(inv_id, {'line_items': line_items})
            print(f"[Invoice] ✅ Updated {target_inv.get('invoice_number', '')} with serial: {new_desc}")
    except Exception as e:
        print(f"[Invoice] ⚠️ Auto-update serial failed: {e}")


def _get_watch_desc(row_or_id, expected_desc=None):
    """Look up watch description by ID (SQLite) or row (Bot Sheet fallback).
    
    With SQLite, 'row' is now the watch ID — no row-shift possible.
    """
    # Try SQLite first
    if DB_AVAILABLE:
        try:
            watch = db_get(int(row_or_id))
            if watch:
                # Add 'row' key for backward compatibility
                watch['row'] = watch['id']
                return watch
        except Exception:
            pass
    
    # Fallback to Bot Sheet
    try:
        result = bs_dump()
        if result.get('ok'):
            rows = result.get('rows', [])
            for r in rows:
                if r.get('row') == row_or_id:
                    if not expected_desc or expected_desc.strip().lower() in r.get('description', '').strip().lower():
                        return r
                    break
            if expected_desc:
                for r in rows:
                    if r.get('description', '').strip() == expected_desc.strip():
                        return r
    except:
        pass
    return {}

