def _extract_ref(desc):
    import re
    m = re.search(r'\b(\d{5,6}[A-Za-z]*)\b', desc)
    return m.group(1).upper() if m else ''

_DIAL_MAP_CACHE = None
def _get_dial_map():
    global _DIAL_MAP_CACHE
    if _DIAL_MAP_CACHE is None:
        try:
            with open(Path(__file__).parent / 'rolex_dial_map.json') as f:
                _DIAL_MAP_CACHE = json.load(f)
        except Exception:
            _DIAL_MAP_CACHE = {}
    return _DIAL_MAP_CACHE

def _extract_dial(desc):
    """Extract dial from Bot Sheet description. Uses dial map for ref-specific matching."""
    # First try ref-specific dial matching
    import re as _re
    ref_m = _re.match(r'(?:Pre-Owned |Retail Ready )?(\d{5,6}[A-Za-z]*)', desc)
    if ref_m:
        ref = ref_m.group(1).upper()
        base_ref = _re.sub(r'[A-Za-z]+$', '', ref)
        dial_map = _get_dial_map()
        # Check full ref first, then base ref
        known_dials = dial_map.get(ref, dial_map.get(base_ref, {}))
        if known_dials:
            # Match longest dial name first (e.g. "Candy Pink" before "Pink", "Root Beer" before "Root")
            for d in sorted(known_dials.keys(), key=len, reverse=True):
                if d in desc:
                    return d
    # Fallback: generic extraction — LONGEST MATCH FIRST to avoid partial matches
    all_dials = ['Bruce Wayne','Mint Green Diamond','Tiffany Blue Diamond','Blue Diamond','Black Diamond',
                 'Grey Diamond','Green Diamond','White Diamond','Slate Diamond','Rhodium Diamond',
                 'MOP Diamond','Root Beer','Candy Pink','Azzurro Blue','Med Blue','Mint Green',
                 'MOP','Black','White','Blue','Green','Slate','Grey','Silver','Champagne','Rhodium',
                 'Pink','Chocolate','Gold','Sundust','Ice','Tiffany','Panda','Beige','Mint',
                 'Wimbledon','Pistachio','Turquoise','Lavender','Olive']
    for d in all_dials:
        if d in desc:
            return d
    return ''

def _extract_bracelet(desc):
    if 'Jubilee' in desc: return 'Jubilee'
    if 'Oyster' in desc: return 'Oyster'
    if 'Oysterflex' in desc: return 'Oysterflex'
    if 'President' in desc: return 'President'
    return ''

def _parse_cost_safe(val):
    if not val: return None
    val = str(val).replace('$','').replace(',','').strip()
    try: return float(val)
    except: return None

