@app.route('/api/shipping/packages', methods=['GET'])
@login_required
def api_shipping_packages():
    """Get all shipment packages with their watches."""
    try:
        db = get_db()
        packages = db.execute('SELECT * FROM shipment_packages ORDER BY shipped ASC, id ASC').fetchall()
        result = []
        for pkg in packages:
            pkg = dict(pkg)
            watches = db.execute('''
                SELECT w.id, w.description, w.sold_to, w.sold_price, w.serial, w.shipped
                FROM package_watches pw
                JOIN watches w ON w.id = pw.watch_id
                WHERE pw.package_id = ?
            ''', (pkg['id'],)).fetchall()
            pkg['watches'] = [dict(w) for w in watches]
            pkg['watch_count'] = len(watches)
            pkg['has_label'] = bool(pkg.get('pdf_path'))
            result.append(pkg)
        return jsonify(result)
    except Exception as e:
        return jsonify({'error': str(e)}), 500


