@app.route('/api/shipping/packages', methods=['POST'])
@login_required
def api_shipping_packages_create():
    """Create a shipment package. Accepts JSON {watch_ids: [...], recipient, carrier, ship_by_date}
    or multipart with PDF files + watch_ids."""
    try:
        if request.content_type and 'multipart' in request.content_type:
            data = request.form.to_dict()
            pdf_files = request.files.getlist('pdfs') or request.files.getlist('pdf')
        else:
            data = request.get_json() or {}
            pdf_files = []

        watch_ids = data.get('watch_ids', '[]')
        if isinstance(watch_ids, str):
            import json as _json
            watch_ids = _json.loads(watch_ids)
        recipient = data.get('recipient', '')
        carrier = data.get('carrier', 'FedEx')
        ship_by_date = data.get('ship_by_date', '')
        
        if not watch_ids:
            return jsonify({'error': 'watch_ids required'}), 400

        db = get_db()
        
        # Build package name from watches
        descs = []
        for wid in watch_ids:
            w = db.execute('SELECT description FROM watches WHERE id=?', (wid,)).fetchone()
            if w:
                descs.append(w['description'].split()[0] if w['description'] else str(wid))
        pkg_name = f"Package - {recipient or ', '.join(descs)}"

        # Handle PDF combination
        pdf_path = ''
        if pdf_files:
            from pathlib import Path as _Path
            labels_dir = _Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'shipping_labels'
            labels_dir.mkdir(parents=True, exist_ok=True)
            
            if len(pdf_files) == 1:
                fname = f"package_{'_'.join(str(w) for w in watch_ids)}_{datetime.now(ET).strftime('%Y%m%d_%H%M%S')}.pdf"
                fpath = labels_dir / fname
                pdf_files[0].save(str(fpath))
                pdf_path = str(fpath)
            else:
                # Combine multiple PDFs
                try:
                    from pypdf import PdfReader, PdfWriter
                    writer = PdfWriter()
                    for pf in pdf_files:
                        import tempfile
                        tmp = tempfile.NamedTemporaryFile(delete=False, suffix='.pdf')
                        pf.save(tmp.name)
                        reader = PdfReader(tmp.name)
                        for page in reader.pages:
                            writer.add_page(page)
                        os.unlink(tmp.name)
                    fname = f"package_{'_'.join(str(w) for w in watch_ids)}_combined_{datetime.now(ET).strftime('%Y%m%d_%H%M%S')}.pdf"
                    fpath = labels_dir / fname
                    with open(str(fpath), 'wb') as fh:
                        writer.write(fh)
                    pdf_path = str(fpath)
                except ImportError:
                    # Fallback: save first PDF only
                    fname = f"package_{'_'.join(str(w) for w in watch_ids)}_{datetime.now(ET).strftime('%Y%m%d_%H%M%S')}.pdf"
                    fpath = labels_dir / fname
                    pdf_files[0].save(str(fpath))
                    pdf_path = str(fpath)

        now = now_et_iso()
        cur = db.execute('''INSERT INTO shipment_packages (package_name, recipient, carrier, pdf_path, ship_by_date, created_at)
            VALUES (?, ?, ?, ?, ?, ?)''', (pkg_name, recipient, carrier, pdf_path, ship_by_date, now))
        pkg_id = cur.lastrowid
        
        for wid in watch_ids:
            db.execute('INSERT OR IGNORE INTO package_watches (package_id, watch_id) VALUES (?, ?)', (pkg_id, wid))
            if ship_by_date:
                db.execute('UPDATE watches SET ship_by_date=?, updated_at=? WHERE id=?', (ship_by_date, now, wid))
        
        db.commit()
        
        # Notify Eddy about new shipments
        try:
            for wid in watch_ids:
                w = db.execute('SELECT description, serial, ship_from, ship_by_date FROM watches WHERE id=?', (wid,)).fetchone()
                if w and w['ship_from'] != 'foreign':
                    _notify_shipper(w['description'], w['serial'], w['ship_by_date'], watch_id=wid, event='sold')
                    if pdf_path:
                        _notify_shipper(w['description'], w['serial'], w['ship_by_date'], watch_id=wid, event='label')
        except Exception as e:
            print(f"Shipper package notification error: {e}")
        
        return jsonify({'ok': True, 'package_id': pkg_id, 'name': pkg_name})
    except Exception as e:
        logger.error(f"Create package error: {e}")
        return jsonify({'error': str(e)}), 500


@app.route('/api/shipping/packages/<int:pkg_id>/attach-label', methods=['POST'])
@login_required
def api_shipping_package_attach_label(pkg_id):
    """Attach PDF label(s) to an existing package. Auto-combines multiple PDFs."""
    try:
        pdf_files = request.files.getlist('pdfs') or request.files.getlist('pdf')
        if not pdf_files:
            return jsonify({'error': 'No PDF files provided'}), 400

        db = get_db()
        pkg = db.execute('SELECT * FROM shipment_packages WHERE id=?', (pkg_id,)).fetchone()
        if not pkg:
            return jsonify({'error': 'Package not found'}), 404

        watch_ids = [r['watch_id'] for r in db.execute('SELECT watch_id FROM package_watches WHERE package_id=?', (pkg_id,)).fetchall()]
        from pathlib import Path as _Path
        labels_dir = _Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'shipping_labels'
        labels_dir.mkdir(parents=True, exist_ok=True)

        # Combine all PDFs (existing + new)
        all_pdfs = []
        if pkg['pdf_path'] and os.path.exists(pkg['pdf_path']):
            all_pdfs.append(pkg['pdf_path'])
        
        import tempfile
        for pf in pdf_files:
            tmp = tempfile.NamedTemporaryFile(delete=False, suffix='.pdf')
            pf.save(tmp.name)
            all_pdfs.append(tmp.name)

        try:
            from pypdf import PdfReader, PdfWriter
            writer = PdfWriter()
            for fp in all_pdfs:
                reader = PdfReader(fp)
                for page in reader.pages:
                    writer.add_page(page)
            fname = f"package_{'_'.join(str(w) for w in watch_ids)}_combined_{datetime.now(ET).strftime('%Y%m%d_%H%M%S')}.pdf"
            fpath = labels_dir / fname
            with open(str(fpath), 'wb') as fh:
                writer.write(fh)
            pdf_path = str(fpath)
        except ImportError:
            pdf_path = all_pdfs[0]

        # Clean up temp files
        for fp in all_pdfs:
            if fp != pkg['pdf_path'] and 'tmp' in fp:
                try: os.unlink(fp)
                except: pass

        db.execute('UPDATE shipment_packages SET pdf_path=?, updated_at=datetime("now") WHERE id=?', (pdf_path, pkg_id))
        db.commit()
        
        # Notify shipper: label attached or label UPDATED
        try:
            had_label = bool(pkg.get('pdf_path'))
            for wid in watch_ids:
                w = db.execute('SELECT description, serial, ship_from, ship_by_date FROM watches WHERE id=?', (wid,)).fetchone()
                if w and w['ship_from'] != 'foreign':
                    if had_label:
                        _notify_shipper(w['description'], w['serial'], w['ship_by_date'], watch_id=wid, event='label_updated')
                    else:
                        _notify_shipper(w['description'], w['serial'], w['ship_by_date'], watch_id=wid, event='label')
        except Exception as e:
            print(f"Shipper label notification error: {e}")
        
        return jsonify({'ok': True, 'pdf_path': pdf_path})
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/terminal/logs')
@login_required
def api_terminal_logs():
    """Stream live logs for the terminal view."""
    import glob as _tglob
    log_filter = request.args.get('filter', 'all')
    after_id = int(request.args.get('after', 0))
    
    lines = []
    last_id = after_id
    workspace = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
    
    try:
        if log_filter in ('all', 'dashboard'):
            # Dashboard log (last 200 lines)
            log_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'dashboard.log')
            if os.path.exists(log_path):
                with open(log_path, 'r') as f:
                    all_lines = f.readlines()
                    start = max(0, len(all_lines) - 200) if after_id == 0 else max(0, after_id)
                    for i, line in enumerate(all_lines[start:], start=start):
                        lines.append({'text': f'[dashboard] {line.rstrip()}', 'id': i + 1})
                    if all_lines:
                        last_id = max(last_id, len(all_lines))
        
        if log_filter in ('all', 'gateway'):
            # OpenClaw gateway log
            gw_log = os.path.expanduser('~/.openclaw/logs/gateway.log')
            if os.path.exists(gw_log):
                with open(gw_log, 'r') as f:
                    all_lines = f.readlines()
                    tail = all_lines[-100:] if after_id == 0 else all_lines[-50:]
                    for line in tail:
                        lines.append({'text': f'[gateway] {line.rstrip()}'})
        
        if log_filter in ('all', 'audit'):
            # Audit log from DB
            db = get_db()
            audit_rows = db.execute('''
                SELECT a.timestamp, a.field, a.old_value, a.new_value, w.description
                FROM audit_log a
                LEFT JOIN watches w ON w.id = a.watch_id
                ORDER BY a.id DESC LIMIT ?
            ''', (50 if after_id == 0 else 20,)).fetchall()
            for r in reversed(list(audit_rows)):
                ts = (r['timestamp'] or '')[:19]
                desc = (r['description'] or '')[:40]
                lines.append({'text': f'[audit] {ts} | {desc} | {r["field"]}: {r["old_value"]} → {r["new_value"]}'})
        
        # Sort by text timestamp if mixed
        return jsonify({'lines': lines, 'last_id': last_id})
    except Exception as e:
        return jsonify({'lines': [{'text': f'[error] {str(e)}'}], 'last_id': last_id})


