# ── Price Suggestion ──
@app.route('/api/market/price-suggest/<ref>')
@login_required
def api_price_suggest(ref):
    """Run parse_v4.py query <ref> and return price suggestion."""
    try:
        result = subprocess.run(
            [sys.executable, str(Path(__file__).parent / 'parse_v4.py'), 'query', ref],
            capture_output=True, text=True, timeout=30,
            cwd=str(Path(__file__).parent)
        )
        output = result.stdout
        us_low = None
        hk_low = None
        median = None
        for line in output.split('\n'):
            line_s = line.strip()
            if line_s.startswith('US low:'):
                try: us_low = int(line_s.split('$')[1].strip().replace(',','').split()[0])
                except: pass
            if line_s.startswith('HK low:'):
                try: hk_low = int(line_s.split('$')[1].strip().replace(',','').split()[0])
                except: pass
            if 'Median:' in line_s and 'LOWEST' in line_s:
                try:
                    parts = line_s.split('Median:')
                    median = int(parts[1].strip().split('$')[1].strip().replace(',','').split()[0])
                except: pass
        suggested = (us_low - 100) if us_low else None
        return jsonify({
            'ok': True, 'ref': ref,
            'us_low': us_low, 'hk_low': hk_low, 'median': median,
            'suggested_price': suggested,
            'raw_output': output[:500]
        })
    except Exception as e:
        return jsonify({'ok': False, 'error': str(e)}), 500

# ── Photo Upload ──
@app.route('/api/inventory/<int:row>/photo', methods=['POST'])
@login_required
def api_inventory_photo_upload(row):
    """Upload a photo for a watch."""
    if 'photo' not in request.files:
        return jsonify({'error': 'No photo file provided'}), 400
    photo = request.files['photo']
    if not photo.filename:
        return jsonify({'error': 'Empty filename'}), 400
    
    upload_dir = Path(__file__).parent.parent / 'watch_photos' / 'uploads'
    upload_dir.mkdir(parents=True, exist_ok=True)
    
    ext = Path(photo.filename).suffix.lower()
    timestamp = int(time.time())
    
    if ext in ('.heic', '.heif'):
        # Save temp, convert to JPEG
        temp_path = upload_dir / f'temp_{row}_{timestamp}{ext}'
        photo.save(str(temp_path))
        out_path = upload_dir / f'row_{row}_{timestamp}.jpg'
        try:
            subprocess.run(['sips', '-s', 'format', 'jpeg', str(temp_path), '--out', str(out_path)],
                         capture_output=True, timeout=15)
            temp_path.unlink(missing_ok=True)
        except Exception as e:
            temp_path.unlink(missing_ok=True)
            return jsonify({'error': f'HEIC conversion failed: {e}'}), 500
    else:
        safe_ext = ext if ext in ('.jpg', '.jpeg', '.png', '.webp') else '.jpg'
        out_path = upload_dir / f'row_{row}_{timestamp}{safe_ext}'
        photo.save(str(out_path))
    
    # Also link to watch_photos table for the inventory photo feature
    photo_type = request.form.get('type', 'arrival')
    try:
        conn = get_db()
        conn.execute('INSERT INTO watch_photos (watch_id, file_path, photo_type) VALUES (?, ?, ?)',
                     (row, str(out_path), photo_type))
        conn.commit()
        # Register with photo_manager for suggestions
        w = conn.execute('SELECT description FROM watches WHERE id=?', (row,)).fetchone()
        _register_photo_manager(str(out_path), watch_id=row, photo_type=photo_type,
                               description=w['description'] if w else '')
        conn.close()
    except Exception:
        pass  # Non-critical — photo is saved regardless
    
    return jsonify({'ok': True, 'path': str(out_path), 'filename': out_path.name})

