try:
    from ifs_label_api import (
        get_presets as ifs_presets,
        get_service_options as ifs_services,
        get_signature_options as ifs_signatures,
        build_config as ifs_build_config,
        get_recent_labels as ifs_recent_labels,
        find_label_pdf as ifs_find_pdf,
    )
    IFS_AVAILABLE = True
    print("✅ IFS Label API loaded")
except Exception as e:
    IFS_AVAILABLE = False
    print(f"⚠️ IFS Label API not available: {e}")

# Store pending label requests (dashboard -> Mochie picks up via heartbeat or direct)
_pending_labels = []
_completed_labels = []


_HAL_CACHE_FILE = Path(__file__).parent / 'data' / 'hal_locations_cache.json'

def _load_hal_cache():
    if _HAL_CACHE_FILE.exists():
        try:
            with open(_HAL_CACHE_FILE) as f:
                return json.load(f)
        except Exception:
            pass
    return {}

def _save_hal_cache(cache):
    _HAL_CACHE_FILE.parent.mkdir(parents=True, exist_ok=True)
    with open(_HAL_CACHE_FILE, 'w') as f:
        json.dump(cache, f, indent=2)

def save_hal_locations_for_zip(zip_code, locations):
    """Called from IFS label creation to cache IFS-validated locations."""
    cache = _load_hal_cache()
    cache[zip_code] = {
        'locations': locations,
        'source': 'ifs',
        'updated': now_et_iso()
    }
    _save_hal_cache(cache)

@app.route('/api/fedex-locations')
@login_required
def api_fedex_locations():
    """Find FedEx Office locations near a ZIP code for HAL labels.
    Uses IFS-cached locations first, falls back to OSM Nominatim."""
    import urllib.request, urllib.parse
    zip_code = request.args.get('zip', '').strip()
    if not zip_code or len(zip_code) < 5:
        return jsonify({'error': 'Valid ZIP code required', 'locations': []})
    
    # Use FedEx Location Search API (sandbox works with real data)
    fedex_key = _security_config.get('fedex_api_key', '')
    fedex_secret = _security_config.get('fedex_api_secret', '')
    
    if fedex_key and fedex_secret:
        try:
            import requests as _req
            # Get OAuth token
            tok_r = _req.post("https://apis-sandbox.fedex.com/oauth/token",
                data={"grant_type": "client_credentials", "client_id": fedex_key, "client_secret": fedex_secret},
                headers={"Content-Type": "application/x-www-form-urlencoded"}, timeout=8)
            if tok_r.status_code == 200:
                token = tok_r.json()["access_token"]
                # Search HAL-eligible FedEx Office locations
                loc_r = _req.post("https://apis-sandbox.fedex.com/location/v1/locations",
                    json={
                        "locationsSummaryRequestControlParameters": {"maxResults": 10, "distance": {"units": "MI", "value": 15}},
                        "locationSearchCriterion": "ADDRESS",
                        "location": {"address": {"postalCode": zip_code, "countryCode": "US"}},
                        "locationCapabilities": [{"locationCapabilityDetails": [{"capabilityCode": "HOLD_AT_LOCATION"}]}],
                        "locationTypesToInclude": ["FEDEX_OFFICE", "FEDEX_SHIP_CENTER", "FEDEX_AUTHORIZED_SHIP_CENTER"]
                    },
                    headers={"Authorization": f"Bearer {token}", "Content-Type": "application/json", "X-locale": "en_US"}, timeout=10)
                
                if loc_r.status_code == 200:
                    locs = loc_r.json().get("output", {}).get("locationDetailList", [])
                    locations = []
                    for loc in locs:
                        addr = loc.get("contactAndAddress", {}).get("address", {})
                        anc = loc.get("contactAndAddress", {}).get("addressAncillaryDetail", {})
                        streets = ", ".join(addr.get("streetLines", []))
                        dist = loc.get("distance", {}).get("value", "")
                        locations.append({
                            'name': anc.get('displayName', 'FedEx Office'),
                            'address': streets,
                            'full_address': f"{streets}, {addr.get('city','')}, {addr.get('stateOrProvinceCode','')} {addr.get('postalCode','')}",
                            'city': addr.get('city', ''),
                            'state': addr.get('stateOrProvinceCode', ''),
                            'zip': addr.get('postalCode', zip_code),
                            'distance_mi': dist,
                            'display': f"{anc.get('displayName','FedEx')} — {streets}, {addr.get('city','')}, {addr.get('stateOrProvinceCode','')} {addr.get('postalCode','')} ({dist} mi)"
                        })
                    
                    # Cache for IFS automation
                    if locations:
                        save_hal_locations_for_zip(zip_code, locations)
                    
                    return jsonify({'locations': locations, 'source': 'fedex_api', 'zip': zip_code})
        except Exception as e:
            pass  # Fall through to cache/fallback
    
    # Fallback: IFS cache
    cache = _load_hal_cache()
    if zip_code in cache:
        cached = cache[zip_code]
        return jsonify({
            'locations': cached['locations'],
            'source': 'ifs_cache',
            'cached_at': cached.get('updated', ''),
            'zip': zip_code
        })
    
    return jsonify({'error': 'FedEx API not configured and no cached data', 'locations': []})


