@app.route('/api/ifs/labels')
@login_required
def api_ifs_labels():
    """Get recent labels."""
    if not IFS_AVAILABLE:
        return jsonify({'error': 'IFS not configured'}), 503
    # Scan Downloads inline (avoid import-level function hang)
    # Scan labels folder (not Downloads — macOS TCC blocks LaunchAgent access)
    labels = []
    _labels_dir = str(Path(__file__).parent / 'labels')
    try:
        fnames = [f for f in os.listdir(_labels_dir) if re.match(r'^\d{12}\.pdf$', f)]
        entries = []
        for f in fnames:
            fp = os.path.join(_labels_dir, f)
            try:
                st = os.stat(fp)
                entries.append((f[:-4], f, st.st_size, st.st_mtime))
            except OSError:
                pass
        entries.sort(key=lambda x: x[3], reverse=True)
        for tracking, fname, sz, mt in entries[:10]:
            labels.append({
                'tracking': tracking,
                'filename': fname,
                'size_kb': round(sz / 1024, 1),
                'created': time.strftime('%Y-%m-%d %H:%M', time.localtime(mt)),
                'is_real_label': 30000 < sz < 50000,
            })
    except Exception:
        pass
    return jsonify({
        'labels': labels,
        'pending': _pending_labels,
        'completed': _completed_labels[-10:],
    })


