@app.route('/api/ifs/create', methods=['POST'])
@login_required
def api_ifs_create_label():
    """Create a FedEx label via IFS automation. Runs in background thread."""
    if not IFS_AVAILABLE:
        return jsonify({'error': 'IFS not configured'}), 503
    try:
        data = request.get_json()
        config = ifs_build_config(data)
        
        # Validate required fields
        required = ['contact', 'address', 'city', 'state', 'zip', 'value']
        missing = [f for f in required if not config.get(f)]
        if missing:
            return jsonify({'error': f'Missing fields: {", ".join(missing)}'}), 400
        
        job_id = f"label_{int(time.time())}"
        job = {
            'id': job_id,
            'status': 'processing',
            'config': config,
            'created': time.strftime('%Y-%m-%d %H:%M:%S'),
            'tracking': None,
            'pdf_path': None,
        }
        _pending_labels.append(job)
        
        # Run automation in background thread
        import threading
        def _run_label_automation(job, config):
            try:
                import subprocess
                script = str(Path(__file__).parent / 'ifs_create_label.py')
                config_json = json.dumps(config)
                venv_python = str(Path(__file__).parent / 'venv' / 'bin' / 'python3')
                proc = subprocess.run(
                    [venv_python, script, '--config', config_json],
                    capture_output=True, text=True, timeout=120
                )
                if proc.returncode == 0 and proc.stdout.strip():
                    result = json.loads(proc.stdout.strip())
                    if result.get('ok'):
                        job['status'] = 'completed'
                        job['tracking'] = result.get('tracking')
                        job['pdf_path'] = result.get('pdf_path')
                        job['completed_at'] = time.strftime('%Y-%m-%d %H:%M:%S')
                        _pending_labels.remove(job)
                        _completed_labels.append(job)
                        return
                    else:
                        job['status'] = 'failed'
                        job['error'] = result.get('error', 'Unknown error')
                else:
                    stderr = proc.stderr[:500] if proc.stderr else ''
                    job['status'] = 'failed'
                    job['error'] = f'Script failed (exit {proc.returncode}): {stderr}'
            except subprocess.TimeoutExpired:
                job['status'] = 'failed'
                job['error'] = 'Automation timed out after 120s'
            except Exception as e:
                job['status'] = 'failed'
                job['error'] = str(e)
        
        t = threading.Thread(target=_run_label_automation, args=(job, config), daemon=True)
        t.start()
        
        return jsonify({
            'message': 'Label creation started — automation running',
            'job': job,
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500


