@app.route('/api/ifs/complete', methods=['POST'])
@login_required
def api_ifs_complete_label():
    """Mark a label as completed (called by Mochie after automation)."""
    data = request.get_json()
    job_id = data.get('job_id')
    for job in _pending_labels:
        if job['id'] == job_id:
            job['status'] = 'completed'
            job['tracking'] = data.get('tracking')
            job['pdf_path'] = data.get('pdf_path')
            job['cost'] = data.get('cost')
            job['eta'] = data.get('eta')
            job['completed_at'] = time.strftime('%Y-%m-%d %H:%M:%S')
            _pending_labels.remove(job)
            _completed_labels.append(job)
            # Copy PDF to labels folder if it exists elsewhere
            if job['pdf_path'] and os.path.isfile(job['pdf_path']):
                labels_dir = str(Path(__file__).parent / 'labels')
                dest = os.path.join(labels_dir, f"{job['tracking']}.pdf")
                if not os.path.isfile(dest):
                    import shutil
                    shutil.copy2(job['pdf_path'], dest)
                # Also copy to shipping_labels
                ship_labels_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'shipping_labels'
                ship_labels_dir.mkdir(parents=True, exist_ok=True)
                ship_dest = ship_labels_dir / f"label_{job.get('row','?')}_{job['tracking']}.pdf"
                if not ship_dest.exists():
                    import shutil
                    shutil.copy2(job['pdf_path'], str(ship_dest))
            
            # Auto-add to Ship tab (NOT marking shipped) so Eddy can see it
            watch_row = job.get('row')
            if watch_row:
                try:
                    db = get_db()
                    now = datetime.now()
                    ship_date = (now + __import__('datetime').timedelta(days=1)).strftime('%Y-%m-%d') if now.hour >= 21 else now.strftime('%Y-%m-%d')
                    db.execute('UPDATE watches SET ship_by_date=COALESCE(NULLIF(ship_by_date,""), ?), updated_at=? WHERE id=?',
                               (ship_date, now.isoformat(), watch_row))
                    pdf_path = str(ship_dest) if job['pdf_path'] else ''
                    db.execute('INSERT INTO shipping (watch_id, tracking, carrier, ship_type, pdf_path, created_at) VALUES (?, ?, ?, ?, ?, ?)',
                               (watch_row, job.get('tracking', ''), 'FedEx', 'fedex', pdf_path, now.isoformat()))
                    db.commit()
                except Exception as e:
                    logger.error(f"Auto-add to ship tab error: {e}")
            
            return jsonify({'message': 'Label marked complete', 'job': job})
    return jsonify({'error': 'Job not found'}), 404


