def _sync_paid_invoice_to_botsheet(inv):
    """Match a paid invoice to DB rows and mark paid=Yes.
    Matches by: (1) serial in line items, (2) customer name + line item amount."""
    if not DB_AVAILABLE:
        return []
    try:
        all_watches = db_all()
        rows = [{'row': w['id'], **w} for w in all_watches]
        # Unpaid sold watches
        unpaid = [r for r in rows if (r.get('sold') or '').lower() == 'yes'
                  and (r.get('watch_paid') or r.get('paid_after_sold') or '').lower() != 'yes']
        if not unpaid:
            return []
        
        inv_customer = (inv.get('customer_name') or '').lower()
        inv_total = float(inv.get('total', 0))
        items = inv.get('line_items', [])
        synced = []
        
        # 1. Serial match from line items
        for li in items:
            desc = (li.get('description') or '') + ' ' + (li.get('name') or '')
            import re as _re
            m = _re.search(r'Serial:\s*([A-Z0-9]+)', desc, _re.IGNORECASE)
            if m:
                serial = m.group(1).upper()
                for row in unpaid:
                    if (row.get('serial') or '').upper().strip() == serial and row['row'] not in [s['row'] for s in synced]:
                        if DB_AVAILABLE:
                            db_paid(int(row['row']))
                        synced.append({'row': row['row'], 'desc': row.get('description',''), 'match': f'serial:{serial}'})
        
        # 2. Customer name + total match (for invoices without serials)
        if not synced:
            for row in unpaid:
                buyer = (row.get('sold_to') or '').lower().strip()
                price_str = str(row.get('sold_price') or row.get('sale_price') or '0')
                try:
                    price = float(price_str.replace('$','').replace(',',''))
                except:
                    continue
                first_word = buyer.split()[0] if buyer.split() else ''
                if len(first_word) > 2 and first_word in inv_customer and abs(inv_total - price) < 1:
                    if row['row'] not in [s['row'] for s in synced]:
                        if DB_AVAILABLE:
                            db_paid(int(row['row']))
                        synced.append({'row': row['row'], 'desc': row.get('description',''), 'match': f'customer+amount:{buyer}/${price}'})
        
        if synced:
            print(f"✅ Payment sync: marked {len(synced)} row(s) as paid: {[s['row'] for s in synced]}")
            _bg_sheet_sync([s['row'] for s in synced])
        return synced
    except Exception as e:
        print(f"⚠️ _sync_paid_invoice_to_botsheet error: {e}")
        return []


@app.route('/api/zoho/invoices/<invoice_id>/payment', methods=['POST'])
@login_required
def api_zoho_record_payment(invoice_id):
    """Record a payment against an invoice."""
    if not ZOHO_AVAILABLE:
        return jsonify({'error': 'Zoho Invoice not configured'}), 503
    try:
        data = request.get_json()
        result = zoho_record_payment(
            invoice_id=invoice_id,
            amount=data['amount'],
            date=data.get('date'),
            payment_mode=data.get('payment_mode'),
            description=data.get('description'),
        )
        zoho_invalidate_cache()
        
        # Auto-sync: if invoice is now fully paid, update Bot Sheet M=Yes
        synced = []
        try:
            inv_detail = zoho_get_invoice(invoice_id)
            inv = inv_detail.get('invoice', inv_detail)
            remaining = float(inv.get('balance', 1))
            if remaining <= 0 and DB_AVAILABLE:
                synced = _sync_paid_invoice_to_botsheet(inv)
        except Exception as sync_err:
            print(f"⚠️ Payment sync after record failed: {sync_err}")
        
        result['synced_rows'] = synced
        return jsonify(result)
    except Exception as e:
        return jsonify({'error': str(e)}), 500


