@app.route('/api/internal-invoices', methods=['GET'])
@login_required
def api_internal_invoices_list():
    """List all internal invoices."""
    try:
        conn = get_db()
        status_filter = request.args.get('status', '')
        query = request.args.get('q', '')
        
        sql = "SELECT * FROM internal_invoices WHERE 1=1"
        params = []
        if status_filter:
            sql += " AND status = ?"
            params.append(status_filter)
        if query:
            sql += " AND (customer_name LIKE ? OR invoice_number LIKE ?)"
            params.extend([f'%{query}%', f'%{query}%'])
        sql += " ORDER BY id DESC"
        
        limit = request.args.get('limit', type=int)
        offset = request.args.get('offset', 0, type=int)
        if limit:
            sql += f" LIMIT {limit} OFFSET {offset}"
        
        rows = conn.execute(sql, params).fetchall()
        
        # Get total count for pagination
        count_sql = "SELECT COUNT(*) FROM internal_invoices WHERE 1=1"
        count_params = []
        if status_filter:
            count_sql += " AND status = ?"
            count_params.append(status_filter)
        if query:
            count_sql += " AND (customer_name LIKE ? OR invoice_number LIKE ?)"
            count_params.extend([f'%{query}%', f'%{query}%'])
        total_count = conn.execute(count_sql, count_params).fetchone()[0]
        
        # Summary stats (always unfiltered)
        stats = {}
        stats['outstanding'] = conn.execute("SELECT COALESCE(SUM(total),0) FROM internal_invoices WHERE status='sent'").fetchone()[0]
        stats['paid'] = conn.execute("SELECT COUNT(*) FROM internal_invoices WHERE status='paid'").fetchone()[0]
        stats['draft'] = conn.execute("SELECT COUNT(*) FROM internal_invoices WHERE status='draft'").fetchone()[0]
        stats['total'] = conn.execute("SELECT COUNT(*) FROM internal_invoices").fetchone()[0]
        
        invoices = []
        for r in rows:
            d = dict(r)
            # Convert any bytes to strings for JSON serialization
            for k, v in d.items():
                if isinstance(v, bytes):
                    d[k] = v.decode('utf-8', errors='replace')
            if isinstance(d.get('items_json'), str):
                try:
                    d['items'] = json.loads(d['items_json'])
                except Exception:
                    d['items'] = []
            else:
                d['items'] = d.get('items_json', [])
            # Remove raw items_json from response
            d.pop('items_json', None)
            invoices.append(d)
        
        conn.close()
        
        return jsonify({'ok': True, 'invoices': invoices, 'count': len(invoices), 'total': total_count, 'stats': stats})
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/internal-invoices', methods=['POST'])
@login_required
def api_internal_invoices_create():
    """Create a new internal invoice."""
    try:
        from invoice_pdf import get_next_invoice_number
        
        data = request.get_json()
        conn = get_db()
        
        inv_number = get_next_invoice_number(conn)
        
        watch_id = data.get('watch_id')
        items = data.get('items', [])
        
        # HARD RULE: If watch_id provided, serial and card_date MUST exist
        if watch_id:
            w = conn.execute('SELECT serial, card_date, description, sold_price FROM watches WHERE id=?', (watch_id,)).fetchone()
            if w:
                serial = w['serial'] or ''
                card_date = w['card_date'] or ''
                if not serial or not card_date:
                    missing = []
                    if not serial: missing.append('serial')
                    if not card_date: missing.append('card_date')
                    conn.close()
                    return jsonify({'error': f'Cannot generate invoice: watch #{watch_id} is missing {" and ".join(missing)}. Update the watch first.'}), 400
                # Auto-populate items from watch data if none provided
                if not items:
                    desc = w['description'] or ''
                    price = float(data.get('amount', 0) or w['sold_price'] or 0)
                    items = [{'name': desc, 'serial': serial, 'description': card_date, 'qty': 1, 'rate': price, 'amount': price}]
                else:
                    # Ensure serial is in items
                    for item in items:
                        if not item.get('serial'):
                            item['serial'] = serial
        
        items_json = json.dumps(items)
        
        subtotal = sum(float(item.get('amount', float(item.get('rate', 0)) * int(item.get('qty', 1)))) for item in items)
        tax_rate = float(data.get('tax_rate', 0))
        tax_amount = subtotal * (tax_rate / 100)
        total = subtotal + tax_amount
        
        now = now_et_iso()
        
        conn.execute("""
            INSERT INTO internal_invoices 
            (invoice_number, customer_name, customer_address, customer_email, customer_phone,
             items_json, subtotal, tax_rate, tax_amount, total, status, notes, watch_id, due_date, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """, (
            inv_number,
            data.get('customer_name', ''),
            data.get('customer_address', ''),
            data.get('customer_email', ''),
            data.get('customer_phone', ''),
            items_json,
            subtotal, tax_rate, tax_amount, total,
            data.get('status', 'sent'),
            data.get('notes', ''),
            watch_id,
            data.get('due_date', ''),
            now, now
        ))
        conn.commit()
        
        inv_id = conn.execute("SELECT last_insert_rowid()").fetchone()[0]
        conn.close()
        
        return jsonify({
            'ok': True,
            'id': inv_id,
            'invoice_number': inv_number,
            'total': total
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500


