@app.route('/api/internal-invoices/<int:inv_id>', methods=['PUT'])
@login_required
def api_internal_invoices_update(inv_id):
    """Update an invoice."""
    try:
        data = request.get_json()
        conn = get_db()
        
        row = conn.execute("SELECT * FROM internal_invoices WHERE id = ?", (inv_id,)).fetchone()
        if not row:
            conn.close()
            return jsonify({'error': 'Invoice not found'}), 404
        
        updates = []
        params = []
        
        for field in ['customer_name', 'customer_address', 'customer_email', 'customer_phone', 'notes', 'status', 'due_date', 'payment_date']:
            if field in data:
                updates.append(f"{field} = ?")
                params.append(data[field])
        
        if 'items' in data:
            items = data['items']
            items_json = json.dumps(items)
            subtotal = sum(float(item.get('amount', float(item.get('rate', 0)) * int(item.get('qty', 1)))) for item in items)
            tax_rate = float(data.get('tax_rate', row['tax_rate']))
            tax_amount = subtotal * (tax_rate / 100)
            total = subtotal + tax_amount
            
            updates.extend(['items_json = ?', 'subtotal = ?', 'tax_rate = ?', 'tax_amount = ?', 'total = ?'])
            params.extend([items_json, subtotal, tax_rate, tax_amount, total])
        
        updates.append("updated_at = ?")
        params.append(now_et_iso())
        params.append(inv_id)
        
        conn.execute(f"UPDATE internal_invoices SET {', '.join(updates)} WHERE id = ?", params)
        conn.commit()
        conn.close()
        
        return jsonify({'ok': True, 'id': inv_id})
    except Exception as e:
        return jsonify({'error': str(e)}), 500


