def _invoice_filename(inv_data):
    """Generate buyer-friendly filename like Invoice_126334_Blue_Diamond.pdf"""
    items = inv_data.get('items') or []
    if not items and inv_data.get('items_json'):
        try: items = json.loads(inv_data['items_json'])
        except: items = []
    if items:
        name = items[0].get('name', '').strip()
        # "126334 Jubilee Blue Diamond" → "126334_Jubilee_Blue_Diamond"
        slug = '_'.join(name.split())
        if slug:
            return f'Invoice_{slug}.pdf'
    return f'Invoice_{inv_data.get("invoice_number","")}.pdf'

