@app.route('/api/telegram/post-to-my-postings', methods=['POST'])
@login_required
def api_post_to_my_postings():
    """Post a watch to My Postings group with photos from storage or upload.
    
    Accepts JSON: {row, caption, price, use_photos, photo_path}
    Or multipart form with 'photo' file + 'row', 'caption', 'price' fields.
    
    This is the SINGLE entry point for all My Postings — handles:
    1. Post to WhatsApp My Postings group (via wacli)
    2. Capture message_id  
    3. Log to my_postings_log.json
    4. Update Bot Sheet (posted=Yes, sale_price)
    5. Save photo to watch_photos library
    """
    try:
        # Support both JSON and multipart form data
        if request.content_type and 'multipart' in request.content_type:
            data = request.form.to_dict()
            uploaded_photo = request.files.get('photo')
        else:
            data = request.get_json() or {}
            uploaded_photo = None
        
        row = data.get('row')
        caption = data.get('caption', '')
        price = data.get('price', '')
        use_photos = data.get('use_photos', False)
        photo_path = data.get('photo_path', '')  # Direct path to a photo file

        from whatsapp_postings import send_photo as wa_send_photo, send_photos as wa_send_photos, send_text as wa_send_text

        photos_sent = []
        valid_photos = []
        
        # Priority 1: Uploaded photo via multipart form
        if uploaded_photo:
            import tempfile
            tmp = tempfile.NamedTemporaryFile(suffix='.jpg', delete=False, dir='/tmp')
            uploaded_photo.save(tmp.name)
            valid_photos = [Path(tmp.name)]
            # Also save to watch_photos library
            try:
                import re as _re2
                ref_m2 = _re2.match(r'(?:Pre-Owned |BNIB |Retail Ready )?(?:Full Set )?(\d{5,6}[A-Za-z]*)', caption)
                if ref_m2:
                    ref_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'watch_photos' / ref_m2.group(1)
                    ref_dir.mkdir(parents=True, exist_ok=True)
                    import shutil
                    shutil.copy2(tmp.name, str(ref_dir / f"{ref_m2.group(1)}_posted_{datetime.now(ET).strftime('%Y-%m-%d')}.jpg"))
            except Exception as pe:
                logger.warning(f"Failed to save to photo library: {pe}")
        
        # Priority 2: Direct photo path
        elif photo_path and Path(photo_path).exists():
            valid_photos = [Path(photo_path)]
            # Also save to watch_photos library
            try:
                import re as _re2
                ref_m2 = _re2.match(r'(?:Pre-Owned |BNIB |Retail Ready )?(?:Full Set )?(\d{5,6}[A-Za-z]*)', caption)
                if ref_m2:
                    ref_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'watch_photos' / ref_m2.group(1)
                    ref_dir.mkdir(parents=True, exist_ok=True)
                    import shutil
                    shutil.copy2(str(photo_path), str(ref_dir / f"{ref_m2.group(1)}_posted_{datetime.now(ET).strftime('%Y-%m-%d')}.jpg"))
            except Exception as pe:
                logger.warning(f"Failed to save to photo library: {pe}")
        
        # Priority 3: Photos from watch_photo_manager
        elif use_photos:
            from watch_photo_manager import get_photos
            import re as _re3
            _ref_for_photos = None
            _ref_m3 = _re3.match(r'(?:Pre-Owned |BNIB |Retail Ready )?(?:Full Set )?(\d{5,6}[A-Za-z]*)', caption)
            if _ref_m3:
                _ref_for_photos = _ref_m3.group(1)
            info = get_photos(row, ref=_ref_for_photos)
            photo_files = info.get('photos', [])

            if photo_files:
                # Convert HEIC to JPEG if needed, collect valid photo paths
                valid_photos = []
                for p in photo_files[:10]:
                    fpath = Path(p['path'])
                    if not fpath.exists():
                        continue
                    if fpath.suffix.lower() in ('.heic', '.heif'):
                        try:
                            from PIL import Image
                            jpeg_path = fpath.with_suffix('.jpg')
                            if not jpeg_path.exists():
                                img = Image.open(str(fpath))
                                img.save(str(jpeg_path), 'JPEG', quality=92)
                            valid_photos.append(jpeg_path)
                        except Exception as conv_err:
                            logger.error(f"HEIC conversion failed: {conv_err}")
                            continue
                    else:
                        valid_photos.append(fpath)

        # Send via WhatsApp — only 1 photo per posting (no duplicate/captionless images)
        if valid_photos:
            wa_result = wa_send_photos([str(valid_photos[0])], caption)
            if wa_result.get('ok'):
                photos_sent = wa_result.get('message_ids', [])
            else:
                logger.error(f"WhatsApp photo send failed: {wa_result.get('error')}")
        
        # No photo = no post (WhatsApp postings require a photo)
        if not photos_sent and not valid_photos:
            return jsonify({'error': 'No photo available — postings require a photo'}), 400

        if not photos_sent:
            return jsonify({'error': 'Failed to send photo to WhatsApp'}), 500

        # Save to my_postings_log with message_id
        try:
            log_path = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'my_postings_log.json'
            if log_path.exists():
                with open(log_path) as _lf:
                    log_data = json.load(_lf)
            else:
                log_data = []
            import re as _re
            ref_m = _re.match(r'(?:Pre-Owned |BNIB |Retail Ready )?(?:Full Set )?(\d{5,6}[A-Za-z]*)', caption)
            # Determine photo filename for the log
            _posting_photo = ''
            if photos_sent and valid_photos:
                try:
                    _photo_path = Path(str(valid_photos[0]))
                    _posting_photo_name = f"posting_{photos_sent[0]}.jpg"
                    _posting_dest = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos' / _posting_photo_name
                    _posting_dest.parent.mkdir(parents=True, exist_ok=True)
                    import shutil
                    shutil.copy2(str(_photo_path), str(_posting_dest))
                    _posting_photo = _posting_photo_name
                except Exception as _photo_err:
                    logger.warning(f"Failed to save posting photo: {_photo_err}")
            
            log_entry = {
                'ref': ref_m.group(1) if ref_m else '',
                'description': caption,
                'message_id': str(photos_sent[0]) if photos_sent else '',
                'price': price,
                'row': row,
                'status': 'active',
                'posted_at': now_et_iso(),
                'posted_date': datetime.now(ET).strftime('%Y-%m-%d')
            }
            if _posting_photo:
                log_entry['photo'] = _posting_photo
            log_data.append(log_entry)
            with open(log_path, 'w') as _lf:
                json.dump(log_data, _lf, indent=2)
        except Exception as log_err:
            logger.error(f"Failed to update postings log: {log_err}")

        # Mark as posted in SQLite DB + sync to sheet
        if DB_AVAILABLE and row:
            try:
                update_fields = {'posted': 'Yes'}
                if price:
                    update_fields['sale_price'] = str(price)
                db_update(int(row), **update_fields)
                _bg_sheet_sync([int(row)])
            except Exception as db_err:
                logger.warning(f"DB mark posted failed: {db_err}")

        # Delete old active posting for the same watch before inserting new one
        _watch_id = int(row) if row else None
        _delete_old_postings_for_watch(_watch_id)

        # Insert into DB postings table (golden source)
        try:
            import re as _re_ref
            _ref_m = _re_ref.match(r'(?:Pre-Owned |BNIB |Retail Ready )?(?:Full Set )?(\d{5,6}[A-Za-z]*)', caption)
            _ref = _ref_m.group(1) if _ref_m else ''
            _msg_id = str(photos_sent[0]) if photos_sent else str(result.get('result', {}).get('message_id', ''))
            _db = get_db()
            _db.execute('''INSERT INTO postings (watch_id, ref, description, caption, price, message_id, photo, status, posted_date, posted_at)
                          VALUES (?,?,?,?,?,?,?,?,?,datetime('now','localtime'))''',
                       (int(row) if row else None, _ref, caption, caption, float(price) if price else 0, _msg_id, _posting_photo, 'active', datetime.now(ET).strftime('%Y-%m-%d')))
            # Keep watches.posted and sale_price in sync
            if row:
                _db.execute('UPDATE watches SET posted=1 WHERE id=? AND posted=0', (int(row),))
                if price:
                    _db.execute('UPDATE watches SET sale_price=? WHERE id=? AND (sale_price IS NULL OR sale_price=0)', (float(price), int(row)))
            _db.commit()
        except Exception as _db_post_err:
            logger.warning(f"DB postings insert failed: {_db_post_err}")

        return jsonify({'ok': True, 'photos_sent': len(photos_sent), 'message_id': photos_sent[0] if photos_sent else None})

    except Exception as e:
        logger.error(f"Post to My Postings error: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/repost-watch', methods=['POST'])
@login_required
def api_repost_watch():
    """Repost a watch to My Postings using existing photos and updated caption."""
    try:
        data = request.get_json()
        row = data.get('row')
        
        if not row:
            return jsonify({'success': False, 'error': 'Row number required'}), 400

        # Get watch data from Bot Sheet
        from bot_sheet_automation import read_sheet
        try:
            df = read_sheet()
            watch_data = df[df['Row'] == int(row)]
            if watch_data.empty:
                return jsonify({'success': False, 'error': f'Watch not found in row {row}'}), 404
            watch = watch_data.iloc[0]
        except Exception as e:
            return jsonify({'success': False, 'error': f'Failed to read Bot Sheet: {str(e)}'}), 500

        # Extract watch details for caption generation
        desc = str(watch.get('Description', ''))
        sale_price = watch.get('Sale Price', '') or watch.get('F', '')
        
        # Generate updated caption using existing posting format
        caption_parts = []
        
        # Extract ref from description
        import re
        ref_match = re.search(r'\b(\d{5,6}[A-Z]*)\b', desc)
        ref = ref_match.group(1) if ref_match else ''
        
        # Extract condition
        if 'BNIB' in desc.upper():
            condition = 'BNIB Full Set'
        elif 'pre-owned' in desc.lower() or 'preowned' in desc.lower():
            condition = 'Pre-Owned Full Set'
        else:
            condition = 'Full Set'
        
        # Extract dial and bracelet from description
        dial_color = ''
        bracelet = ''
        if ref.startswith('126'):  # Submariner/GMT patterns
            if 'black' in desc.lower():
                dial_color = 'Black'
            elif 'green' in desc.lower():
                dial_color = 'Green'
            elif 'blue' in desc.lower():
                dial_color = 'Blue'
            if 'oysterflex' in desc.lower():
                bracelet = 'Oysterflex'
            else:
                bracelet = 'Oyster'
        else:
            # Extract colors from description
            if 'black' in desc.lower():
                dial_color = 'Black'
            elif 'white' in desc.lower():
                dial_color = 'White'
            elif 'slate' in desc.lower():
                dial_color = 'Slate'
            elif 'green' in desc.lower():
                dial_color = 'Green'
            elif 'blue' in desc.lower():
                dial_color = 'Blue'
            elif 'wimbledon' in desc.lower():
                dial_color = 'Wimbledon'
            
            if 'president' in desc.lower():
                bracelet = 'President'
            elif 'jubilee' in desc.lower():
                bracelet = 'Jubilee'
            else:
                bracelet = 'Oyster'
        
        # Extract card date (always output MM/YYYY, even if stored as MM/DD/YYYY)
        card_date = str(watch.get('Card Date', '') or watch.get('O', ''))
        full_date_match = re.match(r'(\d{1,2})/\d{1,2}/(\d{4})', card_date)
        mm_yyyy_match = re.match(r'(\d{1,2})/(\d{4})', card_date)
        if full_date_match:
            month_num = full_date_match.group(1).zfill(2)
            year = full_date_match.group(2)
            month_year = f"{month_num}/{year}"
            month_name = datetime.strptime(month_num, '%m').strftime('%B')
            written_date = f"{month_name} {year}"
        elif mm_yyyy_match:
            month_num = mm_yyyy_match.group(1).zfill(2)
            year = mm_yyyy_match.group(2)
            month_year = f"{month_num}/{year}"
            month_name = datetime.strptime(month_num, '%m').strftime('%B')
            written_date = f"{month_name} {year}"
        else:
            month_year = ''
            written_date = ''
        
        # Extract serial prefix from card date (N=month code)
        serial_prefix = ''
        if date_match:
            month_num = int(date_match.group(1))
            serial_prefix = f"N{month_num}"
        
        # Build caption
        caption = f"{condition} {ref}"
        if len(ref) > 6:  # Has suffix, show both full and short ref
            short_ref = ref[:6]
            caption = f"{condition} {ref} {short_ref}"
        
        if bracelet:
            caption += f" {bracelet}"
        if dial_color:
            caption += f" {dial_color} Dial"
        if month_year:
            caption += f" {month_year} {written_date}"
        if serial_prefix:
            caption += f" {serial_prefix}"
        
        # Check for WT (hang tag)
        if 'WT' in desc.upper() or 'hang tag' in desc.lower():
            caption += " with WT"
        
        # Add price on next line
        price_str = str(sale_price).replace('$', '').replace(',', '') if sale_price else ''
        if price_str:
            try:
                price_num = int(float(price_str))
                caption += f"\n${price_num:,} + label"
            except:
                caption += f"\n{sale_price} + label"
        
        # Special case: Bruce Wayne (126710GRNR)
        if ref == '126710GRNR':
            if 'Bruce Wayne' not in caption:
                caption = caption.replace(ref, f"{ref} Bruce Wayne")

        # Post to WhatsApp My Postings group via wacli
        from whatsapp_postings import send_photo as wa_send_photo, send_photos as wa_send_photos, send_text as wa_send_text

        photos_sent = []
        valid_photos = []
        
        # Get existing photos for this watch
        from watch_photo_manager import get_photos
        info = get_photos(row)
        photo_files = info.get('photos', [])

        if photo_files:
            # Convert HEIC to JPEG if needed, collect valid photo paths
            for p in photo_files[:10]:
                fpath = Path(p['path'])
                if not fpath.exists():
                    continue
                if fpath.suffix.lower() in ('.heic', '.heif'):
                    try:
                        from PIL import Image
                        jpeg_path = fpath.with_suffix('.jpg')
                        if not jpeg_path.exists():
                            img = Image.open(str(fpath))
                            img.save(str(jpeg_path), 'JPEG', quality=92)
                        valid_photos.append(jpeg_path)
                    except Exception as conv_err:
                        logger.error(f"HEIC conversion failed: {conv_err}")
                        continue
                else:
                    valid_photos.append(fpath)

        # Send via WhatsApp
        if valid_photos:
            wa_result = wa_send_photos([str(p) for p in valid_photos], caption)
            if wa_result.get('ok'):
                photos_sent = wa_result.get('message_ids', [])
            else:
                logger.error(f"WhatsApp photo send failed: {wa_result.get('error')}")

        # If no photos or photo send failed, send caption only
        if not photos_sent and not valid_photos:
            wa_result = wa_send_text(caption)
            if not wa_result.get('ok'):
                return jsonify({'success': False, 'error': 'Failed to send message', 'detail': wa_result.get('error')}), 500
            photos_sent = [wa_result.get('message_id', '')]

        # Update my_postings_log with new entry
        try:
            log_path = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'my_postings_log.json'
            if log_path.exists():
                with open(log_path) as _lf:
                    log_data = json.load(_lf)
            else:
                log_data = []
            
            # Determine photo filename for the log
            _posting_photo = ''
            if photos_sent and valid_photos:
                try:
                    _photo_path = Path(str(valid_photos[0]))
                    _posting_photo_name = f"posting_{photos_sent[0]}.jpg"
                    _posting_dest = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos' / _posting_photo_name
                    _posting_dest.parent.mkdir(parents=True, exist_ok=True)
                    import shutil
                    shutil.copy2(str(_photo_path), str(_posting_dest))
                    _posting_photo = _posting_photo_name
                except Exception as _photo_err:
                    logger.warning(f"Failed to save posting photo: {_photo_err}")
            
            log_entry = {
                'ref': ref,
                'description': caption,
                'message_id': str(photos_sent[0]),
                'price': price_str,
                'row': row,
                'status': 'active',
                'posted_at': now_et_iso(),
                'posted_date': datetime.now(ET).strftime('%Y-%m-%d')
            }
            if _posting_photo:
                log_entry['photo'] = _posting_photo
            log_data.append(log_entry)
            with open(log_path, 'w') as _lf:
                json.dump(log_data, _lf, indent=2)
        except Exception as log_err:
            logger.error(f"Failed to update postings log: {log_err}")

        return jsonify({
            'success': True, 
            'message_id': photos_sent[0] if photos_sent else None,
            'caption': caption,
            'photos_count': len(valid_photos)
        })

    except Exception as e:
        logger.error(f"Repost watch error: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/batch-invoice', methods=['POST'])
@login_required
def api_batch_invoice():
    """Create invoices for multiple sold watches."""
    try:
        data = request.get_json()
        rows = data.get('rows', [])
        
        if not rows:
            return jsonify({'success': False, 'error': 'No rows provided'}), 400

        # Get watch data from Bot Sheet
        from bot_sheet_automation import read_sheet
        try:
            df = read_sheet()
        except Exception as e:
            return jsonify({'success': False, 'error': f'Failed to read Bot Sheet: {str(e)}'}), 500

        created = 0
        skipped = 0
        invoices_created = []
        
        for row in rows:
            try:
                watch_data = df[df['Row'] == int(row)]
                if watch_data.empty:
                    logger.warning(f"Watch not found in row {row}")
                    skipped += 1
                    continue
                
                watch = watch_data.iloc[0]
                
                # Check if this watch is sold and has customer info
                if watch.get('Sold', '') != 'Yes' or not watch.get('Sold to', ''):
                    logger.warning(f"Row {row}: not sold or no customer")
                    skipped += 1
                    continue
                
                # Extract watch details
                desc = str(watch.get('Description', ''))
                sold_to = str(watch.get('Sold to', ''))
                sold_price = watch.get('Sold Price', '') or watch.get('F', '')
                serial = str(watch.get('Serial', '') or watch.get('P', ''))
                card_date = str(watch.get('Card Date', '') or watch.get('O', ''))
                
                # Extract ref and generate item name
                import re
                ref_match = re.search(r'\b(\d{5,6}[A-Z]*)\b', desc)
                ref = ref_match.group(1) if ref_match else ''
                
                # Generate item name (ref + bracelet + dial)
                item_name = ref
                if 'president' in desc.lower():
                    item_name += ' President'
                elif 'jubilee' in desc.lower():
                    item_name += ' Jubilee'
                elif 'oysterflex' in desc.lower():
                    item_name += ' Oysterflex'
                else:
                    item_name += ' Oyster'
                
                # Extract dial color
                if 'black' in desc.lower():
                    item_name += ' Black'
                elif 'white' in desc.lower():
                    item_name += ' White'
                elif 'slate' in desc.lower():
                    item_name += ' Slate'
                elif 'green' in desc.lower():
                    item_name += ' Green'
                elif 'blue' in desc.lower():
                    item_name += ' Blue'
                elif 'wimbledon' in desc.lower():
                    item_name += ' Wimbledon'
                elif 'gold' in desc.lower():
                    item_name += ' Gold'
                
                # Generate item description (serial + date)
                item_desc = ''
                if serial and serial != 'nan':
                    item_desc = serial
                if card_date and card_date != 'nan':
                    # Extract MM/YYYY from card date if present
                    date_match = re.search(r'(\d{2}/\d{4})', card_date)
                    if date_match:
                        if item_desc:
                            item_desc += f' {date_match.group(1)}'
                        else:
                            item_desc = date_match.group(1)
                
                # Clean up price
                price_str = str(sold_price).replace('$', '').replace(',', '') if sold_price else ''
                try:
                    price_amount = float(price_str) if price_str and price_str != 'nan' else 0
                except ValueError:
                    price_amount = 0
                
                # Create invoice using dashboard API
                invoice_data = {
                    'customer': sold_to,
                    'items': [
                        {
                            'name': item_name,
                            'description': item_desc,
                            'rate': price_amount
                        }
                    ]
                }
                
                # Call internal invoice creation function
                try:
                    invoice_id = create_zoho_invoice_internal(invoice_data)
                    if invoice_id:
                        invoices_created.append({
                            'row': row,
                            'invoice_id': invoice_id,
                            'customer': sold_to,
                            'amount': price_amount
                        })
                        created += 1
                        logger.info(f"Created invoice {invoice_id} for row {row}")
                    else:
                        logger.warning(f"Failed to create invoice for row {row}")
                        skipped += 1
                except Exception as invoice_err:
                    logger.error(f"Invoice creation failed for row {row}: {invoice_err}")
                    skipped += 1
                    
            except Exception as watch_err:
                logger.error(f"Error processing row {row}: {watch_err}")
                skipped += 1
                continue

        return jsonify({
            'success': True,
            'created': created,
            'skipped': skipped,
            'invoices': invoices_created
        })

    except Exception as e:
        logger.error(f"Batch invoice error: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

