@app.route('/api/ocr-process', methods=['POST'])
@login_required  
def api_ocr_process():
    """Process photos with OCR for a specific watch row."""
    try:
        data = request.get_json()
        row = data.get('row')
        update_sheet = data.get('update_sheet', False)
        
        if not row:
            return jsonify({'success': False, 'error': 'Row number required'}), 400
        
        # Import and run OCR
        try:
            import sys
            sys.path.append(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
            from photo_ocr_pipeline import WatchPhotoOCR
            
            ocr = WatchPhotoOCR()
            result = ocr.process_watch_photos(row)
            
            if not result:
                return jsonify({'success': False, 'error': 'No text extracted from photos'}), 400
            
            response_data = {
                'success': True,
                'row': row,
                'extracted_data': result.get('parsed_data', {}),
                'confidence_scores': result.get('confidence', {}),
                'updated_sheet': False
            }
            
            # Update sheet if requested and data was extracted
            if update_sheet and result.get('parsed_data'):
                success = ocr.update_bot_sheet_from_ocr(row, result)
                response_data['updated_sheet'] = success
            
            return jsonify(response_data)
            
        except ImportError as e:
            return jsonify({'success': False, 'error': f'OCR dependencies not installed: {str(e)}'}), 503
        except Exception as e:
            logger.error(f"OCR processing error: {e}")
            return jsonify({'success': False, 'error': str(e)}), 500
            
    except Exception as e:
        logger.error(f"OCR API error: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/ocr-batch', methods=['POST'])
@login_required
def api_ocr_batch():
    """Process OCR for multiple watches in batch."""
    try:
        data = request.get_json() 
        rows = data.get('rows', [])
        update_sheet = data.get('update_sheet', False)
        
        if not rows:
            return jsonify({'success': False, 'error': 'No rows provided'}), 400
        
        try:
            import sys
            sys.path.append(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
            from photo_ocr_pipeline import WatchPhotoOCR
            
            ocr = WatchPhotoOCR()
            processed = 0
            updated = 0
            results = []
            
            for row in rows:
                try:
                    result = ocr.process_watch_photos(row)
                    
                    if result and result.get('parsed_data'):
                        processed += 1
                        
                        row_result = {
                            'row': row,
                            'extracted_data': result.get('parsed_data', {}),
                            'confidence_scores': result.get('confidence', {}),
                            'updated': False
                        }
                        
                        # Update sheet if requested
                        if update_sheet:
                            success = ocr.update_bot_sheet_from_ocr(row, result)
                            if success:
                                updated += 1
                                row_result['updated'] = True
                        
                        results.append(row_result)
                        
                except Exception as row_err:
                    logger.warning(f"OCR failed for row {row}: {row_err}")
                    results.append({
                        'row': row,
                        'error': str(row_err),
                        'updated': False
                    })
            
            return jsonify({
                'success': True,
                'processed': processed,
                'updated': updated,
                'total_rows': len(rows),
                'results': results
            })
            
        except ImportError as e:
            return jsonify({'success': False, 'error': f'OCR dependencies not installed: {str(e)}'}), 503
        except Exception as e:
            logger.error(f"Batch OCR error: {e}")
            return jsonify({'success': False, 'error': str(e)}), 500
            
    except Exception as e:
        logger.error(f"Batch OCR API error: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/watch-documentation', methods=['POST'])
@login_required
def api_watch_documentation():
    """Watch documentation status — reads from SQLite watches + watch_photos tables."""
    try:
        data = request.get_json()
        action = data.get('action', 'get_report')
        db = get_db()

        if action == 'get_report':
            import re as _re
            # Get all unsold, non-deleted watches
            watches = db.execute('''
                SELECT w.id, w.description, w.serial, w.card_date, w.arrived, w.sold, w.wt,
                       (SELECT COUNT(*) FROM watch_photos wp WHERE wp.watch_id = w.id) as photo_count,
                       (SELECT COUNT(*) FROM watch_photos wp WHERE wp.watch_id = w.id AND wp.photo_type = 'hero') as has_hero,
                       (SELECT COUNT(*) FROM watch_photos wp WHERE wp.watch_id = w.id AND wp.photo_type = 'arrival') as has_arrival,
                       (SELECT COUNT(*) FROM watch_photos wp WHERE wp.watch_id = w.id AND wp.photo_type = 'posted') as has_posted
                FROM watches w
                WHERE w.deleted = 0
                ORDER BY w.description ASC
            ''').fetchall()

            sku_report = {}
            total_watches = 0
            total_with_hero = 0
            total_with_serial = 0
            total_with_card_date = 0
            total_arrived = 0
            missing_docs = []

            for w in watches:
                w = dict(w)
                total_watches += 1
                desc = w['description'] or ''
                # Extract ref (first 5-6 digit number with optional suffix)
                ref_match = _re.match(r'(\d{5,6}\w*)', desc)
                ref = ref_match.group(1) if ref_match else 'Unknown'
                short_ref = _re.match(r'(\d{5,6})', ref).group(1) if _re.match(r'(\d{5,6})', ref) else ref

                has_serial = bool(w['serial'])
                has_card = bool(w['card_date'])
                has_hero = w['has_hero'] > 0
                is_arrived = bool(w['arrived'])

                if has_serial: total_with_serial += 1
                if has_card: total_with_card_date += 1
                if has_hero: total_with_hero += 1
                if is_arrived: total_arrived += 1

                # Documentation completeness score
                score = 0
                if has_serial: score += 1
                if has_card: score += 1
                if has_hero: score += 1
                if w['photo_count'] > 0: score += 1
                max_score = 4

                watch_entry = {
                    'id': w['id'],
                    'serial': w['serial'] or '',
                    'description': desc,
                    'row': w['id'],
                    'photo_count': w['photo_count'],
                    'has_hero': has_hero,
                    'has_arrival': w['has_arrival'] > 0,
                    'has_posted': w['has_posted'] > 0,
                    'has_serial': has_serial,
                    'has_card_date': has_card,
                    'card_date': w['card_date'] or '',
                    'arrived': is_arrived,
                    'sold': bool(w['sold']),
                    'wt': w['wt'] or '',
                    'score': score,
                    'max_score': max_score,
                }

                if short_ref not in sku_report:
                    sku_report[short_ref] = {
                        'sku': short_ref,
                        'display_name': ref,
                        'watches': [],
                        'total_count': 0
                    }
                sku_report[short_ref]['watches'].append(watch_entry)
                sku_report[short_ref]['total_count'] += 1

                # Track watches missing documentation (arrived but incomplete)
                if is_arrived and score < max_score:
                    missing_docs.append(watch_entry)

            sku_list = [v for _, v in sorted(sku_report.items())]

            return jsonify({
                'success': True,
                'skus': sku_list,
                'total_watches': total_watches,
                'total_skus': len(sku_report),
                'total_with_hero': total_with_hero,
                'total_with_serial': total_with_serial,
                'total_with_card_date': total_with_card_date,
                'total_arrived': total_arrived,
                'coverage_pct': round(total_with_hero / max(total_arrived, 1) * 100),
                'missing_docs': sorted(missing_docs, key=lambda x: x['score']),
            })

        elif action == 'get_photos':
            watch_id = data.get('watch_id')
            if not watch_id:
                return jsonify({'success': False, 'error': 'Watch ID required'}), 400

            photos = db.execute('''
                SELECT id, file_path, photo_type FROM watch_photos WHERE watch_id = ?
            ''', (watch_id,)).fetchall()

            watch = db.execute('SELECT id, description, serial, card_date FROM watches WHERE id = ?', (watch_id,)).fetchone()

            return jsonify({
                'success': True,
                'watch_info': dict(watch) if watch else {},
                'photos': [{'id': p['id'], 'path': p['file_path'], 'type': p['photo_type']} for p in photos]
            })

        else:
            return jsonify({'success': False, 'error': f'Unknown action: {action}'}), 400

    except Exception as e:
        logger.error(f"Watch documentation API error: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/telegram/send', methods=['POST'])
@login_required
def api_telegram_send():
    """Send a message to any configured Telegram group"""
    try:
        from telegram_integration import get_telegram_bot, TELEGRAM_GROUPS
        data = request.get_json()
        group = data.get('group', '')
        message = data.get('message', '')
        
        if group not in TELEGRAM_GROUPS:
            return jsonify({'error': f'Unknown group: {group}', 'available': list(TELEGRAM_GROUPS.keys())}), 400
        
        bot = get_telegram_bot()
        result = bot.send_message(TELEGRAM_GROUPS[group], message)
        msg_id = result.get('result', {}).get('message_id') if result else None
        return jsonify({'success': bool(result and result.get('ok')), 'message_id': msg_id})
        
    except Exception as e:
        logger.error(f"Telegram send error: {e}")
        return jsonify({'error': str(e)}), 500

