@app.route('/api/payments/collections-dashboard')
@login_required
def api_collections_dashboard():
    """Get collections dashboard data — Bot Sheet is source of truth for receivables.
    Receivable = sold_price where sold=Yes AND paid_after_sold != Yes.
    Zoho invoices supplement with payment details but don't define receivables."""
    try:
        import subprocess, re
        
        # 1. Get all inventory from Bot Sheet
        result = subprocess.run(
            ['python3', str(Path(__file__).parent.parent / 'sheet_updater.py'), 'dump'],
            capture_output=True, text=True, timeout=15
        )
        items = json.loads(result.stdout) if result.returncode == 0 and result.stdout.strip() else []
        
        # 2. Build receivables from SQLite (sold + not paid, cross-check invoices)
        receivables = []
        total_receivables = 0
        _ar_db = get_db()
        _ar_watches = _ar_db.execute('''
            SELECT w.id, w.description, w.sold_to, w.sold_price, w.sale_price, w.shipped, w.paid_buyer, w.sale_date, w.serial,
                   i.status as inv_status, i.total as inv_total, i.payment_date as inv_payment_date
            FROM watches w
            LEFT JOIN internal_invoices i ON i.watch_id = w.id AND i.status != 'void'
            WHERE w.sold = 1 AND w.deleted = 0
            ORDER BY w.id
        ''').fetchall()
        for w in _ar_watches:
            # Consider paid if EITHER watches.paid_buyer=1 OR invoice status='paid'
            is_paid = bool(w['paid_buyer']) or (w['inv_status'] == 'paid')
            if is_paid:
                continue
            amount = w['sold_price'] or w['sale_price'] or w['inv_total'] or 0
            receivables.append({
                'row': w['id'],
                'ref': w['description'] or '',
                'counterparty': w['sold_to'] or '?',
                'amount': float(amount) if amount else 0,
                'shipped': bool(w['shipped']),
                'sale_date': w['sale_date'] or '',
                'serial': w['serial'] or '',
                'invoice_status': w['inv_status'] or 'no invoice',
            })
            total_receivables += float(amount) if amount else 0
        
        # 3. Build payables from SQLite (arrived but seller not paid)
        payables = []
        total_payables = 0
        _ap_watches = _ar_db.execute('''
            SELECT id, description, bought_from, cost_price, sold, sold_to
            FROM watches
            WHERE paid_supplier = 0 AND deleted = 0 AND cost_price > 0
        ''').fetchall()
        for w in _ap_watches:
            amount = float(w['cost_price']) if w['cost_price'] else 0
            if amount > 0:
                payables.append({
                    'row': w['id'],
                    'ref': w['description'] or '',
                    'counterparty': w['bought_from'] or '?',
                    'amount': amount,
                })
                total_payables += amount
        
        # 4. Overdue = shipped but not paid (most urgent)
        overdue_receivables = [r for r in receivables if r['shipped']]
        overdue_total = sum(r['amount'] for r in overdue_receivables)
        
        return jsonify({
            'cash_flow': {
                'total_receivables': total_receivables,
                'total_payables': total_payables,
                'net_position': total_receivables - total_payables,
                'overdue_receivables': overdue_total,
            },
            'overdue_receivables': overdue_receivables,
            'pending_receivables': [r for r in receivables if not r['shipped']],
            'overdue_payables': payables,
            'reminders_due': [],
        })
        
    except Exception as e:
        logger.error(f"Collections dashboard error: {e}")
        return jsonify({'error': str(e)}), 500

