@app.route('/api/payments/sin-cashflow/add', methods=['POST'])
@login_required
def api_sin_cashflow_add():
    """Add an entry to Sin cash flow sheet.
    Body: { side: 'outflow'|'inflow', type: 'wire'|'watch'|'crypto'|'expense'|'cash',
            description, amount, cost?, cleared?, tracking?, date? }
    """
    data = request.get_json() or {}
    side = data.get('side')
    desc = data.get('description', '').strip()
    amount = data.get('amount')
    cost = data.get('cost')
    cleared = data.get('cleared', 'Yes')
    tracking = data.get('tracking', '')
    entry_date = data.get('date')

    if not side or not desc:
        return jsonify({'error': 'side and description required'}), 400

    try:
        from sin_cashflow import add_outflow, add_inflow
        if side == 'outflow':
            if not amount:
                return jsonify({'error': 'amount required for outflow'}), 400
            result = add_outflow(desc, float(amount), entry_date=entry_date)
        elif side == 'inflow':
            amt = float(amount) if amount else None
            cst = float(cost) if cost else None
            result = add_inflow(desc, amount=amt, cost=cst, cleared=cleared,
                              tracking=tracking, entry_date=entry_date)
        else:
            return jsonify({'error': 'side must be outflow or inflow'}), 400

        return jsonify(result)
    except Exception as e:
        logger.error(f"Sin cashflow add error: {e}")
        return jsonify({'error': str(e)}), 500

