@app.route('/api/photos/upload', methods=['POST'])
@login_required
def api_upload_photo():
    """Upload photo"""
    try:
        from photo_manager import get_photo_manager
        manager = get_photo_manager()
        
        if 'file' not in request.files:
            return jsonify({'error': 'No file provided'}), 400
        
        file = request.files['file']
        if file.filename == '':
            return jsonify({'error': 'No file selected'}), 400
        
        category = request.form.get('category', 'general')
        ref = request.form.get('ref')
        tags = request.form.get('tags', '').split(',') if request.form.get('tags') else []
        
        file_data = file.read()
        photo_id = manager.upload_photo(file_data, file.filename, category, ref, tags)
        
        if photo_id:
            # Update posting-specific fields if provided
            photo = manager.get_photo(photo_id)
            if photo:
                for field in ('dial', 'bracelet', 'condition', 'year', 'posting_text', 'source'):
                    val = request.form.get(field, '').strip()
                    if val:
                        setattr(photo, field, val)
                manager._save_database()
            return jsonify({'success': True, 'photo_id': photo_id})
        else:
            return jsonify({'error': 'Failed to upload photo'}), 500
            
    except Exception as e:
        logger.error(f"Upload photo error: {e}")
        return jsonify({'error': str(e)}), 500

