@app.route('/api/watch-photos/search-library')
@login_required
def api_watch_photos_search_library():
    """Search watch_photos table for photos from ANY watch matching the ref."""
    try:
        ref = (request.args.get('ref') or '').strip()
        limit = int(request.args.get('limit', 6))
        if not ref:
            return jsonify({'photos': []})
        
        # Strip suffix letters for broader matching (126234LN -> 126234)
        import re
        ref_base = re.match(r'(\d{5,6})', ref)
        ref_pattern = f'%{ref_base.group(1)}%' if ref_base else f'%{ref}%'
        
        conn = get_db()
        rows = conn.execute('''
            SELECT wp.id, wp.watch_id, wp.file_path, wp.photo_type, wp.created_at,
                   w.description
            FROM watch_photos wp
            JOIN watches w ON w.id = wp.watch_id
            WHERE w.description LIKE ? AND w.deleted = 0
            ORDER BY wp.created_at DESC
            LIMIT ?
        ''', (ref_pattern, limit)).fetchall()
        conn.close()
        
        results = []
        for r in rows:
            if not os.path.exists(r['file_path']):
                continue
            import re as _re
            desc = r['description'] or ''
            ref_m = _re.search(r'(\d{5,6}\w*)', desc)
            dial_words = ['Black Diamond','Green Diamond','Blue','Green','Black','White','Champagne','Silver','Slate','Mint','Polar','Pink','Grey','Wimbledon','Palm','Beige','Aubergine','MOP']
            dial_val = ''
            for dw in dial_words:
                if dw.lower() in desc.lower():
                    dial_val = dw; break
            results.append({
                'id': r['id'],
                'watch_id': r['watch_id'],
                'filename': os.path.basename(r['file_path']),
                'photo_type': r['photo_type'],
                'description': r['description'],
                'ref': ref_m.group(1) if ref_m else '',
                'dial': dial_val,
                'url': f'/api/watch-photo/{r["id"]}',
                '_isLibrary': True,
            })
        
        return jsonify({'photos': results, 'total': len(results)})
    except Exception as e:
        logger.error(f"Library search error: {e}")
        return jsonify({'error': str(e)}), 500


@app.route('/api/watch-photos/library/<watch_id>/image')
@login_required
def api_watch_photos_library_image(watch_id):
    """Serve a library photo by watch_id from the redacted folder."""
    try:
        import json as _json
        workspace = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
        idx_path = os.path.join(workspace, 'watch_photos', 'photo_index.json')
        with open(idx_path) as f:
            idx = _json.load(f)
        w = idx.get('watches', {}).get(watch_id)
        if not w:
            return 'Not found', 404
        img_path = w.get('redacted_path') or w.get('path', '')
        if not os.path.exists(img_path):
            img_path = w.get('path', '')
        if not os.path.exists(img_path):
            return 'File not found', 404
        # Auto-orient based on EXIF
        try:
            from PIL import Image as PILImage, ImageOps
            pimg = PILImage.open(img_path)
            pimg = ImageOps.exif_transpose(pimg)
            import io as _io
            buf = _io.BytesIO()
            pimg.save(buf, format='JPEG', quality=90)
            buf.seek(0)
            from flask import send_file as _send_file
            return _send_file(buf, mimetype='image/jpeg')
        except Exception:
            from flask import send_file as _send_file
            return _send_file(img_path, mimetype='image/jpeg')
    except Exception as e:
        return str(e), 500


@app.route('/api/watch-photos')
@login_required
def api_watch_photos_list():
    """List all watches with photo and documentation status (from SQLite)."""
    try:
        import re as _re
        db = get_db()
        watches = db.execute('''
            SELECT w.id, w.description, w.serial, w.card_date, w.arrived, w.sold, w.sold_to,
                   (SELECT COUNT(*) FROM watch_photos wp WHERE wp.watch_id = w.id) as photo_count,
                   (SELECT COUNT(*) FROM watch_photos wp WHERE wp.watch_id = w.id AND wp.photo_type = 'hero') as has_hero,
                   (SELECT COUNT(*) FROM watch_photos wp WHERE wp.watch_id = w.id AND wp.photo_type = 'posted') as has_posted
            FROM watches w
            WHERE w.deleted = 0
            ORDER BY w.description ASC
        ''').fetchall()
        
        result = []
        for w in watches:
            w = dict(w)
            desc = w['description'] or ''
            ref_match = _re.match(r'(\d{5,6}\w*)', desc)
            ref = ref_match.group(1) if ref_match else ''
            # Parse dial/bracelet from description
            parts = desc.split()
            model = ref
            bracelet = ''
            dial = ''
            for p in parts[1:]:
                if p.lower() in ('oyster','jubilee','oysterflex','president'):
                    bracelet = p
                elif p.lower() not in ('with','wt','full','set') and not _re.match(r'\d{2}/\d{4}', p):
                    if not dial:
                        dial = p
                    else:
                        dial += ' ' + p
            # Strip date from dial
            dial = _re.sub(r'\d{2}/\d{4}.*', '', dial).strip()
            
            card_date = w['card_date'] or ''
            # Extract MM/YYYY from description if no card_date
            if not card_date:
                date_match = _re.search(r'(\d{2}/\d{4})', desc)
                if date_match:
                    card_date = date_match.group(1)
            
            condition = 'BNIB' if 'BNIB' in desc else ('Pre-owned' if 'Pre-Owned' in desc or 'Pre-owned' in desc else '')
            
            result.append({
                'watch_id': str(w['id']),
                'model': model,
                'dial': dial,
                'bracelet': bracelet,
                'condition': condition,
                'card_date': card_date,
                'serial': w['serial'] or '',
                'has_hero': w['has_hero'] > 0,
                'has_posted': w['has_posted'] > 0,
                'has_photos': w['photo_count'] > 0,
                'photo_count': w['photo_count'],
                'arrived': bool(w['arrived']),
                'sold': bool(w['sold']),
                'sold_to': w['sold_to'] or '',
            })
        
        return jsonify({'watches': result})
    except Exception as e:
        logger.error(f"Watch photos list error: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/watch-photos/<int:row>')
@login_required
def api_watch_photos_get(row):
    """Get photos for a specific watch row."""
    try:
        # Check DB watch_photos table first
        db = get_db()
        db_photos = db.execute('SELECT id, file_path, photo_type, created_at FROM watch_photos WHERE watch_id=? ORDER BY created_at DESC', (row,)).fetchall()
        photos = []
        for p in db_photos:
            fp = Path(p['file_path'])
            if fp.exists():
                photos.append({
                    'id': p['id'],
                    'filename': fp.name,
                    'path': str(fp),
                    'photo_type': p['photo_type'],
                    'source': 'db'
                })
        # Also check watch_photo_manager for legacy photos
        try:
            from watch_photo_manager import get_photos
            info = get_photos(row)
            if info and info.get('photos'):
                existing_paths = {p['path'] for p in photos}
                for mp in info['photos']:
                    if mp.get('path') not in existing_paths:
                        photos.append(mp)
        except Exception:
            pass
        if not photos:
            return jsonify({'error': 'No photos found'}), 404
        return jsonify({'row': row, 'photos': photos, 'photo_count': len(photos)})
    except Exception as e:
        logger.error(f"Watch photos get error: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/watch-photos/<int:row>/images/<filename>', methods=['GET'])
@login_required
def api_watch_photo_serve(row, filename):
    """Serve a specific watch photo file."""
    try:
        # Check DB watch_photos table first
        db = get_db()
        db_photos = db.execute('SELECT file_path FROM watch_photos WHERE watch_id=?', (row,)).fetchall()
        for p in db_photos:
            fp = Path(p['file_path'])
            if fp.name == filename and fp.exists():
                return send_from_directory(str(fp.parent), fp.name)
        # Also check watch_library directly
        lib = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'watch_library'
        lib_path = lib / filename
        if lib_path.exists():
            return send_from_directory(str(lib), filename)
        # Legacy: check watch_photo_manager
        from watch_photo_manager import get_photos
        info = get_photos(row)
        for photo in (info or {}).get('photos', []):
            if photo['filename'] == filename:
                photo_path = Path(photo['path'])
                if photo_path.exists():
                    if photo_path.suffix.lower() in ('.heic', '.heif'):
                        jpg_path = photo_path.with_suffix('.jpg')
                        if not jpg_path.exists():
                            try:
                                from PIL import Image
                                img = Image.open(str(photo_path))
                                img.save(str(jpg_path), 'JPEG', quality=92)
                            except Exception:
                                pass
                        if jpg_path.exists():
                            return send_from_directory(str(jpg_path.parent), jpg_path.name)
                    return send_from_directory(str(photo_path.parent), photo_path.name)
        return jsonify({'error': 'Photo not found'}), 404
    except Exception as e:
        logger.error(f"Watch photo serve error: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/watch-photos/<watch_id>/image', methods=['GET'])
@login_required  
def api_watch_photo_serve_by_id(watch_id):
    """Serve a photo by watch ID — prefers posting photo (WhatsApp listing), then watch_photos."""
    try:
        from flask import send_file
        db = get_db()
        posting_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos'
        
        # Posting photo first — this is the actual listing photo used on WhatsApp
        posting_photo = db.execute(
            "SELECT photo FROM postings WHERE watch_id=? AND status='active' AND photo IS NOT NULL AND photo != '' ORDER BY posted_at DESC LIMIT 1",
            (watch_id,)
        ).fetchone()
        if posting_photo and posting_photo[0]:
            posting_path = posting_dir / posting_photo[0]
            if posting_path.exists():
                return send_file(str(posting_path), as_attachment=False)
            if Path(posting_photo[0]).exists():
                return send_file(posting_photo[0], as_attachment=False)
        
        # Fallback: watch_photos table (hero > arrival > other)
        photo = db.execute(
            "SELECT file_path FROM watch_photos WHERE watch_id=? ORDER BY CASE photo_type WHEN 'hero' THEN 0 WHEN 'arrival' THEN 1 WHEN 'posted' THEN 2 ELSE 3 END LIMIT 1",
            (watch_id,)
        ).fetchone()
        
        if photo and Path(photo['file_path']).exists():
            return send_file(photo['file_path'], as_attachment=False)
        
        # Fallback: check legacy watch_photo_manager index
        try:
            import sys
            workspace_dir = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
            if workspace_dir not in sys.path:
                sys.path.insert(0, workspace_dir)
            from watch_photo_manager import _load_index
            index = _load_index()
            if str(watch_id) in index.get('watches', {}):
                legacy_path = Path(index['watches'][str(watch_id)].get('path', ''))
                if legacy_path.exists():
                    return send_file(legacy_path, as_attachment=False)
        except Exception:
            pass
        
        return jsonify({'error': 'No photo found'}), 404
        
    except Exception as e:
        logger.error(f"Watch photo serve by ID error: {e}")
        return jsonify({'error': str(e)}), 500

