@app.route('/api/watch-photos/<watch_id>', methods=['DELETE'])
@login_required
def api_delete_library_photo(watch_id):
    """Delete a photo from the library."""
    try:
        import sys, os as _os
        workspace_dir = _os.path.dirname(_os.path.dirname(_os.path.abspath(__file__)))
        if workspace_dir not in sys.path:
            sys.path.insert(0, workspace_dir)
        from watch_photo_manager import _load_index, _save_index

        index = _load_index()
        if watch_id not in index.get('watches', {}):
            return jsonify({'error': 'Watch not found'}), 404

        watch_info = index['watches'][watch_id]
        photo_path = Path(watch_info.get('path', ''))

        # Delete the file
        if photo_path.exists():
            photo_path.unlink()
            logger.info(f"Deleted photo file: {photo_path}")

        # Remove from index
        del index['watches'][watch_id]

        # Remove from any row mappings
        for row_str, watch_ids in list(index.get('mappings', {}).items()):
            if watch_id in watch_ids:
                watch_ids.remove(watch_id)
                if not watch_ids:
                    del index['mappings'][row_str]

        _save_index(index)
        logger.info(f"Deleted photo {watch_id} from library index")
        return jsonify({'ok': True})

    except Exception as e:
        logger.error(f"Delete library photo error: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/watch-photos/<watch_id>/update', methods=['POST'])
@login_required
def api_update_watch_metadata(watch_id):
    """Update watch metadata (model, dial, bracelet, condition, card_date). Logs corrections and enriches reference dictionary."""
    try:
        import sys, os as _os
        workspace_dir = _os.path.dirname(_os.path.dirname(_os.path.abspath(__file__)))
        if workspace_dir not in sys.path:
            sys.path.insert(0, workspace_dir)
        from watch_photo_manager import _load_index, _save_index
        from datetime import datetime

        index = _load_index()
        if watch_id not in index.get('watches', {}):
            return jsonify({'error': 'Watch not found'}), 404

        data = request.get_json() or {}
        editable = ['model', 'dial', 'bracelet', 'condition', 'card_date']
        watch = index['watches'][watch_id]
        changes = {}

        for field in editable:
            if field in data and data[field] != watch.get(field, ''):
                changes[field] = {'was': watch.get(field, ''), 'now': data[field]}
                watch[field] = data[field]

        if not changes:
            return jsonify({'ok': True, 'changes': 0})

        _save_index(index)

        # Log corrections and enrich reference dictionary
        ref_path = os.path.join(workspace_dir, 'watch_reference.json')
        try:
            with open(ref_path, 'r') as f:
                ref = json.load(f)
        except Exception:
            ref = {"version": "1.0", "models": {}, "conditions": [], "corrections": []}

        model_ref = data.get('model') or watch.get('model', '')

        # Record correction
        for field, change in changes.items():
            ref.setdefault('corrections', []).append({
                'photo': watch_id,
                'field': field,
                'was': change['was'],
                'corrected_to': change['now'],
                'ref': model_ref,
                'timestamp': now_et_iso()
            })

        # Enrich model dictionary
        if model_ref:
            m = ref.setdefault('models', {}).setdefault(model_ref, {'dials': [], 'bracelets': []})
            new_dial = data.get('dial') or watch.get('dial', '')
            new_bracelet = data.get('bracelet') or watch.get('bracelet', '')
            new_condition = data.get('condition') or watch.get('condition', '')

            if new_dial and new_dial not in m.get('dials', []):
                m.setdefault('dials', []).append(new_dial)
            if new_bracelet and new_bracelet not in m.get('bracelets', []):
                m.setdefault('bracelets', []).append(new_bracelet)
            if new_condition and new_condition not in ref.get('conditions', []):
                ref.setdefault('conditions', []).append(new_condition)

        ref['updated'] = datetime.now(ET).strftime('%Y-%m-%d')
        with open(ref_path, 'w') as f:
            json.dump(ref, f, indent=2)

        logger.info(f"Updated {watch_id}: {changes}")
        return jsonify({'ok': True, 'changes': len(changes), 'details': changes})

    except Exception as e:
        logger.error(f"Update watch metadata error: {e}")
        return jsonify({'error': str(e)}), 500

