@app.route('/api/watch-photos/save-from-telegram', methods=['POST'])
@login_required
def api_save_telegram_photo():
    """Download a photo from Telegram and save it for a watch."""
    try:
        from watch_photo_manager import save_photo_bytes
        data = request.get_json()
        row = data.get('row')
        description = data.get('description', '')
        file_id = data.get('file_id')
        serial = data.get('serial')

        if not row or not file_id:
            return jsonify({'error': 'row and file_id required'}), 400

        bot_token = os.environ.get('TELEGRAM_BOT_TOKEN', '')
        if not bot_token:
            return jsonify({'error': 'Telegram bot token not configured'}), 503

        import requests as req
        # Get file path from Telegram
        r = req.get(f'https://api.telegram.org/bot{bot_token}/getFile?file_id={file_id}')
        file_info = r.json()
        if not file_info.get('ok'):
            return jsonify({'error': 'Could not get file from Telegram'}), 400

        file_path = file_info['result']['file_path']
        ext = '.' + file_path.rsplit('.', 1)[-1] if '.' in file_path else '.jpg'

        # Download the file
        r2 = req.get(f'https://api.telegram.org/file/bot{bot_token}/{file_path}')
        if r2.status_code != 200:
            return jsonify({'error': 'Could not download file'}), 400

        saved_path = save_photo_bytes(row, description, r2.content, ext=ext, source='jam_masuk', serial=serial)
        return jsonify({'ok': True, 'path': saved_path})

    except Exception as e:
        logger.error(f"Save telegram photo error: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/watch-photos/<int:row>/images/<filename>', methods=['DELETE'])
@login_required
def api_watch_photo_delete(row, filename):
    """Delete a specific photo from a watch."""
    try:
        # Try DB first (watch_photos table)
        db = get_db()
        db_photo = db.execute(
            'SELECT id, file_path FROM watch_photos WHERE watch_id=? AND file_path LIKE ?',
            (row, f'%{filename}')
        ).fetchone()
        if db_photo:
            # Delete from DB
            db.execute('DELETE FROM watch_photos WHERE id=?', (db_photo['id'],))
            db.commit()
            # Optionally delete file (keep for library)
            # fpath = Path(db_photo['file_path'])
            # if fpath.exists(): fpath.unlink()
            db.close()
            return jsonify({'ok': True})

        # Fallback: legacy file index
        from watch_photo_manager import get_photos, _load_index, _save_index
        info = get_photos(row)
        photos = (info or {}).get('photos', [])
        found = None
        for p in photos:
            if p['filename'] == filename:
                found = p
                break
        if not found:
            db.close()
            return jsonify({'error': 'Photo not found'}), 404

        # Delete file
        fpath = Path(found['path'])
        if fpath.exists():
            fpath.unlink()
        jpg_path = fpath.with_suffix('.jpg')
        if jpg_path.exists() and fpath.suffix.lower() in ('.heic', '.heif'):
            jpg_path.unlink()

        # Update index
        index = _load_index()
        key = str(row)
        if key in index:
            index[key]['photos'] = [p for p in index[key]['photos'] if p['filename'] != filename]
            if not index[key]['photos']:
                del index[key]
            _save_index(index)

        db.close()
        return jsonify({'ok': True})
    except Exception as e:
        logger.error(f"Watch photo delete error: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/watch-photos/upload', methods=['POST'])
@login_required
def api_watch_photo_upload():
    """Upload a photo directly for a watch. Supports HEIC auto-conversion."""
    try:
        from watch_photo_manager import save_photo_bytes
        row = request.form.get('row', type=int)
        description = request.form.get('description', '')
        serial = request.form.get('serial')
        source = request.form.get('source', 'manual')

        if not row:
            return jsonify({'error': 'row required'}), 400

        file = request.files.get('photo')
        if not file:
            return jsonify({'error': 'No photo file provided'}), 400

        ext = '.' + file.filename.rsplit('.', 1)[-1] if '.' in file.filename else '.jpg'
        file_bytes = file.read()

        # Auto-convert HEIC/HEIF to JPEG
        if ext.lower() in ('.heic', '.heif'):
            file_bytes = _convert_heic_bytes(file_bytes)
            ext = '.jpg'

        saved_path = save_photo_bytes(row, description, file_bytes, ext=ext, source=source, serial=serial)
        return jsonify({'ok': True, 'path': saved_path})

    except Exception as e:
        logger.error(f"Watch photo upload error: {e}")
        return jsonify({'error': str(e)}), 500

def _convert_heic_bytes(data):
    """Convert HEIC/HEIF bytes to JPEG bytes using Pillow or sips."""
    import io
    try:
        from PIL import Image
        img = Image.open(io.BytesIO(data))
        buf = io.BytesIO()
        img.convert('RGB').save(buf, 'JPEG', quality=92)
        return buf.getvalue()
    except Exception:
        pass
    # Fallback: macOS sips
    import tempfile, subprocess
    try:
        with tempfile.NamedTemporaryFile(suffix='.heic', delete=False) as tmp:
            tmp.write(data)
            tmp_path = tmp.name
        out_path = tmp_path.replace('.heic', '.jpg')
        subprocess.run(['sips', '-s', 'format', 'jpeg', tmp_path, '--out', out_path],
                       capture_output=True, timeout=15)
        with open(out_path, 'rb') as f:
            result = f.read()
        os.unlink(tmp_path)
        os.unlink(out_path)
        return result
    except Exception as e:
        logger.error(f"HEIC conversion failed: {e}")
        raise ValueError("Cannot convert HEIC. Install Pillow with HEIC support or use macOS.")

@app.route('/api/watch-photos/<watch_id>/auto-redact', methods=['POST'])
@login_required
def api_auto_redact_photo(watch_id):
    """Auto-redact serial numbers and dates from a photo using OCR."""
    try:
        import sys, os as _os
        workspace_dir = _os.path.dirname(_os.path.dirname(_os.path.abspath(__file__)))
        if workspace_dir not in sys.path:
            sys.path.insert(0, workspace_dir)
        from watch_photo_manager import _load_index, _save_index
        from smart_redactor import redact_image

        index = _load_index()
        if watch_id not in index.get('watches', {}):
            return jsonify({'error': 'Watch not found'}), 404

        watch_info = index['watches'][watch_id]
        photo_path = Path(watch_info.get('path', ''))
        if not photo_path.exists():
            return jsonify({'error': 'Photo not found'}), 404

        data = request.get_json() or {}
        known_serial = data.get('serial', watch_info.get('serial', ''))

        result = redact_image(str(photo_path), str(photo_path), known_serial=known_serial, padding=15)

        return jsonify({
            'ok': True,
            'redaction_count': result['redaction_count'],
            'detections': [{'text': d['text'], 'type': d['type'], 'reason': d['reason']} for d in result['detections']]
        })

    except Exception as e:
        logger.error(f"Auto-redact error: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/auto-redact', methods=['POST'])
@login_required
def api_auto_redact_upload():
    """Auto-redact an uploaded image. Returns the redacted image."""
    try:
        import sys, os as _os
        workspace_dir = _os.path.dirname(_os.path.dirname(_os.path.abspath(__file__)))
        if workspace_dir not in sys.path:
            sys.path.insert(0, workspace_dir)

        file = request.files.get('image')
        if not file:
            return jsonify({'error': 'No image'}), 400

        known_serial = request.form.get('serial', '')
        image_bytes = file.read()

        # Convert HEIC if needed
        name = (file.filename or '').lower()
        if name.endswith('.heic') or name.endswith('.heif'):
            image_bytes = _convert_heic_bytes(image_bytes)

        # Try vision-based redactor first (more reliable), fall back to OCR
        try:
            from vision_redactor import redact_bytes
            result = redact_bytes(image_bytes, known_serial=known_serial, padding=10)
        except Exception as vision_err:
            logger.warning(f"Vision redactor failed ({vision_err}), falling back to OCR")
            from smart_redactor import redact_bytes as ocr_redact_bytes
            result = ocr_redact_bytes(image_bytes, known_serial=known_serial, padding=15)

        from flask import Response
        return Response(
            result['redacted_bytes'],
            mimetype='image/jpeg',
            headers={
                'X-Redaction-Count': str(result['redaction_count']),
                'X-Detections': json.dumps([{'text': d['text'], 'type': d['type']} for d in result['detections']])
            }
        )

    except Exception as e:
        logger.error(f"Auto-redact upload error: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/convert-heic', methods=['POST'])
@login_required
def api_convert_heic():
    """Convert an uploaded HEIC file to JPEG and return it."""
    file = request.files.get('file')
    if not file:
        return jsonify({'error': 'No file'}), 400
    try:
        data = _convert_heic_bytes(file.read())
        return Response(data, mimetype='image/jpeg')
    except Exception as e:
        return jsonify({'error': str(e)}), 500


# ── FX Calculator with Wise Fees ──────────────────────────────────────────────
import urllib.request as _urlreq

_FX_CACHE = {}  # {pair: (rate, timestamp)}
_FX_CACHE_TTL = 300  # 5 minutes

# Wise fee schedule (% of transfer amount, from balance)
_WISE_FEES = {
    ('USD', 'HKD'): 0.0041,
    ('USD', 'CAD'): 0.0043,
    ('USD', 'IDR'): 0.0051,
    ('HKD', 'USD'): 0.0041,
    ('CAD', 'USD'): 0.0043,
    ('IDR', 'USD'): 0.0104,
    ('HKD', 'CAD'): 0.0055,
    ('HKD', 'IDR'): 0.0060,
    ('CAD', 'HKD'): 0.0055,
    ('CAD', 'IDR'): 0.0060,
    ('IDR', 'HKD'): 0.0104,
    ('IDR', 'CAD'): 0.0104,
}

def _get_wise_rate(source, target):
    """Get mid-market rate from Wise, with caching."""
    pair = f"{source}_{target}"
    now = time.time()
    if pair in _FX_CACHE and now - _FX_CACHE[pair][1] < _FX_CACHE_TTL:
        return _FX_CACHE[pair][0]
    try:
        url = f"https://wise.com/rates/live?source={source}&target={target}"
        req = _urlreq.Request(url, headers={'User-Agent': 'MKOpulence/1.0'})
        with _urlreq.urlopen(req, timeout=5) as resp:
            data = json.loads(resp.read().decode())
            rate = data.get('value')
            if rate:
                _FX_CACHE[pair] = (rate, now)
                return rate
    except Exception as e:
        print(f"FX rate fetch error {source}->{target}: {e}")
    return None

@app.route('/api/fx/convert')
@login_required
def fx_convert():
    """Convert currency with Wise mid-market rate and fee estimate.
    Params: amount, from, to (currency codes)
    """
    try:
        amount = float(request.args.get('amount', 10000))
        source = request.args.get('from', 'USD').upper()
        target = request.args.get('to', 'HKD').upper()

        supported = ['USD', 'HKD', 'CAD', 'IDR']
        if source not in supported or target not in supported:
            return jsonify({'error': f'Supported currencies: {", ".join(supported)}'}), 400
        if source == target:
            return jsonify({'error': 'Source and target must differ'}), 400

        rate = _get_wise_rate(source, target)
        if not rate:
            return jsonify({'error': 'Could not fetch exchange rate'}), 503

        fee_pct = _WISE_FEES.get((source, target), 0.005)
        fee_amount = round(amount * fee_pct, 2)
        net_amount = amount - fee_amount
        converted = round(net_amount * rate, 2)
        converted_no_fee = round(amount * rate, 2)

        return jsonify({
            'source': source,
            'target': target,
            'amount': amount,
            'rate': rate,
            'fee_pct': round(fee_pct * 100, 3),
            'fee_amount': fee_amount,
            'net_amount': net_amount,
            'converted': converted,
            'converted_no_fee': converted_no_fee,
            'fee_savings': round(converted_no_fee - converted, 2),
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/fx/rates')
@login_required
def fx_rates():
    """Get all supported FX rates at once."""
    try:
        pairs = [
            ('USD', 'HKD'), ('USD', 'CAD'), ('USD', 'IDR'),
            ('HKD', 'USD'), ('CAD', 'USD'), ('IDR', 'USD'),
        ]
        rates = {}
        for s, t in pairs:
            r = _get_wise_rate(s, t)
            if r:
                fee_pct = _WISE_FEES.get((s, t), 0.005)
                rates[f"{s}_{t}"] = {
                    'rate': r,
                    'fee_pct': round(fee_pct * 100, 3),
                    'effective_rate': round(r * (1 - fee_pct), 6),
                }
        return jsonify({'rates': rates, 'timestamp': int(time.time())})
    except Exception as e:
        return jsonify({'error': str(e)}), 500


