@app.route('/api/public/posting-photo/<filename>')
def serve_posting_photo_public(filename):
    """Serve posting photos publicly (for Google Sheets IMAGE formula)."""
    import re
    if not re.match(r'^posting_[\w\-]+\.(jpg|jpeg|png)$', filename):
        return 'Invalid filename', 400
    photos_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos'
    response = send_from_directory(str(photos_dir), filename, mimetype='image/jpeg')
    # Remove restrictive CSP for public photo serving (Google Sheets needs to embed these)
    response.headers.pop('Content-Security-Policy', None)
    response.headers.pop('X-Frame-Options', None)
    response.headers['Access-Control-Allow-Origin'] = '*'
    response.headers['Cache-Control'] = 'public, max-age=86400'
    return response

