def _fb_parse_watch(row_dict):
    """Parse a watch dict for Facebook bundle grouping."""
    import re
    desc = row_dict.get('description', '')
    ref_match = re.match(r'(?:BNIB|Pre-Owned|Unworn|Used|NOS|Like New)?\s*(?:Full Set\s+)?(\d{5,6}[A-Z]*)', desc)
    ref = ref_match.group(1) if ref_match else ''
    ref_num = re.match(r'(\d+)', ref).group(1) if ref and re.match(r'(\d+)', ref) else ''
    
    model, size_mm = '', 0
    if ref_num:
        prefix3 = ref_num[:3]
        mid2 = ref_num[3:5] if len(ref_num) >= 5 else ''
        if prefix3 in ('126', '116'):
            mapping = {'10': ('Submariner', 41), '13': ('Datejust', 36), '23': ('Datejust', 36),
                       '33': ('Datejust', 41), '34': ('Datejust', 41), '00': ('OP', 36),
                       '30': ('OP', 36), '51': ('Daytona', 40), '61': ('Submariner', 41),
                       '71': ('GMT-Master II', 40), '90': ('Explorer', 36)}
            model, size_mm = mapping.get(mid2, ('', 0))
        elif prefix3 == '228': model, size_mm = 'Day-Date', 40
        elif prefix3 == '278': model, size_mm = 'Datejust', 31
        elif prefix3 == '276': model, size_mm = 'OP', 28
        elif prefix3 == '124': model, size_mm = ('OP', 41) if '12400' in ref_num or '12430' in ref_num else ('OP', 34)
        elif prefix3 == '134': model, size_mm = 'OP', 41
        elif prefix3 == '336': model, size_mm = 'Sky-Dweller', 42
        elif prefix3 in ('214', '216', '226'): model, size_mm = 'Explorer', 42
        elif prefix3 == '224': model, size_mm = 'Explorer', 40
        elif prefix3 == '155': model, size_mm = 'Royal Oak', 41
    
    row_dict['ref'] = ref
    row_dict['model'] = model
    row_dict['size_mm'] = size_mm
    row_dict['price'] = float(row_dict['sale_price']) if row_dict.get('sale_price') else 0
    return row_dict


def _fb_build_bundles(watches, bundle_size=5):
    """Build bundles of exactly `bundle_size` watches using smart grouping.
    Priority: same ref → same model+size → same model → similar price."""
    used = set()
    bundles = []
    
    # Helper: pick watches not yet used
    def available(pool):
        return [w for w in pool if w['id'] not in used]
    
    # Group pools
    ref_pools = {}
    model_size_pools = {}
    model_pools = {}
    for w in watches:
        ref_pools.setdefault(w['ref'], []).append(w)
        key = f"{w['model']}_{w['size_mm']}" if w['model'] else None
        if key:
            model_size_pools.setdefault(key, []).append(w)
            model_pools.setdefault(w['model'], []).append(w)
    
    def make_bundle(selected):
        """Create a bundle dict from selected watches."""
        # Determine bundle title
        refs = set(w['ref'] for w in selected)
        models = set(w['model'] for w in selected if w['model'])
        sizes = set(w['size_mm'] for w in selected if w['size_mm'])
        
        if len(refs) == 1:
            title = list(refs)[0]
        elif len(models) == 1 and len(sizes) == 1:
            title = f"{list(models)[0]} {list(sizes)[0]}mm Collection"
        elif len(models) == 1:
            title = f"{list(models)[0]} Collection"
        else:
            title = "Curated Collection"
        
        # Build caption
        lines = []
        for w in selected:
            price_str = f"${w['price']:,.0f}" if w['price'] else "Call"
            lines.append(f"{w['description']} — {price_str} + label")
        
        caption = "\n".join(lines)
        caption += "\n\nAll watches complete full set with box, papers, and warranty card."
        caption += "\nLocated and ship from NY"
        caption += "\nDM for inquiries."
        
        watch_list = []
        for w in selected:
            pp = w.get('photo_path', '')
            posting_dir = os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))), 'posting_photos')
            has_photo = bool(pp) and (os.path.exists(str(pp)) or os.path.exists(os.path.join(posting_dir, str(pp))))
            watch_list.append({
                'id': w['id'],
                'description': w['description'],
                'price': w.get('sale_price'),
                'serial': w.get('serial', ''),
                'photo_url': f"/api/watch-photos/{w['id']}/image" if has_photo else '',
                'photo_filename': f"{w['ref']}_{w['id']}.jpg" if has_photo else '',
            })
        
        return {'title': title, 'caption': caption, 'watches': watch_list}
    
    # Pass 1: Same ref groups (fill to bundle_size from same model+size if needed)
    for ref, pool in sorted(ref_pools.items(), key=lambda x: -len(x[1])):
        avail = available(pool)
        if len(avail) >= bundle_size:
            for i in range(0, len(avail), bundle_size):
                chunk = avail[i:i+bundle_size]
                if len(chunk) == bundle_size:
                    bundles.append(make_bundle(chunk))
                    for w in chunk: used.add(w['id'])
    
    # Pass 2: Same ref (partial) + fill from same model+size
    for ref, pool in sorted(ref_pools.items(), key=lambda x: -len(x[1])):
        avail = available(pool)
        if len(avail) >= 2:
            # Try to fill to bundle_size from same model+size
            w0 = avail[0]
            ms_key = f"{w0['model']}_{w0['size_mm']}" if w0['model'] else None
            filler = []
            if ms_key and ms_key in model_size_pools:
                filler = [w for w in available(model_size_pools[ms_key]) if w['id'] not in {a['id'] for a in avail}]
            selected = avail[:bundle_size]
            if len(selected) < bundle_size and filler:
                selected += filler[:bundle_size - len(selected)]
            if len(selected) >= bundle_size:
                selected = selected[:bundle_size]
                bundles.append(make_bundle(selected))
                for w in selected: used.add(w['id'])
    
    # Pass 3: Same model+size groups
    for ms_key, pool in sorted(model_size_pools.items(), key=lambda x: -len(x[1])):
        avail = available(pool)
        while len(avail) >= bundle_size:
            chunk = avail[:bundle_size]
            bundles.append(make_bundle(chunk))
            for w in chunk: used.add(w['id'])
            avail = available(pool)
    
    # Pass 4: Same model groups
    for model, pool in sorted(model_pools.items(), key=lambda x: -len(x[1])):
        avail = available(pool)
        while len(avail) >= bundle_size:
            chunk = avail[:bundle_size]
            bundles.append(make_bundle(chunk))
            for w in chunk: used.add(w['id'])
            avail = available(pool)
    
    # Pass 5: Similar price range — remaining watches sorted by price
    remaining = sorted([w for w in watches if w['id'] not in used], key=lambda w: w['price'])
    while len(remaining) >= bundle_size:
        chunk = remaining[:bundle_size]
        bundles.append(make_bundle(chunk))
        for w in chunk: used.add(w['id'])
        remaining = remaining[bundle_size:]
    
    # Pass 6: Leftover (< bundle_size) — still show as partial bundle
    if remaining:
        bundles.append(make_bundle(remaining))
    
    return bundles


@app.route('/api/postings/facebook-bundles')
@login_required
def api_postings_facebook_bundles():
    """Get watches grouped into bundles of 5 for Facebook posting.
    Grouping priority: same ref > same model+size > same model > similar price."""
    try:
        conn = get_db()
        # Safety: sync watches.posted flag with postings table
        conn.execute('''UPDATE watches SET posted=1 WHERE id IN (
            SELECT DISTINCT watch_id FROM postings WHERE status='active' AND watch_id IS NOT NULL
        ) AND posted=0 AND sold=0 AND deleted=0''')
        conn.commit()
        
        rows = conn.execute('''
            SELECT w.id, w.description, w.serial, w.card_date, w.sale_price,
                   COALESCE(
                       (SELECT p.photo FROM postings p WHERE p.watch_id = w.id AND p.status='active' 
                        AND p.photo IS NOT NULL AND p.photo != '' ORDER BY p.posted_at DESC LIMIT 1),
                       (SELECT wp.file_path FROM watch_photos wp WHERE wp.watch_id = w.id 
                        ORDER BY CASE wp.photo_type WHEN 'hero' THEN 0 WHEN 'arrival' THEN 1 ELSE 2 END, 
                        wp.created_at DESC LIMIT 1)
                   ) as photo_path
            FROM watches w
            WHERE w.sold = 0 AND w.deleted = 0 AND w.posted = 1
            ORDER BY w.description
        ''').fetchall()
        conn.close()

        watches = [_fb_parse_watch(dict(r)) for r in rows]
        bundles = _fb_build_bundles(watches, bundle_size=5)
        
        return jsonify({'ok': True, 'bundles': bundles, 'total_watches': len(watches)})
    except Exception as e:
        logger.error(f"Facebook bundles error: {e}")
        return jsonify({'ok': False, 'error': str(e)}), 500


@app.route('/api/postings/create-draft', methods=['POST'])
@login_required
def api_postings_create_draft():
    """Create a draft posting in DB without sending to Telegram.
    Accepts JSON: {watch_id, caption, price, photo_path?}
    Or multipart with 'photo' file.
    """
    try:
        if request.content_type and 'multipart' in request.content_type:
            data = request.form.to_dict()
            uploaded_photo = request.files.get('photo')
        else:
            data = request.get_json() or {}
            uploaded_photo = None

        watch_id = data.get('watch_id') or data.get('row')
        caption = data.get('caption', '')
        price = data.get('price', '')
        photo_path = data.get('photo_path', '')

        if not watch_id or not caption:
            return jsonify({'error': 'watch_id and caption required'}), 400

        db = get_db()
        watch = db.execute('SELECT * FROM watches WHERE id=?', (watch_id,)).fetchone()
        if not watch:
            return jsonify({'error': f'Watch {watch_id} not found'}), 404

        import re as _re_draft
        ref_match = _re_draft.match(r'(?:Pre-Owned |BNIB |Retail Ready )?(?:Full Set )?(\d{5,6}[A-Za-z]*)', caption)
        ref = ref_match.group(1) if ref_match else (watch['ref'] if 'ref' in watch.keys() else '')

        # Handle photo
        saved_photo = ''
        if uploaded_photo:
            photo_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos'
            photo_dir.mkdir(parents=True, exist_ok=True)
            fname = f"draft_{watch_id}_{datetime.now(ET).strftime('%Y%m%d_%H%M%S')}.jpg"
            fpath = photo_dir / fname
            uploaded_photo.save(str(fpath))
            saved_photo = fname
        elif photo_path and Path(photo_path).exists():
            saved_photo = photo_path
        else:
            # Auto-pick from watch_photos if no photo explicitly provided
            wp = db.execute(
                "SELECT file_path FROM watch_photos WHERE watch_id=? ORDER BY CASE photo_type WHEN 'hero' THEN 0 WHEN 'arrival' THEN 1 ELSE 2 END, created_at DESC LIMIT 1",
                (watch_id,)
            ).fetchone()
            if wp:
                wp_path = Path(wp['file_path'])
                if wp_path.exists():
                    # Copy to posting_photos
                    photo_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos'
                    photo_dir.mkdir(parents=True, exist_ok=True)
                    fname = f"draft_{watch_id}_{datetime.now(ET).strftime('%Y%m%d_%H%M%S')}.jpg"
                    import shutil as _shutil
                    _shutil.copy2(str(wp_path), str(photo_dir / fname))
                    saved_photo = fname

        # Parse price
        price_val = None
        if price:
            import re as _re_p
            price_clean = _re_p.sub(r'[^0-9.]', '', str(price))
            try:
                price_val = float(price_clean)
            except:
                price_val = None

        # If still no photo, try watch_photo_manager (legacy photos on disk)
        if not saved_photo:
            try:
                from watch_photo_manager import get_photos
                info = get_photos(int(watch_id))
                if info and info.get('photos'):
                    src_path = Path(info['photos'][0].get('path', ''))
                    if src_path.exists():
                        photo_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos'
                        photo_dir.mkdir(parents=True, exist_ok=True)
                        fname = f"draft_{watch_id}_{datetime.now(ET).strftime('%Y%m%d_%H%M%S')}.jpg"
                        import shutil as _shutil2
                        _shutil2.copy2(str(src_path), str(photo_dir / fname))
                        saved_photo = fname
            except Exception:
                pass

        # One draft/active posting per watch
        existing = db.execute("SELECT id FROM postings WHERE watch_id=? AND status IN ('draft','active')", (watch_id,)).fetchone()
        if existing:
            return jsonify({'error': f'This watch already has a posting (#{existing["id"]}). Delete it first to create a new one.'}), 400

        # Photo is MANDATORY for postings
        if not saved_photo:
            return jsonify({'error': 'Photo required. Upload at least one photo before saving a posting.'}), 400

        now = now_et_iso()
        db.execute('''
            INSERT INTO postings (watch_id, ref, description, caption, price, photo, status, posted_at, created_at)
            VALUES (?, ?, ?, ?, ?, ?, 'draft', ?, ?)
        ''', (watch_id, ref, caption, caption, price_val, saved_photo, now, now))
        db.commit()
        posting_id = db.execute('SELECT last_insert_rowid()').fetchone()[0]

        # Update watch sale_price if provided
        if price_val:
            db.execute('UPDATE watches SET sale_price=?, updated_at=? WHERE id=?', (price_val, now, watch_id))
            db.commit()

        return jsonify({'ok': True, 'posting_id': posting_id, 'status': 'draft'})

    except Exception as e:
        logger.error(f"Create draft posting error: {e}")
        return jsonify({'error': str(e)}), 500


@app.route('/api/postings/<int:posting_id>/send-telegram', methods=['POST'])
@login_required
def api_postings_send_telegram(posting_id):
    """Send an existing draft posting to WhatsApp My Postings group, save message_id back."""
    try:
        db = get_db()
        posting = db.execute('SELECT * FROM postings WHERE id=?', (posting_id,)).fetchone()
        if not posting:
            return jsonify({'error': 'Posting not found'}), 404

        caption = posting['caption'] or posting['description'] or ''
        photo = posting['photo'] or ''
        watch_id = posting['watch_id']

        from whatsapp_postings import send_photo as wa_send_photo, send_text as wa_send_text

        # Delete old active postings for this watch (excluding current draft) before sending
        if watch_id:
            try:
                db2 = get_db()
                old_actives = db2.execute(
                    "SELECT id, message_id FROM postings WHERE watch_id=? AND status='active' AND id!=?",
                    (watch_id, posting_id)
                ).fetchall()
                for old in old_actives:
                    old_mid = old[1] if len(old) > 1 else None
                    if old_mid:
                        try:
                            from whatsapp_postings import delete_message as wa_delete_message
                            wa_delete_message(old_mid)
                            logger.info(f"Deleted old WA posting {old_mid} before send-telegram for watch_id={watch_id}")
                        except Exception:
                            pass
                    db2.execute("UPDATE postings SET status='deleted' WHERE id=?", (old[0],))
                if old_actives:
                    db2.commit()
            except Exception as _ce:
                logger.warning(f"Old posting cleanup failed in send-telegram: {_ce}")

        message_id = None

        # Try to send with photo
        photo_path = None
        if photo:
            # Check various photo locations
            for candidate in [
                Path(photo),
                Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos' / photo,
                Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'watch_library' / photo,
            ]:
                if candidate.exists():
                    photo_path = candidate
                    break

            # Also check watch_photos in DB
            if not photo_path and watch_id:
                wp = db.execute('SELECT file_path FROM watch_photos WHERE watch_id=? AND photo_type IN (?, ?) LIMIT 1',
                               (watch_id, 'hero', 'posting')).fetchone()
                if wp:
                    p = Path(wp['file_path'])
                    if p.exists():
                        photo_path = p

        if photo_path and photo_path.exists():
            wa_result = wa_send_photo(str(photo_path), caption)
            if wa_result.get('ok'):
                message_id = str(wa_result.get('message_id', ''))
        else:
            # Text-only post
            wa_result = wa_send_text(caption)
            if wa_result.get('ok'):
                message_id = str(wa_result.get('message_id', ''))

        if not message_id:
            return jsonify({'error': 'Failed to send to WhatsApp', 'details': wa_result.get('error', 'unknown')}), 500

        # Update posting with message_id and status=active
        now = now_et_iso()
        today = datetime.now(ET).strftime('%Y-%m-%d')
        db.execute('''
            UPDATE postings SET message_id=?, status='active', posted_date=?, posted_at=? WHERE id=?
        ''', (message_id, today, now, posting_id))
        # Keep watches.posted and sale_price in sync
        watch_id = posting.get('watch_id')
        if watch_id:
            db.execute('UPDATE watches SET posted=1 WHERE id=? AND posted=0', (watch_id,))
            posting_price = posting.get('price')
            if posting_price:
                db.execute('UPDATE watches SET sale_price=? WHERE id=? AND (sale_price IS NULL OR sale_price=0)', (float(posting_price), watch_id))
        db.commit()

        # Also update legacy JSON log
        try:
            log = _load_postings_log()
            log.append({
                'ref': posting['ref'],
                'caption': caption,
                'message_id': message_id,
                'date': today,
                'active': True,
                'watch_id': watch_id,
                'posting_id': posting_id,
            })
            _save_postings_log(log)
        except Exception as je:
            logger.warning(f"JSON log update failed: {je}")

        return jsonify({'ok': True, 'message_id': message_id, 'posting_id': posting_id})

    except Exception as e:
        logger.error(f"Send posting to Telegram error: {e}")
        return jsonify({'error': str(e)}), 500


@app.route('/api/my-postings')
@login_required
def api_my_postings():
    """Return all active+draft postings from DB postings table (golden source), newest first."""
    def _time_ago(date_str):
        """Convert date string to relative time."""
        if not date_str:
            return '—'
        try:
            from datetime import datetime
            d = datetime.fromisoformat(date_str.replace('Z', '+00:00')) if 'T' in date_str else datetime.strptime(date_str[:10], '%Y-%m-%d')
            now = datetime.now()
            diff = now - d
            mins = int(diff.total_seconds() / 60)
            hrs = int(diff.total_seconds() / 3600)
            days = diff.days
            if mins < 1: return 'Just now'
            if mins < 60: return f'{mins}m ago'
            if hrs < 24: return f'{hrs}h ago'
            if days == 1: return 'Yesterday'
            if days < 7: return f'{days}d ago'
            return d.strftime('%b %d')
        except:
            return date_str[:10] if date_str else '—'
    
    try:
        db = get_db()
        rows = db.execute('''
            SELECT p.id, p.watch_id as row, p.ref, p.description, p.caption, p.price, 
                   p.message_id, p.photo, p.status, p.posted_date, p.posted_at,
                   w.description as watch_desc, w.sale_price, w.sold
            FROM postings p
            LEFT JOIN watches w ON w.id = p.watch_id
            WHERE p.status IN ('active', 'draft')
            ORDER BY p.posted_at DESC, p.id DESC
        ''').fetchall()
        active = []
        for r in rows:
            posted_raw = r['posted_at'] or r['posted_date'] or ''
            active.append({
                'id': r['id'],
                'row': r['row'],
                'watch_id': r['row'],
                'ref': r['ref'] or '',
                'description': r['description'] or r['caption'] or '',
                'caption': r['caption'] or r['description'] or '',
                'price': r['price'] or r['sale_price'] or '',
                'message_id': r['message_id'] or '',
                'photo': r['photo'] or '',
                'status': r['status'],
                'posted_date': _time_ago(posted_raw),
                'posted_at': _time_ago(posted_raw),
                'posted_raw': posted_raw[:10] if posted_raw and len(posted_raw) >= 10 else '',
                'time_ago': _time_ago(posted_raw),
            })
        # Include reload flag + file hash so client can auto-update
        import hashlib
        file_hash = hashlib.md5((V2_DIR / 'index.html').read_bytes()).hexdigest()[:8]
        return jsonify({'ok': True, 'postings': active, 'total': len(active), '_v': file_hash})
    except Exception as e:
        return jsonify({'ok': False, 'error': str(e)}), 500


@app.route('/api/my-postings/delete', methods=['POST'])
@login_required
def api_my_postings_delete():
    """Delete a posting from DB postings table and optionally from Telegram."""
    try:
        data = request.get_json()
        message_id = str(data.get('message_id', '') or '')
        posting_id = data.get('posting_id') or data.get('id')

        if not message_id and not posting_id:
            return jsonify({'ok': False, 'error': 'message_id or posting_id required'}), 400

        db = get_db()
        # Find posting in DB
        if posting_id:
            posting = db.execute('SELECT * FROM postings WHERE id=?', (posting_id,)).fetchone()
        elif message_id and message_id != 'None':
            posting = db.execute('SELECT * FROM postings WHERE message_id=? AND status="active"', (message_id,)).fetchone()
        else:
            posting = None

        tg_deleted = False
        if message_id and message_id != 'None':
            # Try WhatsApp delete first, fall back to Telegram
            try:
                from whatsapp_postings import delete_message as wa_delete_message
                wa_result = wa_delete_message(message_id)
                tg_deleted = wa_result.get('ok', False)
            except Exception:
                pass
            if not tg_deleted:
                tg_deleted = _tg_delete_message(message_id)

        if posting:
            db.execute('UPDATE postings SET status="deleted" WHERE id=?', (posting['id'],))
            watch_id = posting['watch_id']
            # Check if watch has other active postings
            other = db.execute('SELECT id FROM postings WHERE watch_id=? AND status IN ("active","draft") AND id!=?', (watch_id, posting['id'])).fetchone()
            if not other:
                db.execute('UPDATE watches SET posted=0, updated_at=datetime("now") WHERE id=? AND sold=0', (watch_id,))
            db.commit()

        # Also update JSON log for backward compat
        posts = _load_postings_log()
        if message_id and message_id != 'None':
            deleted_post = next((p for p in posts if str(p.get('message_id', '')) == message_id), None)
            new_posts = [p for p in posts if str(p.get('message_id', '')) != message_id]
            _save_postings_log(new_posts)
        else:
            deleted_post = None
            new_posts = posts

        return jsonify({'ok': True, 'tg_deleted': tg_deleted, 'posting_deleted': posting is not None})
    except Exception as e:
        return jsonify({'ok': False, 'error': str(e)}), 500


@app.route('/api/my-postings/sync', methods=['POST'])
@login_required
def api_my_postings_sync():
    """Sync postings DB: clean orphans + sold, auto-repost expiring postings."""
    try:
        db = get_db()
        stale_removed = 0
        reposted = 0
        repost_errors = []
        
        # Mark postings for sold watches as 'sold'
        sold = db.execute('''UPDATE postings SET status='sold' 
            WHERE status='active' AND watch_id IN (SELECT id FROM watches WHERE sold=1)''')
        stale_removed += sold.rowcount
        
        # Mark postings for deleted watches as 'deleted'
        orphans = db.execute('''UPDATE postings SET status='deleted'
            WHERE status='active' AND watch_id NOT IN (SELECT id FROM watches WHERE deleted=0)''')
        stale_removed += orphans.rowcount
        
        if stale_removed > 0:
            db.commit()
        
        # Auto-repost: anything older than 47 hours (before the 48h delete window closes)
        # ONLY reposts if old message was successfully deleted first
        from datetime import datetime, timedelta
        import pytz
        et = pytz.timezone('America/New_York')
        now_et = datetime.now(et)
        cutoff = (now_et - timedelta(hours=47)).isoformat()
        expiring = db.execute('''SELECT p.* FROM postings p
            WHERE p.status='active' AND p.message_id IS NOT NULL AND p.message_id != ''
            AND (COALESCE(p.last_reposted, p.posted_at, p.created_at) < ?)
        ''', (cutoff,)).fetchall()
        
        if expiring:
            import time as _rtime
            try:
                from whatsapp_postings import send_photo as wa_send_photo, delete_message as wa_delete_message
            except ImportError:
                wa_send_photo = None
                wa_delete_message = None
            
            photos_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos'
            
            for ep in expiring:
                ep = dict(ep)
                try:
                    old_mid = ep.get('message_id', '')
                    caption = ep.get('caption', '') or ep.get('description', '')
                    photo_file = ep.get('photo', '')
                    photo_path = photos_dir / photo_file if photo_file else None
                    
                    if not photo_path or not photo_path.exists():
                        repost_errors.append(f"#{ep['id']} {ep.get('ref','')} no photo")
                        continue
                    
                    if not wa_send_photo or not wa_delete_message:
                        repost_errors.append('whatsapp_postings module not available')
                        break
                    
                    # Delete old message — MUST succeed before we send a new one
                    delete_ok = False
                    if old_mid and len(str(old_mid)) > 10:
                        try:
                            del_result = wa_delete_message(old_mid)
                            delete_ok = del_result.get('ok', False) if isinstance(del_result, dict) else bool(del_result)
                            _rtime.sleep(2)
                        except Exception as del_err:
                            logger.warning(f"Repost delete failed for {old_mid}: {del_err}")
                            delete_ok = False
                    
                    if not delete_ok:
                        repost_errors.append(f"#{ep['id']} {ep.get('ref','')} delete failed, skipping repost")
                        continue
                    
                    # Delete confirmed — send new posting
                    new_mid = wa_send_photo(str(photo_path), caption)
                    _rtime.sleep(3)  # Rate limit
                    
                    if new_mid:
                        now_iso = now_et_iso()
                        db.execute('''UPDATE postings SET message_id=?, posted_at=?, last_reposted=?,
                            extra_json=json_set(COALESCE(extra_json,'{}'), '$.old_message_id', ?, '$.reposted', 1)
                            WHERE id=?''', (new_mid, now_iso, now_iso, old_mid, ep['id']))
                        reposted += 1
                    else:
                        repost_errors.append(f"#{ep['id']} {ep.get('ref','')} send failed")
                except Exception as e:
                    repost_errors.append(f"#{ep['id']} {ep.get('ref','')}: {str(e)[:50]}")
            
            if reposted > 0:
                db.commit()
        
        active = db.execute("SELECT COUNT(*) FROM postings WHERE status='active'").fetchone()[0]
        return jsonify({
            'ok': True, 
            'active': active,
            'stale_removed': stale_removed, 
            'reposted': reposted,
            'expiring_found': len(expiring) if expiring else 0,
            'errors': repost_errors if repost_errors else 0
        })
    except Exception as e:
        return jsonify({'ok': False, 'error': str(e)}), 500


