@app.route('/api/my-postings/update', methods=['POST'])
@login_required
def api_my_postings_update():
    """Update caption, price, and/or photo of a posting."""
    try:
        import urllib.parse, urllib.request
        # Handle both JSON and multipart form data
        if request.content_type and 'multipart' in request.content_type:
            message_id = str(request.form.get('message_id', ''))
            new_caption = request.form.get('caption', '').strip()
            new_price = str(request.form.get('price', '')).replace('$', '').replace(',', '').strip() or None
            new_photo = request.files.get('photo')
        else:
            data = request.get_json()
            message_id = str(data.get('message_id', ''))
            new_caption = data.get('caption', '').strip()
            new_price = str(data.get('price', '')).replace('$', '').replace(',', '').strip() or None
            new_photo = None
        if not message_id:
            return jsonify({'ok': False, 'error': 'message_id required'}), 400
        if not new_caption and not new_price and not new_photo:
            return jsonify({'ok': False, 'error': 'Nothing to update'}), 400

        # Look up posting in SQLite (primary) then fall back to JSON log
        db = get_db()
        post = db.execute("SELECT * FROM postings WHERE message_id = ? AND status = 'active'", (message_id,)).fetchone()
        if not post:
            # Try JSON log fallback
            posts = _load_postings_log()
            post = next((p for p in posts if str(p.get('message_id', '')) == message_id), None)
        else:
            post = dict(post)
        if not post:
            return jsonify({'ok': False, 'error': 'Posting not found'}), 404

        posting_id = post.get('id')

        # Build final caption
        final_caption = new_caption if new_caption else (post.get('caption') or post.get('description', ''))
        
        # If price changed, update the price line in caption
        if new_price:
            import re as _re
            # Remove old price line
            final_caption = _re.sub(r'\n?\$?[\d,]+\s*\+\s*label\s*$', '', final_caption).strip()
            final_caption += f'\n${int(float(new_price)):,} + label'

        tg_updated = False
        new_message_id = None
        photos_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos'
        photos_dir.mkdir(parents=True, exist_ok=True)

        from whatsapp_postings import send_photo as wa_send_photo, send_text as wa_send_text

        if new_photo:
            # Photo changed — delete old message first, then repost with new photo
            import tempfile, shutil
            # Delete old WhatsApp message before sending new one
            try:
                from whatsapp_postings import delete_message as wa_delete_message
                wa_delete_message(message_id)
                logger.info(f"Deleted old WA posting message_id={message_id} before photo update")
            except Exception as _del_err:
                logger.warning(f"Failed to delete old WA posting {message_id}: {_del_err}")
            
            tmp = tempfile.NamedTemporaryFile(suffix='.jpg', delete=False)
            new_photo.save(tmp)
            tmp.close()

            wa_result = wa_send_photo(tmp.name, final_caption)
            if wa_result.get('ok'):
                new_message_id = str(wa_result.get('message_id', ''))
                tg_updated = True
                new_photo_name = f'posting_{new_message_id}.jpg'
                shutil.copy2(tmp.name, str(photos_dir / new_photo_name))
            else:
                logger.error(f"WhatsApp repost with photo failed: {wa_result.get('error')}")
            os.unlink(tmp.name)
        else:
            # No photo change — try in-place edit via wa-manage
            from whatsapp_postings import edit_message as wa_edit_message
            wa_result = wa_edit_message(message_id, final_caption)
            if wa_result.get('ok'):
                tg_updated = True
            else:
                # Edit failed — delete old and resend WITH photo (never text-only)
                logger.warning(f"WhatsApp edit failed, falling back to delete+resend with photo: {wa_result.get('error')}")
                # Find existing photo for this posting
                _existing_photo_path = None
                if post.get('photo'):
                    _candidate = photos_dir / post['photo']
                    if _candidate.exists():
                        _existing_photo_path = str(_candidate)
                # Also check watch_photos DB
                if not _existing_photo_path and post.get('watch_id'):
                    _wp = db.execute('SELECT file_path FROM watch_photos WHERE watch_id=? AND photo_type IN (?, ?) LIMIT 1',
                                     (post['watch_id'], 'hero', 'posting')).fetchone()
                    if _wp and Path(_wp[0]).exists():
                        _existing_photo_path = _wp[0]
                
                # Delete old message first
                try:
                    from whatsapp_postings import delete_message as wa_delete_message
                    wa_delete_message(message_id)
                    logger.info(f"Deleted old WA posting {message_id} before price-change resend")
                except Exception as _del_err:
                    logger.warning(f"Failed to delete old WA posting {message_id}: {_del_err}")
                
                if _existing_photo_path:
                    wa_result = wa_send_photo(_existing_photo_path, final_caption)
                else:
                    # Last resort: text only (shouldn't happen if photos are stored properly)
                    logger.error(f"No photo found for posting {posting_id}, sending text-only")
                    wa_result = wa_send_text(final_caption)
                if wa_result.get('ok'):
                    new_message_id = str(wa_result.get('message_id', ''))
                    tg_updated = True

        # Update SQLite posting
        if posting_id:
            updates = ['caption = ?']
            params = [final_caption]
            if new_price:
                updates.append('price = ?')
                params.append(float(new_price))
            if new_message_id:
                updates.append('message_id = ?')
                params.append(new_message_id)
                if new_photo:
                    updates.append('photo = ?')
                    params.append(f'posting_{new_message_id}.jpg')
            updates.append('last_reposted = ?')
            params.append(now_et_iso())
            params.append(posting_id)
            db.execute(f"UPDATE postings SET {', '.join(updates)} WHERE id = ?", params)
            # Also update watch sale_price if price changed
            if new_price and post.get('watch_id'):
                db.execute('UPDATE watches SET sale_price = ?, updated_at = datetime("now") WHERE id = ?',
                           (float(new_price), post['watch_id']))
            db.commit()

        # Also update JSON log for backward compat
        try:
            posts = _load_postings_log()
            for p in posts:
                if str(p.get('message_id', '')) == message_id:
                    p['description'] = final_caption
                    if new_price:
                        p['price'] = new_price
                    if new_message_id:
                        p['message_id'] = new_message_id
                        p['photo'] = f'posting_{new_message_id}.jpg'
                    break
            _save_postings_log(posts)
        except Exception:
            pass

        return jsonify({'ok': True, 'tg_updated': tg_updated, 'caption': final_caption})
    except Exception as e:
        logger.error(f"Update posting error: {e}")
        return jsonify({'ok': False, 'error': str(e)}), 500


@app.route('/api/my-postings/update-price', methods=['POST'])
@login_required
def api_my_postings_update_price():
    """Update price of a posting: delete old Telegram message, repost with new price."""
    try:
        data = request.get_json()
        message_id = str(data.get('message_id', ''))
        new_price = str(data.get('price', '')).replace('$', '').replace(',', '').strip()
        if not message_id:
            return jsonify({'ok': False, 'error': 'message_id required'}), 400
        if not new_price:
            return jsonify({'ok': False, 'error': 'price required'}), 400

        # Look up posting in SQLite first
        db = get_db()
        post = db.execute("SELECT * FROM postings WHERE message_id = ? AND status = 'active'", (message_id,)).fetchone()
        if post:
            post = dict(post)
        else:
            posts = _load_postings_log()
            post = next((p for p in posts if str(p.get('message_id', '')) == message_id), None)
        if not post:
            return jsonify({'ok': False, 'error': 'Posting not found'}), 404

        posting_id = post.get('id')
        old_desc = post.get('caption') or post.get('description', '')
        old_price = post.get('price', '')

        # Build new caption with updated price
        import re as _re
        # Strip any previously appended price lines first
        clean_desc = _re.sub(r'\n\$?[\d,]+\s*\+\s*label', '', old_desc)
        # Replace the original price (with or without $) at end of line
        new_caption = _re.sub(
            r'\$?[\d,]+\s*\+\s*label\s*$',
            f'${int(float(new_price)):,} + label',
            clean_desc
        )
        if new_caption == clean_desc:
            # No price found at all — append it
            new_caption = clean_desc + f'\n${int(float(new_price)):,} + label'

        # Step 1: Delete old WhatsApp message (best effort)
        from whatsapp_postings import delete_message as wa_delete_message
        old_deleted = False
        try:
            wa_del = wa_delete_message(message_id)
            old_deleted = wa_del.get('ok', False)
        except Exception:
            pass

        # Step 2: Repost with photo + new caption via WhatsApp
        from whatsapp_postings import send_photo as wa_send_photo, send_text as wa_send_text
        photos_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos'
        photo_file = post.get('photo', '')
        photo_path = photos_dir / photo_file if photo_file else None
        new_message_id = None

        if photo_path and photo_path.exists():
            wa_result = wa_send_photo(str(photo_path), new_caption)
            if wa_result.get('ok'):
                new_message_id = str(wa_result.get('message_id', ''))
            else:
                logger.error(f"WhatsApp repost photo failed: {wa_result.get('error')}")
        
        if not new_message_id:
            # Fallback: send as text if no photo
            wa_result = wa_send_text(new_caption)
            if wa_result.get('ok'):
                new_message_id = str(wa_result.get('message_id', ''))

        if not new_message_id:
            return jsonify({'ok': False, 'error': 'Failed to repost to WhatsApp'}), 500

        # Step 3: Update SQLite posting
        if posting_id:
            db.execute('''UPDATE postings SET message_id=?, price=?, caption=?, last_reposted=? WHERE id=?''',
                       (new_message_id, float(new_price), new_caption, now_et_iso(), posting_id))
            if post.get('watch_id'):
                db.execute('UPDATE watches SET sale_price=?, updated_at=datetime("now") WHERE id=?',
                           (float(new_price), post['watch_id']))
            db.commit()

        # Also update JSON log for backward compat
        try:
            posts = _load_postings_log()
            for p in posts:
                if str(p.get('message_id', '')) == message_id:
                    p['message_id'] = new_message_id
                    p['price'] = new_price
                    p['description'] = new_caption
                    if photo_path and photo_path.exists():
                        new_photo_name = f'posting_{new_message_id}.jpg'
                        new_photo_path = photos_dir / new_photo_name
                        import shutil
                        shutil.copy2(str(photo_path), str(new_photo_path))
                        p['photo'] = new_photo_name
                    break
            _save_postings_log(posts)
        except Exception:
            pass
        return jsonify({
            'ok': True,
            'old_deleted': old_deleted,
            'new_message_id': new_message_id,
            'old_price': old_price,
            'new_price': new_price,
            'new_caption': new_caption
        })
    except Exception as e:
        logger.error(f"Update price error: {e}")
        return jsonify({'ok': False, 'error': str(e)}), 500


def generate_posting_caption(ref, bracelet='', dial='', card_date='', wt=False, price='', condition='BNIB'):
    """Generate standardized My Postings caption.

    Format: {condition} Full Set {ref} [{short_ref}] {bracelet} {dial} Dial {MM/YYYY} {Month YYYY} {serial_prefix} [with WT] ${price} + label
    Short ref included only when ref has a suffix (e.g. 126518LN -> include 126518).
    Serial prefix = N{month_number} from card_date.
    """
    import re as _re
    # Auto-detect dial from ref suffix if not provided
    if not dial:
        try:
            from parse_v4 import FIXED_DIAL
            dial = FIXED_DIAL.get(ref, '')
        except ImportError:
            pass
    # Full ref vs short ref (only include short if suffix exists)
    ref_match = _re.match(r'^(\d{5,6})([A-Za-z]+)$', ref)
    ref_line = f"{ref} {ref_match.group(1)}" if ref_match else ref

    # Month/year from card_date (always extract MM/YYYY even from MM/DD/YYYY)
    month_year = ''
    mm_yyyy = ''
    serial_prefix = ''
    if card_date:
        full = _re.match(r'(\d{1,2})/\d{1,2}/(\d{4})', card_date)
        short = _re.match(r'(\d{1,2})/(\d{4})', card_date)
        m = full or short
        if m:
            mm, yyyy = int(m.group(1)), m.group(2)
            months = ['','January','February','March','April','May','June','July','August','September','October','November','December']
            month_year = f"{months[mm]} {yyyy}"
            mm_yyyy = f"{mm:02d}/{yyyy}"
            serial_prefix = f"N{mm}"

    wt_str = 'with WT' if wt else ''
    price_str = f"${int(float(price)):,}" if price else ''

    parts = [condition, 'Full Set', ref_line, bracelet, dial, 'Dial', mm_yyyy, month_year, serial_prefix, wt_str, price_str, '+ label']
    caption = ' '.join(p for p in parts if p)
    # Collapse multiple spaces
    caption = _re.sub(r'  +', ' ', caption).strip()
    return caption


@app.route('/api/my-postings/generate-caption', methods=['POST'])
@login_required
def api_generate_caption():
    """Generate a standardized posting caption from watch data."""
    try:
        data = request.get_json()
        caption = generate_posting_caption(
            ref=data.get('ref', ''),
            bracelet=data.get('bracelet', ''),
            dial=data.get('dial', ''),
            card_date=data.get('card_date', ''),
            wt=bool(data.get('wt', False)),
            price=str(data.get('price', '')),
            condition=data.get('condition', 'BNIB')
        )
        return jsonify({'ok': True, 'caption': caption})
    except Exception as e:
        return jsonify({'ok': False, 'error': str(e)}), 500


@app.route('/api/my-postings/post-direct', methods=['POST'])
@login_required
def api_my_postings_post_direct():
    """Post a watch to My Postings directly with an uploaded photo file.

    Accepts multipart/form-data with: photo (file), caption, price, ref, row (optional).
    Saves photo to posting_photos/, sends to Telegram, saves to log, marks posted in Bot Sheet.
    """
    try:
        caption = request.form.get('caption', '')
        price = request.form.get('price', '').replace('$', '').replace(',', '').strip()
        ref = request.form.get('ref', '')
        row = request.form.get('row', '')
        photo_file = request.files.get('photo')

        if not caption:
            return jsonify({'ok': False, 'error': 'Caption is required'}), 400

        from whatsapp_postings import send_photo as wa_send_photo, send_text as wa_send_text

        photos_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos'
        photos_dir.mkdir(exist_ok=True)

        # Delete old active posting for this watch before creating new one
        if row:
            _delete_old_postings_for_watch(int(row))

        message_id = None
        saved_photo_filename = None

        if photo_file and photo_file.filename:
            # Save photo to temp file first, then send via WhatsApp
            import tempfile
            tmp = tempfile.NamedTemporaryFile(suffix='.jpg', delete=False, dir='/tmp')
            photo_bytes = photo_file.read()
            tmp.write(photo_bytes)
            tmp.close()
            
            wa_result = wa_send_photo(tmp.name, caption)
            if not wa_result.get('ok'):
                return jsonify({'ok': False, 'error': 'Failed to send photo to WhatsApp', 'detail': wa_result.get('error')}), 500
            message_id = str(wa_result.get('message_id', ''))

            # Save photo to posting_photos/
            saved_photo_filename = f"posting_{message_id}.jpg"
            with open(photos_dir / saved_photo_filename, 'wb') as pf:
                pf.write(photo_bytes)
            os.unlink(tmp.name)
        else:
            # No photo — send text message
            wa_result = wa_send_text(caption)
            if not wa_result.get('ok'):
                return jsonify({'ok': False, 'error': 'Failed to send message', 'detail': wa_result.get('error')}), 500
            message_id = str(wa_result.get('message_id', ''))

        # Save to log
        posts = _load_postings_log()
        log_entry = {
            'ref': ref,
            'description': caption,
            'price': price,
            'status': 'active',
            'posted_at': now_et_iso(),
            'posted_date': datetime.now(ET).strftime('%Y-%m-%d'),
            'message_id': message_id,
            'photo': saved_photo_filename or ''
        }
        if row:
            log_entry['row'] = row
        posts.append(log_entry)
        _save_postings_log(posts)

        # Mark posted in SQLite DB
        if row and DB_AVAILABLE:
            try:
                db_fields = {'posted': 'Yes'}
                if price:
                    db_fields['sale_price'] = str(price)
                db_update(int(row), **db_fields)
                _bg_sheet_sync([int(row)])
            except Exception as db_err:
                logger.warning(f"DB mark posted failed: {db_err}")
        return jsonify({'ok': True, 'message_id': message_id, 'photo': saved_photo_filename})
    except Exception as e:
        logger.error(f"Post direct error: {e}")
        return jsonify({'ok': False, 'error': str(e)}), 500


@app.route('/api/my-postings/repost', methods=['POST'])
@login_required
def api_my_postings_repost():
    """Smart repost a single posting.
    
    Default: if posting already has a message_id, edit caption in place.
    Pass force=true to delete old + send new (bumps to top of chat).
    If no message_id exists, sends a new message.
    Pass caption/price to update before sending/editing.
    """
    try:
        data = request.get_json() or {}
        posting_id = data.get('posting_id') or data.get('id')
        force = data.get('force', False)
        new_caption = data.get('caption')
        new_price = data.get('price')
        if not posting_id:
            return jsonify({'ok': False, 'error': 'posting_id required'}), 400

        db = get_db()
        posting = db.execute('SELECT * FROM postings WHERE id = ?', (posting_id,)).fetchone()
        if not posting:
            return jsonify({'ok': False, 'error': 'Posting not found'}), 404
        posting = dict(posting)

        from whatsapp_postings import send_photo as wa_send_photo, send_text as wa_send_text
        from whatsapp_postings import delete_message as wa_delete_message, edit_message as wa_edit_message

        old_mid = posting.get('message_id')
        caption = new_caption or posting.get('caption') or posting.get('description') or ''
        
        # Update price in caption if provided
        if new_price:
            import re as _re
            caption = _re.sub(r'\n?\$?[\d,]+\s*\+\s*label\s*$', '', caption).strip()
            try:
                caption += f'\n${int(float(str(new_price).replace("$","").replace(",",""))):,} + label'
            except:
                caption += f'\n{new_price} + label'

        photos_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos'
        photo_file = posting.get('photo', '')
        photo_path = photos_dir / photo_file if photo_file else None

        action_taken = 'none'
        new_mid = old_mid

        if not old_mid or old_mid == 'None' or old_mid == '':
            # No message yet — send new
            if photo_path and photo_path.exists():
                wa_result = wa_send_photo(str(photo_path), caption)
            else:
                wa_result = wa_send_text(caption)
            if not wa_result.get('ok'):
                return jsonify({'ok': False, 'error': 'Failed to send', 'detail': wa_result.get('error')}), 500
            new_mid = str(wa_result.get('message_id', ''))
            action_taken = 'posted'

        elif force:
            # Force: delete old + send new (bumps to top)
            try:
                wa_delete_message(old_mid)
            except Exception:
                pass

            import time
            time.sleep(2)

            if photo_path and photo_path.exists():
                wa_result = wa_send_photo(str(photo_path), caption)
            else:
                wa_result = wa_send_text(caption)
            if not wa_result.get('ok'):
                return jsonify({'ok': False, 'error': 'Failed to send', 'detail': wa_result.get('error')}), 500
            new_mid = str(wa_result.get('message_id', ''))
            action_taken = 'reposted'

        else:
            # Edit in place (no bump)
            wa_result = wa_edit_message(old_mid, caption)
            if wa_result.get('ok'):
                action_taken = 'edited'
            else:
                # Edit failed — might be a photo message, can't edit caption via protocol
                # Fall back to delete + resend
                logger.warning(f"Edit failed for {old_mid}, falling back to delete+resend")
                try:
                    wa_delete_message(old_mid)
                except Exception:
                    pass
                import time
                time.sleep(2)
                if photo_path and photo_path.exists():
                    wa_result = wa_send_photo(str(photo_path), caption)
                else:
                    wa_result = wa_send_text(caption)
                if not wa_result.get('ok'):
                    return jsonify({'ok': False, 'error': 'Failed to resend', 'detail': wa_result.get('error')}), 500
                new_mid = str(wa_result.get('message_id', ''))
                action_taken = 'reposted'

        # Update DB
        db.execute('UPDATE postings SET message_id = ?, caption = ?, last_reposted = ? WHERE id = ?',
                   (new_mid, caption, now_et_iso(), posting_id))
        if new_price:
            db.execute('UPDATE postings SET price = ? WHERE id = ?',
                       (float(str(new_price).replace('$','').replace(',','')), posting_id))
        db.commit()

        return jsonify({'ok': True, 'posting_id': posting_id, 'action': action_taken, 
                        'old_message_id': old_mid, 'new_message_id': new_mid})
    except Exception as e:
        logger.error(f"Repost error: {e}")
        return jsonify({'ok': False, 'error': str(e)}), 500


@app.route('/api/my-postings/repost-all', methods=['POST'])
@login_required
def api_my_postings_repost_all():
    """Smart sync of all postings to WhatsApp My Postings group.
    
    Safeguards:
    - Orphan cleanup: postings whose watch_id doesn't exist → delete from WA + mark deleted
    - Sold cleanup: postings for sold watches → delete from WA + mark sold
    - Dedup: only keep the newest active posting per watch_id, delete older dupes
    - No photo = no post: skip postings without a valid photo file
    - Already posted: skip postings that already have a WhatsApp message_id
    - New postings: send to WhatsApp (photo required)
    
    Pass ?force=true to force delete+resend all existing posts.
    """
    import time
    try:
        db = get_db()
        force = request.args.get('force', 'false').lower() == 'true'

        from whatsapp_postings import send_photo as wa_send_photo
        from whatsapp_postings import delete_message as wa_delete_message
        photos_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'posting_photos'
        watch_photos_dir = Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'watch_photos'

        results = {'deleted': [], 'posted': [], 'skipped': [], 'no_photo': [], 'errors': []}

        # ── Step 1: Delete orphan postings (watch_id doesn't exist in watches table)
        orphans = db.execute('''
            SELECT p.* FROM postings p
            LEFT JOIN watches w ON p.watch_id = w.id
            WHERE p.status = 'active' AND w.id IS NULL
        ''').fetchall()
        for op in orphans:
            op = dict(op)
            mid = op.get('message_id')
            if mid and len(str(mid)) > 10:
                try:
                    wa_delete_message(mid)
                    time.sleep(2)
                except Exception:
                    pass
            db.execute("UPDATE postings SET status = 'deleted' WHERE id = ?", (op['id'],))
            results['deleted'].append({'id': op['id'], 'ref': op.get('ref', ''), 'reason': 'orphan'})

        # ── Step 2: Delete postings for sold watches
        sold_postings = db.execute('''
            SELECT p.* FROM postings p
            JOIN watches w ON p.watch_id = w.id
            WHERE p.status = 'active' AND w.sold = 1
        ''').fetchall()
        for sp in sold_postings:
            sp = dict(sp)
            mid = sp.get('message_id')
            if mid and len(str(mid)) > 10:
                try:
                    wa_delete_message(mid)
                    time.sleep(2)
                except Exception:
                    pass
            db.execute("UPDATE postings SET status = 'sold' WHERE id = ?", (sp['id'],))
            results['deleted'].append({'id': sp['id'], 'ref': sp.get('ref', ''), 'reason': 'sold'})

        # ── Step 3: Dedup — keep only newest active posting per watch_id
        dupes = db.execute('''
            SELECT p.* FROM postings p
            WHERE p.status = 'active'
            AND p.id NOT IN (
                SELECT MAX(id) FROM postings WHERE status = 'active' GROUP BY watch_id
            )
        ''').fetchall()
        for dp in dupes:
            dp = dict(dp)
            mid = dp.get('message_id')
            if mid and len(str(mid)) > 10:
                try:
                    wa_delete_message(mid)
                    time.sleep(2)
                except Exception:
                    pass
            db.execute("UPDATE postings SET status = 'deleted' WHERE id = ?", (dp['id'],))
            results['deleted'].append({'id': dp['id'], 'ref': dp.get('ref', ''), 'reason': 'duplicate'})

        db.commit()

        # ── Step 4: Process remaining active + draft postings (drafts get sent and promoted to active)
        active_postings = db.execute("SELECT * FROM postings WHERE status IN ('active', 'draft') ORDER BY id").fetchall()

        for posting in active_postings:
            posting = dict(posting)
            pid = posting['id']
            old_mid = posting.get('message_id')
            caption = posting.get('caption') or posting.get('description') or ''
            photo_file = posting.get('photo', '')
            
            # Resolve photo path — check posting_photos, then watch_photos in DB
            photo_path = None
            if photo_file:
                candidate = photos_dir / photo_file
                if candidate.exists():
                    photo_path = candidate
            if not photo_path and posting.get('watch_id'):
                wp = db.execute('''SELECT file_path FROM watch_photos 
                                   WHERE watch_id=? AND photo_type IN ('hero','posting','arrival') 
                                   ORDER BY CASE photo_type WHEN 'posting' THEN 1 WHEN 'hero' THEN 2 ELSE 3 END
                                   LIMIT 1''', (posting['watch_id'],)).fetchone()
                if wp:
                    p = Path(wp[0] if isinstance(wp, tuple) else wp['file_path'])
                    if p.exists():
                        photo_path = p

            # Try watch_photo_manager (legacy disk photos) as last resort
            if not photo_path and posting.get('watch_id'):
                try:
                    from watch_photo_manager import get_photos as _wpm_get
                    _wpm_info = _wpm_get(int(posting['watch_id']))
                    if _wpm_info and _wpm_info.get('photos'):
                        _wpm_path = Path(_wpm_info['photos'][0].get('path', ''))
                        if _wpm_path.exists():
                            photo_path = _wpm_path
                except Exception:
                    pass

            # ── No photo = no post
            if not photo_path:
                results['no_photo'].append({'id': pid, 'ref': posting.get('ref', '')})
                continue

            if force:
                # Force mode: delete old + resend
                if old_mid and len(str(old_mid)) > 10:
                    try:
                        wa_delete_message(old_mid)
                    except Exception:
                        pass
                    time.sleep(2)

                try:
                    wa_result = wa_send_photo(str(photo_path), caption)
                    if wa_result.get('ok'):
                        new_mid = str(wa_result.get('message_id', ''))
                        db.execute('UPDATE postings SET message_id = ?, last_reposted = ? WHERE id = ?',
                                   (new_mid, now_et_iso(), pid))
                        results['posted'].append({'id': pid, 'ref': posting.get('ref', '')})
                    else:
                        results['errors'].append({'id': pid, 'ref': posting.get('ref', ''), 'error': wa_result.get('error', 'send failed')})
                except Exception as e:
                    results['errors'].append({'id': pid, 'error': str(e)})
                time.sleep(2)

            elif not old_mid or old_mid == 'None' or old_mid == '' or len(str(old_mid)) < 10:
                # No WhatsApp message yet — send new (with photo only)
                try:
                    wa_result = wa_send_photo(str(photo_path), caption)
                    if wa_result.get('ok'):
                        new_mid = str(wa_result.get('message_id', ''))
                        db.execute('UPDATE postings SET message_id = ?, status = "active", posted_date = ?, last_reposted = ? WHERE id = ?',
                                   (new_mid, datetime.now(ET).strftime('%Y-%m-%d'), now_et_iso(), pid))
                        # Also mark watch as posted
                        if posting.get('watch_id'):
                            db.execute('UPDATE watches SET posted=1, updated_at=datetime("now") WHERE id=?', (posting['watch_id'],))
                        results['posted'].append({'id': pid, 'ref': posting.get('ref', '')})
                    else:
                        results['errors'].append({'id': pid, 'ref': posting.get('ref', ''), 'error': wa_result.get('error', 'send failed')})
                except Exception as e:
                    results['errors'].append({'id': pid, 'error': str(e)})
                time.sleep(2)

            else:
                # Already has a WhatsApp message — skip
                results['skipped'].append({'id': pid, 'ref': posting.get('ref', '')})

        db.commit()

        # ── Step 5: Flag unsold watches with NO active posting (missing postings)
        missing = db.execute('''
            SELECT w.id, w.description FROM watches w
            WHERE w.sold = 0 AND w.deleted = 0 AND w.posted = 1
            AND w.id NOT IN (SELECT watch_id FROM postings WHERE status = 'active')
        ''').fetchall()
        results['missing_postings'] = [{'watch_id': m['id'], 'desc': m['description']} for m in missing]

        summary = {
            'ok': True,
            'deleted': len(results['deleted']),
            'posted': len(results['posted']),
            'skipped': len(results['skipped']),
            'no_photo': len(results['no_photo']),
            'errors': len(results['errors']),
            'missing_postings': len(results['missing_postings']),
            'details': results
        }
        return jsonify(summary)
    except Exception as e:
        logger.error(f"Repost all error: {e}")
        return jsonify({'ok': False, 'error': str(e)}), 500


# ══════════════════════════════════════════════════════════════
# ── SHIPPING TRACKER ROUTES ──────────────────────────────────
# ══════════════════════════════════════════════════════════════

SHIPPING_TRACKER_FILE = WORKSPACE / 'shipping_tracker.json'

def _load_shipping_tracker():
    """Load shipping_tracker.json, return dict with 'trackings' list."""
    if SHIPPING_TRACKER_FILE.exists():
        try:
            with open(SHIPPING_TRACKER_FILE, 'r') as f:
                data = json.load(f)
            # Normalize: if trackings is a dict (legacy format), convert to list
            if isinstance(data.get('trackings'), dict):
                trackings_list = []
                for tn, info in data['trackings'].items():
                    if isinstance(info, dict):
                        entry = dict(info)
                        entry.setdefault('tracking_number', tn)
                    else:
                        entry = {'tracking_number': tn}
                    trackings_list.append(entry)
                data['trackings'] = trackings_list
            if 'trackings' not in data:
                data['trackings'] = []
            return data
        except Exception:
            pass
    return {'trackings': [], 'fedex_config': {}}


def _save_shipping_tracker(data):
    """Save shipping_tracker.json."""
    with open(SHIPPING_TRACKER_FILE, 'w') as f:
        json.dump(data, f, indent=2)


def _fedex_poll_tracking(tracking_number):
    """
    Poll FedEx Track API for a single tracking number.
    Returns dict with status, status_detail, eta, last_update, history, or None on failure.
    Falls back to IFS ship history if no FedEx credentials.
    """
    import os as _os
    api_key = _os.environ.get('FEDEX_API_KEY', '')
    secret_key = _os.environ.get('FEDEX_SECRET_KEY', '')
    account = _os.environ.get('FEDEX_ACCOUNT', '')

    # Try to load from shipping_tracker.json fedex_config if env not set
    if not api_key:
        try:
            data = _load_shipping_tracker()
            cfg = data.get('fedex_config', {})
            api_key = cfg.get('api_key', '')
            secret_key = cfg.get('secret_key', '')
            account = cfg.get('account_number', '')
        except Exception:
            pass

    if not api_key or not secret_key:
        return None  # No credentials — caller will use fallback

    try:
        import urllib.request as _req
        import urllib.parse as _parse

        # Step 1: Get OAuth token
        token_url = 'https://apis.fedex.com/oauth/token'
        token_data = _parse.urlencode({
            'grant_type': 'client_credentials',
            'client_id': api_key,
            'client_secret': secret_key,
        }).encode()
        token_req = _req.Request(token_url, data=token_data, method='POST')
        token_req.add_header('Content-Type', 'application/x-www-form-urlencoded')
        with _req.urlopen(token_req, timeout=10) as resp:
            token_resp = json.loads(resp.read())
        access_token = token_resp.get('access_token', '')
        if not access_token:
            return None

        # Step 2: Track
        track_url = 'https://apis.fedex.com/track/v1/trackingnumbers'
        track_payload = json.dumps({
            'includeDetailedScans': True,
            'trackingInfo': [{'trackingNumberInfo': {'trackingNumber': tracking_number}}]
        }).encode()
        track_req = _req.Request(track_url, data=track_payload, method='POST')
        track_req.add_header('Authorization', f'Bearer {access_token}')
        track_req.add_header('Content-Type', 'application/json')
        track_req.add_header('X-locale', 'en_US')
        with _req.urlopen(track_req, timeout=10) as resp:
            track_resp = json.loads(resp.read())

        # Parse response
        outputs = track_resp.get('output', {}).get('completeTrackResults', [])
        if not outputs:
            return None
        result = outputs[0].get('trackResults', [{}])[0]
        status = result.get('latestStatusDetail', {})
        dates = result.get('dateAndTimes', [])
        scans = result.get('scanEvents', [])

        # Find ETA
        eta = ''
        for d in dates:
            if d.get('type') in ('ESTIMATED_DELIVERY', 'ACTUAL_DELIVERY'):
                eta = d.get('dateTime', '')[:10]
                break

        # Build history
        history = []
        for scan in scans:
            loc = scan.get('scanLocation', {})
            city = loc.get('city', '')
            state = loc.get('stateOrProvinceCode', '')
            loc_str = f"{city}, {state}".strip(', ')
            history.append({
                'timestamp': scan.get('date', ''),
                'status': scan.get('eventDescription', ''),
                'location': loc_str,
            })

        return {
            'status': status.get('description', 'Unknown'),
            'status_code': status.get('code', ''),
            'status_detail': status.get('ancillaryDetails', [{}])[0].get('localizedDescription', '') if status.get('ancillaryDetails') else '',
            'eta': eta,
            'last_update': now_et_iso(),
            'history': history,
        }
    except Exception as e:
        logger.warning(f"FedEx API error for {tracking_number}: {e}")
        return None


def _send_telegram_shipping_notify(text):
    """Send a Telegram notification about a shipping event."""
    try:
        creds_file = WORKSPACE / 'briefing_state.json'
        bot_token = ''
        chat_id = ''
        if creds_file.exists():
            with open(creds_file) as f:
                state = json.load(f)
            bot_token = state.get('telegram_bot_token', '')
            chat_id = state.get('telegram_chat_id', '')
        if not bot_token or not chat_id:
            return
        import urllib.request as _req
        url = f'https://api.telegram.org/bot{bot_token}/sendMessage'
        payload = json.dumps({'chat_id': chat_id, 'text': text, 'parse_mode': 'HTML'}).encode()
        req = _req.Request(url, data=payload)
        req.add_header('Content-Type', 'application/json')
        with _req.urlopen(req, timeout=8):
            pass
    except Exception as e:
        logger.warning(f"Telegram shipping notify failed: {e}")


# Background polling thread for active trackings
_shipping_poll_stop = threading.Event()

def _shipping_poll_loop():
    """Background thread: polls FedEx for active (non-delivered) trackings."""
    while not _shipping_poll_stop.is_set():
        try:
            data = _load_shipping_tracker()
            changed = False
            now = datetime.now()
            for t in data.get('trackings', []):
                status = t.get('status', '').lower()
                if status in ('delivered', 'exception'):
                    # Poll every 2h just to keep record fresh
                    last = t.get('last_update', '')
                    if last:
                        try:
                            age = (now - datetime.fromisoformat(last)).total_seconds()
                            if age < 7200:
                                continue
                        except Exception:
                            pass
                # Poll every 30 min for in-transit
                last = t.get('last_update', '')
                if last:
                    try:
                        age = (now - datetime.fromisoformat(last)).total_seconds()
                        poll_interval = 7200 if status in ('delivered',) else 1800
                        if age < poll_interval:
                            continue
                    except Exception:
                        pass

                result = _fedex_poll_tracking(t['tracking_number'])
                if result:
                    old_status = t.get('status', '')
                    t.update(result)
                    changed = True
                    new_status = t.get('status', '')
                    # Telegram notify on delivery
                    if new_status.lower() == 'delivered' and old_status.lower() != 'delivered':
                        ref = t.get('watch_ref', t.get('tracking_number', ''))
                        if t.get('direction') == 'outbound':
                            _send_telegram_shipping_notify(
                                f"📦 {ref} delivered to {t.get('to', '?')} — {t['tracking_number']}"
                            )
                        else:
                            _send_telegram_shipping_notify(
                                f"📦 {ref} arrived from {t.get('from', '?')} — mark as arrived? — {t['tracking_number']}"
                            )

            if changed:
                _save_shipping_tracker(data)
        except Exception as e:
            logger.warning(f"Shipping poll loop error: {e}")

        _shipping_poll_stop.wait(300)  # Check every 5 min; actual polling intervals enforced above


# Start background polling thread when module loads
_shipping_poll_thread = threading.Thread(target=_shipping_poll_loop, daemon=True)
_shipping_poll_thread.start()


@app.route('/api/shipping/trackings', methods=['GET'])
@login_required
def api_shipping_trackings_list():
    """List all trackings, optionally filtered by direction and/or status."""
    direction = request.args.get('direction', '')
    status_filter = request.args.get('status', '')
    data = _load_shipping_tracker()
    trackings = data.get('trackings', [])
    if direction:
        trackings = [t for t in trackings if t.get('direction') == direction]
    if status_filter:
        trackings = [t for t in trackings if t.get('status', '').lower() == status_filter.lower()]
    # Sort newest ship_date first
    trackings = sorted(trackings, key=lambda t: t.get('ship_date', ''), reverse=True)
    return jsonify({'ok': True, 'trackings': trackings, 'total': len(trackings)})


@app.route('/api/shipping/trackings', methods=['POST'])
@login_required
def api_shipping_trackings_add():
    """Add a new tracking entry."""
    body = request.get_json() or {}
    tracking_number = (body.get('tracking_number') or '').strip()
    if not tracking_number:
        return jsonify({'ok': False, 'error': 'tracking_number required'}), 400
    direction = body.get('direction', 'outbound')
    if direction not in ('inbound', 'outbound'):
        return jsonify({'ok': False, 'error': 'direction must be inbound or outbound'}), 400

    data = _load_shipping_tracker()
    # Prevent duplicates
    existing = [t for t in data['trackings'] if t.get('tracking_number') == tracking_number]
    if existing:
        return jsonify({'ok': False, 'error': 'tracking number already exists'}), 409

    entry = {
        'id': f"{direction[0]}{int(datetime.now().timestamp())}",
        'tracking_number': tracking_number,
        'direction': direction,
        'watch_ref': body.get('watch_ref', ''),
        'bot_sheet_row': body.get('bot_sheet_row', None),
        'from': body.get('from', 'Jeffin' if direction == 'outbound' else ''),
        'to': body.get('to', ''),
        'ship_date': body.get('ship_date', datetime.now(ET).strftime('%Y-%m-%d')),
        'service': body.get('service', ''),
        'notes': body.get('notes', ''),
        'status': 'Pending',
        'status_detail': '',
        'eta': '',
        'last_update': '',
        'history': [],
    }

    # Immediately try to poll FedEx
    result = _fedex_poll_tracking(tracking_number)
    if result:
        entry.update(result)

    data['trackings'].append(entry)
    _save_shipping_tracker(data)
    return jsonify({'ok': True, 'tracking': entry})


@app.route('/api/shipping/trackings/<tracking_id>/refresh', methods=['POST'])
@login_required
def api_shipping_trackings_refresh(tracking_id):
    """Force-refresh a tracking from FedEx."""
    data = _load_shipping_tracker()
    t = next((x for x in data['trackings'] if x.get('id') == tracking_id), None)
    if not t:
        return jsonify({'ok': False, 'error': 'not found'}), 404
    result = _fedex_poll_tracking(t['tracking_number'])
    if result:
        t.update(result)
        _save_shipping_tracker(data)
        return jsonify({'ok': True, 'tracking': t})
    return jsonify({'ok': False, 'error': 'FedEx API unavailable or no credentials — status not updated', 'tracking': t})


@app.route('/api/shipping/trackings/<tracking_id>', methods=['DELETE'])
@login_required
def api_shipping_trackings_delete(tracking_id):
    """Remove a tracking entry."""
    data = _load_shipping_tracker()
    before = len(data['trackings'])
    data['trackings'] = [t for t in data['trackings'] if t.get('id') != tracking_id]
    if len(data['trackings']) == before:
        return jsonify({'ok': False, 'error': 'not found'}), 404
    _save_shipping_tracker(data)
    return jsonify({'ok': True})


@app.route('/api/shipping/stats', methods=['GET'])
@login_required
def api_shipping_stats():
    """Summary stats: active inbound, active outbound, delivered today."""
    data = _load_shipping_tracker()
    trackings = data.get('trackings', [])
    today = datetime.now(ET).strftime('%Y-%m-%d')

    active_inbound = sum(1 for t in trackings
                         if t.get('direction') == 'inbound'
                         and t.get('status', '').lower() not in ('delivered', 'exception'))
    active_outbound = sum(1 for t in trackings
                          if t.get('direction') == 'outbound'
                          and t.get('status', '').lower() not in ('delivered', 'exception'))
    delivered_today = sum(1 for t in trackings
                          if t.get('status', '').lower() == 'delivered'
                          and (t.get('last_update', '') or '').startswith(today))
    total = len(trackings)
    return jsonify({
        'ok': True,
        'active_inbound': active_inbound,
        'active_outbound': active_outbound,
        'delivered_today': delivered_today,
        'total': total,
    })


@app.route('/api/unified_search')
@login_required
def api_unified_search():
    """Fan-out search across all data sources: inventory, market, invoices, labels, postings.

    Returns categorized results so the frontend can show them grouped.
    Example: /api/unified_search?q=126334
    """
    q = request.args.get('q', '').strip().lower()
    if not q or len(q) < 2:
        return jsonify({'error': 'Query too short', 'results': {}})

    results = {}

    # ── 1. Inventory (Bot Sheet) ──
    try:
        inv_data = calculate_inventory_pnl()
        rows = inv_data.get('items', inv_data.get('rows', []))
        # Also try all rows if available in cache
        inv_hits = []
        for item in rows:
            desc = str(item.get('description', '')).lower()
            ref = str(item.get('ref', '')).lower()
            buyer = str(item.get('buyer', '')).lower()
            seller = str(item.get('seller', '')).lower()
            serial = str(item.get('serial', '')).lower()
            if q in desc or q in ref or q in buyer or q in seller or q in serial:
                inv_hits.append({
                    'row': item.get('row'),
                    'ref': item.get('ref', ''),
                    'description': item.get('description', ''),
                    'cost': item.get('cost'),
                    'sale_price': item.get('sale_price'),
                    'sold': item.get('sold', 'No'),
                    'arrived': item.get('arrived', 'No'),
                    'posted': item.get('posted', 'No'),
                    'buyer': item.get('buyer', ''),
                    'seller': item.get('seller', ''),
                    'type': 'inventory',
                    'page': 'inventory',
                })
        results['inventory'] = {'items': inv_hits[:20], 'total': len(inv_hits)}
    except Exception as e:
        results['inventory'] = {'items': [], 'total': 0, 'error': str(e)}

    # ── 2. Market Listings ──
    try:
        listings = data_cache.get('listings', [])
        market_hits = []
        for l in listings:
            ref = str(l.get('ref', '')).lower()
            desc = str(l.get('description', '')).lower()
            dial = str(l.get('dial', '')).lower()
            bracelet = str(l.get('bracelet', '')).lower()
            if q in ref or q in desc or q in dial or q in bracelet:
                market_hits.append({
                    'ref': l.get('ref', ''),
                    'description': l.get('description', ''),
                    'price_usd': l.get('price_usd'),
                    'price_hkd': l.get('price_hkd'),
                    'condition': l.get('condition', ''),
                    'region': l.get('region', ''),
                    'dial': l.get('dial', ''),
                    'bracelet': l.get('bracelet', ''),
                    'source': l.get('source', ''),
                    'url': l.get('url', ''),
                    'type': 'market',
                    'page': 'lookup',
                })
        market_hits.sort(key=lambda x: x.get('price_usd') or float('inf'))
        results['market'] = {'items': market_hits[:20], 'total': len(market_hits)}
    except Exception as e:
        results['market'] = {'items': [], 'total': 0, 'error': str(e)}

    # ── 3. Invoices (Zoho) ──
    try:
        if ZOHO_AVAILABLE:
            inv_result = zoho_list_invoices(page=1, per_page=50, search_text=q)
            invoices = inv_result.get('items', [])
            invoice_hits = []
            for inv in invoices:
                invoice_hits.append({
                    'invoice_id': inv.get('invoice_id'),
                    'invoice_number': inv.get('invoice_number', ''),
                    'customer_name': inv.get('customer_name', ''),
                    'total': inv.get('total'),
                    'status': inv.get('status', ''),
                    'date': inv.get('date', ''),
                    'type': 'invoice',
                    'page': 'invoices',
                })
            results['invoices'] = {'items': invoice_hits[:10], 'total': len(invoice_hits)}
        else:
            results['invoices'] = {'items': [], 'total': 0, 'note': 'Zoho not configured'}
    except Exception as e:
        results['invoices'] = {'items': [], 'total': 0, 'error': str(e)}

    # ── 4. Shipping Labels (IFS) ──
    try:
        if IFS_AVAILABLE:
            _labels_dir = str(Path(__file__).parent / 'labels')
            label_hits = []
            fnames = [f for f in os.listdir(_labels_dir) if re.match(r'^\d{12}\.pdf$', f)]
            for fname in fnames:
                tracking = fname[:-4]
                if q in tracking.lower():
                    fp = os.path.join(_labels_dir, fname)
                    try:
                        st = os.stat(fp)
                        label_hits.append({
                            'tracking': tracking,
                            'filename': fname,
                            'size_kb': round(st.st_size / 1024, 1),
                            'created': time.strftime('%Y-%m-%d %H:%M', time.localtime(st.st_mtime)),
                            'type': 'label',
                            'page': 'shipping',
                        })
                    except OSError:
                        pass
            label_hits.sort(key=lambda x: x['created'], reverse=True)
            results['labels'] = {'items': label_hits[:10], 'total': len(label_hits)}
        else:
            results['labels'] = {'items': [], 'total': 0, 'note': 'IFS not configured'}
    except Exception as e:
        results['labels'] = {'items': [], 'total': 0, 'error': str(e)}

    # ── 5. My Postings ──
    try:
        _sdb = get_db()
        _search_postings = _sdb.execute(
            "SELECT * FROM postings WHERE status='active' AND (ref LIKE ? OR caption LIKE ?)",
            (f'%{q}%', f'%{q}%')
        ).fetchall()
        posting_hits = []
        for p in _search_postings:
            p = dict(p)
            posting_hits.append({
                'ref': p.get('ref', ''),
                'description': p.get('caption', ''),
                'price': p.get('price'),
                'posted_at': p.get('posted_at', p.get('posted_date', '')),
                'message_id': p.get('message_id'),
                'photo': p.get('photo', ''),
                'type': 'posting',
                'page': 'postings',
            })
        results['postings'] = {'items': posting_hits[:10], 'total': len(posting_hits)}
    except Exception as e:
        results['postings'] = {'items': [], 'total': 0, 'error': str(e)}

    # ── Summary ──
    total_hits = sum(v.get('total', 0) for v in results.values())
    return jsonify({
        'ok': True,
        'query': q,
        'total': total_hits,
        'results': results,
    })


