@app.route('/api/daily-digest')
@login_required
def api_daily_digest():
    """Aggregate yesterday's activity, pending actions, cash position."""
    try:
        today = datetime.now().date()
        yesterday = today - timedelta(days=1)
        ystr = yesterday.strftime('%Y-%m-%d')
        tstr = today.strftime('%Y-%m-%d')

        # Load inventory
        items = []
        try:
            result = subprocess.run(
                ['python3', str(Path(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))) / 'sheet_updater.py'), 'dump'],
                capture_output=True, text=True, timeout=30
            )
            if result.returncode == 0:
                items = json.loads(result.stdout)
        except Exception:
            pass
        if not items:
            try:
                from botsheet_api import _call_webapp, REVERSE_MAP
                wa_result = _call_webapp('dump')
                if wa_result.get('ok'):
                    for r in wa_result.get('rows', []):
                        row_data = {}
                        for col_letter, field_name in REVERSE_MAP.items():
                            row_data[field_name] = r.get(col_letter, '')
                        items.append(row_data)
            except Exception:
                pass

        # Helper: check if date string is yesterday or today
        def is_yesterday(d):
            if not d: return False
            return str(d)[:10] == ystr

        def is_today(d):
            if not d: return False
            return str(d)[:10] == tstr

        # Yesterday's activity
        bought_yday = [i for i in items if is_yesterday(i.get('buy_date', ''))]
        sold_yday = [i for i in items if is_yesterday(i.get('sale_date', ''))]
        # Arrived = buy_date is today or yesterday and arrived=Yes and no sale_date (rough heuristic)
        arrived_yday = [i for i in items if i.get('arrived', '') == 'Yes' and is_yesterday(i.get('buy_date', ''))]
        shipped_yday = [i for i in items if i.get('shipped', '') == 'Yes' and is_yesterday(i.get('sale_date', ''))]

        # Pending actions
        unsold_unshipped = [i for i in items if i.get('sold', '') == 'Yes' and i.get('shipped', '') != 'Yes']
        unpaid = [i for i in items if i.get('sold', '') == 'Yes' and i.get('paid_after_sold', '') != 'Yes']
        not_arrived = [i for i in items if i.get('arrived', '') != 'Yes' and i.get('sold', '') != 'Yes']

        # Cash position
        total_capital = sum(_parse_cost_safe(i.get('cost_price', '')) or 0 for i in items if i.get('sold', '') != 'Yes')
        total_receivables = sum(_parse_cost_safe(i.get('sold_price', '') or i.get('sale_price', '')) or 0
                                for i in items if i.get('sold', '') == 'Yes' and i.get('paid_after_sold', '') != 'Yes')
        total_revenue = sum(_parse_cost_safe(i.get('sold_price', '') or i.get('sale_price', '')) or 0
                            for i in items if i.get('sold', '') == 'Yes')
        total_cost = sum(_parse_cost_safe(i.get('cost_price', '')) or 0 for i in items if i.get('sold', '') == 'Yes')
        total_profit = total_revenue - total_cost

        # Market movers: refs in inventory that had price changes (compare to day-before history)
        market_movers = []
        try:
            hist_dir = Path(__file__).parent / 'history'
            today_file = hist_dir / f'{tstr}.json'
            yday_file = hist_dir / f'{ystr}.json'
            if today_file.exists() and yday_file.exists():
                with open(today_file) as f:
                    today_hist = json.load(f)
                with open(yday_file) as f:
                    yday_hist = json.load(f)
                # Get refs we hold
                held_refs = set(_extract_ref(i.get('description', '')) for i in items if i.get('sold', '') != 'Yes')
                for ref in held_refs:
                    if not ref: continue
                    tp = today_hist.get(ref, {}).get('b25') or today_hist.get(ref, {}).get('median')
                    yp = yday_hist.get(ref, {}).get('b25') or yday_hist.get(ref, {}).get('median')
                    if tp and yp and abs(tp - yp) / yp > 0.01:  # >1% move
                        pct = (tp - yp) / yp * 100
                        market_movers.append({'ref': ref, 'yesterday': yp, 'today': tp, 'pct': round(pct, 1)})
            market_movers.sort(key=lambda x: abs(x['pct']), reverse=True)
        except Exception:
            pass

        def item_summary(i):
            return {
                'description': i.get('description', ''),
                'ref': _extract_ref(i.get('description', '')),
                'cost': _parse_cost_safe(i.get('cost_price', '')),
                'sale': _parse_cost_safe(i.get('sold_price', '') or i.get('sale_price', '')),
                'sold_to': i.get('sold_to', ''),
                'bought_from': i.get('bought_from', ''),
            }

        return jsonify({
            'ok': True,
            'date': tstr,
            'yesterday': ystr,
            'activity': {
                'bought': [item_summary(i) for i in bought_yday],
                'sold': [item_summary(i) for i in sold_yday],
                'arrived': [item_summary(i) for i in arrived_yday],
                'shipped': [item_summary(i) for i in shipped_yday],
            },
            'pending': {
                'unsold_unshipped': [item_summary(i) for i in unsold_unshipped],
                'unpaid': [item_summary(i) for i in unpaid],
                'not_arrived': [item_summary(i) for i in not_arrived],
            },
            'market_movers': market_movers[:5],
            'cash': {
                'capital_deployed': round(total_capital, 2),
                'receivables': round(total_receivables, 2),
                'total_profit': round(total_profit, 2),
                'total_revenue': round(total_revenue, 2),
            },
        })
    except Exception as e:
        logger.error(f"Daily digest error: {e}")
        return jsonify({'ok': False, 'error': str(e)}), 500


