# POSTING PERFORMANCE
# ══════════════════════════════════════════════════════════════════

@app.route('/api/posting-performance')
@login_required
def api_posting_performance():
    """Return per-posting metrics: days listed, price change history, summary stats."""
    try:
        db = get_db()
        rows = db.execute('SELECT * FROM postings ORDER BY posted_at DESC, id DESC').fetchall()
        posts = [dict(r) for r in rows]
        today = datetime.now().date()

        metrics = []
        sold_days = []
        for p in posts:
            posted_str = p.get('posted_at') or p.get('posted_date') or ''
            posted_date = None
            if posted_str:
                try:
                    posted_date = datetime.fromisoformat(posted_str[:10]).date()
                except Exception:
                    pass

            status = p.get('status', 'active')
            deleted_at = p.get('deleted_at') or p.get('sold_at') or ''
            end_date = None
            if deleted_at:
                try:
                    end_date = datetime.fromisoformat(deleted_at[:10]).date()
                except Exception:
                    pass

            days = None
            if posted_date:
                if status != 'active' and end_date:
                    days = (end_date - posted_date).days
                else:
                    days = (today - posted_date).days

            if status != 'active' and days is not None:
                sold_days.append(days)

            # Price history: check price_history field or infer from current vs original
            price_history = p.get('price_history', [])
            if not price_history:
                orig = p.get('original_price') or p.get('price')
                curr = p.get('price')
                if orig and curr and orig != curr:
                    price_history = [{'price': orig, 'at': posted_str}, {'price': curr, 'at': p.get('last_updated', '')}]

            metrics.append({
                'message_id': p.get('message_id'),
                'ref': p.get('ref', ''),
                'description': p.get('description', ''),
                'price': p.get('price'),
                'posted_at': posted_str,
                'status': status,
                'days_listed': days,
                'price_history': price_history,
                'price_changes': len(price_history) - 1 if len(price_history) > 1 else 0,
            })

        # Summary stats
        active_metrics = [m for m in metrics if m['status'] == 'active']
        sold_metrics = [m for m in metrics if m['status'] != 'active' and m['days_listed'] is not None]

        avg_days_to_sell = round(sum(sold_days) / len(sold_days), 1) if sold_days else None
        fastest = min(sold_metrics, key=lambda x: x['days_listed']) if sold_metrics else None
        slowest = max(sold_metrics, key=lambda x: x['days_listed']) if sold_metrics else None
        avg_price_drops = round(
            sum(m['price_changes'] for m in metrics) / len(metrics), 1
        ) if metrics else 0

        return jsonify({
            'ok': True,
            'metrics': metrics,
            'summary': {
                'total_active': len(active_metrics),
                'avg_days_to_sell': avg_days_to_sell,
                'avg_price_drops': avg_price_drops,
                'fastest_seller': fastest,
                'slowest_seller': slowest,
            }
        })
    except Exception as e:
        logger.error(f"Posting performance error: {e}")
        return jsonify({'ok': False, 'error': str(e)}), 500


