_CONTACTS_FILE = Path(__file__).parent / 'data' / 'contacts.json'

def _load_contacts():
    _CONTACTS_FILE.parent.mkdir(exist_ok=True)
    if not _CONTACTS_FILE.exists():
        return []
    with open(_CONTACTS_FILE) as f:
        return json.load(f)

def _save_contacts(contacts):
    _CONTACTS_FILE.parent.mkdir(exist_ok=True)
    with open(_CONTACTS_FILE, 'w') as f:
        json.dump(contacts, f, indent=2)


@app.route('/api/contacts', methods=['GET'])
@login_required
def api_contacts_list():
    """List all contacts."""
    try:
        contacts = _load_contacts()
        q = request.args.get('q', '').lower().strip()
        if q:
            contacts = [c for c in contacts if
                        q in (c.get('name', '') or '').lower() or
                        q in (c.get('company', '') or '').lower() or
                        q in (c.get('city', '') or '').lower()]
        return jsonify({'ok': True, 'contacts': contacts, 'total': len(contacts)})
    except Exception as e:
        return jsonify({'ok': False, 'error': str(e)}), 500


@app.route('/api/contacts', methods=['POST'])
@login_required
def api_contacts_save():
    """Create or update a contact. If contact_id provided, update; else create."""
    try:
        data = request.get_json()
        contacts = _load_contacts()
        contact_id = data.get('contact_id')
        if contact_id:
            # Update existing
            for i, c in enumerate(contacts):
                if c.get('contact_id') == contact_id:
                    contacts[i].update({k: v for k, v in data.items() if k != 'contact_id'})
                    contacts[i]['updated_at'] = now_et_iso()
                    _save_contacts(contacts)
                    return jsonify({'ok': True, 'contact': contacts[i]})
            return jsonify({'ok': False, 'error': 'Contact not found'}), 404
        else:
            # Create new
            new_contact = {
                'contact_id': str(int(time.time() * 1000)),
                'name': data.get('name', ''),
                'company': data.get('company', ''),
                'address': data.get('address', ''),
                'apt': data.get('apt', ''),
                'city': data.get('city', ''),
                'state': data.get('state', ''),
                'zip': data.get('zip', ''),
                'phone': data.get('phone', ''),
                'email': data.get('email', ''),
                'notes': data.get('notes', ''),
                'is_residential': data.get('is_residential', False),
                'hal_preference': data.get('hal_preference', False),
                'hal_address': data.get('hal_address', ''),
                'hal_city': data.get('hal_city', ''),
                'hal_state': data.get('hal_state', ''),
                'hal_zip': data.get('hal_zip', ''),
                'created_at': now_et_iso(),
                'updated_at': now_et_iso(),
            }
            contacts.append(new_contact)
            _save_contacts(contacts)
            return jsonify({'ok': True, 'contact': new_contact})
    except Exception as e:
        return jsonify({'ok': False, 'error': str(e)}), 500


@app.route('/api/contacts/<contact_id>', methods=['DELETE'])
@login_required
def api_contacts_delete(contact_id):
    """Delete a contact by ID."""
    try:
        contacts = _load_contacts()
        before = len(contacts)
        contacts = [c for c in contacts if c.get('contact_id') != contact_id]
        if len(contacts) == before:
            return jsonify({'ok': False, 'error': 'Contact not found'}), 404
        _save_contacts(contacts)
        return jsonify({'ok': True})
    except Exception as e:
        return jsonify({'ok': False, 'error': str(e)}), 500


