MC_DATA_FILE = os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))), 'mission_control_data.json')

def _mc_load():
    """Load mission control data from JSON file."""
    try:
        with open(MC_DATA_FILE, 'r') as f:
            return json.load(f)
    except:
        return {'backlog': [], 'errors': [], 'journal': [], 'schedule': []}

def _mc_save(data):
    """Save mission control data to JSON file."""
    with open(MC_DATA_FILE, 'w') as f:
        json.dump(data, f, indent=2)

