# ── Changelog endpoint ──
@app.route('/api/mission-control/changelog', methods=['GET'])
@login_required
def api_mc_changelog():
    try:
        import subprocess
        workspace = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
        
        commits = []
        # Main workspace repo
        try:
            result = subprocess.run(
                ['git', 'log', '--format=%H|%ad|%s|%an', '--date=short', '-30'],
                cwd=workspace, capture_output=True, text=True, timeout=10
            )
            for line in result.stdout.strip().split('\n'):
                if '|' in line:
                    parts = line.split('|', 3)
                    if len(parts) == 4:
                        commits.append({'hash': parts[0][:7], 'date': parts[1], 'message': parts[2], 'author': parts[3], 'repo': 'workspace'})
        except: pass
        
        # Frontend repo
        frontend_dir = os.path.join(workspace, 'opulence-dashboard')
        try:
            result = subprocess.run(
                ['git', 'log', '--format=%H|%ad|%s|%an', '--date=short', '-30'],
                cwd=frontend_dir, capture_output=True, text=True, timeout=10
            )
            for line in result.stdout.strip().split('\n'):
                if '|' in line:
                    parts = line.split('|', 3)
                    if len(parts) == 4:
                        commits.append({'hash': parts[0][:7], 'date': parts[1], 'message': parts[2], 'author': parts[3], 'repo': 'frontend'})
        except: pass
        
        # Price analyzer repo
        pa_dir = os.path.join(workspace, 'price_analyzer')
        try:
            result = subprocess.run(
                ['git', 'log', '--format=%H|%ad|%s|%an', '--date=short', '-15'],
                cwd=pa_dir, capture_output=True, text=True, timeout=10
            )
            for line in result.stdout.strip().split('\n'):
                if '|' in line:
                    parts = line.split('|', 3)
                    if len(parts) == 4:
                        commits.append({'hash': parts[0][:7], 'date': parts[1], 'message': parts[2], 'author': parts[3], 'repo': 'price_analyzer'})
        except: pass
        
        # Sort by date descending, group by day
        commits.sort(key=lambda c: c['date'], reverse=True)
        grouped = {}
        for c in commits:
            grouped.setdefault(c['date'], []).append(c)
        
        return jsonify({'days': [{'date': d, 'commits': cs} for d, cs in grouped.items()]})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

