@app.route('/api/mission-control/health', methods=['GET'])
@login_required
def api_mc_health():
    try:
        workspace = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
        metrics = {}
        
        # Memory health
        memory_file = os.path.join(workspace, 'MEMORY.md')
        memory_size = os.path.getsize(memory_file) if os.path.exists(memory_file) else 0
        metrics['memory_size'] = f"{memory_size // 1024}KB"
        
        # Daily files count
        memory_dir = os.path.join(workspace, 'memory')
        daily_count = len([f for f in os.listdir(memory_dir) if f.endswith('.md')]) if os.path.isdir(memory_dir) else 0
        metrics['daily_files'] = daily_count
        
        # SuperMemory
        sm_index = os.path.join(workspace, 'supermemory', 'data', 'memory_index.json')
        if os.path.exists(sm_index):
            sm_size = os.path.getsize(sm_index)
            metrics['supermemory'] = f"{sm_size // 1024}KB"
            try:
                with open(sm_index) as f:
                    sm = json.load(f)
                metrics['supermemory_count'] = len(sm.get('entries', sm.get('memories', [])))
            except:
                metrics['supermemory_count'] = 0
        else:
            metrics['supermemory'] = 'N/A'
            metrics['supermemory_count'] = 0
        
        # Watch photos
        photos_dir = os.path.join(workspace, 'watch_photos')
        photo_count = 0
        ref_count = 0
        if os.path.isdir(photos_dir):
            for d in os.listdir(photos_dir):
                dp = os.path.join(photos_dir, d)
                if os.path.isdir(dp):
                    ref_count += 1
                    photo_count += len([f for f in os.listdir(dp) if f.lower().endswith(('.jpg','.jpeg','.png','.heic'))])
        metrics['photo_refs'] = ref_count
        metrics['photo_count'] = photo_count
        
        # Bot Sheet rows
        try:
            rows = bs_dump().get('rows', [])
            metrics['botsheet_rows'] = len(rows)
            metrics['botsheet_missing_serial'] = len([r for r in rows if not r.get('serial')])
        except:
            metrics['botsheet_rows'] = '?'
            metrics['botsheet_missing_serial'] = '?'
        
        # Dashboard uptime
        metrics['uptime'] = str(datetime.now() - app_start_time).split('.')[0]
        
        # Data file sizes
        mc_data = _mc_load()
        metrics['backlog_total'] = len(mc_data.get('backlog', []))
        metrics['backlog_done'] = len([b for b in mc_data.get('backlog', []) if b.get('status') == 'done'])
        metrics['errors_total'] = len(mc_data.get('errors', []))
        metrics['errors_fixed'] = len([e for e in mc_data.get('errors', []) if e.get('status') == 'fixed'])
        metrics['journal_entries'] = len(mc_data.get('journal', []))
        
        return jsonify(metrics)
    except Exception as e:
        return jsonify({'error': str(e)}), 500

