app_start_time = datetime.now()

# ── CLAUDE CODE SESSIONS ──
def _get_claude_sessions():
    """Scan ~/.claude/projects/ for session files and return metadata."""
    import os
    import json
    from pathlib import Path
    
    claude_dir = Path.home() / '.claude' / 'projects'
    sessions = []
    
    if not claude_dir.exists():
        return sessions
    
    # Scan each project directory
    for project_dir in claude_dir.iterdir():
        if not project_dir.is_dir():
            continue
            
        # Extract project name from path (e.g., "-Users-jeffin-workspace-project" -> "project")
        project_name = project_dir.name.replace('-Users-jeffin--openclaw-workspace-', '').replace('-Users-jeffin-', '')
        if project_name.startswith('-'):
            project_name = project_name[1:]
        
        # Find .jsonl session files
        for session_file in project_dir.glob('*.jsonl'):
            session_id = session_file.stem
            try:
                # Read first and last few lines to get metadata
                lines = []
                with open(session_file, 'r') as f:
                    lines = f.readlines()
                
                if not lines:
                    continue
                    
                # Parse first line for session start
                first_line = json.loads(lines[0].strip())
                last_line = json.loads(lines[-1].strip()) if len(lines) > 1 else first_line
                
                # Count messages
                user_msgs = 0
                assistant_msgs = 0
                last_assistant_msg = None
                last_timestamp = None
                
                for line in lines[-50:]:  # Check last 50 lines for recent activity
                    try:
                        data = json.loads(line.strip())
                        if data.get('type') == 'user':
                            user_msgs += 1
                        elif data.get('type') == 'assistant':
                            assistant_msgs += 1
                            # Extract last assistant message content
                            if data.get('message', {}).get('content'):
                                content = data['message']['content']
                                if isinstance(content, list) and content:
                                    # Handle structured content
                                    text_content = ''
                                    for item in content:
                                        if isinstance(item, dict) and item.get('type') == 'text':
                                            text_content += item.get('text', '')
                                    last_assistant_msg = text_content[:100] if text_content else None
                                elif isinstance(content, str):
                                    last_assistant_msg = content[:100]
                        
                        if data.get('timestamp'):
                            last_timestamp = data['timestamp']
                    except (json.JSONDecodeError, KeyError):
                        continue
                
                # Determine status
                status = 'idle'
                if last_timestamp:
                    from datetime import datetime, timedelta
                    try:
                        last_time = datetime.fromisoformat(last_timestamp.replace('Z', '+00:00'))
                        if datetime.now(last_time.tzinfo) - last_time < timedelta(hours=1):
                            status = 'active'
                    except:
                        pass
                
                # Decode Claude Code's project path encoding
                # Try progressively joining path segments with hyphens
                raw = project_dir.name.lstrip('-').replace('--', '/.')
                parts = raw.split('-')
                project_path = str(Path.home() / '.openclaw' / 'workspace')  # fallback
                for i in range(len(parts), 0, -1):
                    candidate = '/' + '/'.join(parts[:i])
                    if i < len(parts):
                        candidate += '/' + '-'.join(parts[i:])
                    if os.path.isdir(candidate):
                        project_path = candidate
                        break
                
                sessions.append({
                    'session_id': session_id,
                    'session_id_short': session_id[:8] + '...' if len(session_id) > 8 else session_id,
                    'project_name': project_name,
                    'project_path': project_path,
                    'last_activity': last_timestamp,
                    'status': status,
                    'message_count': user_msgs + assistant_msgs,
                    'last_message_preview': last_assistant_msg,
                    'file_path': str(session_file)
                })
                
            except Exception as e:
                print(f"Error parsing {session_file}: {e}")
                continue
    
    # Sort by last activity (newest first)
    sessions.sort(key=lambda x: x.get('last_activity', ''), reverse=True)
    return sessions

def _get_claude_session_history(session_id):
    """Get full conversation history for a specific Claude Code session."""
    import json
    from pathlib import Path
    
    claude_dir = Path.home() / '.claude' / 'projects'
    
    # Find the session file in any project directory
    session_file = None
    for project_dir in claude_dir.iterdir():
        if not project_dir.is_dir():
            continue
        candidate = project_dir / f"{session_id}.jsonl"
        if candidate.exists():
            session_file = candidate
            break
    
    if not session_file:
        return {'error': 'Session not found'}
    
    messages = []
    try:
        with open(session_file, 'r') as f:
            for line in f:
                try:
                    data = json.loads(line.strip())
                    
                    # Handle different message formats
                    msg_type = data.get('type') or data.get('role')
                    if msg_type in ('user', 'assistant'):
                        msg = {
                            'role': msg_type,  # Use 'role' for consistency with frontend
                            'timestamp': data.get('timestamp'),
                            'uuid': data.get('uuid'),
                        }
                        
                        # Extract content from various possible structures
                        content = None
                        
                        # Try message.content first (structured format)
                        if 'message' in data and 'content' in data['message']:
                            content = data['message']['content']
                        # Try direct content field
                        elif 'content' in data:
                            content = data['content']
                        
                        # Parse content based on type
                        if isinstance(content, list):
                            # Handle structured content (array of content blocks)
                            text_parts = []
                            for item in content:
                                if isinstance(item, dict):
                                    if item.get('type') == 'text':
                                        text_parts.append(item.get('text', ''))
                                    elif 'text' in item:
                                        text_parts.append(item['text'])
                                elif isinstance(item, str):
                                    text_parts.append(item)
                            msg['content'] = '\n'.join(text_parts)
                        elif isinstance(content, str):
                            msg['content'] = content
                        elif content is not None:
                            msg['content'] = str(content)
                        else:
                            msg['content'] = ''
                        
                        # Skip empty messages
                        if msg['content'].strip():
                            messages.append(msg)
                            
                except json.JSONDecodeError:
                    continue
    except Exception as e:
        return {'error': f'Failed to read session: {e}'}
    
    return {'messages': messages}

