# Async Claude Code task storage
_claude_tasks = {}  # task_id -> {status, response, error, partial}
import threading as _threading

def _run_claude_task(task_id, cmd, cwd):
    """Background thread to run claude CLI with stream-json output."""
    import json as _json, time as _time
    try:
        # Use stream-json for real-time output
        stream_cmd = []
        for c in cmd:
            stream_cmd.append(c)
            if c == '--print':
                stream_cmd.extend(['--output-format', 'stream-json', '--verbose', '--include-partial-messages'])
        proc = subprocess.Popen(stream_cmd, cwd=cwd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, stdin=subprocess.DEVNULL, text=True, bufsize=1)
        text_parts = []  # Accumulated assistant text
        deadline = _time.time() + 300
        while True:
            if _time.time() > deadline:
                proc.kill()
                _claude_tasks[task_id] = {'status': 'error', 'error': 'Timed out after 5 minutes', 'partial': ''.join(text_parts)}
                return
            line = proc.stdout.readline()
            if not line:
                if proc.poll() is not None:
                    break
                continue
            line = line.strip()
            if not line:
                continue
            try:
                evt = _json.loads(line)
            except:
                continue
            etype = evt.get('type', '')
            if etype == 'stream_event':
                se = evt.get('event', {})
                st = se.get('type', '')
                if st == 'content_block_delta':
                    delta = se.get('delta', {})
                    if delta.get('type') == 'text_delta':
                        text_parts.append(delta.get('text', ''))
                        _claude_tasks[task_id]['partial'] = ''.join(text_parts)
            elif etype == 'assistant' and 'message' in evt:
                msg = evt['message']
                content = msg.get('content', [])
                text = ''.join(b.get('text', '') for b in content if b.get('type') == 'text')
                if text:
                    text_parts = [text]
                    _claude_tasks[task_id]['partial'] = text
            elif etype == 'result':
                result_text = evt.get('result', '')
                if result_text:
                    text_parts = [result_text]
        proc.wait()
        full = ''.join(text_parts).strip()
        if proc.returncode == 0:
            _claude_tasks[task_id] = {'status': 'done', 'response': full or '(no response)'}
        else:
            stderr = proc.stderr.read().strip()
            _claude_tasks[task_id] = {'status': 'error', 'error': stderr or 'Command failed', 'partial': full}
    except Exception as e:
        _claude_tasks[task_id] = {'status': 'error', 'error': str(e)}

@app.route('/api/mission-control/claude-code/send', methods=['POST'])
@login_required
def api_mc_claude_send():
    """Start a Claude Code message (async). Returns task_id to poll."""
    import threading, uuid
    try:
        data = request.get_json()
        session_id = data.get('session_id')
        message = data.get('message', '')
        project_path = data.get('project_path', '/Users/jeffin/.openclaw/workspace')
        
        if not session_id or not message:
            return jsonify({'error': 'session_id and message are required'}), 400
        
        # Check if session is recent enough to resume (< 1 hour old)
        import time as _t
        session_file = None
        sessions_dir = os.path.expanduser('~/.claude/sessions')
        use_resume = False
        if os.path.isdir(sessions_dir):
            for f in os.listdir(sessions_dir):
                fp = os.path.join(sessions_dir, f)
                try:
                    import json as _j
                    sd = _j.load(open(fp))
                    if sd.get('sessionId') == session_id:
                        age = _t.time() - os.path.getmtime(fp)
                        use_resume = age < 3600  # Resume only if < 1 hour old
                        break
                except:
                    pass
        
        cmd = ['/opt/homebrew/bin/claude', '--print', '--permission-mode', 'bypassPermissions']
        if use_resume:
            cmd.extend(['--resume', session_id])
        cmd.extend(['-p', message])
        
        task_id = str(uuid.uuid4())
        _claude_tasks[task_id] = {'status': 'running'}
        t = threading.Thread(target=_run_claude_task, args=(task_id, cmd, project_path), daemon=True)
        t.start()
        
        return jsonify({'task_id': task_id, 'status': 'running'})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/mission-control/claude-code/poll/<task_id>', methods=['GET'])
@login_required
def api_mc_claude_poll(task_id):
    """Poll for Claude Code task result."""
    task = _claude_tasks.get(task_id)
    if not task:
        return jsonify({'status': 'not_found'}), 404
    if task['status'] == 'done':
        resp = task.copy()
        del _claude_tasks[task_id]  # cleanup
        return jsonify(resp)
    if task['status'] == 'error':
        resp = task.copy()
        del _claude_tasks[task_id]
        return jsonify(resp)
    # Return running status with partial output
    return jsonify({'status': task['status'], 'partial': task.get('partial', '')})

@app.route('/api/mission-control/claude-code/new-session', methods=['POST'])
@login_required
def api_mc_claude_new_session():
    """Start a new Claude Code session."""
    try:
        data = request.get_json()
        message = data.get('message', '')
        project_path = data.get('project_path', '/Users/jeffin/.openclaw/workspace')
        
        if not message:
            return jsonify({'error': 'message is required'}), 400
        
        # Run claude --print -p "MESSAGE" in the project directory (creates new session)
        cmd = [
            '/opt/homebrew/bin/claude',
            '--print',
            '-p', message
        ]
        
        result = subprocess.run(
            cmd,
            cwd=project_path,
            capture_output=True,
            text=True,
            timeout=120
        )
        
        if result.returncode == 0:
            response_text = result.stdout.strip()
            
            # Get the new session ID by finding the most recently created session
            import time
            time.sleep(0.5)  # Brief delay to ensure session file is written
            sessions = _get_claude_sessions()
            if sessions:
                new_session = sessions[0]  # Most recent session
                session_id = new_session['session_id']
                return jsonify({
                    'response': response_text,
                    'session_id': session_id
                })
            else:
                return jsonify({
                    'response': response_text,
                    'session_id': None
                })
        else:
            error_msg = result.stderr.strip() if result.stderr else 'Claude command failed'
            return jsonify({'error': error_msg}), 500
    
    except subprocess.TimeoutExpired:
        return jsonify({'error': 'Request timed out'}), 500
    except Exception as e:
        return jsonify({'error': str(e)}), 500

