@app.route('/api/siri/ask', methods=['POST'])
def api_siri_ask():
    """Siri webhook: accept text, send to Telegram bot, return confirmation.
    
    For instant queries (price, inventory), answers directly.
    For complex tasks, sends to Telegram and confirms.
    """
    # Auth check
    auth = request.headers.get('Authorization', '')
    api_key = request.headers.get('X-Siri-Key', '')
    if api_key != SIRI_API_KEY and auth != f'Bearer {SIRI_API_KEY}':
        return jsonify({'error': 'Unauthorized'}), 401
    
    data = request.json or {}
    text = data.get('text', '').strip()
    if not text:
        return jsonify({'error': 'No text provided'}), 400
    
    try:
        # Try to answer simple queries instantly
        instant_response = _try_instant_answer(text)
        if instant_response:
            # Also forward to Telegram so there's a record
            if BOT_TOKEN:
                import requests as _req
                _req.post(
                    f'https://api.telegram.org/bot{BOT_TOKEN}/sendMessage',
                    json={'chat_id': 1507693753, 'text': f'🎙️ [Siri] {text}'},
                    timeout=5
                )
            return jsonify({'ok': True, 'response': instant_response, 'instant': True})
        
        # Complex query — write to siri_inbox for next heartbeat pickup
        # Also send via Telegram so it appears as a user message
        siri_inbox = os.path.join(
            os.path.dirname(os.path.dirname(os.path.abspath(__file__))),
            '.siri_inbox.json'
        )
        try:
            import requests as _req
            from datetime import datetime as _dt
            
            # Save to inbox file for pickup
            inbox = []
            if os.path.exists(siri_inbox):
                try:
                    with open(siri_inbox) as _sf:
                        inbox = json.load(_sf)
                except:
                    pass
            inbox.append({'text': text, 'ts': _dt.now().isoformat()})
            with open(siri_inbox, 'w') as _sf:
                json.dump(inbox, _sf)
            
            # Also send notification to Jeffin via Telegram so he knows it was received
            if BOT_TOKEN:
                _req.post(
                    f'https://api.telegram.org/bot{BOT_TOKEN}/sendMessage',
                    json={'chat_id': 1507693753, 'text': f'🎙️ Siri request queued: "{text}"\n\nI\'ll process this shortly.'},
                    timeout=10
                )
            
            return jsonify({
                'ok': True,
                'response': f"Got it. I'll handle '{text}' and send you the result in Telegram.",
                'async': True
            })
        except Exception as _e:
            return jsonify({
                'ok': True,
                'response': f"I heard: {text}. Something went wrong queuing it. Try sending directly in Telegram.",
                'async': True
            })
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500


