def _siri_normalize(text):
    """Normalize Siri speech recognition output.
    Handles: spelled-out numbers, watch nicknames, common Siri mistakes."""
    t = text
    
    # Watch nicknames → ref numbers
    nicknames = {
        'batman': '126710BLNR', 'pepsi': '126710BLRO', 'sprite': '126710GRNR',
        'destro': '126720VTNR', 'bruce wayne': '126710GRNR',
        'starbucks': '126610LV', 'kermit': '126610LV', 'hulk': '116610LV',
        'panda': '126500', 'daytona panda': '126500',
        'sub': '126610', 'submariner': '126610', 'sub date': '126610LN',
        'gmt': '126710', 'day date': '228238', 'day-date': '228238',
        'datejust 36': '126234', 'datejust 41': '126334', 'dj36': '126234', 'dj41': '126334',
        'sky dweller': '336934', 'sky-dweller': '336934', 'skydweller': '336934',
        'explorer': '226570', 'explorer 2': '226570', 'explorer ii': '226570',
        'op 41': '124300', 'oyster perpetual': '124300',
        'root beer': '126711', 'rootbeer': '126711',
        'wimbledon': '126334', 'wimbeldon': '126334',
        'rainbow': '126599', 'rainbow daytona': '126599',
    }
    t_lower = t.lower()
    for nick, ref in sorted(nicknames.items(), key=lambda x: -len(x[0])):
        if nick in t_lower:
            t = t_lower.replace(nick, ref)
            break
    
    # Common Siri number mishearings
    # "one two six five hundred" → 126500
    # "one twenty six" → 126
    number_words = {
        'one two six': '126', 'one two seven': '127', 'one two eight': '128',
        'one three four': '134', 'one two four': '124',
        'two two eight': '228', 'two seven six': '276', 'two seven seven': '277',
        'two seven eight': '278', 'three three six': '336', 'three two six': '326',
        'twelve six': '126', 'twelve seven': '127', 'twelve eight': '128',
        'thirteen four': '134', 'twenty two eight': '228',
    }
    for words, digits in number_words.items():
        if words in t.lower():
            # Try to find trailing number
            import re as _re
            pattern = words + r'\s*(\d{2,3})'
            match = _re.search(pattern, t.lower())
            if match:
                full_ref = digits + match.group(1)
                t = _re.sub(pattern, full_ref, t.lower())
            break
    
    return t

def _try_instant_answer(text):
    """Massive instant answer engine for Siri voice queries."""
    import re
    from datetime import datetime, timedelta
    
    # Pre-process: normalize Siri speech
    text = _siri_normalize(text)
    text_lower = text.lower().strip()
    # Siri often drops apostrophes: "whats" vs "what's", "hasnt" vs "hasn't"
    # Standardize: add apostrophes back to common contractions
    for contraction, expanded in [('whats', "what's"), ('hows', "how's"), ('whos', "who's"),
                                   ('hasnt', "hasn't"), ('dont', "don't"), ('doesnt', "doesn't"),
                                   ('didnt', "didn't"), ('cant', "can't"), ('isnt', "isn't"),
                                   ('wasnt', "wasn't"), ('wouldnt', "wouldn't"), ('thats', "that's"),
                                   ('wheres', "where's"), ('im ', "i'm "), ('ive ', "i've ")]:
        text_lower = text_lower.replace(contraction, expanded)
    
    # Session context: resolve "that one", "the last one", "same watch"
    import re as _re2
    if any(w in text_lower for w in ['that one', 'the last one', 'same watch', 'same one', 'that watch',
                                      'the one i just asked', 'previous one']) and _siri_session.get('last_ref'):
        text = _re2.sub(r'(?:that one|the last one|same watch|same one|that watch|the one i just asked|previous one)',
                        _siri_session['last_ref'], text, flags=_re2.IGNORECASE)
        text_lower = text.lower().strip()
    
    # ═══════════════════════════════════════════
    # 1. GREETINGS & META
    # ═══════════════════════════════════════════
    if text_lower in ['hello', 'hi', 'hey', 'test', 'are you there', 'you there', 'yo', 'sup']:
        return "Hey Jeffin, I'm here. What do you need?"
    
    if any(w in text_lower for w in ['what can you do', 'what do you know', 'help', 'what can i ask']):
        return ("I can answer: watch prices, inventory count, who owes you, profit, "
                "capital deployed, what needs shipping, what's at store, top deals, "
                "stale inventory, and more. Try: how much is 126500, or who owes me money.")
    
    if any(w in text_lower for w in ['what time', 'current time']):
        return f"It's {datetime.now(ET).strftime('%I:%M %p')} Eastern."
    
    # ═══════════════════════════════════════════
    # 1B. QUICK MATH (before price lookup to avoid ref collision)
    # ═══════════════════════════════════════════
    math_match = re.search(r'\$?(\d[\d,]*)\s*(?:minus|less|subtract|−|-)\s*\$?(\d[\d,]*)', text_lower)
    if math_match:
        a = float(math_match.group(1).replace(',',''))
        b = float(math_match.group(2).replace(',',''))
        return f"${a:,.0f} minus ${b:,.0f} is ${a-b:,.0f}."
    
    math_match = re.search(r'\$?(\d[\d,]*)\s*(?:plus|add|\+)\s*\$?(\d[\d,]*)', text_lower)
    if math_match:
        a = float(math_match.group(1).replace(',',''))
        b = float(math_match.group(2).replace(',',''))
        return f"${a:,.0f} plus ${b:,.0f} is ${a+b:,.0f}."
    
    pct_match = re.search(r'(\d+)\s*(?:percent|%)\s*(?:of|on|margin)\s*\$?(\d[\d,]*)', text_lower)
    if pct_match:
        pct = float(pct_match.group(1))
        amount = float(pct_match.group(2).replace(',',''))
        result = amount * pct / 100
        return f"{pct}% of ${amount:,.0f} is ${result:,.0f}."
    
    # 1C. FX CONVERSIONS (before price lookup)
    fx_match = re.search(r'\$?(\d[\d,]*)\s*(?:hkd|hong kong|hk)\s*(?:to|in)\s*(?:usd|us|dollars?)', text_lower)
    if not fx_match:
        fx_match = re.search(r'convert\s*\$?(\d[\d,]*)\s*(?:hkd|hk)', text_lower)
    if fx_match:
        hkd = float(fx_match.group(1).replace(',',''))
        usd = hkd / 7.82
        return f"HK${hkd:,.0f} is about ${usd:,.0f} USD (at 7.82 rate)."
    
    fx_match2 = re.search(r'\$?(\d[\d,]*)\s*(?:usd|us|dollars?)\s*(?:to|in)\s*(?:hkd|hong kong|hk)', text_lower)
    if not fx_match2:
        fx_match2 = re.search(r'convert\s*\$?(\d[\d,]*)\s*(?:usd|to hk)', text_lower)
    if fx_match2:
        usd = float(fx_match2.group(1).replace(',',''))
        hkd = usd * 7.82
        return f"${usd:,.0f} USD is about HK${hkd:,.0f} (at 7.82 rate)."
    
    # ═══════════════════════════════════════════
    # 1D. SPECIFIC WATCH QUERIES (before generic price lookup)
    # ═══════════════════════════════════════════
    
    # "Do I have a 126500" / "find 126234"
    if any(w in text_lower for w in ['do i have', 'do i own', 'find me', 'look up', 'search for', 'check if']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            try:
                rows = _siri_get_rows()
                found = [r for r in rows if ref in r.get('description', '').upper()]
                unsold = [r for r in found if r.get('sold') != 'Yes']
                sold_ones = [r for r in found if r.get('sold') == 'Yes']
                if unsold:
                    items = [f"{r.get('description','')} (cost ${_siri_parse_money(r.get('cost_price')):,.0f})" for r in unsold]
                    return f"Yes, you have {len(unsold)} unsold {ref}: {'. '.join(items)}" + (f". Plus {len(sold_ones)} sold." if sold_ones else ".")
                elif sold_ones:
                    return f"No unsold {ref}, but you've sold {len(sold_ones)} previously."
                return f"No {ref} found in your inventory."
            except:
                pass
    
    # "Who did I sell X to" / "who bought"
    if any(w in text_lower for w in ['who did i sell', 'who bought', 'sold to who', 'who purchased']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            try:
                rows = _siri_get_rows()
                sold_ones = [r for r in rows if ref in r.get('description','').upper() and r.get('sold') == 'Yes']
                if sold_ones:
                    items = [f"{r.get('description','')} to {r.get('sold_to','?')} for ${_siri_parse_money(r.get('sold_price')):,.0f}" for r in sold_ones]
                    return '. '.join(items)
                return f"Haven't sold any {ref}."
            except:
                pass
    
    # "Who did I buy X from"
    if any(w in text_lower for w in ['who did i buy', 'where did i get', 'bought from who', 'who sold me']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            try:
                rows = _siri_get_rows()
                found = [r for r in rows if ref in r.get('description','').upper()]
                if found:
                    items = [f"{r.get('description','')} from {r.get('bought_from','?')} for ${_siri_parse_money(r.get('cost_price')):,.0f}" for r in found]
                    return '. '.join(items[:5])
                return f"No {ref} found."
            except:
                pass
    
    # "What's my margin on X"
    if any(w in text_lower for w in ['margin on', 'profit on', 'make on']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            try:
                rows = _siri_get_rows()
                found = [r for r in rows if ref in r.get('description','').upper() and r.get('sold') != 'Yes']
                if found:
                    r = found[0]
                    cost = _siri_parse_money(r.get('cost_price'))
                    sale = _siri_parse_money(r.get('sale_price'))
                    if cost and sale:
                        margin = sale - cost
                        pct = margin / cost * 100
                        return f"{r.get('description','')}: cost ${cost:,.0f}, listed ${sale:,.0f}, margin ${margin:,.0f} ({pct:.0f}%)."
                    elif cost:
                        return f"{r.get('description','')}: cost ${cost:,.0f}, no sale price set."
            except:
                pass
    
    # Cheapest / lowest
    if any(w in text_lower for w in ['cheapest', 'lowest price', 'best price']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            try:
                listings = _siri_get_listings()
                matches = [l for l in listings if l.get('ref') == ref or l.get('ref','').startswith(ref)]
                if matches:
                    by_price = sorted(matches, key=lambda l: l.get('price', 999999))
                    cheapest = by_price[0]
                    return (f"Cheapest {ref}: ${cheapest['price']:,.0f} "
                            f"({cheapest.get('currency','?')}, {cheapest.get('condition','')}, "
                            f"{cheapest.get('seller','')[:30]})")
                return f"No listings for {ref}."
            except:
                pass
    
    # ═══════════════════════════════════════════
    # 2. GENERIC PRICE LOOKUPS (fallback for bare ref numbers)
    # ═══════════════════════════════════════════
    ref_match = re.search(r'\b(\d{5,6}[A-Z]{0,4})\b', text, re.IGNORECASE)
    # Don't match numbers that are clearly prices (> 999999) or math
    if ref_match and int(re.sub(r'[A-Za-z]', '', ref_match.group(1))) > 999999:
        ref_match = None
    is_action = any(w in text_lower for w in ['sold', 'bought', 'label', 'ship', 'invoice', 'arrived', 
                                               'make', 'create', 'post', 'mark', 'update',
                                               'should i buy', 'good price', 'fair price', 'worth it',
                                               'what should i price', 'what should i sell', 'how much should i sell',
                                               'what can i sell', 'how much to sell', 'what to list',
                                               'what is a', "what's a", 'what model', 'what watch', 'which model',
                                               'serial number', 'serial for', 'card date', 'warranty',
                                               'tracking', 'shipment status', 'did i ship',
                                               'margin on', 'profit on', 'make on',
                                               'compare', 'versus', ' vs ', 'difference between',
                                               'what to offer', 'should i offer', 'how much to offer', 'bid on', 'offer on',
                                               'spread', 'bid ask',
                                               'how much did i pay', 'what did i pay', 'cost for', 'my cost on',
                                               'total value', 'inventory value', 'net worth', 'portfolio value',
                                               'what is my inventory',
                                               'sell everything', 'liquidation', 'if i sold',
                                               'what would i make', 'what if i sold'])
    
    # Also skip generic price for dial-specific queries (e.g. "blue 126234")
    dial_words_in_query = any(d in text_lower for d in ['blue', 'black', 'green', 'white', 'silver', 
                                                          'champagne', 'chocolate', 'slate', 'wimbledon', 
                                                          'mint', 'pink', 'panda', 'meteorite'])
    if ref_match and not is_action and not dial_words_in_query:
        ref = ref_match.group(1).upper()
        _siri_session['last_ref'] = ref
        _siri_session['last_query'] = text
        _siri_session['last_ts'] = _time.time()
        try:
            listings = _siri_get_listings()
            matches = [l for l in listings if l.get('ref') == ref or l.get('ref', '').startswith(ref)]
            if matches:
                prices = sorted([l['price'] for l in matches if l.get('price')])
                us = sorted([l['price'] for l in matches if l.get('price') and l.get('currency') == 'USD'])
                hk = sorted([l['price'] for l in matches if l.get('price') and l.get('currency') == 'HKD'])
                low = prices[0] if prices else 0
                high = prices[-1] if prices else 0
                us_low = us[0] if us else 0
                
                # Check if we own this ref
                rows = _siri_get_rows()
                owned = [r for r in rows if ref in r.get('description', '').upper() and r.get('sold') != 'Yes']
                
                resp = f"{ref}: {len(matches)} listings, ${low:,.0f} to ${high:,.0f}. US low ${us_low:,.0f} from {len(us)} US listings."
                if hk:
                    resp += f" HK low ${hk[0]:,.0f}."
                if owned:
                    costs = [_siri_parse_money(r.get('cost_price')) for r in owned]
                    resp += f" You own {len(owned)}, cost avg ${sum(costs)/len(costs):,.0f}."
                return resp
            else:
                return f"No listings found for {ref}."
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 3. INVENTORY QUERIES
    # ═══════════════════════════════════════════
    # Inventory value queries go to section 30, not here
    if (any(w in text_lower for w in ['how many watches', 'inventory count', 'how many do i have', 
                                       'stock count', 'watches do i', 'total watches',
                                       'what do i have', 'my watches'])
        and not any(w in text_lower for w in ['worth', 'value', 'total value'])):
        try:
            rows = _siri_get_rows()
            unsold = [r for r in rows if r.get('sold') != 'Yes']
            posted = [r for r in rows if r.get('posted') == 'Yes' and r.get('sold') != 'Yes']
            in_transit = [r for r in rows if r.get('arrived') != 'Yes' and r.get('sold') != 'Yes']
            at_store = [r for r in rows if r.get('at_store') == 'Yes' and r.get('sold') != 'Yes']
            in_hand = [r for r in unsold if r.get('arrived') == 'Yes' and r.get('at_store') != 'Yes']
            return (f"You have {len(unsold)} unsold watches. "
                    f"{len(posted)} posted, {len(in_hand)} in hand, "
                    f"{len(at_store)} at store, {len(in_transit)} in transit.")
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 4. FINANCIAL QUERIES
    # ═══════════════════════════════════════════
    
    # Receivables / who owes me
    if any(w in text_lower for w in ['who owes', 'receivable', 'outstanding', 'unpaid', 'owe me', 
                                      'money do i', 'how much money', 'collections', 'need to collect',
                                      'haven\'t paid', 'not paid', 'waiting for payment']):
        try:
            rows = _siri_get_rows()
            unpaid = [r for r in rows if r.get('sold') == 'Yes' and r.get('paid_after_sold') != 'Yes']
            if unpaid:
                total = sum(_siri_parse_money(r.get('sold_price')) for r in unpaid)
                buyer_totals = {}
                for r in unpaid:
                    buyer = r.get('sold_to', 'Unknown')
                    buyer_totals[buyer] = buyer_totals.get(buyer, 0) + _siri_parse_money(r.get('sold_price'))
                buyers_str = '. '.join(f"{b}: ${v:,.0f}" for b, v in sorted(buyer_totals.items(), key=lambda x: -x[1]))
                return f"{len(unpaid)} unpaid watches, ${total:,.0f} total. {buyers_str}"
            return "Everyone's paid up. No outstanding receivables."
        except:
            pass
    
    # Payables / who do I owe
    if any(w in text_lower for w in ['who do i owe', 'payable', 'need to pay', 'haven\'t paid seller',
                                      'owe anyone', 'seller not paid', 'accounts payable']):
        try:
            rows = _siri_get_rows()
            unpaid_sellers = [r for r in rows if r.get('paid') != 'Yes' and r.get('sold') != 'Yes' 
                             and r.get('bought_from')]
            if unpaid_sellers:
                total = sum(_siri_parse_money(r.get('cost_price')) for r in unpaid_sellers)
                seller_totals = {}
                for r in unpaid_sellers:
                    seller = r.get('bought_from', 'Unknown')
                    seller_totals[seller] = seller_totals.get(seller, 0) + _siri_parse_money(r.get('cost_price'))
                sellers_str = '. '.join(f"{s}: ${v:,.0f}" for s, v in sorted(seller_totals.items(), key=lambda x: -x[1])[:5])
                return f"{len(unpaid_sellers)} watches with unpaid sellers, ${total:,.0f} total. Top: {sellers_str}"
            return "All sellers paid."
        except:
            pass
    
    # Profit
    if any(w in text_lower for w in ['profit', 'how much have i made', 'total profit', 'earnings',
                                      'how much did i make', 'revenue', 'total sales', 'made so far']):
        try:
            rows = _siri_get_rows()
            sold = [r for r in rows if r.get('sold') == 'Yes']
            total_revenue = sum(_siri_parse_money(r.get('sold_price')) for r in sold)
            total_cost = sum(_siri_parse_money(r.get('cost_price')) for r in sold)
            total_profit = total_revenue - total_cost
            margin = (total_profit / total_revenue * 100) if total_revenue else 0
            return (f"{len(sold)} watches sold. Revenue ${total_revenue:,.0f}, "
                    f"cost ${total_cost:,.0f}, profit ${total_profit:,.0f}. "
                    f"Margin {margin:.1f}%.")
        except:
            pass
    
    # Capital deployed / portfolio value
    if any(w in text_lower for w in ['capital', 'deployed', 'portfolio', 'total cost', 'invested',
                                      'how much have i spent', 'total investment', 'money in']):
        try:
            rows = _siri_get_rows()
            unsold = [r for r in rows if r.get('sold') != 'Yes']
            total_cost = sum(_siri_parse_money(r.get('cost_price')) for r in unsold)
            total_sale = sum(_siri_parse_money(r.get('sale_price')) for r in unsold if r.get('sale_price'))
            return (f"${total_cost:,.0f} capital deployed across {len(unsold)} watches. "
                    f"Listed value ${total_sale:,.0f}." if total_sale else
                    f"${total_cost:,.0f} capital deployed across {len(unsold)} watches.")
        except:
            pass
    
    # ROI
    if any(w in text_lower for w in ['roi', 'return on investment', 'return rate']):
        try:
            rows = _siri_get_rows()
            sold = [r for r in rows if r.get('sold') == 'Yes']
            total_revenue = sum(_siri_parse_money(r.get('sold_price')) for r in sold)
            total_cost = sum(_siri_parse_money(r.get('cost_price')) for r in sold)
            roi = ((total_revenue - total_cost) / total_cost * 100) if total_cost else 0
            return f"ROI: {roi:.1f}%. Spent ${total_cost:,.0f}, sold for ${total_revenue:,.0f}."
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 5. SHIPPING & LOGISTICS
    # ═══════════════════════════════════════════
    
    # What needs shipping
    if any(w in text_lower for w in ['need to ship', 'needs shipping', 'what to ship', 'not shipped',
                                      'sold not shipped', 'pending shipment', 'waiting to ship',
                                      'need labels', 'need a label']):
        try:
            rows = _siri_get_rows()
            need_ship = [r for r in rows if r.get('sold') == 'Yes' and r.get('shipped') != 'Yes']
            if need_ship:
                items = [f"{r.get('description','')} to {r.get('sold_to','?')}" for r in need_ship]
                return f"{len(need_ship)} watches need shipping: {'. '.join(items)}"
            return "Everything sold has been shipped."
        except:
            pass
    
    # In transit / waiting to arrive
    if any(w in text_lower for w in ['in transit', 'waiting to arrive', 'not arrived', 'incoming',
                                      'on the way', 'coming in', 'expected deliveries', 'arriving']):
        try:
            rows = _siri_get_rows()
            transit = [r for r in rows if r.get('arrived') != 'Yes' and r.get('sold') != 'Yes']
            if transit:
                items = [f"{r.get('description','')} from {r.get('bought_from','?')}" for r in transit]
                return f"{len(transit)} watches in transit: {'. '.join(items[:5])}" + (f" and {len(items)-5} more." if len(items) > 5 else ".")
            return "Nothing in transit. All watches have arrived."
        except:
            pass
    
    # At store
    if any(w in text_lower for w in ['at store', 'at the store', 'in store', 'store inventory',
                                      'what\'s at store', 'jennifer', 'consignment']):
        try:
            rows = _siri_get_rows()
            at_store = [r for r in rows if r.get('at_store') == 'Yes' and r.get('sold') != 'Yes']
            if at_store:
                total_val = sum(_siri_parse_money(r.get('cost_price')) for r in at_store)
                items = [r.get('description','') for r in at_store]
                return f"{len(at_store)} watches at store, ${total_val:,.0f} total. {', '.join(items[:5])}" + (f" and {len(items)-5} more." if len(items) > 5 else ".")
            return "No watches at store right now."
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 6. POSTING & SALES STATUS
    # ═══════════════════════════════════════════
    
    # Not posted / need to post
    if any(w in text_lower for w in ['not posted', 'need to post', 'unposted', 'haven\'t posted',
                                      'waiting to post', 'idle', 'sitting']):
        try:
            rows = _siri_get_rows()
            unposted = [r for r in rows if r.get('posted') != 'Yes' and r.get('sold') != 'Yes' and r.get('at_store') != 'Yes']
            if unposted:
                total_val = sum(_siri_parse_money(r.get('cost_price')) for r in unposted)
                items = [r.get('description','') for r in unposted]
                return f"{len(unposted)} watches not posted yet. ${total_val:,.0f} idle capital. {', '.join(items[:5])}."
            return "All arrived watches are posted."
        except:
            pass
    
    # Stale inventory
    if any(w in text_lower for w in ['stale', 'old inventory', 'slow movers', 'sitting too long',
                                      'not selling', 'hard to sell', 'oldest']):
        try:
            rows = _siri_get_rows()
            posted = [r for r in rows if r.get('posted') == 'Yes' and r.get('sold') != 'Yes']
            # Calculate days posted (rough — based on bought_date)
            stale = []
            for r in posted:
                bd = r.get('bought_date', '')
                try:
                    if '/' in bd:
                        d = datetime.strptime(bd, '%m/%d/%Y')
                    else:
                        d = datetime.strptime(bd, '%B %d, %Y') if bd else None
                    if d:
                        days = (datetime.now() - d).days
                        if days >= 30:
                            stale.append((r.get('description',''), days))
                except:
                    pass
            stale.sort(key=lambda x: -x[1])
            if stale:
                items = [f"{desc} ({days}d)" for desc, days in stale[:5]]
                return f"{len(stale)} watches posted 30+ days: {'. '.join(items)}"
            return "No stale inventory. Everything's moving well."
        except:
            pass
    
    # Best deals / highest margin
    if any(w in text_lower for w in ['best deal', 'highest margin', 'most profit', 'biggest margin',
                                      'best flip', 'top deal']):
        try:
            rows = _siri_get_rows()
            listings = _siri_get_listings()
            opportunities = []
            for r in rows:
                if r.get('sold') == 'Yes' or not r.get('sale_price'):
                    continue
                cost = _siri_parse_money(r.get('cost_price'))
                sale = _siri_parse_money(r.get('sale_price'))
                if cost and sale and cost > 100:  # Skip placeholder $1 costs
                    margin = sale - cost
                    pct = margin / cost * 100
                    opportunities.append((r.get('description',''), margin, pct))
            opportunities.sort(key=lambda x: -x[1])
            if opportunities:
                items = [f"{desc}: ${margin:,.0f} ({pct:.0f}%)" for desc, margin, pct in opportunities[:3]]
                return f"Top margin watches: {'. '.join(items)}"
            return "No margin data available."
        except:
            pass
    
    # (Sections 7 moved to 1D above)
    
    # ═══════════════════════════════════════════
    # 8. MARKET INTELLIGENCE
    # ═══════════════════════════════════════════
    
    # Total listings / market size
    if any(w in text_lower for w in ['total listings', 'market size', 'how many listings', 'listing count']):
        try:
            listings = _siri_get_listings()
            us = len([l for l in listings if l.get('currency') == 'USD'])
            hk = len([l for l in listings if l.get('currency') == 'HKD'])
            refs = len(set(l.get('ref') for l in listings))
            return f"{len(listings)} total listings across {refs} references. {us} US, {hk} HK."
        except:
            pass
    
    # Cheapest / lowest price for a ref
    if any(w in text_lower for w in ['cheapest', 'lowest', 'best price', 'lowest price']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            try:
                listings = _siri_get_listings()
                matches = [l for l in listings if l.get('ref') == ref or l.get('ref','').startswith(ref)]
                if matches:
                    by_price = sorted(matches, key=lambda l: l.get('price', 999999))
                    cheapest = by_price[0]
                    return (f"Cheapest {ref}: ${cheapest['price']:,.0f} "
                            f"({cheapest.get('currency','?')}, {cheapest.get('condition','')}, "
                            f"{cheapest.get('seller','')[:30]})")
                return f"No listings for {ref}."
            except:
                pass
    
    # ═══════════════════════════════════════════
    # 9. ACTIVITY & TIMELINE
    # ═══════════════════════════════════════════
    
    # Today's summary
    if any(w in text_lower for w in ["what happened today", "today's activity", "today summary", 
                                      "daily summary", "today's sales", 'today recap']):
        try:
            rows = _siri_get_rows()
            today = datetime.now(ET).strftime('%m/%d/%Y')
            today2 = datetime.now(ET).strftime('%B %d, %Y')
            today3 = datetime.now(ET).strftime('%d %B %Y')
            sold_today = [r for r in rows if r.get('sale_date','') in [today, today2, today3]]
            bought_today = [r for r in rows if r.get('bought_date','') in [today, today2, today3]]
            parts = []
            if sold_today:
                rev = sum(_siri_parse_money(r.get('sold_price')) for r in sold_today)
                parts.append(f"{len(sold_today)} sold for ${rev:,.0f}")
            if bought_today:
                cost = sum(_siri_parse_money(r.get('cost_price')) for r in bought_today)
                parts.append(f"{len(bought_today)} bought for ${cost:,.0f}")
            return f"Today: {'. '.join(parts)}." if parts else "Quiet day — no sales or purchases logged."
        except:
            pass
    
    # Recent sales
    if any(w in text_lower for w in ['recent sales', 'last sold', 'what did i sell', 'latest sales']):
        try:
            rows = _siri_get_rows()
            sold = [r for r in rows if r.get('sold') == 'Yes' and r.get('sale_date')]
            sold.sort(key=lambda r: r.get('sale_date',''), reverse=True)
            if sold:
                items = [f"{r.get('description','')} to {r.get('sold_to','?')} for ${_siri_parse_money(r.get('sold_price')):,.0f}" for r in sold[:3]]
                return f"Recent sales: {'. '.join(items)}"
            return "No recent sales."
        except:
            pass
    
    # How many sold
    if any(w in text_lower for w in ['how many sold', 'total sold', 'watches sold', 'sales count']):
        try:
            rows = _siri_get_rows()
            sold = [r for r in rows if r.get('sold') == 'Yes']
            total = sum(_siri_parse_money(r.get('sold_price')) for r in sold)
            return f"{len(sold)} watches sold for a total of ${total:,.0f}."
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 10. SPECIFIC BUYER/SELLER QUERIES
    # ═══════════════════════════════════════════
    
    # "What did I sell to [name]" / "what did [name] buy"
    name_sell_match = re.search(r'(?:sell to|sold to|buy from me|bought from me)\s+(.+)', text_lower)
    if not name_sell_match:
        name_sell_match = re.search(r'(?:what did|how much does?)\s+(.+?)\s+(?:buy|owe|get|purchase)', text_lower)
    if name_sell_match:
        name = name_sell_match.group(1).strip()
        try:
            rows = _siri_get_rows()
            found = [r for r in rows if name in r.get('sold_to','').lower()]
            if found:
                total = sum(_siri_parse_money(r.get('sold_price')) for r in found)
                items = [r.get('description','') for r in found]
                paid = len([r for r in found if r.get('paid_after_sold') == 'Yes'])
                return f"{name.title()}: {len(found)} watches, ${total:,.0f}. {paid} paid. Watches: {', '.join(items[:5])}"
            return f"No sales to anyone matching '{name}'."
        except:
            pass
    
    # "What did I buy from [name]"
    name_buy_match = re.search(r'(?:buy from|bought from|get from)\s+(.+)', text_lower)
    if name_buy_match:
        name = name_buy_match.group(1).strip()
        try:
            rows = _siri_get_rows()
            found = [r for r in rows if name in r.get('bought_from','').lower()]
            if found:
                total = sum(_siri_parse_money(r.get('cost_price')) for r in found)
                return f"Bought {len(found)} watches from {name.title()}, total ${total:,.0f}."
            return f"No purchases from anyone matching '{name}'."
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 11. DASHBOARD & SYSTEM STATUS
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['dashboard status', 'system status', 'is everything working',
                                      'health check', 'are you online', 'status']):
        try:
            rows = _siri_get_rows()
            return (f"All systems operational. Dashboard up since {app_start_time.strftime('%I:%M %p')}. "
                    f"Bot Sheet has {len(rows)} rows. Ready to go.")
        except:
            return "Dashboard is running. I'm online and ready."
    
    # (Sections 12-13 moved to 1B-1C above)
    
    # ═══════════════════════════════════════════
    # 14. PRICE COMPARISON / SHOULD I BUY
    # ═══════════════════════════════════════════
    
    # "Should I buy 126234 for 12000" / "is 12000 good for 126234"
    buy_match = re.search(r'(?:should i buy|good (?:price|deal)|fair price|buy.*for|worth)\s*.*?(\d{5,6}[A-Z]{0,4}).*?\$?(\d[\d,]+)', text, re.IGNORECASE)
    if not buy_match:
        buy_match = re.search(r'(\d{5,6}[A-Z]{0,4}).*?(?:for|at)\s*\$?(\d[\d,]+).*?(?:good|fair|worth|should|deal)', text, re.IGNORECASE)
    if buy_match:
        ref = buy_match.group(1).upper()
        offer = float(buy_match.group(2).replace(',',''))
        try:
            listings = _siri_get_listings()
            matches = [l for l in listings if l.get('ref') == ref or l.get('ref','').startswith(ref)]
            us = [l for l in matches if l.get('currency') == 'USD']
            if us:
                us_prices = sorted([l['price'] for l in us if l.get('price')])
                us_low = us_prices[0]
                avg = sum(us_prices) / len(us_prices)
                below_count = len([p for p in us_prices if p > offer])
                pct_below = below_count / len(us_prices) * 100
                if offer < us_low:
                    return f"${offer:,.0f} for {ref} is BELOW the lowest US listing (${us_low:,.0f}). Great buy if you can get it. {pct_below:.0f}% of listings are higher."
                elif offer < avg * 0.9:
                    return f"${offer:,.0f} for {ref} is a good deal. US low is ${us_low:,.0f}, average ${avg:,.0f}. You'd be in the bottom {100-pct_below:.0f}% of prices."
                else:
                    return f"${offer:,.0f} for {ref} is around market. US low ${us_low:,.0f}, average ${avg:,.0f}. {pct_below:.0f}% of {len(us_prices)} US listings are higher."
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 15. WHAT SHOULD I PRICE / SELL FOR
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['what should i price', 'what should i sell', 'how much should i sell',
                                      'what price should', 'how much can i get', 'what can i sell',
                                      'how much to sell', 'pricing recommendation', 'what to list']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            try:
                listings = _siri_get_listings()
                matches = [l for l in listings if l.get('ref') == ref or l.get('ref','').startswith(ref)]
                us = sorted([l['price'] for l in matches if l.get('price') and l.get('currency') == 'USD'])
                if us:
                    low = us[0]
                    b25_idx = max(0, len(us) // 4 - 1)
                    b25 = us[b25_idx]
                    median = us[len(us)//2]
                    # Check our cost
                    rows = _siri_get_rows()
                    owned = [r for r in rows if ref in r.get('description','').upper() and r.get('sold') != 'Yes']
                    cost_str = ""
                    if owned:
                        cost = _siri_parse_money(owned[0].get('cost_price'))
                        if cost > 100:
                            cost_str = f" Your cost: ${cost:,.0f}."
                    return f"{ref} pricing: US low ${low:,.0f}, bottom 25% ${b25:,.0f}, median ${median:,.0f}. Recommend listing around ${b25:,.0f} to ${median:,.0f} for competitive pricing.{cost_str}"
            except:
                pass
    
    # ═══════════════════════════════════════════
    # 16. WATCH NAME / MODEL LOOKUP
    # ═══════════════════════════════════════════
    
    model_map = {
        '126500': 'Daytona Panda', '126506': 'Daytona Platinum', '126508': 'Daytona Gold',
        '126509': 'Daytona White Gold', '126518': 'Daytona Gold Oysterflex',
        '126610': 'Submariner', '126610LN': 'Submariner Date Black',
        '126610LV': 'Submariner Starbucks', '126613LB': 'Submariner Two-Tone Blue',
        '126710BLNR': 'GMT-Master Batman', '126710BLRO': 'GMT-Master Pepsi',
        '126710GRNR': 'GMT-Master Sprite', '126720VTNR': 'GMT-Master Destro',
        '126234': 'Datejust 36', '126334': 'Datejust 41', '126331': 'Datejust 41 Rose Gold',
        '126233': 'Datejust 36 Two-Tone', '126283': 'Datejust 36 Rose Gold',
        '126300': 'Datejust 41 Smooth Bezel', '126333': 'Datejust 41 Two-Tone',
        '228238': 'Day-Date 40 Yellow Gold', '228235': 'Day-Date 40 Rose Gold',
        '228236': 'Day-Date 40 Platinum',
        '226570': 'Explorer II', '124270': 'Explorer I', '124200': 'Oyster Perpetual 34',
        '126231': 'Datejust 36 Rose Gold', '126284': 'Datejust 36 Rose Gold Diamond',
        '336934': 'Sky-Dweller', '326934': 'Sky-Dweller Steel',
        '127334': 'DateJust 41 Rose Gold',
        '278271': 'Datejust 31 Rose Gold', '278273': 'Datejust 31 Rose Gold Diamond',
        '278274': 'Datejust 31 White Gold',
        '276200': 'Oyster Perpetual 28', '277200': 'Oyster Perpetual 31',
        '126599': 'Daytona Rainbow', '126598': 'Daytona Rose Gold',
        '15550ST': 'Royal Oak 41',
    }
    
    if any(w in text_lower for w in ['what is', "what's a", 'what model', 'what watch', 'which model']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            name = model_map.get(ref, model_map.get(ref[:6], None))
            if name:
                return f"{ref} is the Rolex {name}."
            # Try prefix match
            for k, v in model_map.items():
                if k.startswith(ref) or ref.startswith(k):
                    return f"{ref} is the Rolex {v}."
            return f"{ref} — I don't have a model name for that reference."
    
    # ═══════════════════════════════════════════
    # 17. TRACKING / SHIPMENT STATUS
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['tracking', 'shipment status', 'where is my shipment',
                                      'shipping status', 'did i ship']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            try:
                rows = _siri_get_rows()
                shipped = [r for r in rows if ref in r.get('description','').upper() and r.get('shipped') == 'Yes']
                not_shipped = [r for r in rows if ref in r.get('description','').upper() and r.get('sold') == 'Yes' and r.get('shipped') != 'Yes']
                parts = []
                if shipped:
                    parts.append(f"{len(shipped)} shipped")
                if not_shipped:
                    parts.append(f"{len(not_shipped)} sold but NOT shipped yet")
                    for r in not_shipped:
                        parts.append(f"  → {r.get('description','')} to {r.get('sold_to','?')}")
                return f"{ref}: {'. '.join(parts)}" if parts else f"No shipping info for {ref}."
            except:
                pass
    
    # ═══════════════════════════════════════════
    # 18. SERIAL NUMBER LOOKUP
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['serial', 'serial number']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            try:
                rows = _siri_get_rows()
                found = [r for r in rows if ref in r.get('description','').upper() and r.get('serial')]
                if found:
                    items = [f"{r.get('description','')}: {r.get('serial','')}" for r in found]
                    return '. '.join(items[:5])
                return f"No serial numbers recorded for {ref}."
            except:
                pass
    
    # ═══════════════════════════════════════════
    # 19. BRAND BREAKDOWN
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['how many rolex', 'how many patek', 'how many ap',
                                      'rolex count', 'patek count', 'brand breakdown']):
        try:
            rows = _siri_get_rows()
            unsold = [r for r in rows if r.get('sold') != 'Yes']
            # Simple brand detection by ref prefix
            rolex = len([r for r in unsold if re.match(r'\d{5,6}', r.get('description',''))])
            return f"Inventory: {len(unsold)} total unsold watches. Most are Rolex based on reference numbers."
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 20. WATCH CONDITION FROM BOT SHEET
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['card date', 'warranty', 'when was.*made', 'year of']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            try:
                rows = _siri_get_rows()
                found = [r for r in rows if ref in r.get('description','').upper()]
                if found:
                    items = [f"{r.get('description','')}: card date {r.get('date_on_card','N/A')}, serial {r.get('serial','N/A')}" for r in found]
                    return '. '.join(items[:5])
                return f"No {ref} found."
            except:
                pass
    
    # ═══════════════════════════════════════════
    # 21. AVERAGE HOLD TIME
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['average hold', 'how long.*hold', 'days to sell', 'turnover',
                                      'how fast.*sell', 'hold time']):
        try:
            rows = _siri_get_rows()
            sold = [r for r in rows if r.get('sold') == 'Yes' and r.get('bought_date') and r.get('sale_date')]
            hold_days = []
            for r in sold:
                try:
                    bd = r.get('bought_date','')
                    sd = r.get('sale_date','')
                    # Try multiple date formats
                    for fmt in ['%m/%d/%Y', '%B %d, %Y']:
                        try:
                            bd_dt = datetime.strptime(bd, fmt)
                            sd_dt = datetime.strptime(sd, fmt)
                            days = (sd_dt - bd_dt).days
                            if 0 <= days < 365:
                                hold_days.append(days)
                            break
                        except:
                            continue
                except:
                    pass
            if hold_days:
                avg = sum(hold_days) / len(hold_days)
                fastest = min(hold_days)
                slowest = max(hold_days)
                return f"Average hold time: {avg:.0f} days ({len(hold_days)} sold watches). Fastest: {fastest} days. Slowest: {slowest} days."
            return "Not enough data to calculate hold times."
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 22. TOP BUYERS / TOP SELLERS
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['top buyer', 'best buyer', 'biggest buyer', 'who buys the most',
                                      'best customer', 'top customer']):
        try:
            rows = _siri_get_rows()
            buyer_counts = {}
            buyer_revenue = {}
            for r in rows:
                if r.get('sold') == 'Yes' and r.get('sold_to'):
                    buyer = r['sold_to']
                    buyer_counts[buyer] = buyer_counts.get(buyer, 0) + 1
                    buyer_revenue[buyer] = buyer_revenue.get(buyer, 0) + _siri_parse_money(r.get('sold_price'))
            top = sorted(buyer_revenue.items(), key=lambda x: -x[1])[:5]
            items = [f"{name}: {buyer_counts.get(name,0)} watches, ${rev:,.0f}" for name, rev in top]
            return f"Top buyers: {'. '.join(items)}"
        except:
            pass
    
    if any(w in text_lower for w in ['top seller', 'biggest seller', 'who sells me the most',
                                      'best supplier', 'top supplier', 'buy from the most']):
        try:
            rows = _siri_get_rows()
            seller_counts = {}
            seller_cost = {}
            for r in rows:
                if r.get('bought_from'):
                    seller = r['bought_from']
                    seller_counts[seller] = seller_counts.get(seller, 0) + 1
                    seller_cost[seller] = seller_cost.get(seller, 0) + _siri_parse_money(r.get('cost_price'))
            top = sorted(seller_cost.items(), key=lambda x: -x[1])[:5]
            items = [f"{name}: {seller_counts.get(name,0)} watches, ${cost:,.0f}" for name, cost in top]
            return f"Top suppliers: {'. '.join(items)}"
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 23. MOST TRADED REF
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['most traded', 'most popular', 'what do i trade most',
                                      'top reference', 'most sold ref']):
        try:
            rows = _siri_get_rows()
            ref_counts = {}
            for r in rows:
                ref = re.search(r'(\d{5,6}[A-Z]{0,4})', r.get('description',''))
                if ref:
                    ref_str = ref.group(1)
                    ref_counts[ref_str] = ref_counts.get(ref_str, 0) + 1
            top = sorted(ref_counts.items(), key=lambda x: -x[1])[:5]
            items = [f"{ref}: {count} watches" for ref, count in top]
            return f"Most traded refs: {'. '.join(items)}"
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 24. CASH FLOW SUMMARY
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['cash flow', 'money in and out', 'inflow outflow',
                                      'financial summary', 'money summary', 'p&l']):
        try:
            rows = _siri_get_rows()
            total_bought = sum(_siri_parse_money(r.get('cost_price')) for r in rows)
            total_sold = sum(_siri_parse_money(r.get('sold_price')) for r in rows if r.get('sold') == 'Yes')
            unsold_cost = sum(_siri_parse_money(r.get('cost_price')) for r in rows if r.get('sold') != 'Yes')
            unpaid_ar = sum(_siri_parse_money(r.get('sold_price')) for r in rows 
                          if r.get('sold') == 'Yes' and r.get('paid_after_sold') != 'Yes')
            return (f"Total bought: ${total_bought:,.0f}. Total sold: ${total_sold:,.0f}. "
                    f"Net P&L: ${total_sold - total_bought + unsold_cost:,.0f}. "
                    f"Capital tied up: ${unsold_cost:,.0f}. Receivables: ${unpaid_ar:,.0f}.")
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 25. DUPLICATE DETECTION
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['duplicate', 'same watch twice', 'do i have two']):
        try:
            rows = _siri_get_rows()
            unsold = [r for r in rows if r.get('sold') != 'Yes']
            desc_counts = {}
            for r in unsold:
                d = r.get('description','')
                desc_counts[d] = desc_counts.get(d, 0) + 1
            dupes = {d: c for d, c in desc_counts.items() if c > 1}
            if dupes:
                items = [f"{d} (x{c})" for d, c in dupes.items()]
                return f"Duplicates found: {'. '.join(items)}"
            return "No duplicate watches in inventory."
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 26. COMPARE TWO REFS
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['compare', 'versus', ' vs ', 'difference between', 'or']):
        refs = re.findall(r'\b(\d{5,6}[A-Z]{0,4})\b', text, re.IGNORECASE)
        if len(refs) >= 2:
            try:
                listings = _siri_get_listings()
                results = []
                for ref in refs[:2]:
                    ref = ref.upper()
                    matches = [l for l in listings if l.get('ref') == ref or l.get('ref','').startswith(ref)]
                    us = sorted([l['price'] for l in matches if l.get('price') and l.get('currency') == 'USD'])
                    us_low = us[0] if us else 0
                    median = us[len(us)//2] if us else 0
                    results.append(f"{ref}: {len(matches)} listings, US low ${us_low:,.0f}, median ${median:,.0f}")
                return f"Comparison: {results[0]}. {results[1]}."
            except:
                pass
    
    # ═══════════════════════════════════════════
    # 27. MARKUP / WHAT TO OFFER
    # ═══════════════════════════════════════════
    
    # "Offer / bid on 126234" → suggests 10-15% below market
    if any(w in text_lower for w in ['what to offer', 'what should i offer', 'how much to offer',
                                      'bid on', 'offer on', 'lowball']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            try:
                listings = _siri_get_listings()
                matches = [l for l in listings if l.get('ref') == ref or l.get('ref','').startswith(ref)]
                us = sorted([l['price'] for l in matches if l.get('price') and l.get('currency') == 'USD'])
                if us:
                    us_low = us[0]
                    b25 = us[max(0, len(us)//4 - 1)]
                    # Suggest 10-15% below B25 for buy price
                    target_low = int(b25 * 0.85 / 100) * 100
                    target_high = int(b25 * 0.90 / 100) * 100
                    return f"For {ref}, US low is ${us_low:,.0f}, B25 is ${b25:,.0f}. Target buy: ${target_low:,.0f} to ${target_high:,.0f} (10-15% below B25)."
            except:
                pass
    
    # ═══════════════════════════════════════════
    # 28. LISTING COUNT BY YEAR
    # ═══════════════════════════════════════════
    
    year_match = re.search(r'(\d{5,6}[A-Z]{0,4})\s*(?:20)?(\d{2})\b', text, re.IGNORECASE)
    if not year_match:
        year_match = re.search(r'(?:20)?(\d{2})\s*(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
    if year_match and any(w in text_lower for w in ['listings', 'available', 'on the market', 'for sale']):
        try:
            groups = year_match.groups()
            # Figure out which is ref, which is year
            if len(groups[0]) >= 5:
                ref, yr = groups[0].upper(), groups[1]
            else:
                yr, ref = groups[0], groups[1].upper()
            if len(yr) == 2:
                yr = '20' + yr
            listings = _siri_get_listings()
            matches = [l for l in listings if (l.get('ref') == ref or l.get('ref','').startswith(ref)) and str(l.get('year','')) == yr]
            us = [l for l in matches if l.get('currency') == 'USD']
            if matches:
                prices = sorted([l['price'] for l in matches if l.get('price')])
                return f"{ref} {yr}: {len(matches)} listings ({len(us)} US). Range ${prices[0]:,.0f} to ${prices[-1]:,.0f}."
            return f"No {yr} {ref} listings found."
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 29. WHAT'S NEW / RECENT PURCHASES
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['recent purchase', 'what did i buy', 'latest purchase',
                                      'new watches', "what's new", 'recently bought']):
        try:
            rows = _siri_get_rows()
            bought = [r for r in rows if r.get('bought_date')]
            bought.sort(key=lambda r: r.get('bought_date',''), reverse=True)
            if bought:
                items = [f"{r.get('description','')} from {r.get('bought_from','?')} for ${_siri_parse_money(r.get('cost_price')):,.0f}" for r in bought[:5]]
                return f"Recent purchases: {'. '.join(items)}"
            return "No recent purchases."
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 30. TOTAL VALUE / NET WORTH OF INVENTORY
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['total value', 'inventory value', 'net worth', 'what is my inventory worth',
                                      'portfolio value', 'how much is my inventory']):
        try:
            rows = _siri_get_rows()
            unsold = [r for r in rows if r.get('sold') != 'Yes']
            cost = sum(_siri_parse_money(r.get('cost_price')) for r in unsold)
            listed = sum(_siri_parse_money(r.get('sale_price')) for r in unsold if r.get('sale_price'))
            posted = len([r for r in unsold if r.get('posted') == 'Yes'])
            unlisted_cost = sum(_siri_parse_money(r.get('cost_price')) for r in unsold if not r.get('sale_price'))
            return (f"Inventory: {len(unsold)} watches. Cost basis ${cost:,.0f}. "
                    f"Listed value ${listed:,.0f} ({posted} posted). "
                    f"${unlisted_cost:,.0f} in unlisted watches.")
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 31. WHAT SHOULD I DO NEXT / PRIORITIES
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['what should i do', 'priorities', 'action items', 'to do',
                                      'what needs attention', 'next steps', 'what needs doing']):
        try:
            rows = _siri_get_rows()
            actions = []
            
            # Sold not shipped
            need_ship = [r for r in rows if r.get('sold') == 'Yes' and r.get('shipped') != 'Yes']
            if need_ship:
                actions.append(f"🚚 Ship {len(need_ship)} sold watches")
            
            # Unpaid receivables
            unpaid = [r for r in rows if r.get('sold') == 'Yes' and r.get('paid_after_sold') != 'Yes']
            if unpaid:
                total = sum(_siri_parse_money(r.get('sold_price')) for r in unpaid)
                actions.append(f"💰 Collect ${total:,.0f} from {len(unpaid)} buyers")
            
            # Arrived not posted
            unposted = [r for r in rows if r.get('posted') != 'Yes' and r.get('sold') != 'Yes' and r.get('at_store') != 'Yes']
            if unposted:
                actions.append(f"📸 Post {len(unposted)} watches")
            
            # In transit
            transit = [r for r in rows if r.get('arrived') != 'Yes' and r.get('sold') != 'Yes']
            if transit:
                actions.append(f"📦 {len(transit)} watches in transit")
            
            if actions:
                return "Priorities: " + ". ".join(actions)
            return "All caught up! Nothing urgent."
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 32. SELL THROUGH RATE
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['sell through', 'conversion rate', 'sold vs posted',
                                      'how many sold out of', 'success rate']):
        try:
            rows = _siri_get_rows()
            total = len(rows)
            sold = len([r for r in rows if r.get('sold') == 'Yes'])
            unsold = total - sold
            rate = (sold / total * 100) if total else 0
            return f"Sell-through: {sold}/{total} watches ({rate:.0f}%). {unsold} still in inventory."
        except:
            pass
    
    # ═══════════════════════════════════════════
    # 33. COST BASIS FOR A SPECIFIC REF
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['how much did i pay', 'what did i pay', 'cost for', 'my cost on']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            try:
                rows = _siri_get_rows()
                found = [r for r in rows if ref in r.get('description','').upper()]
                if found:
                    items = [f"{r.get('description','')}: ${_siri_parse_money(r.get('cost_price')):,.0f} from {r.get('bought_from','?')}" for r in found]
                    return '. '.join(items[:5])
                return f"No {ref} found."
            except:
                pass
    
    # ═══════════════════════════════════════════
    # 34. SPECIFIC DIAL/BRACELET QUERY
    # ═══════════════════════════════════════════
    
    dial_keywords = ['blue', 'black', 'green', 'white', 'silver', 'champagne', 'chocolate', 
                     'slate', 'wimbledon', 'mint', 'pink', 'mother of pearl', 'mop',
                     'panda', 'reverse panda', 'meteorite', 'palm']
    brace_keywords = ['oyster', 'jubilee', 'president', 'oysterflex', 'leather']
    
    # "How many blue 126234" or "blue datejust price"
    for dial in dial_keywords:
        if dial in text_lower:
            ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
            if ref_match2:
                ref = ref_match2.group(1).upper()
                try:
                    listings = _siri_get_listings()
                    matches = [l for l in listings if (l.get('ref') == ref or l.get('ref','').startswith(ref))
                              and dial in (l.get('dial','') or '').lower()]
                    if matches:
                        prices = sorted([l['price'] for l in matches if l.get('price')])
                        us = [l for l in matches if l.get('currency') == 'USD']
                        us_prices = sorted([l['price'] for l in us if l.get('price')])
                        return (f"{ref} {dial.title()} dial: {len(matches)} listings. "
                                f"Range ${prices[0]:,.0f} to ${prices[-1]:,.0f}. "
                                f"US low: ${us_prices[0]:,.0f} ({len(us)} US)." if us_prices else
                                f"{ref} {dial.title()} dial: {len(matches)} listings. "
                                f"Range ${prices[0]:,.0f} to ${prices[-1]:,.0f}.")
                    return f"No {dial} dial listings for {ref}."
                except:
                    pass
            break
    
    # ═══════════════════════════════════════════
    # 35. SPREAD / BID-ASK
    # ═══════════════════════════════════════════
    
    if any(w in text_lower for w in ['spread', 'bid ask', 'buy sell spread']):
        ref_match2 = re.search(r'(\d{5,6}[A-Z]{0,4})', text, re.IGNORECASE)
        if ref_match2:
            ref = ref_match2.group(1).upper()
            try:
                listings = _siri_get_listings()
                matches = [l for l in listings if l.get('ref') == ref or l.get('ref','').startswith(ref)]
                us = sorted([l['price'] for l in matches if l.get('price') and l.get('currency') == 'USD'])
                if us:
                    b25 = us[max(0, len(us)//4 - 1)]
                    t25 = us[min(len(us)-1, len(us)*3//4)]
                    spread = t25 - b25
                    spread_pct = spread / b25 * 100
                    return f"{ref} spread: B25 ${b25:,.0f}, T25 ${t25:,.0f}. Spread ${spread:,.0f} ({spread_pct:.1f}%). Tight = liquid, wide = illiquid."
            except:
                pass
    
    # ═══════════════════════════════════════════
    # NEW INSTANT ANSWERS - AUTONOMOUS IMPROVEMENTS
    # ═══════════════════════════════════════════
    
    # Help/what can you do (must be primary intent, not incidental "help")
    if text_lower in ['help', 'what can you do', 'what can i ask', 'what can i ask mochie',
                       'what do you do', 'commands', 'menu', 'options']:
        return ("I can help with: 1. PRICES: 'how much is 126500' 2. INVENTORY: 'how many watches' 3. MONEY: 'who owes me money' 4. OPERATIONS: 'what needs shipping' 5. DEALS: 'best deals today' 6. PROFIT: 'total profit' 7. STALE: 'what's been sitting too long' 8. ARRIVALS: 'what arrived' 9. CAPITAL: 'cash deployed' 10. MARKET: 'underwater watches'")
    
    # Good morning/briefing
    if any(w in text_lower for w in ['good morning', 'morning briefing']):
        try:
            rows = _siri_get_rows()
            unsold = len([r for r in rows if r.get('sold') != 'Yes'])
            need_ship = len([r for r in rows if r.get('sold') == 'Yes' and r.get('shipped') != 'Yes'])
            unpaid = [r for r in rows if r.get('sold') == 'Yes' and r.get('paid_after_sold') != 'Yes']
            outstanding = sum(_siri_parse_money(r.get('sold_price', '')) for r in unpaid)
            return f"Good morning Jeffin! {unsold} watches in inventory. {need_ship} need shipping. ${outstanding:,.0f} outstanding from {len(unpaid)} buyers. Market data current as of {get_latest_sync()}."
        except:
            pass
    
    # Who hasn't paid/deadbeats
    if any(w in text_lower for w in ['who hasn\'t paid', 'who hasnt paid', 'deadbeats', 'who owes', 'unpaid buyers', 'not paid']):
        try:
            rows = _siri_get_rows()
            unpaid = [r for r in rows if r.get('sold') == 'Yes' and r.get('paid_after_sold') != 'Yes']
            if unpaid:
                buyers = {}
                for r in unpaid:
                    buyer = r.get('sold_to', 'Unknown')
                    amount = _siri_parse_money(r.get('sold_price', ''))
                    if buyer in buyers:
                        buyers[buyer] += amount
                    else:
                        buyers[buyer] = amount
                sorted_buyers = sorted(buyers.items(), key=lambda x: x[1], reverse=True)
                top3 = [f"{buyer} owes ${amount:,.0f}" for buyer, amount in sorted_buyers[:3]]
                total = sum(buyers.values())
                return f"Unpaid: {'. '.join(top3)}. Total ${total:,.0f} outstanding from {len(buyers)} buyers."
            return "Everyone has paid! No outstanding receivables."
        except:
            pass
    
    # What's underwater/losing money on
    if any(w in text_lower for w in ['what\'s underwater', 'whats underwater', 'underwater', 'losing money on', 'below cost']):
        try:
            rows = _siri_get_rows()
            listings = _siri_get_listings()
            
            # Build market lows
            market_lows = {}
            for l in listings:
                ref = l.get('ref', '').strip()
                if ref and l.get('region') == 'US' and l.get('price_usd', 0) > 0:
                    if ref not in market_lows:
                        market_lows[ref] = l['price_usd']
                    else:
                        market_lows[ref] = min(market_lows[ref], l['price_usd'])
            
            underwater = []
            for row in rows:
                if row.get('sold') == 'Yes':
                    continue
                cost = _siri_parse_money(row.get('cost_price', ''))
                ref = row.get('description', '').split()[0] if row.get('description') else ''
                market_low = market_lows.get(ref, 0)
                
                if cost > 0 and market_low > 0 and market_low < cost:
                    loss = cost - market_low
                    underwater.append(f"{ref} (cost ${cost:,.0f}, market ${market_low:,.0f}, loss ${loss:,.0f})")
            
            if underwater:
                return f"Underwater watches: {'. '.join(underwater[:3])}" + (f" and {len(underwater)-3} more" if len(underwater) > 3 else "")
            return "Good news! No watches are underwater. All inventory above market lows."
        except:
            pass
    
    # Best margin/most profitable
    if any(w in text_lower for w in ['best margin', 'most profitable', 'highest profit']):
        try:
            rows = _siri_get_rows()
            sold_watches = [r for r in rows if r.get('sold') == 'Yes']
            
            profits = []
            for r in sold_watches:
                cost = _siri_parse_money(r.get('cost_price', ''))
                sale = _siri_parse_money(r.get('sold_price', ''))
                if cost > 0 and sale > 0:
                    profit = sale - cost
                    margin = (profit / cost) * 100
                    profits.append({
                        'desc': r.get('description', ''),
                        'profit': profit,
                        'margin': margin,
                        'cost': cost,
                        'sale': sale
                    })
            
            if profits:
                # Sort by margin percentage
                profits.sort(key=lambda x: x['margin'], reverse=True)
                top3 = profits[:3]
                results = [f"{p['desc']} ({p['margin']:.0f}% margin, +${p['profit']:,.0f})" for p in top3]
                return f"Best margins: {'. '.join(results)}"
            return "No sold watches to analyze margins."
        except:
            pass
    
    # Sell everything/liquidation value (check BEFORE is_action blocks)
    if any(w in text_lower for w in ['sell everything', 'what would i make', 'liquidation value', 'if i sold all',
                                      'what if i sold everything', 'if i sold it all']):
        try:
            rows = _siri_get_rows()
            listings = _siri_get_listings()
            
            # Build market prices
            market_prices = {}
            for l in listings:
                ref = l.get('ref', '').strip()
                if ref and l.get('region') == 'US' and l.get('price_usd', 0) > 0:
                    if ref not in market_prices:
                        market_prices[ref] = []
                    market_prices[ref].append(l['price_usd'])
            
            # Calculate liquidation value (use bottom 25% average for quick sale)
            total_cost = 0
            total_liquidation = 0
            unsold_count = 0
            
            for row in rows:
                if row.get('sold') == 'Yes':
                    continue
                    
                cost = _siri_parse_money(row.get('cost_price', ''))
                ref = row.get('description', '').split()[0] if row.get('description') else ''
                
                if cost > 0:
                    total_cost += cost
                    unsold_count += 1
                    
                    if ref in market_prices:
                        prices = sorted(market_prices[ref])
                        # Use bottom 25% average for liquidation
                        bottom_25_count = max(1, len(prices) // 4)
                        avg_bottom = sum(prices[:bottom_25_count]) / bottom_25_count
                        total_liquidation += avg_bottom
                    else:
                        total_liquidation += cost * 0.8  # Assume 20% haircut if no market data
            
            if unsold_count > 0:
                profit_loss = total_liquidation - total_cost
                return f"Liquidation scenario: {unsold_count} watches cost ${total_cost:,.0f}, quick-sale value ~${total_liquidation:,.0f}. Net: ${profit_loss:+,.0f}"
            return "No unsold inventory to liquidate."
        except:
            pass
    
    # How's business/business summary
    if any(w in text_lower for w in ['how\'s business', 'hows business', 'business summary', 'p&l summary', 'how is business']):
        try:
            rows = _siri_get_rows()
            
            # Calculate P&L
            sold_watches = [r for r in rows if r.get('sold') == 'Yes']
            total_revenue = sum(_siri_parse_money(r.get('sold_price', '')) for r in sold_watches)
            total_cost = sum(_siri_parse_money(r.get('cost_price', '')) for r in sold_watches)
            total_profit = total_revenue - total_cost
            
            # Inventory stats
            unsold = [r for r in rows if r.get('sold') != 'Yes']
            inventory_cost = sum(_siri_parse_money(r.get('cost_price', '')) for r in unsold)
            
            # Outstanding receivables
            unpaid = [r for r in rows if r.get('sold') == 'Yes' and r.get('paid_after_sold') != 'Yes']
            outstanding = sum(_siri_parse_money(r.get('sold_price', '')) for r in unpaid)
            
            margin = (total_profit / total_revenue * 100) if total_revenue > 0 else 0
            
            return f"Business summary: {len(sold_watches)} sales, ${total_revenue:,.0f} revenue, ${total_profit:,.0f} profit ({margin:.1f}% margin). {len(unsold)} watches in inventory (${inventory_cost:,.0f}). ${outstanding:,.0f} outstanding receivables."
        except:
            pass
    
    return None  # Can't answer instantly — goes to async

