# ── SIRI SESSION MEMORY (conversational context) ──
_siri_session = {'last_ref': None, 'last_query': None, 'last_ts': 0}

# ── PROACTIVE ALERTS API ──
@app.route('/api/siri/alerts', methods=['GET'])
def api_siri_alerts():
    """Returns urgent action items for push notifications.
    Used by scheduled Shortcut automations on iPhone."""
    auth = request.headers.get('X-Siri-Key', request.headers.get('Authorization','').replace('Bearer ',''))
    if auth != SIRI_API_KEY:
        return jsonify({'error': 'Unauthorized'}), 401
    
    try:
        from datetime import datetime
        rows = _siri_get_rows()
        alerts = []
        
        # 1. Sold but not shipped (URGENT)
        need_ship = [r for r in rows if r.get('sold') == 'Yes' and r.get('shipped') != 'Yes']
        if need_ship:
            descs = [r.get('description','')[:30] for r in need_ship[:3]]
            alerts.append({
                'priority': 'high',
                'emoji': '🚚',
                'title': f'{len(need_ship)} watches need shipping',
                'body': ', '.join(descs),
                'category': 'shipping'
            })
        
        # 2. Unpaid receivables > 3 days
        unpaid = [r for r in rows if r.get('sold') == 'Yes' and r.get('paid_after_sold') != 'Yes']
        if unpaid:
            total = sum(_siri_parse_money(r.get('sold_price')) for r in unpaid)
            buyers = list(set(r.get('sold_to','?') for r in unpaid))
            alerts.append({
                'priority': 'high',
                'emoji': '💰',
                'title': f'${total:,.0f} outstanding from {len(buyers)} buyers',
                'body': ', '.join(b[:25] for b in buyers[:3]),
                'category': 'collections'
            })
        
        # 3. Arrived but not posted (idle capital)
        unposted = [r for r in rows if r.get('posted') != 'Yes' and r.get('sold') != 'Yes' and r.get('at_store') != 'Yes']
        if unposted:
            idle = sum(_siri_parse_money(r.get('cost_price')) for r in unposted)
            alerts.append({
                'priority': 'medium',
                'emoji': '📸',
                'title': f'{len(unposted)} watches sitting unposted',
                'body': f'${idle:,.0f} idle capital',
                'category': 'posting'
            })
        
        # 4. In transit count
        transit = [r for r in rows if r.get('arrived') != 'Yes' and r.get('sold') != 'Yes']
        if transit:
            alerts.append({
                'priority': 'low',
                'emoji': '📦',
                'title': f'{len(transit)} watches in transit',
                'body': 'Check for arrivals',
                'category': 'logistics'
            })
        
        # 5. Quick P&L snapshot
        sold = [r for r in rows if r.get('sold') == 'Yes']
        total_rev = sum(_siri_parse_money(r.get('sold_price')) for r in sold)
        total_cost = sum(_siri_parse_money(r.get('cost_price')) for r in sold)
        unsold_count = len([r for r in rows if r.get('sold') != 'Yes'])
        
        # Build spoken summary for Siri
        high_alerts = [a for a in alerts if a['priority'] == 'high']
        spoken = ""
        if high_alerts:
            spoken = "Urgent: " + ". ".join(f"{a['emoji']} {a['title']}" for a in high_alerts)
        elif alerts:
            spoken = ". ".join(f"{a['emoji']} {a['title']}" for a in alerts[:3])
        else:
            spoken = "All clear. Nothing urgent right now."
        
        return jsonify({
            'ok': True,
            'alerts': alerts,
            'spoken': spoken,
            'summary': {
                'unsold': unsold_count,
                'need_shipping': len(need_ship),
                'unpaid': len(unpaid),
                'unposted': len(unposted),
                'in_transit': len(transit),
                'total_profit': total_rev - total_cost,
            }
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500


