# ── NEW AUTONOMOUS IMPROVEMENTS ──

@app.route('/api/siri/price-monitor', methods=['GET'])
def api_siri_price_monitor():
    """Real-time price monitoring: compares inventory cost to current market prices."""
    auth = request.headers.get('X-Siri-Key', request.headers.get('Authorization','').replace('Bearer ',''))
    if auth != SIRI_API_KEY:
        return jsonify({'error': 'Unauthorized'}), 401
    
    try:
        rows = _siri_get_rows()
        listings = _siri_get_listings()
        
        # Build market price lookup by ref
        market_prices = {}
        for l in listings:
            ref = l.get('ref', '').strip()
            if ref and l.get('region') == 'US' and l.get('price_usd', 0) > 0:
                if ref not in market_prices:
                    market_prices[ref] = []
                market_prices[ref].append(l['price_usd'])
        
        # Calculate market lows (US low price)
        market_lows = {}
        for ref, prices in market_prices.items():
            market_lows[ref] = min(prices) if prices else 0
        
        underwater = []
        hot = []
        
        # Analyze unsold inventory
        for row in rows:
            if row.get('sold') == 'Yes':
                continue  # Skip sold watches
                
            cost = _siri_parse_money(row.get('cost_price', ''))
            ref = row.get('description', '').split()[0] if row.get('description') else ''
            
            if not cost or cost <= 100 or not ref:
                continue  # Skip $1 placeholder costs
                
            market_low = market_lows.get(ref, 0)
            if market_low == 0:
                continue  # No market data
            
            # Check if underwater (market below cost)
            if market_low < cost:
                loss = cost - market_low
                loss_pct = (loss / cost) * 100
                underwater.append({
                    'ref': ref,
                    'description': row.get('description', ''),
                    'cost': cost,
                    'market_low': market_low,
                    'loss': loss,
                    'loss_pct': round(loss_pct, 1)
                })
            
            # Check if hot (market 20%+ above cost)
            elif market_low > cost * 1.2:
                gain = market_low - cost
                gain_pct = ((market_low - cost) / cost) * 100
                hot.append({
                    'ref': ref,
                    'description': row.get('description', ''),
                    'cost': cost,
                    'market_low': market_low,
                    'gain': gain,
                    'gain_pct': round(gain_pct, 1)
                })
        
        # Build spoken summary
        spoken_parts = []
        if underwater:
            total_loss = sum(w['loss'] for w in underwater)
            spoken_parts.append(f"{len(underwater)} watches underwater, ${total_loss:,.0f} potential loss")
        
        if hot:
            avg_gain = sum(h['gain_pct'] for h in hot) / len(hot)
            spoken_parts.append(f"{len(hot)} hot watches, averaging {avg_gain:.0f}% above cost")
        
        if not underwater and not hot:
            spoken_parts.append("Market looks stable, no major price alerts")
        
        spoken = ". ".join(spoken_parts) + "."
        
        return jsonify({
            'ok': True,
            'underwater': underwater,
            'hot': hot,
            'spoken': spoken,
            'timestamp': now_et_iso()
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/siri/briefing', methods=['GET'])
def api_siri_briefing():
    """Smart daily briefing with activity, priorities, and market movers."""
    auth = request.headers.get('X-Siri-Key', request.headers.get('Authorization','').replace('Bearer ',''))
    if auth != SIRI_API_KEY:
        return jsonify({'error': 'Unauthorized'}), 401
    
    try:
        rows = _siri_get_rows()
        now = datetime.now()
        yesterday = now - timedelta(days=1)
        
        # Yesterday's activity — parse dates properly
        recent_sales = []
        
        yesterday_str = yesterday.strftime('%m/%d/%Y')
        today_str = now.strftime('%m/%d/%Y')
        
        for row in rows:
            if row.get('sold') == 'Yes':
                sale_date = row.get('sale_date', '')
                if sale_date in (yesterday_str, today_str):
                    recent_sales.append(row)
        
        # Counts of current states (not "yesterday's" since we don't track state change dates)
        need_ship = [r for r in rows if r.get('sold') == 'Yes' and r.get('shipped') != 'Yes']
        need_collect = [r for r in rows if r.get('sold') == 'Yes' and r.get('paid_after_sold') != 'Yes']
        need_post = [r for r in rows if r.get('posted') != 'Yes' and r.get('sold') != 'Yes' and r.get('at_store') != 'Yes']
        
        # Weather-aware greeting
        hour = now.hour
        if hour < 12:
            greeting = "Good morning Jeffin"
        elif hour < 17:
            greeting = "Good afternoon Jeffin"
        else:
            greeting = "Good evening Jeffin"
        
        # Build briefing
        briefing_parts = [greeting + ". Here's your business briefing."]
        
        # Recent sales
        if recent_sales:
            rev = sum(_siri_parse_money(r.get('sold_price', '')) for r in recent_sales)
            briefing_parts.append(f"Recent sales: {len(recent_sales)} for ${rev:,.0f}.")
        
        # Today's priorities
        priority_items = []
        if need_ship:
            priority_items.append(f"{len(need_ship)} need shipping")
        if need_collect:
            total_outstanding = sum(_siri_parse_money(r.get('sold_price', '')) for r in need_collect)
            priority_items.append(f"collect ${total_outstanding:,.0f} from {len(need_collect)} buyers")
        if need_post:
            priority_items.append(f"post {len(need_post)} new arrivals")
        
        if priority_items:
            briefing_parts.append("Priorities: " + ", ".join(priority_items) + ".")
        else:
            briefing_parts.append("No urgent priorities today.")
        
        # Market movers (simplified - would need price history for full implementation)
        briefing_parts.append("Market data updated as of " + get_latest_sync() + ".")
        
        spoken = " ".join(briefing_parts)
        
        return jsonify({
            'ok': True,
            'spoken': spoken,
            'recent_sales': len(recent_sales),
            'today_priorities': {
                'ship': len(need_ship),
                'collect': len(need_collect),
                'post': len(need_post)
            },
            'timestamp': now.isoformat()
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/siri/buyer/<name>', methods=['GET'])
def api_siri_buyer_profile(name):
    """Buyer intelligence: full dossier on a specific buyer."""
    auth = request.headers.get('X-Siri-Key', request.headers.get('Authorization','').replace('Bearer ',''))
    if auth != SIRI_API_KEY:
        return jsonify({'error': 'Unauthorized'}), 401
    
    try:
        rows = _siri_get_rows()
        
        # Find all transactions with this buyer
        buyer_transactions = []
        for row in rows:
            sold_to = (row.get('sold_to', '') or '').lower().strip()
            if name.lower() in sold_to:
                buyer_transactions.append(row)
        
        if not buyer_transactions:
            return jsonify({
                'ok': False,
                'error': f'No transactions found for buyer: {name}',
                'spoken': f"I don't see any transactions with {name}."
            })
        
        # Calculate stats
        total_watches = len(buyer_transactions)
        total_revenue = sum(_siri_parse_money(r.get('sold_price', '')) for r in buyer_transactions)
        avg_deal_size = total_revenue / total_watches if total_watches > 0 else 0
        
        # Payment analysis
        paid_count = len([r for r in buyer_transactions if r.get('paid_after_sold') == 'Yes'])
        unpaid_count = total_watches - paid_count
        outstanding_balance = sum(_siri_parse_money(r.get('sold_price', '')) 
                                for r in buyer_transactions if r.get('paid_after_sold') != 'Yes')
        
        # Last transaction
        last_transaction = max(buyer_transactions, key=lambda r: r.get('sale_date', ''), default=None)
        last_date = last_transaction.get('sale_date', 'Unknown') if last_transaction else 'Unknown'
        
        # Build spoken summary
        spoken_parts = [
            f"{name} has bought {total_watches} watches for ${total_revenue:,.0f} total",
            f"Average deal size ${avg_deal_size:,.0f}"
        ]
        
        if unpaid_count > 0:
            spoken_parts.append(f"Currently owes ${outstanding_balance:,.0f} on {unpaid_count} purchases")
        else:
            spoken_parts.append("All payments current")
            
        spoken_parts.append(f"Last transaction: {last_date}")
        
        spoken = ". ".join(spoken_parts) + "."
        
        return jsonify({
            'ok': True,
            'buyer': name,
            'total_watches': total_watches,
            'total_revenue': total_revenue,
            'avg_deal_size': round(avg_deal_size),
            'paid_count': paid_count,
            'unpaid_count': unpaid_count,
            'outstanding_balance': outstanding_balance,
            'last_transaction_date': last_date,
            'transactions': buyer_transactions,
            'spoken': spoken
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/siri/location-trigger', methods=['GET'])
def api_siri_location_trigger():
    """Location-aware data: returns context based on where Jeffin is."""
    auth = request.headers.get('X-Siri-Key', request.headers.get('Authorization','').replace('Bearer ',''))
    if auth != SIRI_API_KEY:
        return jsonify({'error': 'Unauthorized'}), 401
    
    try:
        location = request.args.get('location', 'home').lower()
        rows = _siri_get_rows()
        
        if location == 'office':
            # Office context: focus on operational tasks
            need_ship = [r for r in rows if r.get('sold') == 'Yes' and r.get('shipped') != 'Yes']
            unposted = [r for r in rows if r.get('posted') != 'Yes' and r.get('sold') != 'Yes' and r.get('at_store') != 'Yes']
            
            response = {
                'location': 'office',
                'spoken': f"At the office: {len(need_ship)} watches need shipping, {len(unposted)} unposted arrivals",
                'need_shipping': len(need_ship),
                'unposted': len(unposted),
                'tasks': []
            }
            
            if need_ship:
                response['tasks'].append(f"Ship {len(need_ship)} sold watches")
            if unposted:
                response['tasks'].append(f"Post {len(unposted)} new arrivals")
                
        elif location == 'fedex':
            # FedEx context: show packages to drop off
            # This would integrate with shipping tracker if available
            response = {
                'location': 'fedex',
                'spoken': "You have packages to drop off. Check your shipping tracker for details.",
                'packages_to_drop': 0  # Would connect to actual shipping data
            }
            
        else:  # home or default
            # Home context: morning briefing summary
            unsold_count = len([r for r in rows if r.get('sold') != 'Yes'])
            need_collect = [r for r in rows if r.get('sold') == 'Yes' and r.get('paid_after_sold') != 'Yes']
            total_outstanding = sum(_siri_parse_money(r.get('sold_price', '')) for r in need_collect)
            
            response = {
                'location': 'home',
                'spoken': f"Morning summary: {unsold_count} watches in inventory, ${total_outstanding:,.0f} outstanding receivables",
                'inventory_count': unsold_count,
                'outstanding_amount': total_outstanding,
                'buyers_owe': len(need_collect)
            }
        
        response['ok'] = True
        response['timestamp'] = now_et_iso()
        return jsonify(response)
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500


