@app.route('/api/users', methods=['GET'])
@login_required
def api_users_list():
    """List all users (admin only)."""
    if _get_user_role() != 'admin':
        return jsonify({'error': 'admin only'}), 403
    from database import get_db
    db = get_db()
    users = db.execute('SELECT id, username, display_name, role, created_at, last_login, active FROM users ORDER BY id').fetchall()
    db.close()
    return jsonify([dict(u) for u in users])

@app.route('/api/users', methods=['POST'])
@login_required
def api_users_create():
    """Create a new employee user (admin only)."""
    if _get_user_role() != 'admin':
        return jsonify({'error': 'admin only'}), 403
    import hashlib
    data = request.json
    username = data.get('username', '').strip().lower()
    pin = data.get('pin', '').strip()
    role = data.get('role', 'logistics')
    display_name = data.get('display_name', '').strip()
    
    if not username or not pin:
        return jsonify({'error': 'username and pin required'}), 400
    if role not in VALID_ROLES:
        return jsonify({'error': f'role must be one of: {", ".join(VALID_ROLES)}'}), 400
    if len(pin) < 4:
        return jsonify({'error': 'pin must be at least 4 characters'}), 400
    
    pin_hash = hashlib.sha256(pin.encode()).hexdigest()
    
    from database import get_db
    db = get_db()
    try:
        db.execute(
            'INSERT INTO users (username, pin_hash, display_name, role) VALUES (?, ?, ?, ?)',
            (username, pin_hash, display_name or username, role)
        )
        db.commit()
        user_id = db.execute('SELECT last_insert_rowid()').fetchone()[0]
        db.close()
        return jsonify({'ok': True, 'id': user_id, 'username': username, 'role': role})
    except Exception as e:
        db.close()
        if 'UNIQUE' in str(e):
            return jsonify({'error': 'username already exists'}), 409
        return jsonify({'error': str(e)}), 500

@app.route('/api/users/<int:user_id>', methods=['DELETE'])
@login_required
def api_users_delete(user_id):
    """Deactivate a user (admin only)."""
    if _get_user_role() != 'admin':
        return jsonify({'error': 'admin only'}), 403
    from database import get_db
    db = get_db()
    db.execute('UPDATE users SET active = 0 WHERE id = ?', (user_id,))
    db.commit()
    db.close()
    return jsonify({'ok': True})


# ═══ JAM (Activity Feed) API ═══

@app.route('/api/jam/feed')
@login_required
def api_jam_feed():
    """Activity feed for Jam sections (Dibeli/Masuk/Dijual/Keluar).
    
    Query params:
      type: dibeli|masuk|dijual|keluar (required)
      limit: max items (default 50)
      offset: pagination offset (default 0)
    """
    try:
        from database import get_db
        db = get_db()
        
        jam_type = request.args.get('type', '').lower()
        limit = min(int(request.args.get('limit', 50)), 200)
        offset = int(request.args.get('offset', 0))
        
        if jam_type not in ('dibeli', 'masuk', 'dijual', 'keluar'):
            return jsonify({'error': 'type must be dibeli|masuk|dijual|keluar'}), 400
        
        # Role-based tab filtering
        role = _get_user_role()
        if role == 'logistics' and jam_type not in LOGISTICS_JAM_TABS:
            return jsonify({'error': 'access denied for this tab'}), 403
        
        # Map Jam types to SQLite queries
        if jam_type == 'dibeli':
            # Bought — ordered by buy_date desc
            rows = db.execute('''
                SELECT id, description, bought_from, cost_price, buy_date, serial, card_date,
                       arrived, sold, paid_supplier, created_at
                FROM watches 
                WHERE buy_date IS NOT NULL AND buy_date != '' AND deleted = 0
                ORDER BY buy_date DESC, id DESC
                LIMIT ? OFFSET ?
            ''', (limit, offset)).fetchall()
            total = db.execute(
                "SELECT COUNT(*) FROM watches WHERE buy_date IS NOT NULL AND buy_date != '' AND deleted = 0"
            ).fetchone()[0]
            
            items = []
            for r in rows:
                items.append({
                    'id': r['id'],
                    'description': r['description'],
                    'from': r['bought_from'] or '',
                    'cost': r['cost_price'],
                    'date': r['buy_date'] or '',
                    'serial': r['serial'] or '',
                    'card_date': r['card_date'] or '',
                    'arrived': bool(r['arrived']),
                    'sold': bool(r['sold']),
                    'paid_supplier': bool(r['paid_supplier']),
                })
        
        elif jam_type == 'masuk':
            # Arrived — ordered by audit_log timestamp for arrived events
            # Logistics users: only show arrivals they uploaded
            if role == 'logistics' and session.get('user_id'):
                uid = session.get('user_id')
                rows = db.execute('''
                    SELECT w.id, w.description, w.bought_from, w.serial, w.card_date, w.wt,
                           w.sold, w.posted, w.at_store,
                           al.created_at as arrived_date
                    FROM activity_log al
                    JOIN watches w ON w.id = al.watch_id
                    WHERE al.user_id = ? AND al.action = 'upload_arrival' AND w.deleted = 0
                    ORDER BY al.created_at DESC
                    LIMIT ? OFFSET ?
                ''', (uid, limit, offset)).fetchall()
                total = db.execute(
                    "SELECT COUNT(*) FROM activity_log al JOIN watches w ON w.id = al.watch_id WHERE al.user_id = ? AND al.action = 'upload_arrival' AND w.deleted = 0",
                    (uid,)
                ).fetchone()[0]
            else:
                rows = db.execute('''
                    SELECT w.id, w.description, w.bought_from, w.serial, w.card_date, w.wt,
                           w.sold, w.posted, w.at_store,
                           COALESCE(
                               (SELECT a.timestamp FROM audit_log a 
                                WHERE a.watch_id = w.id AND a.field = 'arrived' AND a.new_value = '1'
                                ORDER BY a.timestamp DESC LIMIT 1),
                               w.updated_at
                           ) as arrived_date
                    FROM watches w
                    WHERE w.arrived = 1 AND w.deleted = 0
                    ORDER BY arrived_date DESC, w.id DESC
                    LIMIT ? OFFSET ?
                ''', (limit, offset)).fetchall()
                total = db.execute(
                    "SELECT COUNT(*) FROM watches WHERE arrived = 1 AND deleted = 0"
                ).fetchone()[0]
            
            items = []
            for r in rows:
                items.append({
                    'id': r['id'],
                    'description': r['description'],
                    'from': r['bought_from'] or '',
                    'serial': r['serial'] or '',
                    'card_date': r['card_date'] or '',
                    'wt': bool(r['wt']),
                    'sold': bool(r['sold']),
                    'posted': bool(r['posted']),
                    'at_store': bool(r['at_store']),
                    'date': (r['arrived_date'] or '')[:10],
                })
        
        elif jam_type == 'dijual':
            # Sold — ordered by sale_date desc
            rows = db.execute('''
                SELECT w.id, w.description, w.sold_to, w.sold_price, w.sale_price, w.cost_price,
                       w.sale_date, w.serial, w.card_date, w.shipped, w.paid_buyer, w.profit,
                       COALESCE(
                           (SELECT a.timestamp FROM audit_log a 
                            WHERE a.watch_id = w.id AND a.field = 'sold' AND a.new_value = '1'
                            ORDER BY a.timestamp DESC LIMIT 1),
                           w.sale_date, w.updated_at
                       ) as sold_date_ts
                FROM watches w
                WHERE w.sold = 1 AND w.deleted = 0
                ORDER BY sold_date_ts DESC, w.id DESC
                LIMIT ? OFFSET ?
            ''', (limit, offset)).fetchall()
            total = db.execute(
                "SELECT COUNT(*) FROM watches WHERE sold = 1 AND deleted = 0"
            ).fetchone()[0]
            
            items = []
            for r in rows:
                items.append({
                    'id': r['id'],
                    'description': r['description'],
                    'to': r['sold_to'] or '',
                    'sold_price': r['sold_price'] or r['sale_price'],
                    'cost': r['cost_price'],
                    'profit': r['profit'],
                    'date': (r['sale_date'] or r['sold_date_ts'] or '')[:10],
                    'serial': r['serial'] or '',
                    'card_date': r['card_date'] or '',
                    'shipped': bool(r['shipped']),
                    'paid': bool(r['paid_buyer']),
                })
        
        elif jam_type == 'keluar':
            import glob as _glob
            from datetime import date as _date
            workspace = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
            labels_dir = os.path.join(workspace, 'shipping_labels')
            from datetime import datetime as _dtx, timezone as _tz
            import zoneinfo
            today_str = _dtx.now(zoneinfo.ZoneInfo('America/New_York')).strftime('%Y-%m-%d')
            
            # Pre-load package memberships
            _pkg_map = {}
            try:
                for pw in db.execute('''
                    SELECT pw.watch_id, sp.id as pkg_id, sp.package_name, sp.pdf_path, sp.recipient, sp.notes
                    FROM package_watches pw JOIN shipment_packages sp ON sp.id = pw.package_id
                    WHERE sp.shipped = 0
                ''').fetchall():
                    _pkg_map[pw['watch_id']] = {
                        'package_id': pw['pkg_id'],
                        'package_name': pw['package_name'],
                        'package_pdf': pw['pdf_path'] or '',
                        'package_recipient': pw['recipient'] or '',
                        'package_notes': pw['notes'] or '',
                    }
            except Exception:
                pass
            
            def _keluar_item(r, shipped_date_val=None, pending=False):
                wid = r['id']
                has_label = False
                label_file = None
                if os.path.isdir(labels_dir):
                    matches = sorted(_glob.glob(os.path.join(labels_dir, f'label_{wid}_*.pdf')))
                    if matches:
                        has_label = True
                        label_file = os.path.basename(matches[-1])
                
                # Check package for combined label
                pkg_info = _pkg_map.get(wid, {})
                if not has_label and pkg_info.get('package_pdf'):
                    has_label = True
                    label_file = os.path.basename(pkg_info['package_pdf'])
                
                ship_photos = []
                ship_photo_dir = os.path.join(workspace, 'shipping_photos', str(wid))
                if os.path.isdir(ship_photo_dir):
                    for sp_file in sorted(os.listdir(ship_photo_dir)):
                        if sp_file.lower().endswith(('.jpg','.jpeg','.png','.webp')):
                            fl = sp_file.lower()
                            if 'label' in fl: ptype = 'label_photo'
                            elif 'box' in fl: ptype = 'box_photo'
                            elif 'receipt' in fl: ptype = 'receipt_photo'
                            elif 'delivery' in fl: ptype = 'delivery_photo'
                            else: ptype = 'watch_photo'
                            ship_photos.append({'filename': sp_file, 'type': ptype})
                
                # For pending items: keep past ship_by_date as-is (overdue items should still show)
                sbd = r['ship_by_date'] or ''
                
                return {
                    'id': wid,
                    'description': r['description'],
                    'to': r['sold_to'] or '',
                    'sold_price': r['sold_price'] or r['sale_price'],
                    'serial': r['serial'] or '',
                    'card_date': r['card_date'] or '',
                    'paid': bool(r['paid_buyer']),
                    'date': sbd if pending else (shipped_date_val or '')[:10],
                    'has_label': has_label,
                    'label_file': label_file,
                    'ship_photos': ship_photos,
                    'status': 'pending' if pending else 'shipped',
                    'ship_by_date': sbd,
                    'delivery_type': r['delivery_type'] or '',
                    'delivery_address': r['delivery_address'] or '',
                    'package_id': pkg_info.get('package_id'),
                    'package_name': pkg_info.get('package_name', ''),
                    'package_notes': pkg_info.get('package_notes', ''),
                    'ship_from': r['ship_from'] if 'ship_from' in r.keys() else 'office',
                    'package_num': _pkg_nums.get(r['id']),
                    'assigned_shipper': r['assigned_shipper'] if 'assigned_shipper' in r.keys() else None,
                }
            
            # Section 1: Pending — sold but not shipped (with or without label)
            # Logistics users only see their assigned watches
            if role == 'logistics' and session.get('user_id'):
                pending_rows = db.execute('''
                    SELECT w.id, w.description, w.sold_to, w.sold_price, w.sale_price,
                           w.serial, w.card_date, w.paid_buyer, w.ship_by_date,
                           w.delivery_type, w.delivery_address, w.ship_from, w.assigned_shipper
                    FROM watches w
                    WHERE w.sold = 1 AND w.shipped = 0 AND w.deleted = 0
                    AND w.assigned_shipper = ?
                    ORDER BY COALESCE(w.ship_by_date, '9999-99-99') ASC, w.id ASC
                ''', (session.get('user_id'),)).fetchall()
            else:
                pending_rows = db.execute('''
                    SELECT w.id, w.description, w.sold_to, w.sold_price, w.sale_price,
                           w.serial, w.card_date, w.paid_buyer, w.ship_by_date,
                           w.delivery_type, w.delivery_address, w.ship_from, w.assigned_shipper
                    FROM watches w
                    WHERE w.sold = 1 AND w.shipped = 0 AND w.deleted = 0
                    ORDER BY COALESCE(w.ship_by_date, '9999-99-99') ASC, w.id ASC
                ''').fetchall()
            
            # Assign sequential package numbers per shipper (skip foreign)
            _pkg_nums = {}
            _shipper_seq = {}  # per-user counter
            for pr in pending_rows:
                sf = pr['ship_from'] if 'ship_from' in pr.keys() else 'office'
                if sf != 'foreign':
                    shipper = pr['assigned_shipper'] if 'assigned_shipper' in pr.keys() else None
                    _shipper_seq[shipper] = _shipper_seq.get(shipper, 0) + 1
                    _pkg_nums[pr['id']] = _shipper_seq[shipper]
            
            # Section 2: Shipped — completed (logistics: only their own)
            if role == 'logistics' and session.get('user_id'):
                shipped_rows = db.execute('''
                    SELECT w.id, w.description, w.sold_to, w.sold_price, w.sale_price,
                           w.serial, w.card_date, w.paid_buyer, w.ship_by_date,
                           w.delivery_type, w.delivery_address, w.assigned_shipper,
                           COALESCE(
                               (SELECT a.timestamp FROM audit_log a 
                                WHERE a.watch_id = w.id AND a.field = 'shipped' AND a.new_value = '1'
                                ORDER BY a.timestamp DESC LIMIT 1),
                               w.updated_at
                           ) as shipped_date
                    FROM watches w
                    WHERE w.shipped = 1 AND w.deleted = 0 AND w.assigned_shipper = ?
                    ORDER BY shipped_date DESC, w.id DESC
                    LIMIT ? OFFSET ?
                ''', (session.get('user_id'), limit, offset)).fetchall()
            else:
                shipped_rows = db.execute('''
                    SELECT w.id, w.description, w.sold_to, w.sold_price, w.sale_price,
                           w.serial, w.card_date, w.paid_buyer, w.ship_by_date,
                           w.delivery_type, w.delivery_address, w.assigned_shipper,
                           COALESCE(
                               (SELECT a.timestamp FROM audit_log a 
                                WHERE a.watch_id = w.id AND a.field = 'shipped' AND a.new_value = '1'
                                ORDER BY a.timestamp DESC LIMIT 1),
                               w.updated_at
                           ) as shipped_date
                    FROM watches w
                    WHERE w.shipped = 1 AND w.deleted = 0
                    ORDER BY shipped_date DESC, w.id DESC
                    LIMIT ? OFFSET ?
                ''', (limit, offset)).fetchall()
            
            total_pending = len(pending_rows)
            if role == 'logistics' and session.get('user_id'):
                total_shipped = db.execute(
                    "SELECT COUNT(*) FROM watches WHERE shipped = 1 AND deleted = 0 AND assigned_shipper = ?",
                    (session.get('user_id'),)
                ).fetchone()[0]
            else:
                total_shipped = db.execute(
                    "SELECT COUNT(*) FROM watches WHERE shipped = 1 AND deleted = 0"
                ).fetchone()[0]
            total = total_pending + total_shipped
            
            items = []
            pending_items = [_keluar_item(r, pending=True) for r in pending_rows]
            # Sort pending: by package_id ASC (unpackaged last), then by id
            pending_items.sort(key=lambda x: (x.get('package_id') or 99999, x['id']))
            items.extend(pending_items)
            for r in shipped_rows:
                items.append(_keluar_item(r, shipped_date_val=r['shipped_date']))
        
        return jsonify({
            'type': jam_type,
            'items': items,
            'total': total,
            'limit': limit,
            'offset': offset,
        })
    except Exception as e:
        import traceback
        traceback.print_exc()
        return jsonify({'error': str(e)}), 500


@app.route('/api/jam/stats')
@login_required
def api_jam_stats():
    """Summary stats for the Jam dashboard."""
    try:
        from database import get_db
        db = get_db()
        
        stats = {}
        stats['dibeli'] = db.execute("SELECT COUNT(*) FROM watches WHERE buy_date IS NOT NULL AND buy_date != '' AND deleted = 0").fetchone()[0]
        stats['masuk'] = db.execute("SELECT COUNT(*) FROM watches WHERE arrived = 1 AND deleted = 0").fetchone()[0]
        stats['dijual'] = db.execute("SELECT COUNT(*) FROM watches WHERE sold = 1 AND deleted = 0").fetchone()[0]
        stats['keluar'] = db.execute("SELECT COUNT(*) FROM watches WHERE shipped = 1 AND deleted = 0").fetchone()[0]
        
        # Recent activity (last 7 days)
        stats['recent_bought'] = db.execute(
            "SELECT COUNT(*) FROM watches WHERE buy_date >= date('now', '-7 days') AND deleted = 0"
        ).fetchone()[0]
        stats['recent_sold'] = db.execute(
            "SELECT COUNT(*) FROM audit_log WHERE field = 'sold' AND new_value = '1' AND timestamp >= datetime('now', '-7 days')"
        ).fetchone()[0]
        
        # Pending actions
        stats['sold_not_shipped'] = db.execute(
            "SELECT COUNT(*) FROM watches WHERE sold = 1 AND shipped = 0 AND deleted = 0"
        ).fetchone()[0]
        stats['shipped_not_paid'] = db.execute(
            "SELECT COUNT(*) FROM watches WHERE shipped = 1 AND paid_buyer = 0 AND deleted = 0"
        ).fetchone()[0]
        stats['arrived_not_posted'] = db.execute(
            "SELECT COUNT(*) FROM watches WHERE posted = 0 AND sold = 0 AND at_store = 0 AND deleted = 0"
        ).fetchone()[0]
        
        return jsonify(stats)
    except Exception as e:
        return jsonify({'error': str(e)}), 500


