EDDY_WA = '17324899352@s.whatsapp.net'

def _notify_eddy(message):
    """Send a WhatsApp notification to Eddy via wacli (background thread)."""
    import threading, subprocess
    def _send():
        try:
            subprocess.run(
                ['wacli', 'send', 'text', '--to', EDDY_WA, '--message', message],
                capture_output=True, text=True, timeout=30
            )
        except Exception as e:
            print(f"Eddy notification error: {e}")
    threading.Thread(target=_send, daemon=True).start()

def _get_eddy_package_number(watch_id):
    """Get sequential package number per shipper (excludes foreign)."""
    try:
        from database import get_db as _gdb
        db = _gdb()
        w = db.execute('SELECT assigned_shipper FROM watches WHERE id=?', (watch_id,)).fetchone()
        shipper = w['assigned_shipper'] if w else None
        if shipper:
            rows = db.execute('''
                SELECT id FROM watches
                WHERE sold = 1 AND shipped = 0 AND deleted = 0
                AND COALESCE(ship_from, 'office') != 'foreign'
                AND assigned_shipper = ?
                ORDER BY COALESCE(ship_by_date, '9999-99-99') ASC, id ASC
            ''', (shipper,)).fetchall()
        else:
            rows = db.execute('''
                SELECT id FROM watches
                WHERE sold = 1 AND shipped = 0 AND deleted = 0
                AND COALESCE(ship_from, 'office') != 'foreign'
                ORDER BY COALESCE(ship_by_date, '9999-99-99') ASC, id ASC
            ''').fetchall()
        db.close()
        for idx, r in enumerate(rows, 1):
            if r['id'] == watch_id:
                return idx
        return None
    except Exception:
        return None

def _eddy_extract(watch_desc):
    """Extract ref, date from watch description."""
    import re
    ref_match = re.match(r'(\S+)\s+(\d{2}/\d{4})', watch_desc or '')
    ref = ref_match.group(1) if ref_match else watch_desc
    date = ref_match.group(2) if ref_match else ''
    return ref, date

LUIGI_IMSG = '+15034460429'

def _notify_luigi(message):
    """Send an iMessage notification to Luigi (background thread)."""
    import threading, subprocess
    def _send():
        try:
            subprocess.run(
                ['imsg', 'send', '--to', LUIGI_IMSG, '--text', message],
                capture_output=True, text=True, timeout=30
            )
        except Exception as e:
            print(f"Luigi notification error: {e}")
    threading.Thread(target=_send, daemon=True).start()

def _notify_shipper(watch_desc, serial, ship_by_date=None, watch_id=None, event='sold'):
    """Notify the assigned shipper (Eddy or Luigi) about a shipment event."""
    from database import get_db as _gdb
    db = _gdb()
    w = db.execute('SELECT assigned_shipper, ship_from FROM watches WHERE id=?', (watch_id,)).fetchone() if watch_id else None
    shipper = w['assigned_shipper'] if w else None
    ship_from = (w['ship_from'] or 'office') if w else 'office'
    db.close()
    # External watches: only notify if assigned to Luigi (he ships them)
    if ship_from == 'external' and shipper != 4:
        return
    # Default to Eddy (2) if no shipper assigned
    if shipper == 4:  # Luigi
        _notify_luigi_event(watch_desc, serial, ship_by_date, watch_id, event)
    else:
        if event == 'sold':
            _notify_eddy_new_shipment(watch_desc, serial, ship_by_date, watch_id)
        elif event == 'label_updated':
            ref, date = _eddy_extract(watch_desc)
            ser = serial or '?'
            pkg_num = _get_eddy_package_number(watch_id) if watch_id else None
            pkg_str = f"Paket #{pkg_num} — " if pkg_num else ''
            _notify_eddy(f"{pkg_str}LABEL DIGANTI untuk {ref} {date} {ser}. Pakai label yang baru ya!")
        else:
            _notify_eddy_label_attached(watch_desc, serial, ship_by_date, watch_id)

def _notify_luigi_event(watch_desc, serial, ship_by_date=None, watch_id=None, event='sold'):
    """Notify Luigi about a shipment event in English."""
    ref, date = _eddy_extract(watch_desc)
    ser = serial or '?'
    pkg_num = _get_eddy_package_number(watch_id) if watch_id else None
    pkg_str = f"Package #{pkg_num} — " if pkg_num else ''
    if event == 'sold':
        ship_str = f" — ship by {ship_by_date}" if ship_by_date else ''
        msg = f"Luigi, {pkg_str}{ref} {date} {ser} needs to be shipped{ship_str}"
    elif event == 'label_updated':
        msg = f"{pkg_str}LABEL UPDATED for {ref} {date} {ser}. Use the new label!"
    else:  # label attached
        ship_str = f" — ship {ship_by_date}" if ship_by_date else ''
        msg = f"{pkg_str}Label ready for {ref} {date} {ser}{ship_str}"
    _notify_luigi(msg)

def _notify_eddy_new_shipment(watch_desc, serial, ship_by_date=None, watch_id=None):
    """Notify Eddy about a new watch that needs to be shipped."""
    ref, date = _eddy_extract(watch_desc)
    ser = serial or '?'
    pkg_num = _get_eddy_package_number(watch_id) if watch_id else None
    pkg_str = f"Paket #{pkg_num} — " if pkg_num else ''
    ship_str = f" — harus dikirim {ship_by_date}" if ship_by_date else ''
    msg = f"Pak Eddy, {pkg_str}{ref} {date} {ser} yang harus di ship{ship_str}"
    _notify_eddy(msg)

def _notify_eddy_label_attached(watch_desc, serial, ship_by_date=None, watch_id=None):
    """Notify Eddy that a label has been attached to a shipment."""
    ref, date = _eddy_extract(watch_desc)
    ser = serial or '?'
    pkg_num = _get_eddy_package_number(watch_id) if watch_id else None
    pkg_str = f"Paket #{pkg_num} — " if pkg_num else ''
    ship_str = f" — kirim {ship_by_date}" if ship_by_date else ''
    msg = f"{pkg_str}Labelnya udah siap untuk {ref} {date} {ser}{ship_str}"
    _notify_eddy(msg)

