@app.route('/api/jam/activity', methods=['GET'])
@login_required
def api_jam_activity():
    """Get activity log feed. Admin sees all, employees see their own."""
    try:
        from database import get_db
        db = get_db()
        role = _get_user_role()
        limit = min(int(request.args.get('limit', 50)), 200)
        offset = int(request.args.get('offset', 0))
        
        if role in ('admin', 'full'):
            rows = db.execute(
                'SELECT * FROM activity_log ORDER BY created_at DESC LIMIT ? OFFSET ?',
                (limit, offset)
            ).fetchall()
            total = db.execute('SELECT COUNT(*) FROM activity_log').fetchone()[0]
        else:
            uid = session.get('user_id')
            rows = db.execute(
                'SELECT * FROM activity_log WHERE user_id = ? ORDER BY created_at DESC LIMIT ? OFFSET ?',
                (uid, limit, offset)
            ).fetchall()
            total = db.execute('SELECT COUNT(*) FROM activity_log WHERE user_id = ?', (uid,)).fetchone()[0]
        
        db.close()
        items = []
        for r in rows:
            items.append({
                'id': r['id'],
                'user': r['user_name'],
                'action': r['action'],
                'watch_id': r['watch_id'],
                'watch_desc': r['watch_desc'] or '',
                'detail': r['detail'] or '',
                'photo': r['photo_path'] or '',
                'time': r['created_at'],
            })
        return jsonify({'items': items, 'total': total})
    except Exception as e:
        return jsonify({'error': str(e)}), 500


