@app.route('/api/logistics/stats')
@login_required
def api_logistics_stats():
    """Return count of packages/watches to ship today for logistics role."""
    from database import get_db
    from datetime import date
    db = get_db()
    today_str = date.today().isoformat()
    # Count sold, not shipped, with ship_by_date = today (or past/unscheduled)
    user_id = session.get('user_id')
    if user_id:
        pending = db.execute('''
            SELECT COUNT(*) FROM watches
            WHERE sold = 1 AND shipped = 0 AND deleted = 0
            AND COALESCE(ship_from, 'office') != 'foreign'
            AND assigned_shipper = ?
        ''', (user_id,)).fetchone()[0]
        today_count = db.execute('''
            SELECT COUNT(*) FROM watches
            WHERE sold = 1 AND shipped = 0 AND deleted = 0
            AND COALESCE(ship_from, 'office') != 'foreign'
            AND assigned_shipper = ?
            AND ship_by_date = ?
        ''', (user_id, today_str)).fetchone()[0]
    else:
        pending = db.execute('''
            SELECT COUNT(*) FROM watches
            WHERE sold = 1 AND shipped = 0 AND deleted = 0
            AND COALESCE(ship_from, 'office') != 'foreign'
        ''').fetchone()[0]
        today_count = db.execute('''
            SELECT COUNT(*) FROM watches
            WHERE sold = 1 AND shipped = 0 AND deleted = 0
            AND COALESCE(ship_from, 'office') != 'foreign'
            AND ship_by_date = ?
        ''', (today_str,)).fetchone()[0]
    db.close()
    return jsonify({'ok': True, 'to_ship_today': today_count, 'total_pending': pending})

