    @app.route('/api/ad-crm/stores')
    @login_required
    def api_ad_crm_stores():
        """List all stores with contacts and last visit info."""
        try:
            import ad_crm
            conn = ad_crm.get_db()
            stores = conn.execute("""
                SELECT s.*, 
                       MAX(v.visit_date) as last_visit,
                       COUNT(DISTINCT v.id) as visit_count,
                       CAST(julianday('now') - julianday(MAX(v.visit_date)) AS INTEGER) as days_since
                FROM ad_stores s
                LEFT JOIN ad_visits v ON v.store_id = s.id
                GROUP BY s.id
                ORDER BY 
                    CASE WHEN MAX(v.visit_date) IS NULL THEN 0 ELSE 1 END,
                    MAX(v.visit_date) ASC
            """).fetchall()

            result = []
            for s in stores:
                contacts = conn.execute(
                    "SELECT * FROM ad_contacts WHERE store_id = ?", (s['id'],)
                ).fetchall()
                result.append({
                    **dict(s),
                    'contacts': [dict(c) for c in contacts],
                    'is_overdue': (s['days_since'] if s['days_since'] is not None else 999) >= 15
                })
            conn.close()
            return jsonify(result)
        except Exception as e:
            import traceback; traceback.print_exc()
            return jsonify({'error': str(e)}), 500

