    @app.route('/api/ad-crm/imsg-history', methods=['POST'])
    @login_required
    def api_ad_crm_imsg_history():
        """Get iMessage history for given phone numbers via direct DB read."""
        try:
            import subprocess, json as _json, os
            data = request.json or {}
            phones = data.get('phones', [])
            if not phones:
                return jsonify({'error': 'No phones provided'}), 400
            
            script = os.path.join(os.path.dirname(__file__), 'imsg_reader.py')
            result = subprocess.run(
                ['/opt/homebrew/bin/python3', script, _json.dumps(phones)],
                capture_output=True, text=True, timeout=15
            )
            if result.returncode != 0:
                return jsonify({'error': result.stderr.strip() or 'imsg_reader failed'}), 500
            
            all_messages = _json.loads(result.stdout)
            # Sort by date descending
            all_messages.sort(key=lambda m: m.get('date',''), reverse=True)
            return jsonify({'messages': all_messages[:30]})
        except Exception as e:
            return jsonify({'error': str(e)}), 500

    @app.route('/api/ad-crm/send-followup', methods=['POST'])
    @login_required
    def api_ad_crm_send_followup():
        """Send follow-up message via iMessage."""
        try:
            import ad_crm, subprocess
            data = request.json or {}
            store_id = data.get('store_id')
            phone = data.get('phone', '').strip()
            message = data.get('message', '').strip()
            
            if not phone or not message:
                return jsonify({'error': 'Phone and message required'}), 400
            
            # Format phone for imsg (ensure +1 prefix)
            phone_clean = phone.replace('-','').replace(' ','').replace('(','').replace(')','')
            if len(phone_clean) == 10:
                phone_clean = '+1' + phone_clean
            elif not phone_clean.startswith('+'):
                phone_clean = '+' + phone_clean
            
            # Send via imsg
            result = subprocess.run(
                ['/opt/homebrew/bin/imsg', 'send', '--to', phone_clean, '--text', message, '--service', 'imessage'],
                capture_output=True, text=True, timeout=15
            )
            
            if result.returncode != 0:
                return jsonify({'error': f'imsg error: {result.stderr.strip() or result.stdout.strip()}'}), 500
            
            # Log the visit
            if store_id:
                ad_crm.log_visit(store_id, 'followup_imessage', f'Sent: {message[:80]}...' if len(message) > 80 else f'Sent: {message}')
            
            return jsonify({'ok': True, 'sent_to': phone_clean})
        except subprocess.TimeoutExpired:
            return jsonify({'error': 'iMessage send timed out'}), 500
        except Exception as e:
            return jsonify({'error': str(e)}), 500

    @app.route('/api/ad-crm/sync-messages', methods=['POST'])
    @login_required
    def api_ad_crm_sync_messages():
        """Scan Messages DB (iMessage/SMS/RCS) and log new visits."""
        try:
            import imsg_monitor
            import re as _re
            
            phone_map = imsg_monitor.get_sa_phones()
            mdb = __import__('sqlite3').connect(f'file:{imsg_monitor.MESSAGES_DB}?mode=ro', uri=True)
            crm = imsg_monitor.sqlite3.connect(imsg_monitor.CRM_DB)
            crm.row_factory = __import__('sqlite3').Row
            
            chats = mdb.execute('SELECT ROWID, chat_identifier, service_name FROM chat').fetchall()
            
            new_visits = 0
            for chat_rowid, ident, service_name in chats:
                ident_digits = ''.join(c for c in (ident or '') if c.isdigit())[-10:]
                if ident_digits not in phone_map:
                    continue
                
                info = phone_map[ident_digits]
                svc = (service_name or 'iMessage').lower()
                if 'rcs' in svc: service = 'rcs'
                elif 'sms' in svc: service = 'sms'
                else: service = 'imessage'
                
                msgs = mdb.execute('''
                    SELECT date(m.date/1000000000+978307200, 'unixepoch') as d,
                           m.is_from_me, m.text
                    FROM message m JOIN chat_message_join cmj ON cmj.message_id=m.ROWID
                    WHERE cmj.chat_id=? AND m.date/1000000000+978307200 > 1735689600
                    ORDER BY m.date
                ''', (chat_rowid,)).fetchall()
                
                dates_done = set()
                for m in msgs:
                    d = m[0]
                    if not d or d in dates_done:
                        continue
                    dates_done.add(d)
                    
                    existing = crm.execute('SELECT id FROM ad_visits WHERE store_id=? AND visit_date=?',
                                          (info['store_id'], d)).fetchone()
                    if existing:
                        continue
                    
                    direction = 'outbound' if m[1] else 'inbound'
                    vtype = f'{direction}_{service}'
                    txt = (m[2] or '[media]')[:100]
                    note = f"{'To' if m[1] else 'From'} {info['sales_name']}: {txt}"
                    
                    crm.execute('INSERT INTO ad_visits (store_id, visit_date, visit_type, notes) VALUES (?,?,?,?)',
                               (info['store_id'], d, vtype, note))
                    new_visits += 1
            
            crm.commit()
            crm.close()
            mdb.close()
            
            return jsonify({'ok': True, 'new_visits': new_visits})
        except Exception as e:
            return jsonify({'error': str(e)}), 500

